-- Poems batch 43
INSERT OR IGNORE INTO poems (id,title,author,dynasty,collection,collection_id,rhythmic,tags,excerpt,length,source_path,paragraphs) VALUES
('48b50413-6116-423a-b704-87348cac4267','柳 五','翁承贊','唐','唐诗','tang','','[]','纏繞春情卒未休，秦娥蕭史兩相求。',32,'全唐诗/poet.tang.39000.json','["纏繞春情卒未休，秦娥蕭史兩相求。", "玉句闌內朱簾卷，瑟瑟絲籠十二樓。"]'),
('03a8fb6d-6062-4f55-a322-bb3378d17590','隋堤柳','翁承贊','唐','唐诗','tang','','[]','春半煙深汴水東，黃金絲軟不勝風。',32,'全唐诗/poet.tang.39000.json','["春半煙深汴水東，黃金絲軟不勝風。", "輕籠行殿迷天子，拋擲長安似夢中。"]'),
('bf176573-24f0-4ea7-bcf1-5dbdad107033','句','翁承贊','唐','唐诗','tang','','[]','煙蘿況逼神仙窟，丹竈還應許獨尋。',16,'全唐诗/poet.tang.39000.json','["煙蘿況逼神仙窟，丹竈還應許獨尋。"]'),
('c5d1f87f-2ce0-477d-9f2a-1dac7b61c746','送僧歸北巖寺','黃滔','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','北巖泉石清，本自高僧住。',120,'全唐诗/poet.tang.39000.json','["北巖泉石清，本自高僧住。", "新松五十年，藤蘿成古樹。", "題詩昔佳士，清風二林喻。", "上智失扣關，多被浮名誤。", "蓮扃壓月澗，空美黃金布。", "江翻島嶼沈，木落樓臺露。", "伊余東還際，每起煙霞慕。", "旋爲儉府招，未得窮野步。", "西軒白雲閣，師辭洞庭寓。", "越城今送歸，心到焚香處。"]'),
('e5646af5-3b1d-4ef8-aa76-c94e9ecf8085','寓言','黃滔','唐','唐诗','tang','','[]','流年五十前，朝朝倚少年。',48,'全唐诗/poet.tang.39000.json','["流年五十前，朝朝倚少年。", "流年五十後，日日侵皓首。", "非通非介人，誰論四十九。", "賢哉蘧伯玉，清風獨不朽。"]'),
('ec8fe1f7-3c66-45fe-9065-ef1e33cedd7e','長安書事','黃滔','唐','唐诗','tang','','[]','終不離青山，誰道雲無心。',60,'全唐诗/poet.tang.39000.json','["終不離青山，誰道雲無心。", "卻是白雲士，有時出中林。", "昨日擎紫泥，明日要黃金。", "炎夏羣木死，北海驚波深。", "伏蒲無一言，草疏賀德音。"]'),
('96fa9f49-f073-41df-8545-c22af44e51aa','賈客','黃滔','唐','唐诗','tang','','[]','大舟有深利，滄海無淺波。',36,'全唐诗/poet.tang.39000.json','["大舟有深利，滄海無淺波。", "利深波也深，君意竟如何。", "鯨鯢齒上路，何如少經過。"]'),
('bb6eb4a6-14bd-4b9e-8457-dea7db03fed3','寄友人','黃滔','唐','唐诗','tang','','[]','君愛桃李花，桃李花易飄。',60,'全唐诗/poet.tang.39000.json','["君愛桃李花，桃李花易飄。", "妾憐松柏色，松柏色難凋。", "當年識君初，指期非一朝。", "今辰見君意，日暮何蕭條。", "入門有勢利，孰能無囂囂。"]'),
('2aee0dd7-0ef1-49b9-a0e3-bb0de612f2e9','落花','黃滔','唐','唐诗','tang','','[]','落花辭高樹，最是愁人處。',48,'全唐诗/poet.tang.39000.json','["落花辭高樹，最是愁人處。", "一一旋成泥，日暮有風雨。", "不如沙上蓬，根斷隨長風。", "飄然與道俱，無情任西東。"]'),
('c18cf82b-636a-4891-83e5-369f0f6828e5','寄徐正字夤','黃滔','唐','唐诗','tang','','[]','八月月如冰，登樓見姑射。',48,'全唐诗/poet.tang.39000.json','["八月月如冰，登樓見姑射。", "美人隔千里，相思無羽駕。", "紅蘭裛露衰，誰以流光訝。", "何當詩一句，同吟祝玄化。"]'),
('3d041602-050f-46d6-a7aa-81848ed2b018','秋夕貧居','黃滔','唐','唐诗','tang','','[]','聽歌桂席闌，下馬槐煙裏。',48,'全唐诗/poet.tang.39000.json','["聽歌桂席闌，下馬槐煙裏。", "豪門腐粱肉，窮巷思糠秕。", "孤燈照獨吟，半壁秋花死。", "遲明亦如晦，雞唱徒爲爾。"]'),
('4fef34aa-05e6-4c93-83dc-1de9c48d28df','書懷寄友人','黃滔','唐','唐诗','tang','','[]','此生如孤燈，素心挑易盡。',48,'全唐诗/poet.tang.39000.json','["此生如孤燈，素心挑易盡。", "不及如頑石，非與磨礱近。", "常思揚子雲，五藏曾離身。", "寂寞一生中，千載空清芬。"]'),
('2a185f7e-a6a6-4d94-ab9e-40078ec107ef','閨怨','黃滔','唐','唐诗','tang','','[]','妾家五嶺南，君戍三城北。',48,'全唐诗/poet.tang.39000.json','["妾家五嶺南，君戍三城北。", "雁來雖有書，衡陽越不得。", "別久情易料，豈在窺翰墨。", "塞上無煙花，寧思妾顏色。"]'),
('b6dcc6dc-5c43-41e1-baaa-57b4abd5b157','喜翁文堯員外病起','黃滔','唐','唐诗','tang','','[]','衛玠羊車懸，長卿駟馬姿。',120,'全唐诗/poet.tang.39000.json','["衛玠羊車懸，長卿駟馬姿。", "天嫌太端正，神乃減風儀。", "飲冰俾消渴，斷穀皆清羸。", "越僧誇艾炷，秦女隔花枝。", "自能論苦器，不假求良醫。", "驚殺漳濱鬼，錯與劉生隨。", "昨日已如虎，今朝謁荀池。", "揚鞭入王門，四面人熙熙。", "青桂任霜霰，尺璧無瑕疵。", "迴塵却惆悵，歸闕難遲遲。"]'),
('e9552aa0-460f-402b-9478-496784cccf05','寄鄭縣李侍御','黃滔','唐','唐诗','tang','','[]','古縣新煙火，東西入客詩。',48,'全唐诗/poet.tang.39000.json','["古縣新煙火，東西入客詩。", "靜長如假日，貧更甚閑時。", "僧借松蘿住，人將雨雪期。", "三年一官罷，嶽石看成碑。"]'),
('df5bb60b-c2df-4352-b47a-91f129c7f45a','上李補闕','黃滔','唐','唐诗','tang','','[]','十洲非暫別，龍尾肯慵登。',48,'全唐诗/poet.tang.39000.json','["十洲非暫別，龍尾肯慵登。", "諫草封山藥，朝衣施衲僧。", "月留江客待，句歷釣船徵。", "終恐林棲去，飡霞葉上昇。"]'),
('c96262a0-1c55-425f-a44c-bb2ea789924c','送李山人往湘中','黃滔','唐','唐诗','tang','','[]','漢渚往湘川，乘流入遠天。',48,'全唐诗/poet.tang.39000.json','["漢渚往湘川，乘流入遠天。", "新秋無岸水，明月有琴船。", "露坐應通曉，萍居恐隔年。", "嶽峰千萬仞，知上嘯猿巔。"]'),
('a68c5026-aad1-4be5-857c-11b2c2e567df','書崔少府居','黃滔','唐','唐诗','tang','','[]','魯史蜀琴旁，陶然舉一觴。',48,'全唐诗/poet.tang.39000.json','["魯史蜀琴旁，陶然舉一觴。", "夕陽明島嶼，秋水淺池塘。", "世亂憐官替，家貧值歲荒。", "前峰亦曾宿，知有辟寒方。"]'),
('485cabe6-1709-438e-894c-7d994ca9d4a7','敷水盧校書','黃滔','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','九霄無詔下，何事近清塵。',48,'全唐诗/poet.tang.39000.json','["九霄無詔下，何事近清塵。", "宅帶松蘿僻，日唯猿鳥親。", "吟高僊掌月，期有洞庭人。", "莫問煙霞句，懸知見嶽神。"]'),
('68697dad-9428-4dbb-87c9-4dcefd252287','寄漢上友人','黃滔','唐','唐诗','tang','','[]','襄漢多清景，東遊已不能。',48,'全唐诗/poet.tang.39000.json','["襄漢多清景，東遊已不能。", "蒹葭照流水，風雨撲孤燈。", "獻賦聞新鴈，思山見去僧。", "知君北來日，惆悵亦難勝。"]'),
('10455ddd-4726-405e-8e76-c09f2d0b50d8','貽林鐸','黃滔','唐','唐诗','tang','','[]','終被春闈屈，低回至白頭。',48,'全唐诗/poet.tang.39000.json','["終被春闈屈，低回至白頭。", "寄家僧許嶽，釣浦雨移洲。", "戰士曾憐善，豪門不信愁。", "王孫草還綠，何處擬羈遊。"]'),
('9d2555a7-a672-4d0f-a20e-603a853b86f7','書懷','黃滔','唐','唐诗','tang','','[]','退耕逢歉歲，逐貢愧行朝。',48,'全唐诗/poet.tang.39000.json','["退耕逢歉歲，逐貢愧行朝。", "道在愁雖淺，吟勞鬢欲凋。", "破村虹入井，孤館客投魈。", "誰怕秋風起，聽蟬度渭橋。"]'),
('89147c08-d675-43b2-b51e-6fa3b331b736','送陳明府歸衡陽','黃滔','唐','唐诗','tang','','[]','鶵鶴兼留下，單車出柳煙。',48,'全唐诗/poet.tang.39000.json','["鶵鶴兼留下，單車出柳煙。", "三年兩殊考，一日數離筵。", "久別湖波綠，相思嶽月圓。", "翠蘿曾隱處，定恐卻求仙。"]'),
('8c5d3de5-d043-4402-aa7c-c43cb484b5ac','秋辭江南','黃滔','唐','唐诗','tang','','[]','灞陵橋上路，難負一年期。',48,'全唐诗/poet.tang.39000.json','["灞陵橋上路，難負一年期。", "積雨鴻來夜，重江客去時。", "勞生多故疾，漸老少新知。", "惆悵都堂內，無門雪滯遺。"]'),
('f59119f6-d2db-4765-9b5c-b148d5888cc0','入關旅次言懷','黃滔','唐','唐诗','tang','','[]','寸心唯自切，上國與誰期。',48,'全唐诗/poet.tang.39000.json','["寸心唯自切，上國與誰期。", "月晦時風雨，秋深日別離。", "便休終未肯，已苦不能疑。", "獨媿商山路，千年四皓祠。"]'),
('e7d00d66-b549-4f27-8cc4-cabc9f0025a8','貽李山人','黃滔','唐','唐诗','tang','','[]','野步愛江濱，江僧得見頻。',48,'全唐诗/poet.tang.39000.json','["野步愛江濱，江僧得見頻。", "新文無古集，往事有清塵。", "松竹寒時雨，池塘勝處春。", "定應雲雨內，陶謝是前身。"]'),
('02e74cea-0e1c-49cf-890d-be40de69a59f','寄邊上從事','黃滔','唐','唐诗','tang','','[]','斜日下孤城，長吟出點兵。',48,'全唐诗/poet.tang.39000.json','["斜日下孤城，長吟出點兵。", "羽書和客卷，邊思雜詩情。", "朔雪定鴻翼，西風嚴角聲。", "吟餘多獨坐，沙月對樓生。"]'),
('cd5435fc-4df6-4485-ac5a-6b34bf5d3653','題東林寺元祐上人院','黃滔','唐','唐诗','tang','','[]','廬阜東林寺，良遊耻未曾。',48,'全唐诗/poet.tang.39000.json','["廬阜東林寺，良遊耻未曾。", "半生隨計吏，一日對禪僧。", "泉遠攜茶看，峰高結伴登。", "迷津出門是，子細問三乘。"]'),
('96c57b5b-6810-4365-a2d9-cdddb2e76b42','送陳樵下第東歸','黃滔','唐','唐诗','tang','','[]','青山烹茗石，滄海寄家船。',48,'全唐诗/poet.tang.39000.json','["青山烹茗石，滄海寄家船。", "雖得重吟歷，終難任意眠。", "碪疎連寺柳，風爽徹城泉。", "送目紅蕉外，來期已杳然。"]'),
('3ef03442-7fe5-4217-b866-1d9c0b9ec0c0','寄陳磻隱居','黃滔','唐','唐诗','tang','','[]','道經前輩許，名拔後時喧。',48,'全唐诗/poet.tang.39000.json','["道經前輩許，名拔後時喧。", "虛左中興榜，無先北海尊。", "新文漢氏史，別墅謝公村。", "須到三徵處，堂堂謁帝閽。"]'),
('fa8a28c1-b331-448b-9c08-d9467413fb3a','寄林寬','黃滔','唐','唐诗','tang','','[]','相知四十年，故國與長安。',48,'全唐诗/poet.tang.39000.json','["相知四十年，故國與長安。", "俱喜今辰在，休論往歲難。", "海鳴秋日黑，山直夏風寒。", "終始前儒道，昇沈盡一般。"]'),
('25017fba-f180-4dc1-9968-7fd0362eedf3','退居','黃滔','唐','唐诗','tang','','[]','老歸江上村，孤寂欲何言。',48,'全唐诗/poet.tang.39000.json','["老歸江上村，孤寂欲何言。", "世亂時人物，家貧後子孫。", "青山寒帶雨，古木夜啼猿。", "惆悵西川舉，戎裝度劍門。"]'),
('cb6893c6-25b1-49e7-8cc1-f67b172beaba','送友人邊遊','黃滔','唐','唐诗','tang','','[]','銜杯國門外，分手見殘陽。',48,'全唐诗/poet.tang.39000.json','["銜杯國門外，分手見殘陽。", "何日還南越，今朝往北荒。", "砂城經雨壞，虜騎入秋狂。", "親詠關山月，歸吟鬢的霜。"]'),
('7b3f7bc9-3d23-4756-89b2-0a40ee1f18da','下第出京','黃滔','唐','唐诗','tang','','[]','還失禮官求，花時出雍州。',48,'全唐诗/poet.tang.39000.json','["還失禮官求，花時出雍州。", "一生爲遠客，幾處未曾遊。", "故疾江南雨，單衣薊北秋。", "茫茫數年事，今日淚俱流。"]'),
('41b69f07-c4a0-4f82-ae2a-b339e3ebcef9','遊東林寺','黃滔','唐','唐诗','tang','','[]','平生愛山水，下馬虎溪時。',48,'全唐诗/poet.tang.39000.json','["平生愛山水，下馬虎溪時。", "已到終嫌晚，重遊預作期。", "寺寒三伏雨，松偃數朝枝。", "翻譯如曾見，白蓮開舊池。"]'),
('121b0bb9-666a-4f13-80da-999fa8b1f8d9','贈懷光上人','黃滔','唐','唐诗','tang','','[]','謝城還擁入，師以接人勞。',48,'全唐诗/poet.tang.39000.json','["謝城還擁入，師以接人勞。", "過午休齋慣，離經吐論高。", "頂寒拳素髮，珠銳走紅絛。", "終憶泉山寺，聽猨看海濤。"]'),
('1e8e5400-a783-425d-97c6-55e05cdfa277','憶廬山舊遊','黃滔','唐','唐诗','tang','','["\u5e90\u5c71"]','前年入廬嶽，數宿在靈溪。',48,'全唐诗/poet.tang.39000.json','["前年入廬嶽，數宿在靈溪。", "殘燭松堂掩，孤峰月狖啼。", "平生爲客老，勝境失雲棲。", "縱有重遊日，煙霞會恐迷。"]'),
('ab9040ce-f02e-4d91-8126-ca43a6fd7a69','別友人','黃滔','唐','唐诗','tang','','[]','莫恨東牆下，頻傷命不通。',48,'全唐诗/poet.tang.39000.json','["莫恨東牆下，頻傷命不通。", "苦心如有感，他日自推公。", "雨夜扁舟發，花時別酒空。", "越山煙翠在，終媿臥雲翁。"]'),
('4be06e0a-3786-4101-98f9-3da9642d2bc7','陳侍御新居','黃滔','唐','唐诗','tang','','["\u592a\u6e56"]','幕客開新第，詞人遍有詩。',48,'全唐诗/poet.tang.39000.json','["幕客開新第，詞人遍有詩。", "山憐九仙近，石買太湖奇。", "樹勢想高日，地形誇得時。", "自然成避俗，休與白雲期。"]'),
('7e31e280-07e7-498f-9362-3cd49c0d0ae0','寄從兄璞','黃滔','唐','唐诗','tang','','[]','縱徴終不起，相與避煙塵。',48,'全唐诗/poet.tang.39000.json','["縱徴終不起，相與避煙塵。", "待到中興日，同看上國春。", "新詩說人盡，舊宅落花頻。", "移覓深山住，啼猿作四鄰。"]'),
('13b3ca44-8ea0-4043-8e37-ad204a981360','寄李校書遊簡寂觀','黃滔','唐','唐诗','tang','','[]','古觀雲溪上，孤懷永夜中。',48,'全唐诗/poet.tang.39000.json','["古觀雲溪上，孤懷永夜中。", "梧桐四更雨，山水一庭風。", "詩得如何句，仙遊最勝宮。", "卻愁逢羽客，相與入煙空。"]'),
('c42b5436-3ab8-4263-ae8d-dc27bae4ca06','寄友人山居','黃滔','唐','唐诗','tang','','[]','斷嶠滄江上，相思恨阻尋。',48,'全唐诗/poet.tang.39000.json','["斷嶠滄江上，相思恨阻尋。", "高齋秋不掩，幾夜月當吟。", "落石有泉滴，盈庭無樹陰。", "茫茫名利內，何以拂塵襟。"]'),
('9628c479-0f1a-42ea-ac9b-b27498bd59af','上刑部盧員外','黃滔','唐','唐诗','tang','','[]','誰識在官意，開門樹色間。',48,'全唐诗/poet.tang.39000.json','["誰識在官意，開門樹色間。", "尋幽頻宿寺，乞假擬歸山。", "半白侵吟鬢，微紅見藥顏。", "不知琴月夜，幾客得同閑。"]'),
('fe957acd-1c58-4298-bd08-43ce2abadc03','送友人遊邊','黃滔','唐','唐诗','tang','','[]','虜酒不能濃，縱傾愁亦重。',48,'全唐诗/poet.tang.39000.json','["虜酒不能濃，縱傾愁亦重。", "關河初落日，霜雪下窮冬。", "野燒枯蓬旋，沙風匹馬衝。", "薊門無易過，千里斷人蹤。"]'),
('6902a217-01c8-4538-9f3e-d042e7570143','和友人酬寄','黃滔','唐','唐诗','tang','','[]','新發煙霞詠，高人得以傳。',48,'全唐诗/poet.tang.39000.json','["新發煙霞詠，高人得以傳。", "吟銷松際雨，冷咽石間泉。", "大國兵戈日，故鄉饑饉年。", "相逢江海上，寧免一潸然。"]'),
('a4e29f63-a381-4b4c-b888-fc9f293b748e','下第','黃滔','唐','唐诗','tang','','[]','昨夜孤燈下，闌干泣數行。',48,'全唐诗/poet.tang.39000.json','["昨夜孤燈下，闌干泣數行。", "辭家從早歲，落第在初場。", "青草湖田改，單車客路忙。", "何人立功業，新命到封王。"]'),
('1c929dac-3b44-4ce4-9f77-a9b26b1cb3aa','過商山','黃滔','唐','唐诗','tang','','[]','燕鴈一來後，人人盡到關。',48,'全唐诗/poet.tang.39000.json','["燕鴈一來後，人人盡到關。", "如何衝臘雪，獨自過商山。", "羸馬高坡下，哀猿絕壁間。", "此心無處說，鬢向少年斑。"]'),
('4d6ba67f-a834-47b8-a75a-550689740918','旅懷','黃滔','唐','唐诗','tang','','[]','蕭颯聞風葉，驚時不自堪。',48,'全唐诗/poet.tang.39000.json','["蕭颯聞風葉，驚時不自堪。", "宦名中夜切，人事長年諳。", "古畫僧留與，新知客遇談。", "鄉心隨去鴈，一一到江南。"]'),
('084b1d08-48d1-453c-842e-4f75dfd18f1a','冬暮山舍喜標上人見訪','黃滔','唐','唐诗','tang','','[]','寂寞三冬杪，深居業盡拋。',48,'全唐诗/poet.tang.39000.json','["寂寞三冬杪，深居業盡拋。", "逕松開雪後，砌竹忽僧敲。", "茗汲冰銷溜，鑪燒鵲去巢。", "共談慵僻意，微日下林梢。"]'),
('80ed0287-9ffd-4d97-a7d8-f39d6a7320d3','關中言懷','黃滔','唐','唐诗','tang','','[]','三秦五嶺意，不得不依然。',48,'全唐诗/poet.tang.39000.json','["三秦五嶺意，不得不依然。", "跡寓枯槐曲，業蕪芳草川。", "花當落第眼，雨暗出城天。", "層閣浮雲外，何人動管絃。"]'),
('b4a31726-f501-4c68-8e80-aca598d1cb30','題友人山居','黃滔','唐','唐诗','tang','','["\u5c71", "\u5bfb\u8bbf", "\u5199\u666f"]','到君棲跡所，竹逕與衡門。',48,'全唐诗/poet.tang.39000.json','["到君棲跡所，竹逕與衡門。", "亦在乾坤內，獨無塵俗喧。", "新泉浮石蘚，崩壁露松根。", "更說尋僧處，孤峰上嘯猿。"]'),
('3fdeca5f-5bbe-4236-9ae6-acb7781bff92','寄敷水盧校書','黃滔','唐','唐诗','tang','','["\u534e\u5c71"]','諫省垂清論，仙曹豈久臨。',48,'全唐诗/poet.tang.39000.json','["諫省垂清論，仙曹豈久臨。", "雖專良史業，未畏直臣心。", "路入丹霄近，家藏華嶽深。", "還如韓吏部，誰不望知音。"]'),
('567751ef-9c7d-48c8-8429-548cda0cc1d2','贈明州霍員外','黃滔','唐','唐诗','tang','','[]','惠化如施雨，鄰州亦可依。',48,'全唐诗/poet.tang.39000.json','["惠化如施雨，鄰州亦可依。", "正衙無吏近，高會覺人稀。", "海日旗邊出，沙禽角外歸。", "四明多隱客，閑約到巖扉。"]'),
('b32a6b4f-1cc0-4728-8b6c-55ddfcfbfb40','題友人山齋','黃滔','唐','唐诗','tang','','[]','疎竹漏斜暉，庭間陰復遺。',48,'全唐诗/poet.tang.39000.json','["疎竹漏斜暉，庭間陰復遺。", "句成苔石茗，吟弄雪窗碁。", "沙草泉經澀，林齋客集遲。", "西風虛見逼，未擬問京師。"]'),
('d0e8b795-051f-4dc6-8715-81c42a313e89','書事','黃滔','唐','唐诗','tang','','[]','望歲心空切，耕夫盡把弓。',48,'全唐诗/poet.tang.39000.json','["望歲心空切，耕夫盡把弓。", "千家數人在，一稅十年空。", "沒陣風沙黑，燒城水陸紅。", "飛章奏西蜀，明詔與殊功。"]'),
('f93bf510-a18b-4c66-9e7c-791db5882812','題山居逸人','黃滔','唐','唐诗','tang','','[]','十畝餘蘆葦，新秋看雪霜。',48,'全唐诗/poet.tang.39000.json','["十畝餘蘆葦，新秋看雪霜。", "世人誰到此，塵念自應忘。", "斜日風收釣，深秋雨信梁。", "不知雙闕下，何以謂軒裳。"]'),
('b85072e7-c23d-46ae-83fc-a2fb2a1473a1','題鄭山人居','黃滔','唐','唐诗','tang','','[]','履迹遍莓苔，幽枝間藥裁。',50,'全唐诗/poet.tang.39000.json','["履迹遍莓苔，幽枝間藥裁。", "枯杉[擎]雪朵，破牖觸風開。", "泉自孤峰落，人從諸洞來。", "終期宿清夜，斟茗說天台。"]'),
('fa3901b0-d064-470a-bd8b-d67643063189','秋晚山居','黃滔','唐','唐诗','tang','','[]','爽氣遍搜空，難堪倚望中。',48,'全唐诗/poet.tang.39000.json','["爽氣遍搜空，難堪倚望中。", "孤煙愁落日，高木病西風。", "山寂樵聲出，露涼蟬思窮。", "此時塵外事，幽默幾人同。"]'),
('a5bec5cf-a489-46cc-9cc3-f6e77ba5f3bc','遊山','黃滔','唐','唐诗','tang','','[]','洞門穿瀑布，塵世豈能通。',48,'全唐诗/poet.tang.39000.json','["洞門穿瀑布，塵世豈能通。", "曾有遊山客，來逢採藥翁。", "異花尋復失，幽逕躡還窮。", "擬作經宵計，風雷立滿空。"]'),
('1e81d753-2d77-4349-b463-135f61da74d7','題王侍御宅內亭子','黃滔','唐','唐诗','tang','','[]','俗間塵外境，郭內宅中亭。',48,'全唐诗/poet.tang.39000.json','["俗間塵外境，郭內宅中亭。", "或有人家創，還無蓮幕馨。", "石曾湖岸見，琴誤嶽樓聽。", "來客頻頻說，終須作畫屏。"]'),
('36907cec-059f-4a2f-8a33-8fe0dac48a73','題道成上人院','黃滔','唐','唐诗','tang','','[]','花宮城郭內，師住亦清涼。',48,'全唐诗/poet.tang.39000.json','["花宮城郭內，師住亦清涼。", "何必天台寺，幽蟬瀑布房。", "簟舒湘竹滑，茗煮蜀芽香。", "更看道高處，居侯題翠梁。"]'),
('febf4670-d876-4013-a10c-58a5f21a9b2e','貧居冬杪','黃滔','唐','唐诗','tang','','[]','數塞未求通，吾非學養蒙。',48,'全唐诗/poet.tang.39000.json','["數塞未求通，吾非學養蒙。", "窮居歲杪雨，孤坐夜深風。", "年長慙昭代，才微辱至公。", "還愁把春酒，雙淚汚杯中。"]'),
('1d899491-16ef-47e3-a9eb-bf531fca1183','貽張蠙','黃滔','唐','唐诗','tang','','[]','夢思非一日，攜手却淒涼。',48,'全唐诗/poet.tang.39000.json','["夢思非一日，攜手却淒涼。", "詩見江南雹，遊經塞北霜。", "驅車先五漏，把菊後重陽。", "惆悵天邊桂，誰教歲歲香。"]'),
('bd3aecd2-6f77-4b14-a732-3786f0173b0d','晚春關中','黃滔','唐','唐诗','tang','','[]','忍歷通莊出，東風舞酒旗。',48,'全唐诗/poet.tang.39000.json','["忍歷通莊出，東風舞酒旗。", "百花無看處，三月到殘時。", "遊塞聞兵起，還吳值歲饑。", "定唯荒寺裏，坐與噪蟬期。"]'),
('adc79a5d-51fb-4330-bd4d-8d8442ab782f','河梁','黃滔','唐','唐诗','tang','','[]','五原人走馬，昨夜到京師。',48,'全唐诗/poet.tang.39000.json','["五原人走馬，昨夜到京師。", "繡戶新夫婦，河梁生別離。", "隴花開不豔，羌笛靜猶悲。", "惆悵良哉輔，鏗鏘立鳳池。"]'),
('5ddf7d55-5f6b-46f3-8f58-43f472de0512','送翁拾遺','黃滔','唐','唐诗','tang','','[]','還家俄赴闕，別思肯淒淒。',48,'全唐诗/poet.tang.39000.json','["還家俄赴闕，別思肯淒淒。", "山坐軺車看，詩持諫筆題。", "天開中國大，地設四維低。", "拜舞吾君後，青雲更有梯。"]'),
('e16df445-7b88-48d7-aae9-3c1ef334b813','逢友人','黃滔','唐','唐诗','tang','','[]','彼此若飄蓬，二年何所從。',48,'全唐诗/poet.tang.39000.json','["彼此若飄蓬，二年何所從。", "帝都秋未入，江館夜相逢。", "瘴嶺行衝夏，邊沙住隔冬。", "旅愁論未盡，古寺扣晨鍾。"]'),
('7b3db2f7-da36-49ef-b64a-38040045c9d8','寄湘中鄭明府','黃滔','唐','唐诗','tang','','[]','縣與白雲連，滄洲況縣前。',48,'全唐诗/poet.tang.39000.json','["縣與白雲連，滄洲況縣前。", "嶽僧同夜坐，江月看秋圓。", "琴拂莎庭石，茶擔乳洞泉。", "莫耽雲水興，疲俗待君痊。"]'),
('56735a45-59c6-4268-87c0-a4ae83058bdc','寄少常盧同年','黃滔','唐','唐诗','tang','','[]','官拜少常休，青緺換鹿裘。',48,'全唐诗/poet.tang.39000.json','["官拜少常休，青緺換鹿裘。", "狂歌離樂府，醉夢到瀛洲。", "古器巖耕得，神方客謎留。", "清溪莫沈釣，王者或畋遊。"]'),
('1ab523f2-027c-4478-90b8-7411413ecdd7','傷翁外甥','黃滔','唐','唐诗','tang','','[]','江頭去時路，歸客幾紛紛。',48,'全唐诗/poet.tang.39000.json','["江頭去時路，歸客幾紛紛。", "獨在異鄉歿，若爲慈母聞。", "青春成大夜，新雨壞孤墳。", "應作芝蘭出，泉臺月桂分。"]'),
('0335c1ce-cafe-4663-9ec2-85f03688537a','東山之遊未遂漸逼行期作四十字奉寄翁文堯員外','黃滔','唐','唐诗','tang','','[]','軺車難久駐，須到別離時。',48,'全唐诗/poet.tang.39000.json','["軺車難久駐，須到別離時。", "北闕定歸去，東山空作期。", "綠苔勞掃徑，丹鳳欲銜詞。", "楊柳開帆岸，今朝淚已垂。"]'),
('704fce76-2a06-4c39-9b5b-eda2bf50325b','送林寬下第東歸','黃滔','唐','唐诗','tang','','[]','爲君惆悵惜離京，年少無人有屈名。',64,'全唐诗/poet.tang.39000.json','["爲君惆悵惜離京，年少無人有屈名。", "積雪未開移發日，鳴蟬初急說來程。", "楚天去路過飛鴈，灞岸歸塵觸鎖城。", "又得新詩幾章別，煙村竹逕海濤聲。"]'),
('6c580cad-ce6b-4637-b1e3-90ac518cd0a7','商山贈隱者','黃滔','唐','唐诗','tang','','[]','誰不相逢話息機，九重城裏自依依。',64,'全唐诗/poet.tang.39000.json','["誰不相逢話息機，九重城裏自依依。", "蓬萊水淺有人說，商洛山高無客歸。", "數隻珍禽寒月在，千株古木熱時稀。", "西窓昨夜鳴蛩盡，知夢芝翁起扣扉。"]'),
('b6353732-05f3-4cfd-931c-7b544b81cb7c','送二友遊湘中','黃滔','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','千里楚江新雨晴，同征肯恨迹如萍。',64,'全唐诗/poet.tang.39000.json','["千里楚江新雨晴，同征肯恨迹如萍。", "孤舟泊處聯詩句，八月中旬宿洞庭。", "爲客早悲煙草綠，移家晚失嶽峯青。", "今來無計相從去，歸日汀洲乞畫屏。"]'),
('1ab535a2-e9ba-4df6-b85b-3f3352a6de24','塞下','黃滔','唐','唐诗','tang','','[]','匹馬蕭蕭去不前，平蕪千里見窮邊。',64,'全唐诗/poet.tang.39000.json','["匹馬蕭蕭去不前，平蕪千里見窮邊。", "關山色死秋深日，鼓角聲沈霜重天。", "荒骨或銜殘鐵露，驚風時掠暮沙旋。", "隴頭冤氣無歸處，化作陰雲飛杳然。"]'),
('21ac8527-c22c-4cab-9702-2e7745b52c4d','下第東歸留辭刑部鄭郎中諴','黃滔','唐','唐诗','tang','','[]','去違知己住違親，欲發羸蹄進退頻。',64,'全唐诗/poet.tang.39000.json','["去違知己住違親，欲發羸蹄進退頻。", "萬里家山歸養志，數年門館受恩身。", "鶯聲歷歷秦城曉，柳色依依灞水春。", "明日藍田關外路，連天風雨一行人。"]'),
('435a69ed-3f9f-48e7-b980-17878737d255','寄懷南北故人','黃滔','唐','唐诗','tang','','[]','秋風昨夜落芙蕖，一片離心到外區。',64,'全唐诗/poet.tang.39000.json','["秋風昨夜落芙蕖，一片離心到外區。", "南海浪高書墮水，北州城破客降胡。", "玉窗挑鳳佳人老，綺陌啼鶯碧樹枯。", "嶺上青風隴頭月，時通魂夢出來無。"]'),
('73d80199-550f-4669-86ba-99930e2b3650','關中言懷','黃滔','唐','唐诗','tang','','[]','事事朝朝委一尊，自知無復解趨奔。',64,'全唐诗/poet.tang.39000.json','["事事朝朝委一尊，自知無復解趨奔。", "試期交後猶爲客，公道開時敢說冤。", "窮巷住來經積雨，故山歸去見荒村。", "舉頭盡到斷腸處，何必秋風江上猿。"]'),
('25211bfb-1557-4b5a-9de6-03e56fea8577','閨怨','黃滔','唐','唐诗','tang','','[]','寸心杳與馬蹄隨，如蛻形容在錦帷。',64,'全唐诗/poet.tang.39000.json','["寸心杳與馬蹄隨，如蛻形容在錦帷。", "江上月明船發後，花間日暮信迴時。", "五陵夜作酬恩計，四塞秋爲破虜期。", "待到乘軺入門處，淚珠流盡玉顏衰。"]'),
('dccd2ff5-3019-49c7-939f-29c1d419bd7a','旅懷','黃滔','唐','唐诗','tang','','[]','未喫金丹看十洲，乃將身世作仇讎。',64,'全唐诗/poet.tang.39000.json','["未喫金丹看十洲，乃將身世作仇讎。", "羈遊數地值兵亂，宿在孤城聞雨秋。", "東越雲山卻思隱，西秦霜霰苦頻留。", "他人折盡月中桂，惆悵當年江上鷗。"]'),
('1c6e19dd-95cd-4885-90b0-afca61f6bbec','別友人','黃滔','唐','唐诗','tang','','[]','已喜相逢又怨嗟，十年飄泊在京華。',64,'全唐诗/poet.tang.39000.json','["已喜相逢又怨嗟，十年飄泊在京華。", "大朝多事還停舉，故國經荒未有家。", "鳥帶夕陽投遠樹，人衝臘雪往邊沙。", "夢魂空繫瀟湘岸，煙水茫茫蘆葦花。"]'),
('a8c11cc7-cb92-40d5-8924-9f6cac2d697d','寄羅浮山道者二首 一','黃滔','唐','唐诗','tang','','[]','天際雙山壓海濆，天漫絕頂海漫根。',64,'全唐诗/poet.tang.39000.json','["天際雙山壓海濆，天漫絕頂海漫根。", "時聞雷雨驚樵客，長有龍蛇護洞門。", "泉石暮含朱槿書，煙霞冬閉木綿溫。", "林間學道如容我，今便辭他寵辱喧。"]'),
('6c8d4916-c8ad-46a9-bfcc-778f2b56a17a','寄羅浮山道者二首 二','黃滔','唐','唐诗','tang','','[]','有人曾見洞中仙，纔到人間便越年。',64,'全唐诗/poet.tang.39000.json','["有人曾見洞中仙，纔到人間便越年。", "金鼎藥成龍入海，玉函書發鶴歸天。", "樓開石脉千尋直，山拆鼇鱗一半膻。", "誰到月明朝禮處，翠巖深鎖荔枝煙。"]'),
('6bd8e1b2-29a4-4ea1-b42b-3d81ab4a2fd3','喜侯舍人蜀中新命三首 一','黃滔','唐','唐诗','tang','','[]','八都詞客漫喧然，誰解飛揚誥誓間。',64,'全唐诗/poet.tang.39000.json','["八都詞客漫喧然，誰解飛揚誥誓間。", "五色綵毫裁鳳詔，九重天子豁龍顏。", "巴山月在趨朝去，錦水煙生入閤還。", "謀及中興多少事，莫愁明月不收關。"]'),
('a1cf1bba-7961-47bd-b372-2fa416236748','喜侯舍人蜀中新命三首 二','黃滔','唐','唐诗','tang','','[]','却搜文學起吾唐，暫失都城亦未妨。',64,'全唐诗/poet.tang.39000.json','["却搜文學起吾唐，暫失都城亦未妨。", "錦里幸爲丹鳳闕，幕賓徴出紫微郎。", "來時走馬隨中使，到日援毫定外方。", "若以掌言看諫獵，相如從此病輝光。"]'),
('6fe14d7e-13e9-4c74-a6c1-1f3d1eae81f5','喜侯舍人蜀中新命三首 三','黃滔','唐','唐诗','tang','','[]','賈誼纔承宣室召，左思唯預秘書流。',64,'全唐诗/poet.tang.39000.json','["賈誼纔承宣室召，左思唯預秘書流。", "賦家達者無過此，翰苑今朝是獨遊。", "立被御爐煙氣逼，吟經棧閣雨聲秋。", "內人未識江淹筆，竟問當時不早求。"]'),
('a2383203-7f9a-4be1-943f-470e77a2df3c','經安州感故鄭郎中二首 一','黃滔','唐','唐诗','tang','','[]','雲夢江頭見故城，人間四十載垂名。',64,'全唐诗/poet.tang.39000.json','["雲夢江頭見故城，人間四十載垂名。", "馬蹄踐處東風急，雞舌銷時北闕驚。", "嶽客出來尋古劍，野猨相聚呌孤塋。", "騰身飛上鳳凰閣，惆悵終乖吾黨情。"]'),
('bd74769a-356b-4c8d-b60d-539f57e6d5da','經安州感故鄭郎中二首 二','黃滔','唐','唐诗','tang','','[]','錦帳先生作牧州，干戈缺後見荒丘。',64,'全唐诗/poet.tang.39000.json','["錦帳先生作牧州，干戈缺後見荒丘。", "兼無姓賈兒童在，空有還珠煙水流。", "江句行人吟刻石，月腸是處象登樓。", "旅魂頻此歸來否，千載雲山屬一遊。"]'),
('3d7ada33-0e7c-4eb0-ba44-cdc2f184a807','出京別崔學士','黃滔','唐','唐诗','tang','','[]','一從門館遍投文，旋忝恩知驟出羣。',64,'全唐诗/poet.tang.39000.json','["一從門館遍投文，旋忝恩知驟出羣。", "不道鶴雞殊羽翼，許依龍虎借風雲。", "命奇未便乘東律，言重終期雪北軍。", "欲逐飄蓬向岐路，數宵垂淚戀清芬。"]'),
('685148ce-e01b-47cc-baea-6739abf73ddd','鴈','黃滔','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','楚岸花晴塞柳衰，年年南北去來期。',64,'全唐诗/poet.tang.39000.json','["楚岸花晴塞柳衰，年年南北去來期。", "江城日暮見飛處，旅館月明聞過時。", "萬里風霜休更恨，滿川煙草且須疑。", "洞庭雲水瀟湘雨，好把寒更一一知。"]'),
('6a8d61ae-cf5d-418b-86a5-d48214085f99','寄越從事林嵩侍御','黃滔','唐','唐诗','tang','','[]','子虛詞賦動君王，誰不期君入對敭。',64,'全唐诗/poet.tang.39000.json','["子虛詞賦動君王，誰不期君入對敭。", "莫戀兔園留看雪，已乘驄馬合凌霜。", "路歸天上行方別，道在人間久便香。", "應念都城舊吟客，十年蹤跡委滄浪。"]'),
('2bf4c380-5e9a-485b-a947-b51ff2006b38','長安書事','黃滔','唐','唐诗','tang','','[]','一年年課數千言，口祝心祠挈出門。',64,'全唐诗/poet.tang.39000.json','["一年年課數千言，口祝心祠挈出門。", "孤進難時誰肯薦，主司通處不須論。", "頻秋入自邊城雪，昨日聽來嶺樹猨。", "若有水田過十畝，早應歸去狄江村。"]'),
('663ead91-8308-46a4-a57b-2ae7c39b05df','旅懷寄友人','黃滔','唐','唐诗','tang','','[]','重疊愁腸只自知，苦於吞蘖亂於絲。',64,'全唐诗/poet.tang.39000.json','["重疊愁腸只自知，苦於吞蘖亂於絲。", "一船風雨分襟處，千里煙波迴首時。", "故國田園經戰後，窮荒日月逼秋期。", "鳴蟬似會悠揚意，陌上聲聲怨柳衰。"]'),
('3e18d109-7be2-4bd7-b2a1-fb39ae9c50cd','寄蔣先輩','黃滔','唐','唐诗','tang','','[]','夫差宮苑悉蒼苔，攜客朝遊夜未回。',64,'全唐诗/poet.tang.39000.json','["夫差宮苑悉蒼苔，攜客朝遊夜未回。", "塚上題詩蘇小見，江頭酹酒伍員來。", "秋風急處煙花落，明月中時水寺開。", "千載三吳有高跡，虎丘山翠益崔嵬。"]'),
('17e4c958-635b-44d8-8be9-2d772d75f693','旅懷','黃滔','唐','唐诗','tang','','["\u534e\u5c71"]','雪貌潛凋雪髮生，故園魂斷弟兼兄。',64,'全唐诗/poet.tang.39000.json','["雪貌潛凋雪髮生，故園魂斷弟兼兄。", "十年除夜在孤館，萬里一身求大名。", "空有新詩高華嶽，已無丹懇出秦城。", "侯門莫問曾遊處，槐柳影中肝膽傾。"]'),
('5cf4dd03-6197-40cb-b295-d1bb7cf4a6d0','放榜日','黃滔','唐','唐诗','tang','','[]','吾唐取士最堪誇，仙榜標名出曙霞。',64,'全唐诗/poet.tang.39000.json','["吾唐取士最堪誇，仙榜標名出曙霞。", "白馬嘶風三十轡，朱門秉燭一千家。", "郄詵聯臂昇天路，宣聖飛章奏日華。", "歲歲人人來不得，曲江煙水杏園花。"]'),
('819b396b-71f5-4e41-937d-cf1d64c89c33','二月二日宴中貽同年封先輩渭','黃滔','唐','唐诗','tang','','[]','帝堯城裏日銜杯，每倚嵇康到玉頹。',64,'全唐诗/poet.tang.39000.json','["帝堯城裏日銜杯，每倚嵇康到玉頹。", "桂苑五更聽榜後，蓬山二月看花開。", "垂名入甲成龍去，列姓如丁作鶴來。", "同戴大恩何處報，永言交道契陳雷。"]'),
('f15a46a9-3e02-43fa-a7e7-3d3f6cd711e0','新野道中','黃滔','唐','唐诗','tang','','[]','野堂如雪草如茵，光武城邊一水濱。',64,'全唐诗/poet.tang.39000.json','["野堂如雪草如茵，光武城邊一水濱。", "越客歸遙春有雨，杜鵑啼苦夜無人。", "東堂歲去銜杯嬾，南浦期來落淚頻。", "莫道還家不惆悵，蘇秦羈旅長卿貧。"]'),
('95769f6e-18f0-47cd-9c11-ccbfa7cf7ce4','酬俞鈞','黃滔','唐','唐诗','tang','','[]','鄉書一忝薦延恩，二紀三朝泣省門。',64,'全唐诗/poet.tang.39000.json','["鄉書一忝薦延恩，二紀三朝泣省門。", "雖忝立名經聖鑒，敢期興詠疊嘉言。", "莫論蟾月無梯接，大底龍津有浪翻。", "今日朝廷推草澤，佇君承詔出雲根。"]'),
('50dfc0f1-d8d1-43de-b7c8-b077c3dc449f','寄同年崔學士','黃滔','唐','唐诗','tang','','[]','半因同醉杏花園，塵忝鴻鑪與鑄顏。',64,'全唐诗/poet.tang.39000.json','["半因同醉杏花園，塵忝鴻鑪與鑄顏。", "已脫素衣酬素髮，敢持青桂愛青山。", "雖知珠樹懸天上，終賴銀河接世間。", "畢使海涯能拔宅，三秦二十四畿寰。"]'),
('22bc27f4-9c98-43d1-849d-25377a97e9d7','御試二首 一','黃滔','唐','唐诗','tang','','[]','已表隋珠各自攜，更從瓊殿立丹梯。',64,'全唐诗/poet.tang.39000.json','["已表隋珠各自攜，更從瓊殿立丹梯。", "九華燈作三條燭，萬乘君懸四首題。", "靈鳳敢期翻雪羽，洞簫應或諷金閨。", "明朝莫惜場場醉，青桂新香有紫泥。"]'),
('2021be1c-b9f4-45a7-bea9-673c4b6f2a85','御試二首 二','黃滔','唐','唐诗','tang','','[]','六曹三省列簪裾，丹詔宣來試士初。',64,'全唐诗/poet.tang.39000.json','["六曹三省列簪裾，丹詔宣來試士初。", "不是玉皇疑羽客，要教金榜帶天書。", "詞臣假寐題黃絹，宮女敲銅奏子虛。", "御目四篇酬九百，敢從燈下畧躊躇。"]'),
('371eaae7-d6a0-47ae-8092-93f1badb330b','寄陳侍御','黃滔','唐','唐诗','tang','','[]','千年二相未全誇，猶闕閩城賀降麻。',64,'全唐诗/poet.tang.39000.json','["千年二相未全誇，猶闕閩城賀降麻。", "何必錦衣須太守，別無蓮幕勝王家。", "醴泉湧處休論水，黃菊開時獨是花。", "九級燕金滿尊酒，卻愁隨詔謁承華。"]'),
('68ab63c2-34af-464b-974b-b82adc3b2464','酬徐正字夤','黃滔','唐','唐诗','tang','','[]','已免蹉跎負歲華，敢辭霜鬢雪呈花。',64,'全唐诗/poet.tang.39000.json','["已免蹉跎負歲華，敢辭霜鬢雪呈花。", "名從兩榜考昇第，官自三台追起家。", "疋馬有期歸輦轂，故山無計戀桑麻。", "莫言蓬閣從容久，披處終知金在砂。"]'),
('47531e5a-70a7-4419-9f91-90ce7221d62d','辭相府','黃滔','唐','唐诗','tang','','[]','從漢至唐分五州，誰爲將相作諸侯。',64,'全唐诗/poet.tang.39000.json','["從漢至唐分五州，誰爲將相作諸侯。", "閩江似鏡正堪戀，秦客如蓬難久留。", "匹馬忍辭藩屏去，小才寧副廟堂求。", "今朝拜別幡幢下，雙淚如珠滴不休。"]'),
('776a5065-9c8f-4c93-bfb5-96e98bc27836','寄羅郎中隱','黃滔','唐','唐诗','tang','','["\u94b1\u5858\u6c5f"]','休向中興雪至冤，錢塘江上看濤翻。',64,'全唐诗/poet.tang.39000.json','["休向中興雪至冤，錢塘江上看濤翻。", "三徵不起時賢議，九轉終成道者言。", "綠酒千杯腸已爛，新詩數首骨猶存。", "瑤蟾若使知人事，仙桂應遭蠹卻根。"]'),
('3ed3198c-f68a-45c9-9280-d90b3f8a1547','江行遇王侍御','黃滔','唐','唐诗','tang','','[]','數年分散秦吳隔，暫泊官船浦柳中。',64,'全唐诗/poet.tang.39000.json','["數年分散秦吳隔，暫泊官船浦柳中。", "新草軍書名更重，久辭山逕業應空。", "渡頭潮落將行客，天際風高未宿鴻。", "此日相逢魂合斷，賴君身事漸飛沖。"]'),
('7b7bd93c-fa2e-4ce8-b239-62334fa1f94e','客舍秋晚夜懷故山','黃滔','唐','唐诗','tang','','[]','寥寥深巷客中居，況值窮秋百事疎。',64,'全唐诗/poet.tang.39000.json','["寥寥深巷客中居，況值窮秋百事疎。", "孤枕憶山千里外，破窗聞雨五更初。", "經年荒草侵幽逕，幾樹西風鎖弊廬。", "長繫寸心歸未得，起挑殘燭獨躊躇。"]'),
('0013fc1f-5718-4f3f-878a-1e546d4bb5cd','絳州鄭尚書','黃滔','唐','唐诗','tang','','[]','旌旗日日展東風，雲稼連山雪刃空。',64,'全唐诗/poet.tang.39000.json','["旌旗日日展東風，雲稼連山雪刃空。", "剖竹已知垂鳳食，摘珠何必到龍宮。", "諫垣虛位期飛步，翰苑含毫待紀公。", "誰謂唐城諸父老，今時得見蜀文翁。"]'),
('94b0139a-d220-421e-b1e0-98a545a24300','喜陳先輩及第','黃滔','唐','唐诗','tang','','[]','今年春已到京華，天與吾曹雪怨嗟。',64,'全唐诗/poet.tang.39000.json','["今年春已到京華，天與吾曹雪怨嗟。", "甲乙中時公道復，朝廷看處主司誇。", "飛離海浪從燒尾，嚥卻金丹定易牙。", "不是駕前偏落羽，錦城爭得杏園花。"]'),
('46361e22-f75b-401f-bfda-576592bb2243','延福里居和林寬何紹餘醻寄','黃滔','唐','唐诗','tang','','[]','長說愁吟逆旅中，一庭深雪一窗風。',64,'全唐诗/poet.tang.39000.json','["長說愁吟逆旅中，一庭深雪一窗風。", "眼前道路無心覓，象外煙霞有句通。", "幾度相留侵鼓散，頻聞會宿著僧同。", "高情未以干時廢，屬和因知興不窮。"]'),
('81ae0bf3-eaaa-4700-9ff6-342e2945aafe','贈宿松楊明府','黃滔','唐','唐诗','tang','','[]','溪上家家禮樂新，始知爲政異常倫。',64,'全唐诗/poet.tang.39000.json','["溪上家家禮樂新，始知爲政異常倫。", "若非似水清無底，爭得如冰凜拂人。", "月狖聲和琴調咽，煙村景接柳條春。", "宦遊兼得逍遙趣，休憶三吳舊釣津。"]'),
('22180198-25bc-42e9-ab4c-f47e1b81395e','送僧','黃滔','唐','唐诗','tang','','[]','纔年七歲便從師，猶說辭家學佛遲。',64,'全唐诗/poet.tang.39000.json','["纔年七歲便從師，猶說辭家學佛遲。", "新斸松蘿還不住，愛尋雲水擬何之。", "孤溪雪滿維舟夜，疊嶂猿啼過寺時。", "鳥道瀧湫悉行後，豈將翻譯負心期。"]'),
('007ab3b6-4a50-4b26-ab43-b68900d1c257','贈鄭明府','黃滔','唐','唐诗','tang','','[]','庭羅衙吏眼看山，真恐風流是謫仙。',64,'全唐诗/poet.tang.39000.json','["庭羅衙吏眼看山，真恐風流是謫仙。", "垂柳五株春婭姹，鳴琴一弄水潺湲。", "援毫斷獄登殊考，駐樂題詩得出聯。", "莫起陶潛折腰歎，才高位下始稱賢。"]'),
('8fabed83-de6a-401f-b4b4-f8e31678edd6','江州夜宴獻陳員外','黃滔','唐','唐诗','tang','','[]','多少歡娛簇眼前，潯陽江上夜開筵。',64,'全唐诗/poet.tang.39000.json','["多少歡娛簇眼前，潯陽江上夜開筵。", "數枝紅蠟啼香淚，兩面青娥拆瑞蓮。", "清管徹時斟玉醑，碧籌回處擲金船。", "因知往歲樓中月，占得風流是偶然。"]'),
('421a8c1a-1f29-4d01-a168-f38f6ab08fec','湘中贈張逸人','黃滔','唐','唐诗','tang','','[]','羽衣零落帽欹斜，不自孤峰即海沙。',64,'全唐诗/poet.tang.39000.json','["羽衣零落帽欹斜，不自孤峰即海沙。", "曾爲蜀山成寓跡，又因湘水擬營家。", "鳴琴坐見燕鴻沒，曳履吟忘野逕賒。", "更愛扁舟宿寒夜，獨聽風雨過蘆花。"]'),
('e59fc046-6c99-4eb3-9d59-0fd11ecb1de2','寓題','黃滔','唐','唐诗','tang','','[]','紛紛墨勅除官日，處處紅旗打賊時。',64,'全唐诗/poet.tang.39000.json','["紛紛墨勅除官日，處處紅旗打賊時。", "竿底得璜猶未用，夢中吞鳥擬何爲。", "損生莫若攀丹桂，免俗無過詠紫芝。", "兩岸蘆花一江水，依前且把釣魚絲。"]'),
('41b94021-003f-453e-b880-dba94e60c8e0','題陳山人居','黃滔','唐','唐诗','tang','','[]','猶自莓苔馬跡重，石嵌泉冷嬾移峰。',64,'全唐诗/poet.tang.39000.json','["猶自莓苔馬跡重，石嵌泉冷嬾移峰。", "空垂鳳食簷前竹，漫拔龍形澗底松。", "隔岸青山秋見寺，半牀明月夜聞鐘。", "誰能惆悵磻溪事，今古悠悠不再逢。"]'),
('a3bf4e58-b63f-4c00-821c-5b1579f27ec6','宿李少府園林','黃滔','唐','唐诗','tang','','[]','一壺濁酒百家詩，住此園林守選期。',64,'全唐诗/poet.tang.39000.json','["一壺濁酒百家詩，住此園林守選期。", "深院月涼留客夜，古杉風細似泉時。", "嘗頻異茗塵心淨，議罷名山竹影移。", "明日綠苔渾掃後，石庭吟坐復容誰。"]'),
('8a759d88-0634-4508-abd5-4a144555c8b3','送人明經及第東歸','黃滔','唐','唐诗','tang','','[]','十問九通離義牀，今時登第信非常。',64,'全唐诗/poet.tang.39000.json','["十問九通離義牀，今時登第信非常。", "亦從南院看新榜，旋束春關歸故鄉。", "水到吳門方見海，樹侵閩嶺漸無霜。", "知君已塞平生願，日與交親醉幾場。"]'),
('1a9553f1-b52b-4aff-ac5c-c9dc947e34af','斷酒','黃滔','唐','唐诗','tang','','[]','未老先爲百病仍，醉杯無計接賓朋。',64,'全唐诗/poet.tang.39000.json','["未老先爲百病仍，醉杯無計接賓朋。", "免遭拽盞郎君謔，還被簪花錄事憎。", "絲管合時思索馬，池塘晴後獨留僧。", "何因澆得離腸爛，南浦東門恨不勝。"]'),
('acab9730-0561-4e06-96cc-a1cabb73c276','南海幕和段先輩送韋侍御赴闕','黃滔','唐','唐诗','tang','','[]','樹色川光入暮秋，使車西發不勝愁。',64,'全唐诗/poet.tang.39000.json','["樹色川光入暮秋，使車西發不勝愁。", "璧連標格驚分散，雪課篇章互唱酬。", "魏闕別當飛羽翼，燕臺獨且占風流。", "滿園歌管涼宵月，此後相思幾上樓。"]'),
('92d8de82-efd5-44ad-a856-93d23f0662f9','寄南海黃尚書','黃滔','唐','唐诗','tang','','[]','五羊城下駐行車，此事如今八載餘。',64,'全唐诗/poet.tang.39000.json','["五羊城下駐行車，此事如今八載餘。", "燕頷已知飛食肉，龍門猶自退爲魚。", "紅樓入夜笙歌合，白社驚秋草木疎。", "西望清光寄消息，萬重煙水一封書。"]'),
('8fa550fd-b249-4a17-9a45-4a31d59b985f','送人往蘇州覲其兄','黃滔','唐','唐诗','tang','','[]','闔閭城外越江頭，兩地煙濤一葉舟。',64,'全唐诗/poet.tang.39000.json','["闔閭城外越江頭，兩地煙濤一葉舟。", "到日荆枝應便茂，別時珠淚不須流。", "迎歡酒醒山當枕，詠古詩成月在樓。", "明日尊前若相問，爲言今訪赤松遊。"]'),
('304cd810-4a92-474c-a7ef-a5936d5b9139','遊東林寺','黃滔','唐','唐诗','tang','','[]','長生猶自重無生，言讓仙祠佛寺成。',64,'全唐诗/poet.tang.39000.json','["長生猶自重無生，言讓仙祠佛寺成。", "碑折誰忘康樂制，山靈表得遠公名。", "松形入漢藤蘿短，僧語離經耳目清。", "莫怪遲遲不歸去，童年已夢遶林行。"]'),
('6304dafe-be48-4504-9531-b9cf52f4a407','贈旌德呂明府','黃滔','唐','唐诗','tang','','[]','渥洼步數太阿姿，爭遣王侯不奉知。',64,'全唐诗/poet.tang.39000.json','["渥洼步數太阿姿，爭遣王侯不奉知。", "花作城池入官處，錦隨刀尺少年時。", "兩衙斷獄兼留客，三考論功合樹碑。", "須信隔簾看刺史，錦章朱紱已葳蕤。"]'),
('d594626e-7d4b-4201-9496-c18168b38c70','賀清源僕射新命','黃滔','唐','唐诗','tang','','[]','雖言嵩嶽秀崔嵬，少降連枝命世才。',64,'全唐诗/poet.tang.39000.json','["雖言嵩嶽秀崔嵬，少降連枝命世才。", "南史兩榮唯百揆，東閩雙拜有三台。", "二天在頂家家詠，丹鳳銜書歲歲來。", "虛說古賢龍虎盛，誰攀荆樹上金臺。"]'),
('e615c593-e133-40e0-9949-2cf21e813969','浙幕李端公泛建溪','黃滔','唐','唐诗','tang','','[]','越城吳國結良姻，交發芙蓉幕內賓。',64,'全唐诗/poet.tang.39000.json','["越城吳國結良姻，交發芙蓉幕內賓。", "自顧幽沈槐省跡，得陪清顯諫垣臣。", "分題曉並蘭舟遠，對坐宵聽月狖頻。", "更愛延平津上過，一雙神劍是龍鱗。"]'),
('bb4aa559-11aa-4791-b9c6-70ecf024cd94','貽宋評事','黃滔','唐','唐诗','tang','','[]','河陽城裏謝城中，入曳長裾出佩銅。',64,'全唐诗/poet.tang.39000.json','["河陽城裏謝城中，入曳長裾出佩銅。", "燕國金臺無別客，陶家柳下有清風。", "數蹤篆隸書新得，一竈屯蒙火細紅。", "時說三吳欲歸處，綠波洲渚紫蒲藂。"]'),
('c61710d0-63cb-4937-a252-f652bb25f5ff','催妝','黃滔','唐','唐诗','tang','','[]','北府迎塵南郡來，莫將芳意更遲回。',64,'全唐诗/poet.tang.39000.json','["北府迎塵南郡來，莫將芳意更遲回。", "雖言天上光陰別，且被人間更漏催。", "煙樹逈垂連蔕杏，綵童交捧合歡杯。", "吹簫不是神仙曲，爭引秦娥下鳳臺。"]'),
('b6ec652e-f1ad-4207-8697-c4c6e8f88a46','寓題','黃滔','唐','唐诗','tang','','[]','每憶家山即涕零，定須歸老舊雲扃。',64,'全唐诗/poet.tang.39000.json','["每憶家山即涕零，定須歸老舊雲扃。", "銀河水到人間濁，丹桂枝垂月裏馨。", "霜雪不飛無翠竹，鯨鯢猶在有青萍。", "三千九萬平生事，却恨南華說北溟。"]'),
('fba308a7-14a9-40fd-92ef-59803455389d','傷蔣校書德山','黃滔','唐','唐诗','tang','','[]','誰到雙溪溪岸傍，與招魂魄上蒼蒼。',64,'全唐诗/poet.tang.39000.json','["誰到雙溪溪岸傍，與招魂魄上蒼蒼。", "世間無樹勝青桂，隴上有花唯白楊。", "秦苑火然新賦在，越城山秀故居荒。", "如何萬古雕龍手，獨是相如識漢皇。"]'),
('de8792ad-a4ff-4afe-b1e2-338b59f753d8','寄楊贊圖學士','黃滔','唐','唐诗','tang','','[]','東堂第一領春風，時怪關西小驥慵。',64,'全唐诗/poet.tang.39000.json','["東堂第一領春風，時怪關西小驥慵。", "華表柱頭還有鶴，華歆名下別無龍。", "君恩鳳閣含毫數，詩景珠宮列肆供。", "今日江南駐舟處，莫言歸計爲雲峰。"]'),
('46e099a3-0004-4a44-ab01-8305c866c0a7','酬楊學士','黃滔','唐','唐诗','tang','','[]','神仙簿上愧非夫，詔作疑丹兩入爐。',64,'全唐诗/poet.tang.39000.json','["神仙簿上愧非夫，詔作疑丹兩入爐。", "詩裏幾曾吟芍藥，花中方得見菖蒲。", "陽春唱後應無曲，明月圓來別是珠。", "莫下蓬山不迴首，東風猶待重摶扶。"]'),
('8ae1ab35-d55a-4db6-b9c7-6128c0ff3d60','寄同年李侍郎龜正','黃滔','唐','唐诗','tang','','[]','石門南面淚浪浪，自此東西失帝鄉。',64,'全唐诗/poet.tang.39000.json','["石門南面淚浪浪，自此東西失帝鄉。", "崑璞要疑方卓絕，大鵬須息始開張。", "已歸天上趨雙闕，忽喜人間捧八行。", "莫道秋霜不滋物，菊花還借後時黃。"]'),
('1e8174f4-cc1b-4bf7-9450-616bd15c16cf','鍾陵故人','黃滔','唐','唐诗','tang','','["\u6ed5\u738b\u9601"]','滕王閣下昔相逢，此地今難訪所從。',64,'全唐诗/poet.tang.39000.json','["滕王閣下昔相逢，此地今難訪所從。", "唯愛金籠貯鸚鵡，誰論鐵柱鎖蛟龍。", "荆榛翠是錢神染，河嶽期須國士鍾。", "一筯鱸魚千古美，後人終少繼前蹤。"]'),
('3f608ec6-e1d1-4c3b-bba0-a14dfc377557','故山','黃滔','唐','唐诗','tang','','[]','支頤默省舊林泉，石徑茅堂到目前。',64,'全唐诗/poet.tang.39000.json','["支頤默省舊林泉，石徑茅堂到目前。", "衰碧鳴蛩莎有露，濃陰歇鹿竹無煙。", "水從井底通滄海，山在窗中倚遠天。", "何事蒼髯不歸去，燕昭臺上一年年。"]'),
('43b51b3c-6d58-41b3-ac59-9f404b0f6716','塞上','黃滔','唐','唐诗','tang','','[]','塞門關外日光微，角怨單于鴈駐飛。',64,'全唐诗/poet.tang.39000.json','["塞門關外日光微，角怨單于鴈駐飛。", "衝水路從冰解斷，踰城人到月明歸。", "燕山臘雪銷金甲，秦苑秋風脆錦衣。", "欲弔昭君倍惆悵，漢家甥舅竟相違。"]'),
('03b47d5b-3877-460f-85e0-4ed2c7939b95','烏石村','黃滔','唐','唐诗','tang','','[]','往日江村今物華，一迴登覽一悲嗟。',64,'全唐诗/poet.tang.39000.json','["往日江村今物華，一迴登覽一悲嗟。", "故人歿後城頭月，新鳥啼來壠上花。", "賣劍錢銷知絕俗，聞蟬詩苦即思家。", "謝公古郡青山在，三尺孤墳撲海沙。"]'),
('a0fdb3de-cfe3-42eb-b364-59bec4fc9d6c','寄同年盧員外','黃滔','唐','唐诗','tang','','[]','聽盡鸎聲出雍州，秦吳煙月十經秋。',64,'全唐诗/poet.tang.39000.json','["聽盡鸎聲出雍州，秦吳煙月十經秋。", "龍門在地從人上，郎省連天須鶴遊。", "休戀一臺惟妙絕，已經三字入精求。", "當年甲乙皆華顯，應念槐宮今雪頭。"]'),
('4160046d-4114-4fb5-8535-fa73fa904ba3','寄同年封舍人渭','黃滔','唐','唐诗','tang','','[]','唐城接軫赴秦川，憂合懽離驟十年。',64,'全唐诗/poet.tang.39000.json','["唐城接軫赴秦川，憂合懽離驟十年。", "龍頷摘珠同泳海，鳳銜輝翰別升天。", "八行真跡雖收拾，四戶高扃奈隔懸。", "能使丘門終始雪，莫教華髮獨潸然。"]'),
('0a672f30-15f4-461f-ba73-189d9e8b502f','遇羅員外衮','黃滔','唐','唐诗','tang','','[]','灞陵橋外駐征轅，此一分飛十六年。',64,'全唐诗/poet.tang.39000.json','["灞陵橋外駐征轅，此一分飛十六年。", "豸角戴時垂素髮，雞香含處隔青天。", "綺園難貯林棲意，班馬須持筆削權。", "可忘自初相識地，秋風明月客鄜延。"]'),
('bff86ef4-2f6f-4d2a-b0f5-814f9b9d525f','送翁員外承贊','黃滔','唐','唐诗','tang','','[]','誰言吾黨命多奇，榮美如君歷數稀。',64,'全唐诗/poet.tang.39000.json','["誰言吾黨命多奇，榮美如君歷數稀。", "衣錦還鄉翻是客，迴車謁帝卻爲歸。", "鳳旋北闕虛丹穴，星復南宮逼紫微。", "已分十旬無急詔，天涯相送只沾衣。"]'),
('4df8dcfa-24b4-4039-b96f-99d9b1ab0725','奉和翁文堯十九員外中謝日蒙恩賜金紫之什','黃滔','唐','唐诗','tang','','[]','面蒙君賜自龍墀，誰是還鄉一襲衣。',64,'全唐诗/poet.tang.39000.json','["面蒙君賜自龍墀，誰是還鄉一襲衣。", "三品易懸鱗鬣赫，八絲展起綵章飛。", "敻爲勝事垂千古，題作新詩啓七微。", "嚴助買臣精魄在，定應羞著昔年歸。"]'),
('5101916b-b9f5-49d6-bb3c-6af71f4e13a9','翁文堯員外捧金紫還鄉之命雅發篇章將原交情遠爲嘉貺洎燕鴻陸犬楚水荆山又吐瓊瑤逮之幽鄙雖湧泉思觸逸興皆虛而強韻押難非才頗媿輙茲酬和以質獎私','黃滔','唐','唐诗','tang','','[]','摶將盛事更無餘，還向橋邊看舊書。',64,'全唐诗/poet.tang.39000.json','["摶將盛事更無餘，還向橋邊看舊書。", "東越獨推生竹箭，北溟喜足貯鯤魚。", "兩迴誰解歸華表，午夜兼能薦子虛。", "須把頭冠彈盡日，憐君不與故人疎。"]'),
('45b55b1b-a486-4544-8154-d8a0f83177dd','奉和翁文堯員外經過七林書堂見寄之什','黃滔','唐','唐诗','tang','','[]','朱旗引入昔茆堂，半日從容盡日忙。',64,'全唐诗/poet.tang.39000.json','["朱旗引入昔茆堂，半日從容盡日忙。", "駟馬寶車行錫禮，金章紫綬帶天香。", "山從南國添煙翠，龍起東溟認夜光。", "定恐故園留不住，竹風松韻漫淒鏘。"]'),
('d8df3295-5c4f-4ede-ab72-a1f8ee778c81','奉酬翁文堯員外駐南臺見寄之什','黃滔','唐','唐诗','tang','','[]','人指南臺山與川，大驚喜氣異當年。',64,'全唐诗/poet.tang.39000.json','["人指南臺山與川，大驚喜氣異當年。", "花迎金冊非時拆，月對瓊杯此夜圓。", "我愛藏冰從夏結，君憐修竹到冬鮮。", "殷勤更抱鳴琴撫，爲憶秦兒識斷絃。"]'),
('d7465150-72e9-4c61-ab8e-3037988e61be','翁文堯員外擁冊禮之歸一路有詩名晝錦集先將寄示因書五十六字','黃滔','唐','唐诗','tang','','[]','六窠只佩諸侯印，爭比從天擁冊歸。',64,'全唐诗/poet.tang.39000.json','["六窠只佩諸侯印，爭比從天擁冊歸。", "一軸郢人歌處雪，兩重朱氏著來衣。", "閩山秀已鍾君盡，洛水波應濺我稀。", "明日陪塵迎駟馬，定淮齋沐看光輝。"]'),
('7bef737d-93d9-43e8-bab0-346e9c91caea','奉和翁文堯員外文秀光賢晝錦之什 一','黃滔','唐','唐诗','tang','','[]','鄉名里號一朝新，乃覺台恩重萬鈞。',64,'全唐诗/poet.tang.39000.json','["鄉名里號一朝新，乃覺台恩重萬鈞。", "建水閩山無故事，長卿嚴助是前身。", "清泉引入旁添潤，嘉樹移來別帶春。", "莫凭欄干剩留駐，內庭虛位待才臣。"]'),
('6708b552-6e95-4eb1-a1e7-803fb1c3dc36','奉和翁文堯員外文秀光賢晝錦之什 二','黃滔','唐','唐诗','tang','','[]','雖言閩越繫生賢，誰是還家寵自天。',64,'全唐诗/poet.tang.39000.json','["雖言閩越繫生賢，誰是還家寵自天。", "山簡媿兼諸郡命，鄭玄慙秉六經權。", "鳥行去沒孤烟樹，漁唱還從碧島川。", "休說遲迴未能去，夜來新夢禁中泉。"]'),
('fe5d999a-7c2d-4ea8-a3c0-c50d489b88c5','奉和翁文堯員外文秀光賢晝錦之什 三','黃滔','唐','唐诗','tang','','[]','君王面賜紫還鄉，金紫中推是甲裳。',64,'全唐诗/poet.tang.39000.json','["君王面賜紫還鄉，金紫中推是甲裳。", "華構便將垂美號，故山重更發清光。", "水澄此日蘭宮鏡，樹憶當年栢署霜。", "珍重朱欄兼翠拱，來來皆自讀書堂。"]'),
('8c2a496b-9ec1-42fb-8fbe-238588569a8a','奉酬翁文堯員外神泉之遊見寄嘉什','黃滔','唐','唐诗','tang','','[]','含雞假豸喜同遊，野外嘶風並紫騮。',64,'全唐诗/poet.tang.39000.json','["含雞假豸喜同遊，野外嘶風並紫騮。", "松竹迴尋青障寺，姓名題向白雲樓。", "泉源出石清消暑，僧語離經妙破愁。", "爭奈愛山尤戀闕，古來能有幾人休。"]'),
('6f1fcf73-d850-479f-8246-ce2c21555825','輙吟七言四韻攀寄翁文堯拾遺','黃滔','唐','唐诗','tang','','[]','唐設高科表用文，吾曹誰作諫垣臣。',64,'全唐诗/poet.tang.39000.json','["唐設高科表用文，吾曹誰作諫垣臣。", "甄山秀氣曠千古，鳳闕華恩鍾二人。", "起草便論天上事，如君不是世間身。", "龍頭龍尾前年夢，今日須憐應若神。"]'),
('ca4fafcf-8795-4a0a-bcab-986830d9baf4','塞上','黃滔','唐','唐诗','tang','','[]','掘地破重城，燒山搜伏兵。',96,'全唐诗/poet.tang.39000.json','["掘地破重城，燒山搜伏兵。", "金徽互嗚咽，玉笛自淒清。", "使發西都聳，塵空北嶽橫。", "長河涉有路，曠野宿無程。", "沙雨黃鶯囀，轅門青草生。", "馬歸秦苑牧，人在虜雲耕。", "落日牛羊聚，秋風鼓角鳴。", "如何漢天子，青塚杳含情。"]'),
('effaec2f-64f7-4a94-ab76-93c5a7a10cb0','寄獻梓橦山侯侍御','黃滔','唐','唐诗','tang','','[]','漢宮行廟略，簪笏落民間。',96,'全唐诗/poet.tang.39000.json','["漢宮行廟略，簪笏落民間。", "直道三湘水，高情四皓山。", "賜衣僧脫去，奏表主批還。", "地得松蘿塢，泉通雨雪灣。", "東門添故事，南省缺新班。", "片石秋從露，幽窗夜不關。", "夢餘蟾隱映，吟次鳥綿蠻。", "可惜相如作，當時事悉閑。"]'),
('c0b6548b-55ed-4c8d-a4cf-b638beca33ad','壬癸歲書情','黃滔','唐','唐诗','tang','','[]','故園招隱客，應便笑無成。',96,'全唐诗/poet.tang.39000.json','["故園招隱客，應便笑無成。", "謁帝逢移國，投文值用兵。", "孤松憐鶴在，疎柳惡蟬鳴。", "匹馬迷歸處，青雲失曩情。", "江頭寒夜宿，壠上歉年耕。", "冠蓋新人物，漁樵舊弟兄。", "易生唯白髮，難立是浮名。", "惆悵灞橋路，秋風誰入行。"]'),
('4507a4a0-d0c8-4fb0-b441-30329859def0','河南府試秋夕聞新鴈','黃滔','唐','唐诗','tang','','[]','湘南飛去日，薊北乍驚秋。',72,'全唐诗/poet.tang.39000.json','["湘南飛去日，薊北乍驚秋。", "呌出隴雲夜，聞爲客子愁。", "一聲初觸夢，半白已侵頭。", "旅館移欹枕，江城起倚樓。", "餘燈依古壁，片月下滄洲。", "寂聽良宵徹，躊躇感歲流。"]'),
('50a7259d-a675-4bbf-8b57-520ecf1a7817','省試奉詔漲曲江池','黃滔','唐','唐诗','tang','','[]','地脉寒來淺，恩波住後新。',72,'全唐诗/poet.tang.39000.json','["地脉寒來淺，恩波住後新。", "引將諸派水，別貯大都春。", "幽咽疏通處，清泠迸入辰。", "漸平連杏岸，旋闊映樓津。", "沙沒迷行徑，洲寬恣躍鱗。", "願當舟檝便，一附濟川人。"]'),
('7e27f7ea-4335-4cca-8fcd-5fa0a41a3437','題宣一僧正院','黃滔','唐','唐诗','tang','','[]','五級凌虛塔，三生落髮師。',72,'全唐诗/poet.tang.39000.json','["五級凌虛塔，三生落髮師。", "都僧須有託，孤嶠遂無期。", "井邑焚香待，君侯減俸資。", "山衣隨疊破，萊骨逐年羸。", "茶取寒泉試，松於遠澗移。", "吾曹來頂手，不合不題詩。"]'),
('01f557f6-4b73-4436-a644-417b41340edc','和吳學士對春雪獻韋令公次韻','黃滔','唐','唐诗','tang','','[]','春雪下盈空，翻疑臘未窮。',120,'全唐诗/poet.tang.39000.json','["春雪下盈空，翻疑臘未窮。", "連天寧認月，墮地屢兼風。", "忽誤邊沙上，應平火嶺中。", "林間妨走獸，雲際落飛鴻。", "梁苑還吟客，齊都省創宮。", "掩扉皆墐北，移律愧居東。", "書幌飄全濕，茶鐺入旋融。", "奔川半留滯，疊樹互玲瓏。", "出戶行瑤砌，開園見粉叢。", "高才興詠處，真宰荅殊功。"]'),
('3eabe9e6-e14f-49f4-8cf2-9cd6849e9bf4','省試一一吹竽','黃滔','唐','唐诗','tang','','[]','齊竽今歷試，真僞不難知。',72,'全唐诗/poet.tang.39000.json','["齊竽今歷試，真僞不難知。", "欲使聲聲別，須令箇箇吹。", "後先無錯雜，能否立參差。", "次第教單進，宮商乃異宜。", "凡音皆竄跡，至藝始呈奇。", "以此論文學，終憑一一窺。"]'),
('2a876008-b9cc-4a28-aa23-541a02123c8c','明月照高樓','黃滔','唐','唐诗','tang','','[]','月滿長空朗，樓侵碧落橫。',72,'全唐诗/poet.tang.39000.json','["月滿長空朗，樓侵碧落橫。", "波文流藻井，桂魄拂雕楹。", "深鑒羅紈薄，寒搜戶牖清。", "冰鋪梁燕噤，霜覆瓦松傾。", "卓午收全影，斜懸轉半明。", "佳人當此夕，多少別離情。"]'),
('3b03d532-6d60-4673-80f2-42792605f728','廣州試越臺懷古','黃滔','唐','唐诗','tang','','[]','南越千年事，興懷一旦來。',72,'全唐诗/poet.tang.39000.json','["南越千年事，興懷一旦來。", "歌鐘非舊俗，煙月有層臺。", "北望人何在，東流水不回。", "吹窗風雜瘴，沾檻雨經梅。", "壯氣曾難揖，空名信可哀。", "不堪登覽處，花落與花開。"]'),
('4a03797f-a3e4-482b-bc3d-b3f093a8448e','襄州試白雲歸帝鄉','黃滔','唐','唐诗','tang','','[]','杳杳復霏霏，應緣有所依。',72,'全唐诗/poet.tang.39000.json','["杳杳復霏霏，應緣有所依。", "不言天路遠，終望帝鄉歸。", "高嶽和霜過，遙關帶月飛。", "漸憐雙闕近，寧恨衆山違。", "陣觸銀河亂，光連粉署微。", "旅人隨計日，自笑比麻衣。"]'),
('250a1b8b-6774-42a8-9e6e-65f50581d234','省試內出白鹿宣示百官','黃滔','唐','唐诗','tang','','[]','上瑞何曾乏，毛羣表色難。',72,'全唐诗/poet.tang.39000.json','["上瑞何曾乏，毛羣表色難。", "推於五靈少，宣示百寮觀。", "形奪場駒潔，光交月兔寒。", "已馴瑤草別，孤立雪花團。", "戴豸慙端士，抽毫躍史官。", "貴臣歌詠日，皆作白麟看。"]'),
('c2948c89-e662-4211-9aab-5fe4beb8536e','出關言懷','黃滔','唐','唐诗','tang','','[]','又乞書題出，關西謁列侯。',72,'全唐诗/poet.tang.39000.json','["又乞書題出，關西謁列侯。", "寄家僧許嶽，釣浦雨移洲。", "賣馬登長陸，沾衣逐勝遊。", "菜腸終日餒，霜鬢度年秋。", "詩苦無人愛，言公是世仇。", "却憐庭際草，中有號忘憂。"]'),
('6b85b90b-76ed-4597-962e-ed27beff2387','壺公山','黃滔','唐','唐诗','tang','','[]','八面峰巒秀，孤高可偶然。',288,'全唐诗/poet.tang.39000.json','["八面峰巒秀，孤高可偶然。", "數人遊頂上，滄海見東邊。", "不信無靈洞，相傳有古仙。", "橘如珠夏在，池象月垂穿。", "髣髴嘗聞樂，岧嶤半插天。", "山寒徹三伏，松偃出千年。", "樵牧時迷所，倉箱歲疊川。", "嚴祠風雨管，怪木薜蘿纏。", "青草方中藥，蒼苔石裏錢。", "瓊津流乳竇，春色駐芝田。", "烏兔中時近，龍蛇蟄處膻。", "嘉名光列土，秀氣產羣賢。", "瀑鎖瑤臺路，溪昇釣浦船。", "鼇頭擎恐沒，地軸壓應旋。", "蠲疾寒甘露，藏珍起瑞煙。", "畫工飛夢寐，詩客寄林泉。", "掘地多雲母，緣霜欠木綿。", "井通鰌吐脉，僧隔虎棲禪。", "危磴千尋拔，奇花四季鮮。", "鶴歸懸圃少，鳳下碧梧偏。", "桃易炎涼熟，茶推醉醒煎。", "邨家蒙棗栗，俗骨爽猨蟬。", "谷語昇喬鳥，陂開共蔕蓮。", "落楓丹葉舞，新蕨紫芽拳。"]'),
('1557b323-6fab-4f8e-9a96-e15c6c03f469','和王舍人崔補闕題天王寺','黃滔','唐','唐诗','tang','','[]','郭內青山寺，難論此崛奇。',168,'全唐诗/poet.tang.39000.json','["郭內青山寺，難論此崛奇。", "白雲生院落，流水下城池。", "石像雷霆啓，江沙鼎鼐期。", "嶽僧來坐夏，秦客會題詩。", "岡轉泉根滑，門升蘚級危。", "紫微今日句，黃絹昔年碑。", "歇鶴松低閣，鳴蛩徑出籬。", "粉垣千堵束，金塔九層支。", "啼鳥笙簧韻，開花錦繡姿。", "清齋奔井邑，玄髮剃熊羆。", "極浦征帆小，平蕪落日遲。", "風篁清却暑，煙草綠無時。", "信士三公作，靈蹤四絕推。", "良遊如不宿，明月擬何之。"]'),
('2bf6e3d4-8d7f-4d59-9c18-3b55bb7302fb','投翰長趙侍郎','黃滔','唐','唐诗','tang','','[]','禹門西面逐飄蓬，忽喜仙都得入蹤。',160,'全唐诗/poet.tang.39000.json','["禹門西面逐飄蓬，忽喜仙都得入蹤。", "賈氏許頻趨季虎，荀家因敢謁頭龍。", "手扶日月重輪起，數是乾坤正氣鍾。", "五色筆驅神出沒，八花塼接帝從容。", "詩酬御製風騷古，論似人情鼎鼐濃。", "豈有地能先鳳掖，別無山更勝鼇峰。", "攀鴻日淺魂飛越，爲鯉年深勢噞喁。", "澤國雨荒三徑草，秦關雪折一枝筇。", "吹成暖景猶葭律，引上纖蘿在嶽松。", "願向明朝薦幽滯，免教號泣觸登庸。"]'),
('dbb9c4d2-5932-4ec4-864c-aaaa230845b9','鄜畤李相公','黃滔','唐','唐诗','tang','','[]','秦城擇日發征轅，齋戒來投節制尊。',192,'全唐诗/poet.tang.39000.json','["秦城擇日發征轅，齋戒來投節制尊。", "分虎名高初命相，攀龍迹下愧登門。", "夜聽謳詠銷塵夢，曉拜旌幢戰旅魂。", "華舍未開寧有礙，綵毫雖乏敢無言。", "生兼文武爲人傑，出應乾坤靜帝閽。", "計吐六奇誰敢敵，學窮三略不須論。", "功高馬卸黃金甲，臺逈賓懽白玉樽。", "九穗嘉禾垂綺陌，四時甘雨帶雕軒。", "推恩每覺東溟淺，吹律能令北陸暄。", "青草連沙無血濺，黃榆鏁塞有鶯翻。", "笙歌合沓春風郭，雞犬連延碧岫邨。", "遊子不緣貪獻賦，永依棠樹託蓬根。"]'),
('37a2093c-0f6c-4b56-9c89-e11e5200956e','成名後呈同年','黃滔','唐','唐诗','tang','','[]','業詩攻賦薦鄉書，二紀如鴻歷九衢。',128,'全唐诗/poet.tang.39000.json','["業詩攻賦薦鄉書，二紀如鴻歷九衢。", "待得至公搜草澤，如從平陸到蓬壺。", "雖慙錦鯉成穿額，忝獲驪龍不寐珠。", "蒙楚數疑休下泣，師劉大喝已爲盧。", "人間灰管供紅杏，天上煙花應白榆。", "一字連鑣巡甲族，千般唱罰賞皇都。", "名推顏柳題金塔，飲自燕秦索玉姝。", "退媿單寒終預此，敢將恩嶽怠斯須。"]'),
('8c7d8911-9366-4f89-bfe2-bbae17236609','投刑部裴郎中','黃滔','唐','唐诗','tang','','[]','兩牓驅牽別海涔，佗門不合覓知音。',128,'全唐诗/poet.tang.39000.json','["兩牓驅牽別海涔，佗門不合覓知音。", "瞻恩雖隔雲雷賜，向主終知犬馬心。", "禮闈後人窺作鏡，廟堂前席待爲霖。", "已齊日月懸千古，肯誤風塵使陸沉。", "拜首敢將誠吐血，蛻形唯待諾如金。", "愁聞南院看期到，恐被東墻舊恨侵。", "緇化衣空難抵雪，黑銷頭盡不勝簪。", "數行淚裏依投志，直比滄溟未是深。"]'),
('f3b94c0e-0549-42cb-b0c2-1ef22f213a6f','輦下寓題','黃滔','唐','唐诗','tang','','[]','對酒何曾醉，尋僧未覺閑。',24,'全唐诗/poet.tang.39000.json','["對酒何曾醉，尋僧未覺閑。", "無人不惆悵，終日見南山。"]'),
('02fca0ec-0521-4e48-88c3-ce888a2dc502','寄題崔校書郊舍','黃滔','唐','唐诗','tang','','[]','一片寒塘水，尋常立鷺鷥。',24,'全唐诗/poet.tang.39000.json','["一片寒塘水，尋常立鷺鷥。", "主人貧愛客，沽酒往吟詩。"]'),
('c70a56f2-cebf-4a23-8702-9a3288c657c4','秋思','黃滔','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56", "\u6292\u60c5", "\u5199\u666f"]','碧嶂猿啼夜，新秋雨霽天。',24,'全唐诗/poet.tang.39000.json','["碧嶂猿啼夜，新秋雨霽天。", "誰人愛明月，露坐洞庭船。"]'),
('79988dd5-abfb-4ee1-b7b5-9ebe0b697ae4','芳草','黃滔','唐','唐诗','tang','','[]','澤國多芳草，年年長自春。',24,'全唐诗/poet.tang.39000.json','["澤國多芳草，年年長自春。", "應從屈平後，更苦不歸人。"]'),
('bb44459f-f6b8-4d0e-bc36-ce44898355c1','輦下書事','黃滔','唐','唐诗','tang','','[]','北闕新王業，東城入羽書。',24,'全唐诗/poet.tang.39000.json','["北闕新王業，東城入羽書。", "秋風滿林起，誰道有鱸魚。"]'),
('7318c1d9-d6f0-4098-8ee0-28feed5593f5','入關言懷','黃滔','唐','唐诗','tang','','[]','背將蹤跡向京師，出在先春入後時。',32,'全唐诗/poet.tang.39000.json','["背將蹤跡向京師，出在先春入後時。", "落日灞橋飛雪裏，已聞南院有看期。"]'),
('aac6e654-45f5-4f27-b743-4a8845724d10','過長江','黃滔','唐','唐诗','tang','','["\u957f\u6c5f"]','曾搜景象恐通神，地下還應有主人。',32,'全唐诗/poet.tang.39000.json','["曾搜景象恐通神，地下還應有主人。", "若把長江比湘浦，離騷不合自靈均。"]'),
('f0ddb989-ea95-4f9c-a703-f8610cc8bd47','題靈峰僧院','黃滔','唐','唐诗','tang','','[]','繫馬松間不忍歸，數巡香茗一枰棋。',32,'全唐诗/poet.tang.39000.json','["繫馬松間不忍歸，數巡香茗一枰棋。", "擬登絕頂留人宿，猶待滄溟月滿時。"]'),
('653dcbf4-e3ce-4ec8-8351-892bd365233c','司馬長卿','黃滔','唐','唐诗','tang','','[]','一自梁園失意回，無人知有掞天才。',32,'全唐诗/poet.tang.39000.json','["一自梁園失意回，無人知有掞天才。", "漢宮不鏁陳皇后，誰肯量金買賦來。"]'),
('72b77112-aca9-4789-9779-0580b5f4cd26','歸思','黃滔','唐','唐诗','tang','','[]','薊北風煙空漢月，湘南雲水半蠻邊。',32,'全唐诗/poet.tang.39000.json','["薊北風煙空漢月，湘南雲水半蠻邊。", "寒爲旅鴈暖還去，秦越離家可十年。"]'),
('cd2e154b-d3d1-4f68-9575-625bbe03c014','東林寺貫休上人篆隸題詩','黃滔','唐','唐诗','tang','','[]','師名自越徹秦中，秦越難尋師所從。',32,'全唐诗/poet.tang.39000.json','["師名自越徹秦中，秦越難尋師所從。", "墨跡兩般詩一首，香爐峰下似相逢。"]'),
('d726737e-ebce-45bb-81f1-5b24f1928bf5','寓江州李使君','黃滔','唐','唐诗','tang','','[]','使君曾被蟬聲苦，每見詞文即爲愁。',32,'全唐诗/poet.tang.39000.json','["使君曾被蟬聲苦，每見詞文即爲愁。", "況是楚江鴻到後，可堪西望發孤舟。"]'),
('67f842f0-287e-4d31-a84f-77984c8eabbb','遊南寓題','黃滔','唐','唐诗','tang','','[]','江山節被雪霜遺，毒草過秋未擬衰。',32,'全唐诗/poet.tang.39000.json','["江山節被雪霜遺，毒草過秋未擬衰。", "天不當時命鄒衍，亦將寒律入南吹。"]'),
('7f7aa957-4d8c-437e-a72b-3418f666177f','和同年趙先輩觀文','黃滔','唐','唐诗','tang','','[]','玉兔輪中方是樹，金鼇頂上別無山。',32,'全唐诗/poet.tang.39000.json','["玉兔輪中方是樹，金鼇頂上別無山。", "雖然迴首見煙水，事主酬恩難便閑。"]'),
('2ebee9ba-e492-45b3-a893-e4d62c9bcd22','出京別同年','黃滔','唐','唐诗','tang','','[]','一枝仙桂已攀援，歸去煙濤浦口邨。',32,'全唐诗/poet.tang.39000.json','["一枝仙桂已攀援，歸去煙濤浦口邨。", "雖恨別離還有意，槐花黃日出青門。"]'),
('6f390124-8cb4-4b20-92b5-423821350439','木芙蓉三首 一','黃滔','唐','唐诗','tang','','[]','黃鳥啼煙二月朝，若教開即牡丹饒。',32,'全唐诗/poet.tang.39000.json','["黃鳥啼煙二月朝，若教開即牡丹饒。", "天嫌青帝恩光盛，留與秋風雪寂寥。"]'),
('1eb5c29f-42ed-4ae7-a2f9-f549b331decc','木芙蓉三首 二','黃滔','唐','唐诗','tang','','[]','卻假青腰女剪成，綠羅囊綻綵霞呈。',32,'全唐诗/poet.tang.39000.json','["卻假青腰女剪成，綠羅囊綻綵霞呈。", "誰憐不及黃花菊，只遇陶潛便得名。"]'),
('13b76cf1-43fb-43ea-8eab-0d94826a116e','木芙蓉三首 三','黃滔','唐','唐诗','tang','','[]','須到露寒方有態，爲經霜裛稍無香。',32,'全唐诗/poet.tang.39000.json','["須到露寒方有態，爲經霜裛稍無香。", "移根若在秦宮裏，多少佳人泣曉妝。"]'),
('ef3f6c05-bd3b-4e31-a853-22352715d2e9','九日','黃滔','唐','唐诗','tang','','[]','陽數重時陰數殘，露濃風硬欲成寒。',32,'全唐诗/poet.tang.39000.json','["陽數重時陰數殘，露濃風硬欲成寒。", "莫言黃菊花開晚，獨占樽前一日歡。"]'),
('0debd5ca-5faa-4195-ab3a-719760271552','夏州道中','黃滔','唐','唐诗','tang','','[]','隴鴈南飛河水流，秦城千里忍回頭。',32,'全唐诗/poet.tang.39000.json','["隴鴈南飛河水流，秦城千里忍回頭。", "征行渾與求名背，九月中旬往夏州。"]'),
('261454ae-a203-403a-83a6-ddcf9f24b88b','經慈州感謝郎中','黃滔','唐','唐诗','tang','','[]','金聲乃是古詩流，況有池塘春草儔。',32,'全唐诗/poet.tang.39000.json','["金聲乃是古詩流，況有池塘春草儔。", "莫遣宣城獨垂號，雲山彼此謝公遊。"]'),
('b8e18a32-07cd-4bdf-bc22-fcb1ac29960e','寓題','黃滔','唐','唐诗','tang','','[]','吳中煙水越中山，莫把漁樵謾自寬。',32,'全唐诗/poet.tang.39000.json','["吳中煙水越中山，莫把漁樵謾自寬。", "歸泛扁舟可容易，五湖高士是拋官。"]'),
('5dac0a65-b1a2-4904-a336-c0a32afd0517','寄宋明府','黃滔','唐','唐诗','tang','','[]','北闕秋期南國身，重關煙月五溪雲。',32,'全唐诗/poet.tang.39000.json','["北闕秋期南國身，重關煙月五溪雲。", "風蟬已有數聲急，賴在陶家柳下聞。"]'),
('9212cbec-f405-4f08-a5dd-ad3ad3a327af','靈均','黃滔','唐','唐诗','tang','','[]','莫問靈均昔日遊，江蘺春盡岸楓秋。',32,'全唐诗/poet.tang.39000.json','["莫問靈均昔日遊，江蘺春盡岸楓秋。", "至今此事何人雪，月照楚山湘水流。"]'),
('359257da-afcf-4b8c-aae5-fe5c8df3addd','馬嵬','黃滔','唐','唐诗','tang','','[]','錦江晴碧劒鋒奇，合有千年降聖時。',32,'全唐诗/poet.tang.39000.json','["錦江晴碧劒鋒奇，合有千年降聖時。", "天意從來知幸蜀，不關胎禍自蛾眉。"]'),
('0822e517-d03d-4dd7-94a7-2d60873ccc87','和陳先輩陪陸舍人春日遊曲江','黃滔','唐','唐诗','tang','','[]','劉超遊召郄詵陪，爲憶池亭舊賞來。',32,'全唐诗/poet.tang.39000.json','["劉超遊召郄詵陪，爲憶池亭舊賞來。", "紅杏花旁見山色，詩成因觸鼓聲回。"]'),
('164f2527-1886-49a6-8a4a-a51f07181e93','花','黃滔','唐','唐诗','tang','','[]','莫道顏色如渥丹，莫道馨香過𦶜蘭。',32,'全唐诗/poet.tang.39000.json','["莫道顏色如渥丹，莫道馨香過𦶜蘭。", "東風吹綻還吹落，明日誰爲今日看。"]'),
('33b5a5a1-f03e-4d38-a188-3f17a8316fac','卷簾','黃滔','唐','唐诗','tang','','[]','綠鬟侍女手纖纖，新捧嫦娥出素蟾。',32,'全唐诗/poet.tang.39000.json','["綠鬟侍女手纖纖，新捧嫦娥出素蟾。", "衛玠官高難久立，莫辭雙卷水精簾。"]'),
('60dce9b6-5acf-4727-95ed-5b9d4cc195f8','啓帳','黃滔','唐','唐诗','tang','','[]','得人憎定繡芙蓉，愛鏁嫦娥出月蹤。',32,'全唐诗/poet.tang.39000.json','["得人憎定繡芙蓉，愛鏁嫦娥出月蹤。", "侍女莫嫌擡素手，拔開珠翠待相逢。"]'),
('319de2e2-3f3b-43e2-b797-61042a2f6abc','去扇','黃滔','唐','唐诗','tang','','[]','城上風生蠟炬寒，錦帷開處露翔鸞。',32,'全唐诗/poet.tang.39000.json','["城上風生蠟炬寒，錦帷開處露翔鸞。", "已知秦女昇仙態，休把圓輕隔牡丹。"]'),
('1024ff77-7ec5-4a36-9e61-eb353c11efaa','別後','黃滔','唐','唐诗','tang','','[]','夢裏相逢無後期，煙中解珮杳何之。',32,'全唐诗/poet.tang.39000.json','["夢裏相逢無後期，煙中解珮杳何之。", "虧蟾便是陳宮鏡，莫吐清光照別離。"]'),
('bf298977-be7e-473e-9c96-050816004072','嚴陵釣臺','黃滔','唐','唐诗','tang','','[]','終向煙霞作野夫，一竿竹不換簪裾。',32,'全唐诗/poet.tang.39000.json','["終向煙霞作野夫，一竿竹不換簪裾。", "直鉤猶逐熊羆起，獨是先生真釣魚。"]'),
('8d690803-c2cc-4711-93ed-a26a630b45ec','馬嵬二首 一','黃滔','唐','唐诗','tang','','[]','鐵馬嘶風一渡河，淚珠零便作驚波。',32,'全唐诗/poet.tang.39000.json','["鐵馬嘶風一渡河，淚珠零便作驚波。", "鳴泉亦感上皇意，流下隴頭嗚咽多。"]'),
('e4daaafd-e10c-4869-a7c8-8ceeb7be5558','馬嵬二首 二','黃滔','唐','唐诗','tang','','[]','龍腦移香鳳輦留，可能千古永悠悠。',32,'全唐诗/poet.tang.39000.json','["龍腦移香鳳輦留，可能千古永悠悠。", "夜臺若使香魂在，應作煙花出隴頭。"]'),
('8c65b301-22b2-4ee7-b590-f81cd50c3184','閏八月','黃滔','唐','唐诗','tang','','[]','無人不愛今年閏，月看中秋兩度圓。',32,'全唐诗/poet.tang.39000.json','["無人不愛今年閏，月看中秋兩度圓。", "唯恐雨師風伯意，至時還奪上樓天。"]'),
('ce8a79d8-8673-472d-a803-c49a73831b1d','奉和翁文堯戲寄','黃滔','唐','唐诗','tang','','[]','掘蘭宮裏數名郎，好是乘軺出帝鄉。',32,'全唐诗/poet.tang.39000.json','["掘蘭宮裏數名郎，好是乘軺出帝鄉。", "兩度還家還未有，別論光彩向冠裳。"]'),
('e996c456-84b3-43a2-a846-5ef5d5310e5c','奉和文堯對庭前千葉石榴','黃滔','唐','唐诗','tang','','[]','一朵千英綻曉枝，綵霞堪與別爲期。',32,'全唐诗/poet.tang.39000.json','["一朵千英綻曉枝，綵霞堪與別爲期。", "移根若在芙蓉苑，豈向當年有醒時。"]'),
('1425c663-94eb-45cd-a3cf-d2bf7ce869f4','翁文堯以美疹暫滯令公大王益得異禮觀今日寵待之盛輙成一章','黃滔','唐','唐诗','tang','','[]','滋賦諴文侯李盛，終求一襲錦衣難。',32,'全唐诗/poet.tang.39000.json','["滋賦諴文侯李盛，終求一襲錦衣難。", "如何兩度還州里，兼借鄉人更剩觀。"]'),
('a65d2b0d-7f27-4f8a-bc9f-6d7dab32b38a','贈友人','黃滔','唐','唐诗','tang','','[]','超達陶子性，留琴不設弦。',48,'全唐诗/poet.tang.39000.json','["超達陶子性，留琴不設弦。", "覓句朝忘食，傾杯夜廢眠。", "愛月影爲伴，吟風聲自連。", "聽此鶯飛谷，心懷迷遠川。"]'),
('be18e8c2-3439-4545-a001-412dd1fe9fcd','八月十五夜','殷文圭','唐','唐诗','tang','','["\u534e\u5c71"]','萬里無雲鏡九州，最團圓夜是中秋。',64,'全唐诗/poet.tang.39000.json','["萬里無雲鏡九州，最團圓夜是中秋。", "滿衣冰彩拂不落，遍地水光凝欲流。", "華嶽影寒清露掌，海門風急白潮頭。", "因君照我丹心事，減得愁人一夕愁。"]'),
('4828c852-5e8d-46da-882a-979fad7607eb','省試夜投獻座主','殷文圭','唐','唐诗','tang','','[]','闢開公道選時英，神鏡高懸鑒百靈。',64,'全唐诗/poet.tang.39000.json','["闢開公道選時英，神鏡高懸鑒百靈。", "混沌分來融間氣，欃槍滅處炫文星。", "燭然蘭省三條白，山束龍門萬仞青。", "聖教中興周禮在，不勞干羽舞明庭。"]'),
('959dc756-157a-43be-bc74-0e6894a574e3','觀賀皇太子冊命','殷文圭','唐','唐诗','tang','','[]','嗣冊儲皇帝命行，萬方臣妾躍歡聲。',64,'全唐诗/poet.tang.39000.json','["嗣冊儲皇帝命行，萬方臣妾躍歡聲。", "鸞旃再立星辰正，雉扇雙開日月明。", "自有漢元爭翊戴，不勞商皓定欹傾。", "春宮保傅皆周召，致主何憂不太平。"]'),
('64411680-cdf3-4f5a-aaa6-1e9c4e3d6e56','行朝早春侍師門宴西溪席上作','殷文圭','唐','唐诗','tang','','[]','西溪水色淨於苔，畫鷁橫風絳帳開。',64,'全唐诗/poet.tang.39000.json','["西溪水色淨於苔，畫鷁橫風絳帳開。", "弦管旋飄蓬島去，公卿皆是蘂宮來。", "金鱗擲浪錢翻荇，玉爵黏香雪泛梅。", "三榜生徒逾七十，豈期龍坂納非才。"]'),
('048f2dc1-4cd8-4fb6-bfc5-ce107fc6773c','賀同年第三人劉先輩鹹辟命','殷文圭','唐','唐诗','tang','','[]','甲門才子鼎科人，拂地藍衫榜下新。',64,'全唐诗/poet.tang.39000.json','["甲門才子鼎科人，拂地藍衫榜下新。", "脫俗文章笑鸚鵡，凌雲頭角壓麒麟。", "金壺藉草溪亭晚，玉勒穿花野寺春。", "多媿受恩同闕里，不嫌師僻與顏貧。"]'),
('3d33f925-f3fd-4871-9bc8-5c9315f7312c','寄廣南劉僕射','殷文圭','唐','唐诗','tang','','[]','戰國從今却尚文，品流才子作將軍。',64,'全唐诗/poet.tang.39000.json','["戰國從今却尚文，品流才子作將軍。", "畫船清宴蠻溪雨，粉閣閑吟瘴嶠雲。", "暴客卸戈歸惠政，史官調筆待儒勳。", "漢儀一化南人後，牧馬無因更夜聞。"]'),
('ef81769f-400d-48b5-99b1-7a66b4185f66','題吳中陸龜蒙山齋','殷文圭','唐','唐诗','tang','','[]','萬卷圖書千戶貴，十洲煙景四時和。',64,'全唐诗/poet.tang.39000.json','["萬卷圖書千戶貴，十洲煙景四時和。", "花心露洗猩猩血，水面風披瑟瑟羅。", "莊叟靜眠清夢永，客兒芳意小詩多。", "天麟不觸人間網，擬把公卿換得麽。"]'),
('2051671a-5e25-4f77-9949-acfc38fbf8ef','經李翰林墓','殷文圭','唐','唐诗','tang','','[]','詩中日月酒中仙，平地雄飛上九天。',64,'全唐诗/poet.tang.39000.json','["詩中日月酒中仙，平地雄飛上九天。", "身謫蓬萊金籍外，寶裝方丈玉堂前。", "虎靴醉索將軍脫，鴻筆悲無令子傳。", "十字遺碑三尺墓，只應吟客弔秋煙。"]'),
('e5b7e409-6604-4c9a-a0c4-d39550e78923','鸚鵡','殷文圭','唐','唐诗','tang','','[]','丹觜如簧翠羽輕，隨人呼物旋知名。',64,'全唐诗/poet.tang.39000.json','["丹觜如簧翠羽輕，隨人呼物旋知名。", "金籠夜黯山西夢，玉枕曉憎簾外聲。", "才子愛奇吟不足，美人憐爾繡初成。", "應緣是我邯鄲客，相顧咬咬別有情。"]'),
('a3904587-9b0d-4237-a4a2-8834978e9d44','邊將別','殷文圭','唐','唐诗','tang','','[]','地角天涯倍苦辛，十年鉛槧未酬身。',64,'全唐诗/poet.tang.39000.json','["地角天涯倍苦辛，十年鉛槧未酬身。", "朱門泣別同鮫客，紫塞旅游隨鴈臣。", "漢將出師衝曉雪，胡兒奔馬撲征塵。", "行行獨止干戈域，毳帳望誰爲主人。"]'),
('cc384618-e5d9-45da-89ba-4e1165ae78a7','江南秋日','殷文圭','唐','唐诗','tang','','[]','水國由來稱道情，野人經此頓神清。',64,'全唐诗/poet.tang.39000.json','["水國由來稱道情，野人經此頓神清。", "一篷秋雨睡初起，半硯冷雲吟未成。", "青笠漁兒筒釣沒，蒨衣菱女畫橈輕。", "冰綃寫上江南景，寄與金鑾馬長卿。"]'),
('b9e3801b-4982-4eaa-bd9c-e62b9cb7647e','題友人庭竹','殷文圭','唐','唐诗','tang','','[]','叢篁蕭瑟拂清陰，貴地栽成碧玉林。',64,'全唐诗/poet.tang.39000.json','["叢篁蕭瑟拂清陰，貴地栽成碧玉林。", "盡待花開添鳳食，可憐風擊狀龍吟。", "鈿竿離立霜文靜，錦籜飄零粉節深。", "何事子猷偏寄賞，此君心似古人心。"]'),
('33f9a100-e59f-4074-a35d-4ec1320029da','覽陸龜蒙舊集','殷文圭','唐','唐诗','tang','','[]','先生文價沸三吳，白雪千編酒一壺。',64,'全唐诗/poet.tang.39000.json','["先生文價沸三吳，白雪千編酒一壺。", "吟去星辰筆下動，醉來嵩華眼中無。", "峭如謝檜虬蟠活，清似緱山鳳路孤。", "身後獨遺封禪草，何人尋得佐鴻圖。"]'),
('9c2885f8-4869-42a3-8694-121f6726cc68','玉仙道中','殷文圭','唐','唐诗','tang','','[]','蓴鱸方美別吳江，筆陣詩魔兩未降。',64,'全唐诗/poet.tang.39000.json','["蓴鱸方美別吳江，筆陣詩魔兩未降。", "山勢北蟠龍偃蹇，泉聲東漱玉琤瑽。", "古陂狐兔穿蠻塚，破寺荆榛擁佛幢。", "信馬冷吟迷路處，隔溪煙雨吠村厖。"]'),
('8cf65f7b-80ef-442c-a6ce-202ec1898b2e','趙侍郎看紅白牡丹因寄楊狀頭贊圖','殷文圭','唐','唐诗','tang','','[]','遲開都爲讓羣芳，貴地栽成對玉堂。',64,'全唐诗/poet.tang.39000.json','["遲開都爲讓羣芳，貴地栽成對玉堂。", "紅豔褭煙疑欲語，素華映月只聞香。", "翦裁偏得東風意，淡薄似矜西子粧。", "雅稱花中爲首冠，年年長占斷春光。"]'),
('cb7e7cec-9087-4a62-a10a-7152f5952827','題胡州太學丘光庭博士幽居','殷文圭','唐','唐诗','tang','','[]','舜軌堯文混九垓，明堂宏構集良材。',64,'全唐诗/poet.tang.39000.json','["舜軌堯文混九垓，明堂宏構集良材。", "江邊雲臥如龍穩，天外泥書遣鶴來。", "五夜藥苗滋沆瀣，四時花影蔭莓苔。", "草玄門似山中靜，不是公卿到不開。"]'),
('4d642f6a-bf3f-4d38-8b29-c82e3dbd357a','初秋留別越中幕客','殷文圭','唐','唐诗','tang','','[]','魂夢飄零落葉洲，北轅南柁幾時休。',64,'全唐诗/poet.tang.39000.json','["魂夢飄零落葉洲，北轅南柁幾時休。", "月中青桂漸看老，星畔白榆還報秋。", "鶴禁有知須強進，稽峰無事莫相留。", "吳花越柳饒君醉，直待功成始舉頭。"]'),
('8bcee197-0482-4fa9-816a-ae5dfecd785e','送道者朝見後歸山','殷文圭','唐','唐诗','tang','','[]','暫隨蒲帛謁金鑾，蕭灑風儀傲漢官。',64,'全唐诗/poet.tang.39000.json','["暫隨蒲帛謁金鑾，蕭灑風儀傲漢官。", "天馬難將朱索絆，海鼇寧覺碧濤寬。", "松壇月作尊前伴，竹篋書爲教外歡。", "神鼎已乾龍虎伏，一條真氣出雲端。"]'),
('78181ffb-edb3-4526-86b1-a8717931a6b3','贈戰將','殷文圭','唐','唐诗','tang','','[]','綠沈槍利雪峰尖，犀甲軍裝稱紫髯。',64,'全唐诗/poet.tang.39000.json','["綠沈槍利雪峰尖，犀甲軍裝稱紫髯。", "威懾萬人長凜凜，禮延羣客每謙謙。", "陣前戰馬黃金勒，架上兵書白玉籤。", "不爲已爲儒弟子，好依門下學韜鈐。"]'),
('3899229a-f54d-4dd5-beb7-ff87fad2f79e','九華賀雨吟','殷文圭','唐','唐诗','tang','','[]','陶公焦思念生靈，變旱爲豐合杳冥。',64,'全唐诗/poet.tang.39000.json','["陶公焦思念生靈，變旱爲豐合杳冥。", "雷劈老松疑虎怒，雨衝陰洞覺龍腥。", "萬畦香稻蓬葱綠，九朵奇峰撲亞青。", "吟賀西成饒旅興，散絲飛灑滿長亭。"]'),
('174936ab-68e3-4c07-9d17-ce9f47869b60','贈池州張太守','殷文圭','唐','唐诗','tang','','[]','神珠無纇玉無瑕，七葉簪貂漢相家。',64,'全唐诗/poet.tang.39000.json','["神珠無纇玉無瑕，七葉簪貂漢相家。", "陣面奔星破犀象，筆頭飛電躍龍蛇。", "絳幃夜坐窮三史，紅斾春行到九華。", "只怕池人留不住，別遷征鎮擁高牙。"]'),
('acffe249-58f6-4689-94b7-3a06a4b5f412','中秋自宛陵寄池陽太守','殷文圭','唐','唐诗','tang','','[]','出山三見月如眉，蝶夢終宵遶戟枝。',64,'全唐诗/poet.tang.39000.json','["出山三見月如眉，蝶夢終宵遶戟枝。", "旅客思歸鴻去日，賢侯行化子來時。", "郡樓遐想劉琨嘯，相閤方窺謝傅棊。", "按部況聞秋稼熟，馬前迎拜羨幷兒。"]'),
('822e27e9-1b17-44c8-bd94-3718a5519061','次韻九華杜先輩重陽寄投宛陵丞相','殷文圭','唐','唐诗','tang','','[]','日下飛聲徹不毛，酒醒時得廣離騷。',64,'全唐诗/poet.tang.39000.json','["日下飛聲徹不毛，酒醒時得廣離騷。", "先生鬢爲吟詩白，上相心因治國勞。", "千乘信迴魚榼重，九華秋逈鳳巢高。", "強酬小謝重陽句，沙恨無金盡日淘。"]'),
('457546e8-e8ef-460f-8487-a578ce833f51','寄賀杜荀鶴及第','殷文圭','唐','唐诗','tang','','[]','一戰平疇五字勞，晝歸鄉去錦爲袍。',64,'全唐诗/poet.tang.39000.json','["一戰平疇五字勞，晝歸鄉去錦爲袍。", "大鵬出海翎猶濕，駿馬辭天氣正豪。", "九子舊山增秀絕，二南新格變風騷。", "由來稽古符公道，平地丹梯甲乙高。"]'),
('cb0d9309-0baf-4a4a-8321-dd443dd5e45d','春草碧色','殷文圭','唐','唐诗','tang','','[]','細草含愁碧，芊綿南浦濱。',72,'全唐诗/poet.tang.39000.json','["細草含愁碧，芊綿南浦濱。", "萋萋如恨別，苒苒共傷春。", "疎雨煙華潤，斜陽細彩勻。", "花黏繁鬬錦，人藉軟勝茵。", "淺映宮池水，輕遮輦路塵。", "杜回如可結，誓作報恩身。"]'),
('e95f1266-9a74-4f8b-9a9e-b42439d7d779','和友人送衡尚書赴池陽副車','殷文圭','唐','唐诗','tang','','[]','淮王上將例分憂，玉帳參承半列侯。',160,'全唐诗/poet.tang.39000.json','["淮王上將例分憂，玉帳參承半列侯。", "次第選材如創廈，別離排宴向藏舟。", "鵾鵬變化知難測，龍蠖升沈各有由。", "躞蹀行牽金鋄重，嬋娟立唱翠娥愁。", "築頭勳業諧三陣，滿腹詩書究九流。", "金海珠韜乘月讀，肉芝牙茗撥雲收。", "赤鱗斾卷鷗汀晚，青雀船橫雁陣秋。", "十字細波澄鏡面，九華殘雪露峰頭。", "醉沈北海千尊酒，吟上南荆百尺樓。", "況是昭明食魚郡，不妨閑擲釣璜鉤。"]'),
('c0d02af5-49b2-4789-9060-d34beaeae368','貽李南平','殷文圭','唐','唐诗','tang','','[]','紫殿西頭月欲斜，曾草臨淮上相麻。',32,'全唐诗/poet.tang.39000.json','["紫殿西頭月欲斜，曾草臨淮上相麻。", "潤筆已曾經奏謝，更飛章句問張華。"]'),
('cad9759d-76f9-445c-bff4-55d6c7585aa7','句','殷文圭','唐','唐诗','tang','','[]','龍舒太守人中傑，風韻堂中心似月。',32,'全唐诗/poet.tang.39000.json','["龍舒太守人中傑，風韻堂中心似月。", "衆口聲光誇漢將，築頭勳業佐淮王。"]'),
('a818ec31-bce5-4670-b777-ed0179e358f0','釣臺','徐夤','唐','唐诗','tang','','[]','金門誰奉詔，碧岸獨垂鉤。',48,'全唐诗/poet.tang.39000.json','["金門誰奉詔，碧岸獨垂鉤。", "舊友秪樵叟，新交惟野鷗。", "嘉名懸日月，深谷化陵丘。", "便可招巢父，長川好飲牛。"]'),
('45d68ebb-a650-436d-991d-ca1dab63416f','旅次寓題','徐夤','唐','唐诗','tang','','[]','胡爲名利役，來往老關河。',48,'全唐诗/poet.tang.39000.json','["胡爲名利役，來往老關河。", "白髮隨梳少，青山入夢多。", "途窮憐抱疾，世亂恥登科。", "却起漁舟念，春風釣綠波。"]'),
('4b4f29af-952b-48d1-a246-feec0db8fdfb','贈嚴司直','徐夤','唐','唐诗','tang','','[]','承家居闕下，避世出關東。',48,'全唐诗/poet.tang.39000.json','["承家居闕下，避世出關東。", "有酒劉伶醉，無兒伯道窮。", "新詩吟閣賞，舊業釣臺空。", "雨雪還相訪，心懷與我同。"]'),
('5f436348-55cb-404f-bcce-e1bf8f36fa03','贈東方道士','徐夤','唐','唐诗','tang','','[]','葫蘆窗畔挂，是物在其間。',48,'全唐诗/poet.tang.39000.json','["葫蘆窗畔挂，是物在其間。", "雪色老人鬢，桃花童子顏。", "祭星秋卜日，採藥曉登山。", "舊放長生鹿，時銜瑞草還。"]'),
('d62a8d55-1bec-4ef5-a341-4c566105583f','題僧壁','徐夤','唐','唐诗','tang','','[]','香廚流瀑布，獨院鎖孤峯。',48,'全唐诗/poet.tang.39000.json','["香廚流瀑布，獨院鎖孤峯。", "紺髮青螺長，文茵紫豹重。", "卵枯皆化燕，蜜老却成蜂。", "明月留人宿，秋聲夜著松。"]'),
('e788296a-618f-4de8-866f-9c93943a9592','和人經隋唐間戰處','徐夤','唐','唐诗','tang','','[]','孤軍前度戰，一敗一成功。',48,'全唐诗/poet.tang.39000.json','["孤軍前度戰，一敗一成功。", "卷斾早歸國，臥屍猶臂弓。", "草間腥半在，沙上血殘紅。", "傷魄何爲者，五湖垂釣翁。"]'),
('5acb904b-327c-47fd-a213-11883d78ef9e','追和常建嘆王昭君','徐夤','唐','唐诗','tang','','[]','紅顏如朔雪，日爍忽成空。',48,'全唐诗/poet.tang.39000.json','["紅顏如朔雪，日爍忽成空。", "淚盡黃雲雨，塵消白草風。", "君心爭不悔，恨思竟何窮。", "願化南飛燕，年年入漢宮。"]'),
('a7cc5a70-0618-4815-b708-42dc8c95d9eb','贈董先生','徐夤','唐','唐诗','tang','','[]','壽歲過於百，時閑到上京。',36,'全唐诗/poet.tang.39000.json','["壽歲過於百，時閑到上京。", "餐松雙鬢嫩，絕粒四支輕。", "雨雪思中嶽，雲霞夢赤城。"]'),
('4a461b94-a0f1-411e-b70b-8809b679e8d6','河流','徐夤','唐','唐诗','tang','','[]','洪流盤砥柱，淮濟不同波。',48,'全唐诗/poet.tang.39000.json','["洪流盤砥柱，淮濟不同波。", "莫訝清時少，都緣曲處多。", "遠能通玉塞，高復接銀河。", "大禹成門嶮，爲龍始得過。"]'),
('79f0a17f-b45d-4489-8cdf-eb5f2b61d584','題南寺','徐夤','唐','唐诗','tang','','[]','久別猨啼寺，流年刦逝波。',48,'全唐诗/poet.tang.39000.json','["久別猨啼寺，流年刦逝波。", "舊僧歸塔盡，古瓦長松多。", "壁蘚昏題記，窗螢散薜蘿。", "平生英壯節，何故旋消磨。"]'),
('430a8367-6d33-4bf0-8eea-c5af9dd9cdfe','北山秋晚','徐夤','唐','唐诗','tang','','[]','十載衣裘盡，臨寒隱薜蘿。',48,'全唐诗/poet.tang.39000.json','["十載衣裘盡，臨寒隱薜蘿。", "心閑緣事少，身老愛山多。", "玉露催收菊，金風促翦禾。", "燕秦正戎馬，林下好婆娑。"]'),
('63bd98e1-2a01-4500-8d77-326af085e05b','昔遊','徐夤','唐','唐诗','tang','','[]','昔遊紅杏苑，今隱刺桐村。',48,'全唐诗/poet.tang.39000.json','["昔遊紅杏苑，今隱刺桐村。", "歲計懸僧債，科名負國恩。", "不書胝漸穩，頻鑷鬢無根。", "惟有經邦事，年年志尚存。"]'),
('ef5ca4bd-7ef3-437f-97c4-c306cc9d95e9','酒胡子','徐夤','唐','唐诗','tang','','[]','紅筵絲竹合，用爾作歡娛。',48,'全唐诗/poet.tang.39000.json','["紅筵絲竹合，用爾作歡娛。", "直指寧偏黨，無私絕覬覦。", "當歌誰擐袖，應節漸輕軀。", "恰與真相似，氈裘滿頷鬚。"]'),
('fec543b2-3d60-4320-8d03-77de98b03e2d','弔崔補闕','徐夤','唐','唐诗','tang','','[]','近來吾道少，慟哭博陵君。',48,'全唐诗/poet.tang.39000.json','["近來吾道少，慟哭博陵君。", "直節岩前竹，孤魂嶺上雲。", "縉紳傳確論，丞相取遺文。", "廢却中興策，何由免用軍。"]'),
('41dd5cd0-5d24-41ab-ab52-2347d83815de','弔赤水李先生','徐夤','唐','唐诗','tang','','[]','三年悲過隙，一室類銷冰。',48,'全唐诗/poet.tang.39000.json','["三年悲過隙，一室類銷冰。", "妻病入仙觀，子窮隨嶽僧。", "荒丘寒有雨，古屋夜無燈。", "往日清猷著，金門幾欲徴。"]'),
('5b9e31e1-ffdf-4d1f-a224-7dade1853269','香鴨','徐夤','唐','唐诗','tang','','[]','不假陶鎔妙，誰教羽翼全。',48,'全唐诗/poet.tang.39000.json','["不假陶鎔妙，誰教羽翼全。", "五金池畔質，百和口中煙。", "觜鈍魚難啄，心空火自燃。", "御爐如有闕，須進聖君前。"]'),
('62757e20-77f4-45aa-a9cf-064fd4d74d12','雞','徐夤','唐','唐诗','tang','','[]','名參十二屬，花入羽毛深。',48,'全唐诗/poet.tang.39000.json','["名參十二屬，花入羽毛深。", "守信催朝日，能鳴送曉陰。", "峨冠裝瑞璧，利爪削黃金。", "徒有稻粱感，何由報德音。"]'),
('5ef5c26c-117a-46be-8d8b-2dc0c5301f23','白鴿','徐夤','唐','唐诗','tang','','[]','舉翼凌空碧，依人到大邦。',48,'全唐诗/poet.tang.39000.json','["舉翼凌空碧，依人到大邦。", "粉翎棲畫閣，雪影拂瓊窗。", "振鷺堪爲侶，鳴鳩好作雙。", "狎鷗歸未得，覩爾憶晴江。"]'),
('1ecf2229-6fdb-4cea-b397-a7bd615c54f3','龜','徐夤','唐','唐诗','tang','','[]','行止竟何從，深溪與古峰。',48,'全唐诗/poet.tang.39000.json','["行止竟何從，深溪與古峰。", "青荷巢瑞質，綠水返靈蹤。", "鑽骨神明應，酬恩感激重。", "仙翁求一卦，何日脫龍鍾。"]'),
('a054c031-bdb2-4549-86b0-c4375eafb881','銀結條冠子','徐夤','唐','唐诗','tang','','[]','日下徴良匠，宮中贈阿嬌。',48,'全唐诗/poet.tang.39000.json','["日下徴良匠，宮中贈阿嬌。", "瑞蓮開二孕，瓊縷織千條。", "蟬翼輕輕結，花紋細細挑。", "舞時紅袖舉，纖影透龍綃。"]'),
('8b13e5a3-6261-40fe-8fff-50764879e239','蜀葵','徐夤','唐','唐诗','tang','','[]','劍門南面樹，移向會仙亭。',48,'全唐诗/poet.tang.39000.json','["劍門南面樹，移向會仙亭。", "錦水饒花豔，岷山帶葉青。", "文君慚婉娩，神女讓娉婷。", "爛熳紅兼紫，飄香入繡扃。"]'),
('98104dd7-8787-45c8-a4ca-88656ef9830e','華清宮','徐夤','唐','唐诗','tang','','[]','十二瓊樓鏁翠微，暮霞遺却六銖衣。',64,'全唐诗/poet.tang.39000.json','["十二瓊樓鏁翠微，暮霞遺却六銖衣。", "桐枯丹穴鳳何去，天在鼎湖龍不歸。", "簾影罷添新翡翠，露華猶濕舊珠璣。", "君王魂斷驪山路，且向蓬瀛伴貴妃。"]'),
('05031d69-94f5-45f2-84f4-980631175f14','再幸華清宮','徐夤','唐','唐诗','tang','','[]','腸斷將軍改葬歸，錦囊香在憶當時。',64,'全唐诗/poet.tang.39000.json','["腸斷將軍改葬歸，錦囊香在憶當時。", "年來却恨相思樹，春至不生連理枝。", "雪女塚頭瑤草合，貴妃池裏玉蓮衰。", "霓裳舊曲飛霜殿，夢破魂驚絕後期。"]'),
('8242bb00-b796-4c7c-b315-3d45d09f693e','喜雨上主人尚書','徐夤','唐','唐诗','tang','','[]','天皇攘袂勅神龍，雨我公田兆歲豐。',64,'全唐诗/poet.tang.39000.json','["天皇攘袂勅神龍，雨我公田兆歲豐。", "幾日淋漓侵暮角，數宵滂沛徹晨鐘。", "細如春霧籠平野，猛似秋風擊古松。", "門下十年耕稼者，坐來偏憶翠微峰。"]'),
('1f2f7caf-a80a-4c0b-ab39-2868e1588744','迴文詩二首 一','徐夤','唐','唐诗','tang','','[]','飛書一幅錦文迴，恨寫深情寄雁來。',64,'全唐诗/poet.tang.39000.json','["飛書一幅錦文迴，恨寫深情寄雁來。", "機上月殘香閣掩，樹梢煙澹綠窗開。", "霏霏雨罷歌終曲，漠漠雲深酒滿杯。", "歸日幾人行問卜，徽音想望倚高臺。"]'),
('4af306ac-3e8d-41cc-9330-bddb0014b037','迴文詩二首 二','徐夤','唐','唐诗','tang','','[]','輕帆數點千峰碧，水接雲山四望遙。',64,'全唐诗/poet.tang.39000.json','["輕帆數點千峰碧，水接雲山四望遙。", "晴日海霞紅靄靄，曉天江樹綠迢迢。", "清波石眼泉當檻，小逕松門寺對橋。", "明月釣舟漁浦遠，傾山雪浪暗隨潮。"]'),
('45973894-37c7-482d-bd77-fe0d6acbcc8b','不把漁竿','徐夤','唐','唐诗','tang','','[]','不把漁竿不灌園，策筇吟遶綠蕪村。',64,'全唐诗/poet.tang.39000.json','["不把漁竿不灌園，策筇吟遶綠蕪村。", "得爭野老眠雲樂，倍感閩王與善恩。", "鳥趂竹風穿靜戶，魚吹煙浪噴晴軒。", "何人買我安貧趣，百萬黃金未可論。"]'),
('644d737d-d86a-4910-82ed-711ac4e320fa','古往今來','徐夤','唐','唐诗','tang','','[]','古往今來恨莫窮，不如沈醉臥春風。',64,'全唐诗/poet.tang.39000.json','["古往今來恨莫窮，不如沈醉臥春風。", "雀兒無角長穿屋，鸚鵡能言却入籠。", "柳惠豈嫌居下位，朱雲直去指三公。", "閑思郭令長安宅，草沒匡墻舊事空。"]'),
('6287161e-894e-467e-8c05-f10638015b63','十里煙籠','徐夤','唐','唐诗','tang','','[]','十里煙籠一徑分，故人迢遰久離羣。',64,'全唐诗/poet.tang.39000.json','["十里煙籠一徑分，故人迢遰久離羣。", "白雲明月皆由我，碧水青山忽贈君。", "浮世宦名渾似夢，半生勤苦謾爲文。", "北邙坡上青松下，盡是鏘金佩玉墳。"]'),
('d44504aa-9b95-47ab-abd7-4e34bcfdb960','偶書','徐夤','唐','唐诗','tang','','[]','巧者多爲拙者資，良籌第一在乘時。',64,'全唐诗/poet.tang.39000.json','["巧者多爲拙者資，良籌第一在乘時。", "市門逐利終身飽，谷口躬耕盡日飢。", "瓊玖鬻來燕石貴，蓬蒿芳處楚蘭衰。", "高皇冷笑重瞳客，蓋世拔山何所爲。"]'),
('b18cc864-0b55-4667-b561-4b3562848a2b','潤屋','徐夤','唐','唐诗','tang','','[]','潤屋豐家莫妄求，眼看多是與身讐。',64,'全唐诗/poet.tang.39000.json','["潤屋豐家莫妄求，眼看多是與身讐。", "百禽羅得皆黃口，四皓山居始白頭。", "玉爍火光爭肯變，草芳崎岸不曾秋。", "朱門粉署何由到，空寄新詩謝列侯。"]'),
('ee8e72dd-8806-430e-a6e2-9719df03b6e3','退居','徐夤','唐','唐诗','tang','','[]','鶴性松心合在山，五侯門館怯趨攀。',64,'全唐诗/poet.tang.39000.json','["鶴性松心合在山，五侯門館怯趨攀。", "三年臥病不能免，一日受恩方得還。", "明月送人沿驛路，白雲隨馬入柴關。", "笑他范蠡貪惏甚，相罷金多始退閑。"]'),
('54f76d2e-8f87-4269-92cb-f11508cc5997','閉門','徐夤','唐','唐诗','tang','','[]','閉却閑門臥小窗，更何人與療膏肓。',64,'全唐诗/poet.tang.39000.json','["閉却閑門臥小窗，更何人與療膏肓。", "一生有酒唯知醉，四大無根可預量。", "骨冷欲針先覺痛，肉頑頻炙不成瘡。", "漳濱伏枕文園渴，盜跖縱橫似虎狼。"]'),
('63502b6a-b135-4110-a8fb-e67fd2356f40','開窗','徐夤','唐','唐诗','tang','','[]','閉戶開窗寢又興，三更時節也如冰。',64,'全唐诗/poet.tang.39000.json','["閉戶開窗寢又興，三更時節也如冰。", "長閑便是忘機者，不出真如過夏僧。", "環堵豈慚蝸作舍，布衣寧假鶴爲翎。", "薔薇花盡薰風起，綠葉空隨滿架藤。"]'),
('9c78d94c-bc77-4be5-8970-3e18623e4606','燈花','徐夤','唐','唐诗','tang','','[]','點蠟燒銀却勝栽，九華紅豔吐玫瑰。',64,'全唐诗/poet.tang.39000.json','["點蠟燒銀却勝栽，九華紅豔吐玫瑰。", "獨含冬夜寒光拆，不傍春風暖處開。", "難見只因能送喜，莫挑唯恐墮成灰。", "貪膏附熱多相誤，爲報飛蛾罷拂來。"]'),
('22a67fd5-f3b8-4f85-a762-bad65224ec45','東歸出城留別知己','徐夤','唐','唐诗','tang','','[]','韋蒙屈指許非才，三載長安共酒桮。',64,'全唐诗/poet.tang.39000.json','["韋蒙屈指許非才，三載長安共酒桮。", "欲別未攀楊柳贈，相留擬待牡丹開。", "寒隨御水波光散，暖逐衡陽雁影來。", "他日因書問衰颯，東溪須訪子陵臺。"]'),
('8fd43683-676f-4414-8024-c355536fbedf','詠懷','徐夤','唐','唐诗','tang','','[]','愁花變出白髭鬚，半世辛勤一事無。',64,'全唐诗/poet.tang.39000.json','["愁花變出白髭鬚，半世辛勤一事無。", "道在或期君夢想，貧來爭奈鬼揶揄。", "馬卿自愧長嬰疾，顏子誰憐不是愚。", "借取秦宮臺上鏡，爲時開照漢妖狐。"]'),
('ae4776cb-0cb8-4a59-bad7-7a8aefac04bb','郊村獨遊','徐夤','唐','唐诗','tang','','[]','歲閏堪憐曆候遲，出門惟與野雲期。',64,'全唐诗/poet.tang.39000.json','["歲閏堪憐曆候遲，出門惟與野雲期。", "驚魚擲上綠荷芰，棲鳥啄餘紅荔枝。", "末路可能長薄命，修途應合有良時。", "市頭相者休相戲，蹙膝先生半自知。"]'),
('7ba25404-349f-4d70-9525-2f77dfbb34af','經故翰林楊左丞池亭','徐夤','唐','唐诗','tang','','[]','八角紅亭蔭綠池，一朝青草蓋遺基。',64,'全唐诗/poet.tang.39000.json','["八角紅亭蔭綠池，一朝青草蓋遺基。", "薔薇藤老開花淺，翡翠巢空落羽奇。", "春榜幾深門下客，樂章多取集中詩。", "平生德義人間誦，身後何勞更立碑。"]'),
('63d5bf8b-816a-4da3-9e56-090971dc50a1','經故廣平員外舊宅','徐夤','唐','唐诗','tang','','[]','門巷蕭條引涕洟，遺孤三歲著麻衣。',64,'全唐诗/poet.tang.39000.json','["門巷蕭條引涕洟，遺孤三歲著麻衣。", "綠楊樹老垂絲短，翠竹林荒著筍稀。", "結社僧因秋朔弔，買書船近葬時歸。", "平生欲獻匡君策，抱病猶言未息機。"]'),
('848fdc67-9da0-410d-9f64-75fe24f8571d','潘丞相舊宅','徐夤','唐','唐诗','tang','','[]','綠樹垂枝蔭四鄰，春風還似舊時春。',64,'全唐诗/poet.tang.39000.json','["綠樹垂枝蔭四鄰，春風還似舊時春。", "年年燕是雕梁主，處處花隨落月塵。", "七貴竟爲長逝客，五侯尋作不歸人。", "秋槐影薄蟬聲盡，休謂龍門待化鱗。"]'),
('cf0f1447-3bb9-4615-9c54-9d16d3d84dfe','門外閑田數畝長有泉源因築直堤分爲兩沼','徐夤','唐','唐诗','tang','','[]','左右澄漪小檻前，直堤高築古平川。',64,'全唐诗/poet.tang.39000.json','["左右澄漪小檻前，直堤高築古平川。", "十分春水雙簷影，一片秋空兩月懸。", "前岸好山搖細浪，夾門嘉樹合晴煙。", "坐來暗起江湖思，速問溪翁買釣船。"]'),
('98db85c6-7dce-4fa1-ae00-515612996689','北園','徐夤','唐','唐诗','tang','','[]','北園乾葉旋空枝，蘭蕙還將衆草衰。',64,'全唐诗/poet.tang.39000.json','["北園乾葉旋空枝，蘭蕙還將衆草衰。", "籠鳥上天猶有待，病龍興雨豈無期。", "身閑不厭頻來客，年老偏憐最小兒。", "生事罷求名與利，一窗書策是年支。"]'),
('a33915db-c40d-4db0-b8c7-5e466d286899','溪上要一隻白簟扇蓋頭垂釣去年就節推侍御請之蒙惠一柄紫花紋者雖則鱗華具甚紕薄不及清源所出因就南郡陳常侍請之遂成拙句','徐夤','唐','唐诗','tang','','[]','難求珍箑過炎天，遠就金貂乞月圓。',64,'全唐诗/poet.tang.39000.json','["難求珍箑過炎天，遠就金貂乞月圓。", "直在引風欹角枕，且圖遮日上漁船。", "但令織取無花簟，不用挑爲飲露蟬。", "莫道如今時較晚，也應留得到明年。"]'),
('9c8dbcc7-39e8-42fb-9628-0a3effa2e4eb','招隱','徐夤','唐','唐诗','tang','','[]','齒髮那能敵歲華，早知休去避塵沙。',64,'全唐诗/poet.tang.39000.json','["齒髮那能敵歲華，早知休去避塵沙。", "鬼神只闞高明里，倚伏不干棲隱家。", "陶景豈全輕組綬，留侯非獨愛煙霞。", "贈君吉語堪銘座，看取朝開暮落花。"]'),
('36c90b34-7388-4ba4-b3f4-25081e74f014','憶山中友人','徐夤','唐','唐诗','tang','','[]','憶得當年接善鄰，苦將閑事強夫君。',64,'全唐诗/poet.tang.39000.json','["憶得當年接善鄰，苦將閑事強夫君。", "鬬開碧沼分明月，各領青山占白雲。", "近日藥方多繕寫，舊來詩草半燒焚。", "金門幾欲言西上，惆悵關河正用軍。"]'),
('ddab1b9c-d710-48a3-8307-e7b86ba18c4c','溪隱','徐夤','唐','唐诗','tang','','[]','將名將利已無緣，深隱清溪擬學仙。',64,'全唐诗/poet.tang.39000.json','["將名將利已無緣，深隱清溪擬學仙。", "絕却腥羶勝服藥，斷除桮酒合延年。", "蝸牛殼漏寧同舍，榆莢花開不是錢。", "鸞鶴久從籠檻閉，春風却放紙爲鳶。"]'),
('fbfd76de-eb93-43f6-a461-2a4742d996ae','酒醒','徐夤','唐','唐诗','tang','','[]','酒醒欲得適閑情，騎馬那勝策杖行。',64,'全唐诗/poet.tang.39000.json','["酒醒欲得適閑情，騎馬那勝策杖行。", "天暖天寒三月暮，溪南溪北兩村名。", "沙澄淺水魚知釣，花落平田鶴見耕。", "望斷長安故交遠，來書未說九河清。"]'),
('e679b661-fc40-4f60-9b3e-27b35ca8435d','夢斷','徐夤','唐','唐诗','tang','','[]','夢斷紗窗半夜雷，別君花落又花開。',64,'全唐诗/poet.tang.39000.json','["夢斷紗窗半夜雷，別君花落又花開。", "漁陽路遠書難寄，衡嶽山高月不來。", "玄燕有情穿繡戶，靈龜無應祝金杯。", "人生若得長相對，螢火生煙草化灰。"]'),
('d9e317fc-4dd6-4078-94ca-d1c3446be8f6','人事','徐夤','唐','唐诗','tang','','[]','人事飄如一炷煙，且須求佛與求仙。',64,'全唐诗/poet.tang.39000.json','["人事飄如一炷煙，且須求佛與求仙。", "豐年甲子春無雨，良夜庚申夏足眠。", "顏氏豈嫌瓢裏飲，孟光非取鏡中妍。", "平生生計何爲者，三逕蒼苔十畝田。"]'),
('80b8e616-350e-4d40-a1bd-9a455b8da076','休說','徐夤','唐','唐诗','tang','','[]','休說人間有陸沈，一樽閑待月明斟。',64,'全唐诗/poet.tang.39000.json','["休說人間有陸沈，一樽閑待月明斟。", "時來不怕滄溟闊，道大却憂潢潦深。", "白首釣魚應是分，青雲干祿已無心。", "梓桐賦罷相如隱，誰爲君前永夜吟。"]'),
('cc19bbc5-840c-40d0-a2a9-a2344d442b4b','嘉運','徐夤','唐','唐诗','tang','','[]','嘉運良時兩阻修，釣竿簑笠樂林丘。',64,'全唐诗/poet.tang.39000.json','["嘉運良時兩阻修，釣竿簑笠樂林丘。", "家無寸帛渾閑事，身似浮雲且自由。", "庭際鳥啼花旋落，潭心月在水空流。", "晨炊一箸紅銀粒，憶著長安索米秋。"]'),
('53924571-55d4-4f7a-ad55-0612145d85ca','綠鬢','徐夤','唐','唐诗','tang','','[]','綠鬢先生自出林，孟光同樂野雲深。',64,'全唐诗/poet.tang.39000.json','["綠鬢先生自出林，孟光同樂野雲深。", "躬耕爲食古人操，非織不衣賢者心。", "眼衆豈能分瑞璧，舌多須信爍良金。", "君看黃閣南遷客，一過瀧州絕好音。"]'),
('bf523960-aab4-4bfd-bfee-69b38ed9ebab','驕侈','徐夤','唐','唐诗','tang','','[]','驕侈阽危儉素牢，鏡中形影豈能逃。',64,'全唐诗/poet.tang.39000.json','["驕侈阽危儉素牢，鏡中形影豈能逃。", "石家恃富身還滅，顏子非貧道不遭。", "蝙蝠亦能知日月，鸞鳳那肯啄腥臊。", "古今人事惟堪醉，好脫霜裘換綠醪。"]'),
('77f3889c-87a0-4696-aa7c-27fb20302718','龍蟄二首 一','徐夤','唐','唐诗','tang','','[]','龍蟄蛇蟠却待伸，和光何惜且同塵。',64,'全唐诗/poet.tang.39000.json','["龍蟄蛇蟠却待伸，和光何惜且同塵。", "伍員豈是吹簫者，冀缺非同執耒人。", "神劍觸星當變化，良金成器在陶鈞。", "穰侯休忌關東客，張祿先生竟相秦。"]'),
('1e17507c-69f5-4245-ba92-fa6b94f27061','龍蟄二首 二','徐夤','唐','唐诗','tang','','[]','休說雄才間代生，到頭難與運相爭。',64,'全唐诗/poet.tang.39000.json','["休說雄才間代生，到頭難與運相爭。", "時通有詔徵枚乘，世亂無人薦禰衡。", "逐日莫矜駑馬步，司晨誰要牝雞鳴。", "中林且作煙霞侶，塵滿關河未可行。"]'),
('ace23fcc-74dc-438a-a1c6-259fcf745bd2','逐臭蒼蠅','徐夤','唐','唐诗','tang','','[]','逐臭蒼蠅豈有爲，清蟬吟露最高奇。',64,'全唐诗/poet.tang.39000.json','["逐臭蒼蠅豈有爲，清蟬吟露最高奇。", "多藏苟得何名富，飽食嗟來未勝飢。", "窮寂不妨延壽考，貪狂總待算毫釐。", "首陽山翠千年在，好奠冰壺弔伯夷。"]'),
('30a32dfc-174c-42a5-8063-b6b6cd16f389','牡丹花二首 一','徐夤','唐','唐诗','tang','','[]','看徧花無勝此花，翦雲披雪蘸丹砂。',64,'全唐诗/poet.tang.39000.json','["看徧花無勝此花，翦雲披雪蘸丹砂。", "開當青律二三月，破却長安千萬家。", "天縱穠華刳鄙吝，春教妖豔毒豪奢。", "不隨寒令同時放，倍種雙松與辟邪。"]'),
('09215f0d-4ce9-4b2f-8be9-b6c9f63816f4','牡丹花二首 二','徐夤','唐','唐诗','tang','','[]','萬萬花中第一流，淺霞輕染嫩銀甌。',64,'全唐诗/poet.tang.39000.json','["萬萬花中第一流，淺霞輕染嫩銀甌。", "能狂綺陌千金子，也惑朱門萬戶侯。", "朝日照開攜酒看，暮風吹落遶欄收。", "詩書滿架塵埃撲，盡日無人畧舉頭。"]'),
('4b622df6-8c0d-4e75-81c6-4b53f3175d76','尚書座上賦牡丹花得輕字韻其花自越中移植','徐夤','唐','唐诗','tang','','[]','流蘇凝作瑞華精，仙閣開時麗日晴。',64,'全唐诗/poet.tang.39000.json','["流蘇凝作瑞華精，仙閣開時麗日晴。", "霜月冷銷銀燭焰，寶甌圓印綵雲英。", "嬌含嫩臉春妝薄，紅蘸香綃豔色輕。", "早晚有人天上去，寄他將贈董雙成。"]'),
('8d864cd0-5723-4c05-8aca-2f41e09d5528','依韻和尚書再贈牡丹花','徐夤','唐','唐诗','tang','','[]','爛銀基地薄紅妝，羞殺千花百卉芳。',64,'全唐诗/poet.tang.39000.json','["爛銀基地薄紅妝，羞殺千花百卉芳。", "紫陌昔曾遊寺看，朱門今在遶欄望。", "龍分夜雨資嬌態，天與春風發好香。", "多著黃金何處買，輕橈挑過鏡湖光。"]'),
('e0e7f319-5a64-462b-9c5c-d5bfd9a64815','郡庭惜牡丹','徐夤','唐','唐诗','tang','','[]','腸斷東風落牡丹，爲祥爲瑞久留難。',64,'全唐诗/poet.tang.39000.json','["腸斷東風落牡丹，爲祥爲瑞久留難。", "青春不駐堪垂淚，紅豔已空猶倚欄。", "積蘚下銷香蘂盡，晴陽高照露華乾。", "明年萬葉千枝長，倍發芳菲借客看。"]'),
('f7e1f3d0-96a1-4e49-947b-a21cfbd49c25','追和白舍人詠白牡丹','徐夤','唐','唐诗','tang','','[]','蓓蕾抽開素練囊，瓊葩薰出白龍香。',64,'全唐诗/poet.tang.39000.json','["蓓蕾抽開素練囊，瓊葩薰出白龍香。", "裁分楚女朝雲片，翦破姮娥夜月光。", "雪句豈須徴柳絮，粉腮應恨帖梅妝。", "檻邊幾笑東籬菊，冷折金風待降霜。"]'),
('bb7908b9-a0c4-4c31-9441-25276bdbcabc','憶牡丹','徐夤','唐','唐诗','tang','','[]','綠樹多和雪霰栽，長安一別十年來。',64,'全唐诗/poet.tang.39000.json','["綠樹多和雪霰栽，長安一別十年來。", "王侯買得價偏重，桃李落殘花始開。", "宋玉鄰邊腮正嫩，文君機上錦初裁。", "滄洲春暮空腸斷，畫看猶將勸酒杯。"]'),
('e400182d-2270-4b83-9724-d51906a96a0c','惜牡丹','徐夤','唐','唐诗','tang','','[]','今日狂風揭錦筵，預愁吹落夕陽天。',64,'全唐诗/poet.tang.39000.json','["今日狂風揭錦筵，預愁吹落夕陽天。", "閑看紅豔只須醉，謾惜黃金豈是賢。", "南國好偷誇粉黛，漢宮宜摘贈神仙。", "良時雖作鶯花主，白馬王孫恰少年。"]'),
('7612d5ee-f82c-47dc-a27f-811c9615a202','覽柳渾汀洲採白蘋之什因成一章','徐夤','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','採盡汀蘋恨別離，鴛鴦鸂鶒總雙飛。',64,'全唐诗/poet.tang.39000.json','["採盡汀蘋恨別離，鴛鴦鸂鶒總雙飛。", "月明南浦夢初斷，花落洞庭人未歸。", "天遠有書隨驛使，夜長無燭照寒機。", "年來泣淚知多少，重疊成痕在繡衣。"]'),
('9913526a-c1e9-40c1-a2c5-a28adcf0193d','司直巡官無諸移到玫瑰花','徐夤','唐','唐诗','tang','','[]','芳菲移自越王臺，最似薔薇好並栽。',64,'全唐诗/poet.tang.39000.json','["芳菲移自越王臺，最似薔薇好並栽。", "穠豔盡憐勝綵繪，嘉名誰贈作玫瑰。", "春藏錦繡風吹拆，天染瓊瑤日照開。", "爲報朱衣早邀客，莫教零落委蒼苔。"]'),
('c8d4604c-d4e4-4dc7-90dd-bcc65478d830','梅花','徐夤','唐','唐诗','tang','','[]','瓊瑤初綻嶺頭葩，蘂粉新妝姹女家。',64,'全唐诗/poet.tang.39000.json','["瓊瑤初綻嶺頭葩，蘂粉新妝姹女家。", "舉世更誰憐潔白，癡心皆盡愛繁華。", "玄冥借與三冬景，謝氏輸他六出花。", "結實和羹知有日，肯隨羌笛落天涯。"]'),
('3e37b8b3-ff91-4dd3-9eb0-00aebb409500','茘枝二首 一','徐夤','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','朱彈星丸粲日光，綠瓊枝散小香囊。',64,'全唐诗/poet.tang.39000.json','["朱彈星丸粲日光，綠瓊枝散小香囊。", "龍綃殼綻紅紋粟，魚目珠涵白膜漿。", "梅熟已過南嶺雨，橘酸空待洞庭霜。", "蠻山蹋曉和煙摘，拜捧金盤奉越王。"]'),
('7dee099f-fae2-4659-84ea-8f7ddc35de9f','茘枝二首 二','徐夤','唐','唐诗','tang','','[]','日日薰風卷瘴煙，南園珍菓茘枝先。',66,'全唐诗/poet.tang.39000.json','["日日薰風卷瘴煙，南園珍菓茘枝先。", "靈鴉啄破瓊津滴，寶器盛來蚌腹圓。", "錦里只聞銷醉客，蘂宮惟合贈神仙。", "何人刺出[猩猩]血，深染羅紋遍殼鮮。"]'),
('35e41385-8a07-4dd9-88fa-39d625c3bf67','菊花','徐夤','唐','唐诗','tang','','[]','桓景登高事可尋，黃花開處綠畦深。',64,'全唐诗/poet.tang.39000.json','["桓景登高事可尋，黃花開處綠畦深。", "消災辟惡君須採，冷露寒霜我自禁。", "籬物早榮還早謝，澗松同德復同心。", "陶公豈是居貧者，剩有東籬萬朵金。"]'),
('7f32b206-fc43-488f-928a-d798e24d5eee','畫松','徐夤','唐','唐诗','tang','','[]','澗底陰森驗筆精，筆閑開展覺神清。',64,'全唐诗/poet.tang.39000.json','["澗底陰森驗筆精，筆閑開展覺神清。", "曾當月照還無影，若許風吹合有聲。", "枝偃只應玄鶴識，根深且與茯苓生。", "天台道士頻來見，說似株株倚赤城。"]'),
('b8fc13a0-c241-4751-9578-42a43d067f1b','草木','徐夤','唐','唐诗','tang','','[]','草木無情亦可嗟，重開明鏡照無涯。',64,'全唐诗/poet.tang.39000.json','["草木無情亦可嗟，重開明鏡照無涯。", "菊英空折羅含宅，榆莢不生原憲家。", "天命豈憑醫藥石，世途還要辟蟲沙。", "仙翁乞取金盤露，洗却蒼蒼兩鬢華。"]'),
('a52ffef2-aefd-4b5a-90c2-e072d81f9a12','松','徐夤','唐','唐诗','tang','','[]','澗底青松不染塵，未逢良匠競誰分。',64,'全唐诗/poet.tang.39000.json','["澗底青松不染塵，未逢良匠競誰分。", "龍盤勁節岩前見，鶴唳翠梢天上聞。", "大廈可營誰擇木，女蘿相附欲凌雲。", "皇王自有增封日，修竹徒勞號此君。"]'),
('12447b12-0cd6-4d51-9f99-02627b800ee4','竹','徐夤','唐','唐诗','tang','','[]','翠染琅玕粉漸開，東南移得會稽栽。',64,'全唐诗/poet.tang.39000.json','["翠染琅玕粉漸開，東南移得會稽栽。", "游絲挂處漁竿去，綠水夾時龍影來。", "風觸有聲含六律，露沾如洗絕浮埃。", "王猷舊宅無人到，抱却清陰蓋綠苔。"]'),
('10a4d219-f300-40c7-b487-51c387da70cd','尚書打毬小驄步驟最奇因有所贈','徐夤','唐','唐诗','tang','','[]','善價千金未可論，燕王新寄小龍孫。',64,'全唐诗/poet.tang.39000.json','["善價千金未可論，燕王新寄小龍孫。", "逐將白日馳青漢，銜得流星入畫門。", "步驟最能隨手轉，性靈多恐會人言。", "桃花雪點多雖貴，全假當場一顧恩。"]'),
('84412caa-a379-46b3-b323-146d35f2a39a','尚書惠蠟面茶','徐夤','唐','唐诗','tang','','[]','武夷春暖月初圓，採摘新芽獻地仙。',64,'全唐诗/poet.tang.39000.json','["武夷春暖月初圓，採摘新芽獻地仙。", "飛鵲印成香蠟片，啼猿溪走木蘭船。", "金槽和碾沈香末，冰椀輕涵翠縷煙。", "分贈恩深知最異，晚鐺宜煮北山泉。"]'),
('5ed7af94-11ab-4363-9f99-47d25c0a2fbf','勸酒','徐夤','唐','唐诗','tang','','[]','休向尊前愬羽觥，百壺清酌與君傾。',64,'全唐诗/poet.tang.39000.json','["休向尊前愬羽觥，百壺清酌與君傾。", "身同綠樹年年老，事比紅塵日日生。", "六國英雄徒反覆，九原松柏甚分明。", "醉鄉路與乾坤隔，豈信人間有利名。"]'),
('5c7fd124-e276-4fdd-9473-edbdcbfcd11a','斷酒','徐夤','唐','唐诗','tang','','["\u5e90\u5c71"]','因論沈湎覺前非，便碎金罍與羽巵。',64,'全唐诗/poet.tang.39000.json','["因論沈湎覺前非，便碎金罍與羽巵。", "採茗早馳三蜀使，看花甘負五侯期。", "窗間近火劉伶傳，坐右新銘管仲辭。", "此事十年前已說，匡廬山下老僧知。"]'),
('7e22e9fb-2113-4f57-adf5-8bc9d6e7c77f','憶舊山','徐夤','唐','唐诗','tang','','[]','澗竹岩雲有舊期，二年頻長鬢邊絲。',64,'全唐诗/poet.tang.39000.json','["澗竹岩雲有舊期，二年頻長鬢邊絲。", "遊魚不愛金桮水，棲鳥敢求瓊樹枝。", "陶景戀深松檜影，留侯拋却帝王師。", "龍爭虎攫皆閑事，數疊山光在夢思。"]'),
('38d28ed7-484f-4b2c-89d1-06f7ca6c0037','西華','徐夤','唐','唐诗','tang','','[]','五千仞有餘神秀，一一排雲上泬㵳。',66,'全唐诗/poet.tang.39000.json','["五千仞有餘神秀，一一排雲上泬㵳。", "疊嶂出關分二陝，殘岡過水作中條。", "巨靈廟破生春草，毛女峰高入絳[霄]。", "拜祝金天乞陰德，爲民求主降神堯。"]'),
('4e1020a6-b044-4bed-8073-5a12547bcdf0','嵐似屏風','徐夤','唐','唐诗','tang','','[]','嵐似屏風草似茵，草邊時膾錦花鱗。',64,'全唐诗/poet.tang.39000.json','["嵐似屏風草似茵，草邊時膾錦花鱗。", "山中宰相陶弘景，谷口耕夫鄭子真。", "宦達到頭思野逸，才多未必笑清貧。", "君看東洛平泉宅，只有年年百卉春。"]'),
('804553f3-65d9-4b1d-85c1-63a3f8c7ac78','憶潼關','徐夤','唐','唐诗','tang','','["\u9ec4\u6cb3"]','洞壑雙扉入到初，似從深穽覩高墟。',64,'全唐诗/poet.tang.39000.json','["洞壑雙扉入到初，似從深穽覩高墟。", "天開白日臨軍國，山夾黃河護帝居。", "隋煬遠遊宜不反，奉春長策竟何如。", "須知皇漢能扃鐍，延得年過四百餘。"]'),
('435e32de-910b-41c1-a27e-e6c964eced61','憶潼關早行','徐夤','唐','唐诗','tang','','[]','行客起看仙掌月，落星斜照濁河泥。',64,'全唐诗/poet.tang.39000.json','["行客起看仙掌月，落星斜照濁河泥。", "故山遠處高飛雁，去馬鳴時先早雞。", "關柳不知誰氏種，岳碑猶見聖君題。", "蒭蕘十軸僮三尺，豈謂青雲便有梯。"]'),
('901a1f29-906e-4ac3-a8e2-6fe76c973c3a','鴻門','徐夤','唐','唐诗','tang','','[]','耨月耕煙水國春，薄徒應笑作農人。',64,'全唐诗/poet.tang.39000.json','["耨月耕煙水國春，薄徒應笑作農人。", "皇王尚法三推禮，白社寧忘四體勤。", "雨灑簑衣芳草暗，鳥啼雲樹小村貧。", "猶勝墮力求飧者，五斗低腰走世塵。"]'),
('487ebdc1-cb5b-4327-8ecc-8b38ae3252f2','憶長安行','徐夤','唐','唐诗','tang','','[]','舊歷關中憶廢興，僭奢須戒儉須憑。',64,'全唐诗/poet.tang.39000.json','["舊歷關中憶廢興，僭奢須戒儉須憑。", "火光只是燒秦冢，賊眼何曾視灞陵。", "鐘鼓煎催人自急，侯王更換恨難勝。", "不如坐釣清溪月，心共寒潭一片澄。"]'),
('9188b860-b609-4232-a350-324ace45bbc2','憶長安上省年','徐夤','唐','唐诗','tang','','[]','忽憶關中逐計車，歷坊騎馬信空虛。',64,'全唐诗/poet.tang.39000.json','["忽憶關中逐計車，歷坊騎馬信空虛。", "三秋病起見新鴈，八月夜長思舊居。", "宗伯帳前曾獻賦，相君門下再投書。", "如今說著猶堪泣，兩宿都堂過歲除。"]'),
('637289d5-aa1e-4c13-972a-a41f128c8d54','長安述懷','徐夤','唐','唐诗','tang','','["\u9ec4\u6cb3"]','黃河冰合尚來遊，知命知時肯躁求。',66,'全唐诗/poet.tang.39000.json','["黃河冰合尚來遊，知命知時肯躁求。", "詞賦有名堪自負，春風落第不曾羞。", "風塵色裏凋雙鬢，[鼙]鼓聲中歷幾州。", "十載公卿早言屈，何須課夏更冥搜。"]'),
('045cee6c-a56b-4340-b251-984ed0c5cdb4','長安即事三首 一','徐夤','唐','唐诗','tang','','[]','拋擲清溪舊釣鉤，長安寒暑再環周。',64,'全唐诗/poet.tang.39000.json','["拋擲清溪舊釣鉤，長安寒暑再環周。", "便隨鶯羽三春化，只說蟬聲一度愁。", "掃雪自憐窗紙照，上天寧愧海槎流。", "明時則待金門詔，肯羨班超萬戶侯。"]'),
('2702d6d4-922f-4674-8f77-31ff0280a3a9','長安即事三首 二','徐夤','唐','唐诗','tang','','[]','無酒窮愁結自舒，飲河求滿不求餘。',64,'全唐诗/poet.tang.39000.json','["無酒窮愁結自舒，飲河求滿不求餘。", "身登霄漢平時第，家得干戈定後書。", "富貴敢期蘇季子，清貧方見馬相如。", "明時用即匡君去，不用何妨却釣魚。"]'),
('bb5dd857-d103-4b94-aa53-95aaa2833e87','長安即事三首 三','徐夤','唐','唐诗','tang','','[]','拖紫腰金不要論，便堪歸隱白雲村。',64,'全唐诗/poet.tang.39000.json','["拖紫腰金不要論，便堪歸隱白雲村。", "更無名籍強金榜，豈有花枝勝杏園。", "綺席促時皆國器，羽觥飛處盡王孫。", "高眠亦是前賢事，爭報春闈莫大恩。"]'),
('fec157bb-e22e-4671-8f51-9a1ef41777e1','東京次新安道中','徐夤','唐','唐诗','tang','','[]','賊去兵來歲月長，野蒿空滿壞墻匡。',64,'全唐诗/poet.tang.39000.json','["賊去兵來歲月長，野蒿空滿壞墻匡。", "旋從古轍成深谷，幾見金輿過上陽。", "洛水送年催代謝，嵩山擎日拂穹蒼。", "殊時異世爲儒者，不見文皇與武皇。"]'),
('d10a53b2-68ab-41e3-aefa-577a624a9edc','山陰故事','徐夤','唐','唐诗','tang','','[]','坦腹夫君不可逢，千年猶在播英風。',64,'全唐诗/poet.tang.39000.json','["坦腹夫君不可逢，千年猶在播英風。", "紅鵝化鶴青天遠，綵筆成龍綠水空。", "愛竹只應憐直節，書裙多是爲奇童。", "吹笙緱嶺登山後，東注清流豈有窮。"]'),
('4a35772d-80a6-40f4-a28d-abe2563f444a','溫陵即事','徐夤','唐','唐诗','tang','','[]','早年師友教爲文，賣却魚舟網典墳。',64,'全唐诗/poet.tang.39000.json','["早年師友教爲文，賣却魚舟網典墳。", "國有安危期日諫，家無擔石暫從軍。", "非才豈合攀丹桂，多病猶堪伴白雲。", "爭得千鍾季孫粟，滄洲歸與故人分。"]'),
('3d21c2ab-0e9f-4f59-a306-43f8330875d2','溫陵殘臘書懷寄崔尚書','徐夤','唐','唐诗','tang','','[]','濟川無楫擬何爲，三傑還從漢祖推。',66,'全唐诗/poet.tang.39000.json','["濟川無楫擬何爲，三傑還從漢祖推。", "心學庭槐空發火，鬢同門柳即垂絲。", "中興未遇先懷策，除夜相催也課[詩]。", "江上年年接君子，一杯春酒一枰棊。"]'),
('dbc61131-c76e-42d7-a5cd-bae9ea9c9ae0','義通里寓居即事','徐夤','唐','唐诗','tang','','[]','家住寒梅翠嶺東，長安時節詠途窮。',64,'全唐诗/poet.tang.39000.json','["家住寒梅翠嶺東，長安時節詠途窮。", "牡丹窠小春餘雨，楊柳絲疎夏足風。", "愁鬢已還年紀白，衰容寧藉酒杯紅。", "長卿甚有凌雲作，誰與清吟遶帝宮。"]'),
('878ddb03-de81-4a25-b806-0c2ad6e3778a','上陽宮詞','徐夤','唐','唐诗','tang','','[]','點點苔錢上玉墀，日斜空望六龍西。',64,'全唐诗/poet.tang.39000.json','["點點苔錢上玉墀，日斜空望六龍西。", "妝臺塵暗青鸞掩，宮樹月明黃鳥啼。", "庭草可憐分雨露，君恩深恨隔雲泥。", "銀蟾借與金波路，得入重輪伴羿妻。"]'),
('b509e742-e44e-485d-97a7-93de676e1afc','西寨寓居 一','徐夤','唐','唐诗','tang','','[]','閑讀南華對酒杯，醉攜筇竹畫蒼苔。',64,'全唐诗/poet.tang.39000.json','["閑讀南華對酒杯，醉攜筇竹畫蒼苔。", "豪門有利人爭去，陋巷無權客不來。", "解報可能醫病雀，重燃誰肯照寒灰。", "嚴陵萬古清風在，好櫂東溪詠釣臺。"]'),
('867c1506-8f35-484f-887d-85f6aaf71134','西寨寓居 二','徐夤','唐','唐诗','tang','','[]','功智爭馳澹薄空，猶懷忠信擬何從。',64,'全唐诗/poet.tang.39000.json','["功智爭馳澹薄空，猶懷忠信擬何從。", "鴟鳶啄腐疑雛鳳，神鬼欺貧笑伯龍。", "烈日不融雙鬢雪，病身全仰竹枝筇。", "崇侯入輔嚴陵退，堪憶啼猨萬仞峯。"]'),
('f0586535-efbf-4b52-8455-90e586bb5c5c','題福州天王閣','徐夤','唐','唐诗','tang','','[]','絕境宜棲獨角仙，金張到此亦忘還。',64,'全唐诗/poet.tang.39000.json','["絕境宜棲獨角仙，金張到此亦忘還。", "三門裏面千層閣，萬井中心一朵山。", "江拗碧灣盤洞府，石排青壁護禪關。", "有時海上看明月，輾出冰輪疊浪間。"]'),
('199b4541-4639-4288-9865-5d441e6cb43d','憶薦福寺南院','徐夤','唐','唐诗','tang','','[]','憶昔長安落第春，佛宮南院獨遊頻。',64,'全唐诗/poet.tang.39000.json','["憶昔長安落第春，佛宮南院獨遊頻。", "燈前不動惟金像，壁上曾題盡古人。", "鶗鴂聲中雙闕雨，牡丹花際六街塵。", "啼猨溪上將歸去，合問昇平詣秉鈞。"]'),
('9d1f04b5-77fd-4d68-8de6-4e0c8ab73c87','塔院小屋四壁皆是卿相題名因成四韻','徐夤','唐','唐诗','tang','','[]','雁塔攙空映九衢，每看華宇每踟躕。',64,'全唐诗/poet.tang.39000.json','["雁塔攙空映九衢，每看華宇每踟躕。", "題名盡是台衡迹，滿壁堪爲宰輔圖。", "鸞鳳豈巢荆棘樹，虬龍多蟄帝王都。", "誰知遠客思歸夢，夜夜無船自過湖。"]'),
('3e36c5e5-1b70-4526-99a5-ecb43cabe484','題名琉璃院','徐夤','唐','唐诗','tang','','[]','一條溪遶翠巖隈，行脚僧言勝五臺。',64,'全唐诗/poet.tang.39000.json','["一條溪遶翠巖隈，行脚僧言勝五臺。", "農罷樹陰黃犢臥，齋時山下白衣來。", "松因往日門人種，路是前生長老開。", "三卷貝多金粟語，可能長誦免輪迴。"]'),
('ef82e2b3-a58c-403b-be83-7adf4af8529b','寺中偶題','徐夤','唐','唐诗','tang','','[]','聽話金仙眉相毫，每來皆得解塵勞。',64,'全唐诗/poet.tang.39000.json','["聽話金仙眉相毫，每來皆得解塵勞。", "鶴棲雲路看方貴，僧倚松門見始高。", "名利罷燒心內火，雪霜偏垢鬢邊毛。", "銀蟾未出金烏在，更上層樓眺海濤。"]'),
('78bcfba7-e85c-4092-8b7a-387f26b4a072','山寺寓居','徐夤','唐','唐诗','tang','','[]','高臥東林最上方，水聲山翠剔愁腸。',64,'全唐诗/poet.tang.39000.json','["高臥東林最上方，水聲山翠剔愁腸。", "白雲送雨籠僧閣，黃葉隨風入客堂。", "終去四明成大道，暫從雙鬢許秋霜。", "披緇學佛應無分，鶴氅談空亦不妨。"]'),
('e10ced72-23f6-43c4-80c9-e0b38766dacb','寄僧寓題','徐夤','唐','唐诗','tang','','[]','佛頂抄經憶惠休，衆人皆謂我悠悠。',64,'全唐诗/poet.tang.39000.json','["佛頂抄經憶惠休，衆人皆謂我悠悠。", "浮生真箇醉中夢，閑事莫添身外愁。", "百歲付于花暗落，四時隨却水奔流。", "安眠靜笑思何報，日夜焚修祝郡侯。"]'),
('3cc0e6ce-b1b7-4563-ad88-bf2ffcc2a98c','游靈隱天竺二寺','徐夤','唐','唐诗','tang','','[]','丹井冷泉虛易到，兩山真界實難名。',64,'全唐诗/poet.tang.39000.json','["丹井冷泉虛易到，兩山真界實難名。", "石和雲霧蓮華氣，月過樓臺桂子清。", "騰踏回橋巡像設，羅穿曲洞出龍成。", "更憐童子呼猿去，颯颯蕭蕭下樹行。"]'),
('25c0f378-00fb-4883-acc7-fe326c7fa02d','醉題邑宰南塘屋壁','徐夤','唐','唐诗','tang','','["\u9ec4\u6cb3"]','萬古清淮照遠天，黃河濁浪不相關。',64,'全唐诗/poet.tang.39000.json','["萬古清淮照遠天，黃河濁浪不相關。", "縣留東道三千客，宅鎖南塘一片山。", "草色淨經秋雨綠，燒痕寒入曉窗斑。", "閩王美錦求賢製，未許陶公解印還。"]'),
('24694808-e097-4d8e-93aa-702bb937fe05','題泗洲塔','徐夤','唐','唐诗','tang','','[]','十年前事已悠哉，旋被鐘聲早暮催。',64,'全唐诗/poet.tang.39000.json','["十年前事已悠哉，旋被鐘聲早暮催。", "明月似師生又沒，白雲如客去還來。", "煙籠瑞閣僧經靜，風打虛窗佛幌開。", "惟有南邊山色在，重重依舊上高臺。"]'),
('6b953594-f83c-4d53-bf31-b92964be303b','東歸題屋壁','徐夤','唐','唐诗','tang','','[]','塵埃歸去五湖東，還是衡門一畝宮。',64,'全唐诗/poet.tang.39000.json','["塵埃歸去五湖東，還是衡門一畝宮。", "舊業旋從征賦失，故人多逐亂離空。", "因悲盡室如懸罄，却擬攜家學轉蓬。", "見說武王天上夢，無情曾與傅岩通。"]'),
('c53bbead-5457-40ab-b7ef-e0fa3a0e002b','寓題','徐夤','唐','唐诗','tang','','[]','酒壺棋局似閑人，竹笏藍衫老此身。',64,'全唐诗/poet.tang.39000.json','["酒壺棋局似閑人，竹笏藍衫老此身。", "託客買書重得卷，愛山移宅近爲鄰。", "鳴蛩閣上風吹病，落葉庭中月照貧。", "見說天池波浪闊，也應涓滴濺窮鱗。"]'),
('269d6946-b825-4664-a402-c2b617ac75de','偶題','徐夤','唐','唐诗','tang','','[]','閑補亡書見廢興，偶然前古也填膺。',64,'全唐诗/poet.tang.39000.json','["閑補亡書見廢興，偶然前古也填膺。", "秦宮猶自拜張祿，楚幕不知留范增。", "大道豈全關曆數，雄圖強半屬賢能。", "燕臺財力知多少，誰築黃金到九層。"]'),
('dd94dc9b-07fa-4e9a-8e10-6c00d40ec320','寓題述懷','徐夤','唐','唐诗','tang','','[]','大道真風早晚還，妖訛成俗汙乾坤。',64,'全唐诗/poet.tang.39000.json','["大道真風早晚還，妖訛成俗汙乾坤。", "宣尼既沒蘇張起，鳳鳥不來雞雀喧。", "芻少可能供驥子，草多誰復訪蘭蓀。", "堯廷忘却徴元凱，天闕重關十二門。"]'),
('2a0a0754-e046-4601-82fc-7d7a6ecec3d1','將入城靈口道中作','徐夤','唐','唐诗','tang','','[]','路上長安惟咫尺，灞陵西望接秦源。',64,'全唐诗/poet.tang.39000.json','["路上長安惟咫尺，灞陵西望接秦源。", "依稀日下分天闕，隱映雲邊是國門。", "錦袖臂鷹河北客，青桑鳴雉渭南村。", "高風九萬程途近，與報滄洲欲化鯤。"]'),
('0c592f0a-9a96-4b1d-8cd7-e26530c21100','新屋','徐夤','唐','唐诗','tang','','[]','耳順何爲土木勤，叔孫牆屋有前聞。',64,'全唐诗/poet.tang.39000.json','["耳順何爲土木勤，叔孫牆屋有前聞。", "縱然一世如紅葉，猶得十年吟白雲。", "性逸且圖稱野客，才難非敢傲明君。", "清甜數尺沙泉井，平與鄰家晝夜分。"]'),
('31773437-9b6c-41a4-900c-a1de4f30b06f','新葺茆堂 一','徐夤','唐','唐诗','tang','','[]','翦竹誅茆就水濱，靜中還得保天真。',64,'全唐诗/poet.tang.39000.json','["翦竹誅茆就水濱，靜中還得保天真。", "只聞神鬼害盈滿，不見古今爭賤貧。", "樹影便爲廊廡屋，草香權當綺羅茵。", "堦前一片泓澄水，借與汀禽活紫鱗。"]'),
('4b38eb2c-07f2-4c81-a519-72c5c329ca3c','新葺茆堂 二','徐夤','唐','唐诗','tang','','[]','耨水耕山息故林，壯圖嘉話負前心。',64,'全唐诗/poet.tang.39000.json','["耨水耕山息故林，壯圖嘉話負前心。", "素絲鬢上分愁色，絡緯牀頭和苦吟。", "筆研不才當付火，方書多誑罷燒金。", "同年二十八君子，遊楚遊秦斷好音。"]'),
('063991b4-455d-4ebe-8378-0dc051da3050','茆亭','徐夤','唐','唐诗','tang','','[]','鴛瓦虹梁計已疎，織茅編竹稱貧居。',64,'全唐诗/poet.tang.39000.json','["鴛瓦虹梁計已疎，織茅編竹稱貧居。", "翦平恰似山僧笠，掃靜真同道者廬。", "秋晚捲簾看過雁，月明憑檻數跳魚。", "重門公子應相笑，四壁風霜老讀書。"]'),
('ec34f784-d237-4b08-bc9a-c9f0e27d06ac','客廳','徐夤','唐','唐诗','tang','','[]','移却松筠致客堂，淨泥環堵貯荷香。',64,'全唐诗/poet.tang.39000.json','["移却松筠致客堂，淨泥環堵貯荷香。", "衡茅只要免風雨，藻梲不須高棟梁。", "豐蔀仲尼明演易，作歌五子恨雕牆。", "燕臺漢閣王侯事，青史千年播耿光。"]'),
('da0c9dfa-cfdc-4701-ae32-7b1acd002659','詠寫真','徐夤','唐','唐诗','tang','','[]','寫得衰容似十全，閑開僧舍靜時懸。',64,'全唐诗/poet.tang.39000.json','["寫得衰容似十全，閑開僧舍靜時懸。", "瘦于南國從軍日，老却東堂射策年。", "潭底看身寧有異，鏡中引影更無偏。", "借將前輩真儀比，未愧金鑾李謫仙。"]'),
('378c18a9-f8f7-41ee-ad31-cb4fb9cae5ba','放榜日','徐夤','唐','唐诗','tang','','[]','喧喧車馬欲朝天，人探東堂榜已懸。',64,'全唐诗/poet.tang.39000.json','["喧喧車馬欲朝天，人探東堂榜已懸。", "萬里便隨金鸑鷟，三台仍借玉連錢。", "花浮酒影彤霞爛，日照衫光瑞色鮮。", "十二街前樓閣上，卷簾誰不看神仙。"]'),
('aa151c98-47ec-43b0-b5db-7eddcc7152bd','曲江宴日呈諸同年','徐夤','唐','唐诗','tang','','[]','鷦鷯驚與鳳皇同，忽向中興遇至公。',64,'全唐诗/poet.tang.39000.json','["鷦鷯驚與鳳皇同，忽向中興遇至公。", "金榜連名昇碧落，紫花封勅出瓊宮。", "天知惜日遲遲暮，春爲催花旋旋紅。", "好是慈恩題了望，白雲飛盡塔連空。"]'),
('7228cdd0-1804-47b8-866d-ab052ebede04','渤海賓貢高元固先輩閩中相訪云本國人寫得夤斬蛇劍御溝水人生幾何賦家皆以金書列爲屏障因而有贈','徐夤','唐','唐诗','tang','','[]','折桂何年下月中，閩山來問我雕蟲。',64,'全唐诗/poet.tang.39000.json','["折桂何年下月中，閩山來問我雕蟲。", "肯銷金翠書屏上，誰把芻蕘過日東。", "郯子昔時遭孔聖，繇余往代諷秦宮。", "嗟嗟大國金門士，幾個人能振素風。"]'),
('3b70b6be-fd22-4502-be04-24a0a22fcbf9','偶吟','徐夤','唐','唐诗','tang','','[]','千卷長書萬首詩，朝蒸藜藿暮烹葵。',64,'全唐诗/poet.tang.39000.json','["千卷長書萬首詩，朝蒸藜藿暮烹葵。", "清時名立難皆我，晚歲途窮亦問誰。", "碧岸釣歸惟獨笑，青山耕徧亦何爲。", "尋常抖擻懷中策，可便降他兩鬢絲。"]'),
('3b20cb5b-a414-458c-87a4-aef3132f6788','贈表弟黃校書輅','徐夤','唐','唐诗','tang','','[]','產破身窮爲學儒，我家諸表愛詩書。',64,'全唐诗/poet.tang.39000.json','["產破身窮爲學儒，我家諸表愛詩書。", "嚴陵雖說臨溪隱，晏子還聞近市居。", "佳句麗偷紅菡萏，吟窗冷落白蟾蜍。", "閑來共話無生理，今古悠悠事總虛。"]'),
('a70a51da-5d7b-40cc-911e-cc8560ec284d','輦下贈屯田何員外','徐夤','唐','唐诗','tang','','[]','封章頻得帝咨嗟，報國唯將直破邪。',64,'全唐诗/poet.tang.39000.json','["封章頻得帝咨嗟，報國唯將直破邪。", "身到西山書幾達，官登南省鬢初華。", "廚非寒食還無火，菊待重陽擬泛茶。", "內翰好才兼好古，秋來應數到君家。"]'),
('8a5f05c1-2b26-46a3-b8df-c5bd3d67aed4','贈月君','徐夤','唐','唐诗','tang','','[]','出水蓮花比性靈，三生塵夢一時醒。',64,'全唐诗/poet.tang.39000.json','["出水蓮花比性靈，三生塵夢一時醒。", "神傳尊勝陀羅咒，佛授金剛般若經。", "懿德好書添女誡，素容堪畫上銀屏。", "鳴梭軋軋纖纖手，窗戶流光織女星。"]'),
('e2f567eb-2afa-4e62-b01d-f34bcb64db76','贈垂光同年','徐夤','唐','唐诗','tang','','[]','丹桂攀來十七春，如今始見茜袍新。',64,'全唐诗/poet.tang.39000.json','["丹桂攀來十七春，如今始見茜袍新。", "須知紅杏園中客，終作金鑾殿裏臣。", "逸少家風惟筆札，玄成世業是陶鈞。", "他時黃閣朝元處，莫忘同年射策人。"]'),
('7bd5bbf9-71de-455f-843b-763270f3b781','贈楊著','徐夤','唐','唐诗','tang','','[]','藻麗熒煌冠士林，白華榮養有曾參。',64,'全唐诗/poet.tang.39000.json','["藻麗熒煌冠士林，白華榮養有曾參。", "十年去里荆門改，八歲能詩相座吟。", "李廣不侯身漸老，子山操賦恨何深。", "釣魚臺上頻相訪，共說長安淚滿襟。"]'),
('7cba6322-fb6e-4282-ae0a-39a35f8f0761','贈黃校書先輩璞閑居','徐夤','唐','唐诗','tang','','[]','馭得驪龍第四珠，退依僧寺卜貧居。',64,'全唐诗/poet.tang.39000.json','["馭得驪龍第四珠，退依僧寺卜貧居。", "青山入眼不干祿，白髮滿頭猶著書。", "東澗野香添碧沼，南園夜雨長秋蔬。", "月明掃石吟詩坐，諱却全無儋石儲。"]'),
('79932791-0698-4671-b01b-9dd4ebdf24e3','尚書榮拜恩命夤疾中輙課惡詩二首以申攀讚 一','徐夤','唐','唐诗','tang','','[]','明公家鑿鳳皇池，弱冠封侯四海推。',64,'全唐诗/poet.tang.39000.json','["明公家鑿鳳皇池，弱冠封侯四海推。", "富貴有期天授早，關河多難勅來遲。", "昴星人傑當王佐，黃石仙翁識帝師。", "昨日詔書猶漏缺，未言商也最能詩。"]'),
('a4066c46-b92e-4fa2-9b28-2b1b539d4110','尚書榮拜恩命夤疾中輙課惡詩二首以申攀讚 二','徐夤','唐','唐诗','tang','','[]','東郊迎入紫泥封，此日天仙下九重。',64,'全唐诗/poet.tang.39000.json','["東郊迎入紫泥封，此日天仙下九重。", "三五月明臨闞澤，百千人衆看王恭。", "旗傍綠樹遙分影，馬蹋浮雲不見蹤。", "借問乘軺何處客，相庭雄幕卷芙蓉。"]'),
('c8384058-ed16-4f24-9d49-d50d652b9a64','府主僕射王[摶]生日','徐夤','唐','唐诗','tang','','[]','熊羆先兆慶垂休，天地氤氳瑞氣浮。',64,'全唐诗/poet.tang.39000.json','["熊羆先兆慶垂休，天地氤氳瑞氣浮。", "李樹影籠周柱史，昴星光照漢酇侯。", "數鍾龜鶴千年算，律正乾坤八月秋。", "勳業定應歸鼎鼐，生靈豈獨化東甌。"]'),
('ed4450d9-d7ec-49c3-b278-06bf94028db8','獻內翰楊侍郎','徐夤','唐','唐诗','tang','','[]','窗開青瑣見瑤臺，冷拂星辰逼上台。',64,'全唐诗/poet.tang.39000.json','["窗開青瑣見瑤臺，冷拂星辰逼上台。", "丹鳳詔成中使取，白龍香近聖君來。", "欲言溫署三緘口，閑賦宮詞八斗才。", "莫擬吟雲避榮貴，廟堂玉鉉待鹽梅。"]'),
('b63f9cc0-4dee-4de8-bb11-ec4863fe2682','送劉常侍','徐夤','唐','唐诗','tang','','[]','懷君何計更留連，忍送文星上碧天。',64,'全唐诗/poet.tang.39000.json','["懷君何計更留連，忍送文星上碧天。", "杜預注通三十卷，漢皇枝紹幾千年。", "言端信義如明月，筆下篇章似湧泉。", "他日有書隨雁足，東溪無令訪漁船。"]'),
('145c2908-93f9-48ac-a1a2-6d626e253a30','送盧拾遺歸華山','徐夤','唐','唐诗','tang','','[]','紫殿諫多防佞口，清秋假滿別明君。',64,'全唐诗/poet.tang.39000.json','["紫殿諫多防佞口，清秋假滿別明君。", "惟憂急詔歸青瑣，不得經時臥白雲。", "千載茯苓攜鶴斸，一峰仙掌與僧分。", "門前舊客期相薦，猶望飛書及主文。"]'),
('a13f6163-3ba5-4a55-8254-46396a0b249b','春末道陳先輩之清源','徐夤','唐','唐诗','tang','','[]','貧中惟是長年華，每羨君行自嘆嗟。',64,'全唐诗/poet.tang.39000.json','["貧中惟是長年華，每羨君行自嘆嗟。", "歸日捧持明月寶，去時期刻刺桐花。", "春風避酒多游寺，曉騎聽雞早入衙。", "千乘侯王若相問，飛書與報白雲家。"]'),
('6880baf7-81bd-4134-bf2d-554af414cf65','上盧三拾遺以言見黜','徐夤','唐','唐诗','tang','','[]','骨鯁如君道尚存，近來人事不須論。',64,'全唐诗/poet.tang.39000.json','["骨鯁如君道尚存，近來人事不須論。", "疾危必厭神明藥，心惑多嫌正直言。", "冷眼靜看真好笑，傾懷與說却爲冤。", "因思周廟當時誡，金口三緘示後昆。"]'),
('c4d7a5bd-54a8-41a1-8a51-6c25abf677bb','送王校書往清源','徐夤','唐','唐诗','tang','','[]','南國賢侯待德風，長途仍借九花驄。',66,'全唐诗/poet.tang.39000.json','["南國賢侯待德風，長途仍借九花驄。", "清歌早貫驪龍[頷]，丹桂曾攀玉兔宮。", "楊柳堤邊梅雨熟，鷓鴣聲裏麥田空。", "吟詩臺上如相問，與說蟠溪直釣翁。"]'),
('6925574e-9548-4808-be6d-574cd2708b56','岳州端午日送人游郴連','徐夤','唐','唐诗','tang','','[]','五月巴陵值積陰，送君千里客于郴。',64,'全唐诗/poet.tang.39000.json','["五月巴陵值積陰，送君千里客于郴。", "北風吹雨黃梅落，西日過湖青草深。", "競渡岸傍人挂錦，採芳城上女遺簪。", "九嶷雲闊蒼梧暗，與說重華舊德音。"]'),
('e4f93697-8213-41c7-b8d9-f8a519994305','賀清源太保王延[彬] 一','徐夤','唐','唐诗','tang','','[]','蘂珠宮裏謫神仙，八載溫陵萬戶閑。',64,'全唐诗/poet.tang.39000.json','["蘂珠宮裏謫神仙，八載溫陵萬戶閑。", "心地闊于雲夢澤，官資高却太行山。", "姜牙兆寄熊羆內，陶侃文成掌握間。", "應笑清溪舊門吏，年年扶病掩柴關。"]'),
('82e9575f-1a4e-4777-9bc7-3c7fa084434d','賀清源太保王延[彬] 二','徐夤','唐','唐诗','tang','','[]','武榮江畔蔭祥雲，寵拜天人慶郡人。',64,'全唐诗/poet.tang.39000.json','["武榮江畔蔭祥雲，寵拜天人慶郡人。", "五色鶴綾花上勅，九霄龍尾道邊臣。", "英雄達處誰言命，富貴來時自逼身。", "更待春風飛吉語，紫泥分付與陶鈞。"]'),
('691e4775-8ccb-4b71-84ff-82ac1c4da4f5','病中春日即事寄主人尚書二首 一','徐夤','唐','唐诗','tang','','[]','身比秋荷覺漸枯，至君經國墮前圖。',64,'全唐诗/poet.tang.39000.json','["身比秋荷覺漸枯，至君經國墮前圖。", "層冰照日猶能暖，病骨逢春却未蘇。", "鏡裏白鬚撏又長，枝頭黃鳥靜還呼。", "庾樓恩化通神聖，何計能教擲得盧。"]'),
('9926ddbe-74ff-4a59-b126-d782ef439de4','病中春日即事寄主人尚書二首 二','徐夤','唐','唐诗','tang','','[]','風拍衰肌久未蠲，破窗頻見月團圓。',64,'全唐诗/poet.tang.39000.json','["風拍衰肌久未蠲，破窗頻見月團圓。", "更無舊日同人問，只有多情太守憐。", "臘內送將三折股，歲陰分與五銖錢。", "玄穹若假年齡在，願捧銅盤爲國賢。"]'),
('bd847855-f80b-4f29-88b3-b678f619dd69','寄華山司空侍郎二首 一','徐夤','唐','唐诗','tang','','[]','金闕爭權競獻功，獨逃徴詔臥三峰。',64,'全唐诗/poet.tang.39000.json','["金闕爭權競獻功，獨逃徴詔臥三峰。", "雞羣未必容於鶴，蛛網何繇捕得龍。", "清論盡應書國史，靜籌皆可息邊烽。", "風霜落滿千林木，不近青青澗底松。"]'),
('c6131114-b8b0-459d-a9d4-6007440ed2db','寄華山司空侍郎二首 二','徐夤','唐','唐诗','tang','','[]','非雲非鶴不從容，誰敢輕量傲世蹤。',64,'全唐诗/poet.tang.39000.json','["非雲非鶴不從容，誰敢輕量傲世蹤。", "紫殿幾徴王佐業，青山未拆詔書封。", "閑吟每待秋空月，早起長先野寺鐘。", "前古負材多爲國，滿懷經濟欲何從。"]'),
('310c8e8a-2a0b-4496-afdf-914008e3c797','寄盧端公同年仁烱時遷都洛陽新立幼主','徐夤','唐','唐诗','tang','','[]','上陽宮闕翠華歸，百辟傷心序漢儀。',64,'全唐诗/poet.tang.39000.json','["上陽宮闕翠華歸，百辟傷心序漢儀。", "崑岳有炎瓊玉碎，洛川無竹鳳皇飢。", "須簪白筆匡明主，莫許黃㼐博少師。", "惆悵宸居遠于日，長吁空摘鬢邊絲。"]'),
('655f7202-fcaa-4f14-8546-d219efba6dcb','寄天台陳希畋','徐夤','唐','唐诗','tang','','[]','陰山冰凍嘗迎夏，蟄戶雲雷只待春。',64,'全唐诗/poet.tang.39000.json','["陰山冰凍嘗迎夏，蟄戶雲雷只待春。", "呂望豈嫌垂釣老，西施不恨浣紗貧。", "坐爲羽獵車中相，飛作君王掌上身。", "拍手相思惟大笑，我曹寧比等閑人。"]'),
('f8759348-e486-4e64-a088-413bb15e481b','寄兩浙羅書記','徐夤','唐','唐诗','tang','','[]','進即湮沈退却升，錢塘風月過金陵。',64,'全唐诗/poet.tang.39000.json','["進即湮沈退却升，錢塘風月過金陵。", "鴻才入貢無人換，白首從軍有詔徴。", "博簿集成時輩駡，讒書編就薄徒憎。", "憐君道在名長在，不到慈恩最上層。"]'),
('2f3128b3-622e-4e75-848f-82188348ff7d','邑宰相訪翼日有寄','徐夤','唐','唐诗','tang','','[]','淵明深念郤詵貧，踏破莓苔看甑塵。',64,'全唐诗/poet.tang.39000.json','["淵明深念郤詵貧，踏破莓苔看甑塵。", "碧沼共攀紅菡萏，金鞍不卸紫麒麟。", "殘陽妬害催歸客，薄酒甘嘗罰主人。", "夜半夢醒追復想，欲長攀接有何因。"]'),
('feaf2a35-a756-4a8d-a6cd-0e673c9e3a9f','白酒兩瓶送崔侍御','徐夤','唐','唐诗','tang','','[]','雪化霜融好潑醅，滿壺冰凍向春開。',64,'全唐诗/poet.tang.39000.json','["雪化霜融好潑醅，滿壺冰凍向春開。", "求從白石洞中得，攜向百花巖畔來。", "幾夕露珠寒貝齒，一泓銀水冷瓊杯。", "湖邊送與崔夫子，誰見嵇山盡日頹。"]'),
('93be9b41-f876-4516-ab2a-e9b29cb39505','依韻酬常循州','徐夤','唐','唐诗','tang','','[]','早年花縣拜潘郎，尋忝飛鳴出桂堂。',64,'全唐诗/poet.tang.39000.json','["早年花縣拜潘郎，尋忝飛鳴出桂堂。", "日走登天長似箭，人同紅樹豈經霜。", "帆分南浦知離別，駕在東州更可傷。", "公論一麾將塞詔，且隨徴令過瀟湘。"]'),
('7af43a17-25bc-4308-832c-5ac0fb99483c','謝主人惠綠酒白魚','徐夤','唐','唐诗','tang','','[]','早起雀聲送喜頻，白魚芳酒寄來珍。',64,'全唐诗/poet.tang.39000.json','["早起雀聲送喜頻，白魚芳酒寄來珍。", "馨香乍揭春風甕，撥刺初辭夜雨津。", "樽闊最宜澄桂液，網疎殊未損霜鱗。", "不曾垂釣兼親醞，堪愧金臺醉飽身。"]'),
('06cc25ec-bdbd-441e-86e0-d424d86f8ed2','蜀','徐夤','唐','唐诗','tang','','[]','雖倚關張敵萬夫，豈勝恩信作良圖。',64,'全唐诗/poet.tang.39000.json','["雖倚關張敵萬夫，豈勝恩信作良圖。", "能均漢祚三分業，不負荆州六尺孤。", "綠水有魚賢已得，青桑如蓋瑞先符。", "君王幸是中山後，建國如何號蜀都。"]'),
('6ad91f5b-a9dc-4986-a754-11cb52d17c38','魏','徐夤','唐','唐诗','tang','','[]','伐罪書勳令不常，爭教爲帝與爲王。',64,'全唐诗/poet.tang.39000.json','["伐罪書勳令不常，爭教爲帝與爲王。", "十年小怨誅桓邵，一檄深讐怨孔璋。", "在井蟄龍如屈伏，食槽驕馬忽騰驤。", "姦雄事過分明見，英識空懷許子將。"]'),
('d079073b-2d39-4817-b0f3-5c554bf1bf72','吳','徐夤','唐','唐诗','tang','','[]','一主參差六十年，父兄猶慶授孫權。',64,'全唐诗/poet.tang.39000.json','["一主參差六十年，父兄猶慶授孫權。", "不迎曹操真長策，終謝張昭見碩賢。", "建業龍盤雖可貴，武昌魚味亦何偏。", "秦嬴謾作東遊計，紫氣黃旗豈偶然。"]'),
('f540c53c-1df2-4e3f-832e-2790f1c5c0ba','兩晉','徐夤','唐','唐诗','tang','','[]','三世深謀啓帝基，可憐孀婦與孤兒。',64,'全唐诗/poet.tang.39000.json','["三世深謀啓帝基，可憐孀婦與孤兒。", "罪歸成濟皇天恨，戈犯明君萬古悲。", "巴蜀削平輕似紙，勾吳吞却美如飴。", "誰知高鼻能知數，競向中原簸戰旗。"]'),
('ec748d17-d6b4-4468-b1ac-901c32d34367','宋二首 一','徐夤','唐','唐诗','tang','','[]','天爵休將儋石論，一身恭儉萬邦尊。',64,'全唐诗/poet.tang.39000.json','["天爵休將儋石論，一身恭儉萬邦尊。", "賭將金帶驚寰海，留得耕衣誡子孫。", "締構不應饒漢祖，姦雄何足數王敦。", "草中求活非吾事，豈啻橫身向廟門。"]'),
('9fcdc4cc-bb31-4cff-913c-82e027f02499','宋二首 二','徐夤','唐','唐诗','tang','','[]','百萬人甘一擲輸，玄穹惟與道相符。',64,'全唐诗/poet.tang.39000.json','["百萬人甘一擲輸，玄穹惟與道相符。", "豈知紫殿新天子，只是丹徒舊嗇夫。", "五色龍章身早見，六終鴻業數難逾。", "三年未得分明夢，却爲蘭陵起霸圖。"]'),
('3ff4980a-2ff4-44e3-b5b9-94285e74de58','陳','徐夤','唐','唐诗','tang','','[]','三惑昏昏中紫宸，萬機拋却醉臨春。',64,'全唐诗/poet.tang.39000.json','["三惑昏昏中紫宸，萬機拋却醉臨春。", "書中不禮隋文帝，井底常攜張貴嬪。", "玉樹歌聲移入哭，金陵天子化爲臣。", "兵戈半渡前江水，狎客猶聞爭酒巡。"]'),
('3327382d-1056-4ba1-9dec-2e89f8974855','讀史','徐夤','唐','唐诗','tang','','["\u9ec4\u6cb3"]','亞父淒涼別楚營，天留三傑翼龍爭。',64,'全唐诗/poet.tang.39000.json','["亞父淒涼別楚營，天留三傑翼龍爭。", "高才無主不能用，直道有時方始平。", "喜慍子文何頴悟，卷藏蘧瑗甚分明。", "須知飲啄繇天命，休問黃河早晚清。"]'),
('f55363ac-175b-45f9-b69c-00b0331576ef','漢宮新寵','徐夤','唐','唐诗','tang','','[]','位在嬪妃最上頭，笑他長信女悲秋。',64,'全唐诗/poet.tang.39000.json','["位在嬪妃最上頭，笑他長信女悲秋。", "日中月滿可能久，花落色衰殊未憂。", "公主鏡中爭翠羽，君王袖底奪金鉤。", "妾家兄弟知多少，恰要同時拜列侯。"]'),
('1c838ef9-5f85-4449-94b2-0054b8ba57d1','開元即事','徐夤','唐','唐诗','tang','','[]','曲江真宰國中訛，尋奏漁陽忽荷戈。',64,'全唐诗/poet.tang.39000.json','["曲江真宰國中訛，尋奏漁陽忽荷戈。", "堂上有兵天不用，幄中無策印空多。", "塵驚騎透潼關鎖，雲護龍遊渭水波。", "未必蛾眉能破國，千秋休恨馬嵬坡。"]'),
('4b708015-b661-4296-954d-339e15b3bfec','李翰林','徐夤','唐','唐诗','tang','','[]','謫下三清列八仙，獲調羹鼎侍龍顏。',64,'全唐诗/poet.tang.39000.json','["謫下三清列八仙，獲調羹鼎侍龍顏。", "吟開鎖闥窺天近，醉臥金鑾待詔閑。", "舊隱不歸劉備國，旅魂長寄謝公山。", "遺編往簡應飛去，散入祥雲瑞日間。"]'),
('bec1c179-ce28-4797-baad-032a75164879','聞長安庚子歲事','徐夤','唐','唐诗','tang','','[]','羽檄交馳觸冕旒，函關飛入鐵兜鍪。',64,'全唐诗/poet.tang.39000.json','["羽檄交馳觸冕旒，函關飛入鐵兜鍪。", "皇王去國未爲恨，寰海失君方是憂。", "五色大雲凝蜀郡，幾般妖氣撲神州。", "唐堯縱禪乾坤位，不是重華莫謾求。"]'),
('2f8dacd2-59f5-4218-8635-0f1ae67612e6','公子行','徐夤','唐','唐诗','tang','','[]','十五轅門學控弦，六街騎馬去如煙。',64,'全唐诗/poet.tang.39000.json','["十五轅門學控弦，六街騎馬去如煙。", "金多倍著牡丹價，髮白未知章甫賢。", "有耳不聞經國事，拜官方買謝恩箋。", "相如謾說凌雲賦，四壁何曾有一錢。"]'),
('25554349-d0a1-43f8-afde-6c4e8ff4a1cc','依韻贈嚴司直','徐夤','唐','唐诗','tang','','[]','曾轉雙蓬到玉京，宣尼恩奏樂卿名。',64,'全唐诗/poet.tang.39000.json','["曾轉雙蓬到玉京，宣尼恩奏樂卿名。", "歌殘白石扣牛角，賦換黃金愛馬卿。", "滄海二隅身漸老，太行千疊路難行。", "夫君才大官何小，堪恨人間事不平。"]'),
('9e21988a-b05a-4077-b07c-9787e423c17c','傷前翰林楊左丞','徐夤','唐','唐诗','tang','','[]','飛上鰲頭侍玉皇，三台遺耀換餘光。',64,'全唐诗/poet.tang.39000.json','["飛上鰲頭侍玉皇，三台遺耀換餘光。", "人間搦管窮蒼頡，地上修文待卜商。", "真魄肯隨金石化，真風留伴蕙蘭香。", "皇天未啓昇平運，不使伊臯相禹湯。"]'),
('3ad258f6-8437-4742-a5ce-33e9079758c6','日月無情','徐夤','唐','唐诗','tang','','[]','日月無情也有情，朝昇夕沒照均平。',64,'全唐诗/poet.tang.39000.json','["日月無情也有情，朝昇夕沒照均平。", "雖催前代英雄死，還促後來賢聖生。", "三尺靈烏金借耀，一輪飛鏡水饒清。", "憑誰築斷東溟路，龍影蟬光免運行。"]'),
('ec045964-fdc5-49d2-bef1-a9a613d8cd48','新月','徐夤','唐','唐诗','tang','','[]','雲際[嬋娟]出又藏，美人腸斷拜金方。',66,'全唐诗/poet.tang.39000.json','["雲際[嬋娟]出又藏，美人腸斷拜金方。", "姮娥一隻眉先掃，織女三分鏡未光。", "珠箔寄鉤懸杳靄，白龍遺爪印穹蒼。", "更期十五圓明夜，與破陰霾照八荒。"]'),
('29efd110-184b-4974-8912-6695f7f72de9','和尚書詠煙','徐夤','唐','唐诗','tang','','[]','無根無蒂結還融，曾觸嵐光徹底空。',64,'全唐诗/poet.tang.39000.json','["無根無蒂結還融，曾觸嵐光徹底空。", "不散幾知離畢雨，欲飛須待落花風。", "玲瓏薄展蛟綃片，羃歷輕含鳳竹叢。", "瓊什捧來思舊隱，撲窗穿戶曉溟濛。"]'),
('606be72f-bce4-41ca-82bc-f5d85bfeb157','宮鸎','徐夤','唐','唐诗','tang','','[]','領得春光在帝家，早從深谷出煙霞。',64,'全唐诗/poet.tang.39000.json','["領得春光在帝家，早從深谷出煙霞。", "閑棲仙禁日邊柳，飢啄御園天上花。", "睍睆只宜陪閣鳳，間關多是問宮娃。", "可憐鸚鵡矜言語，長閉雕籠歲月賒。"]'),
('445ee2a7-ae62-490b-b15e-05a69677c43e','鬢髮','徐夤','唐','唐诗','tang','','[]','鬢添華髮數莖新，羅雀門前絕故人。',64,'全唐诗/poet.tang.39000.json','["鬢添華髮數莖新，羅雀門前絕故人。", "減食爲緣疎五味，不眠非是守庚申。", "深園竹綠齊抽笋，古木蛇青自脫鱗。", "天地有鑪長鑄物，濁泥遺塊待陶鈞。"]'),
('e6a5f083-adbe-4813-b767-e3704fde3422','春入鯉湖','徐夤','唐','唐诗','tang','','[]','到來峭壁白雲齊，載酒春遊渡九溪。',64,'全唐诗/poet.tang.39000.json','["到來峭壁白雲齊，載酒春遊渡九溪。", "鐵嶂有樓霾欲墮，石門無鎖路還迷。", "湖頭鯉去轟雷在，樹杪猨啼落日低。", "回首浮生真幻夢，何如斯地傍幽棲。"]'),
('87957990-cfc7-4b03-8ba8-ff9ecd8b2566','雙鷺','徐夤','唐','唐诗','tang','','[]','雙鷺雕籠昨夜開，月明飛出立庭隈。',64,'全唐诗/poet.tang.39000.json','["雙鷺雕籠昨夜開，月明飛出立庭隈。", "但教綠水池塘在，自有碧天鴻雁來。", "清韻叫霜歸島樹，素翎遺雪落漁臺。", "何人爲我追尋得，重勸溪翁酒一桮。"]'),
('e48ea0e0-363a-47ea-ac23-941854a558cb','鷓鴣','徐夤','唐','唐诗','tang','','[]','繡僕梅兼羽翼全，楚雞非瑞莫爭先。',64,'全唐诗/poet.tang.39000.json','["繡僕梅兼羽翼全，楚雞非瑞莫爭先。", "啼歸明月落邊樹，飛入百花深處煙。", "避燒幾曾遺遠岫，引雛時見飲晴川。", "茘枝初熟無人際，啄破紅苞墜野田。"]'),
('4d0a5204-9f81-4192-a320-dc95cdae4b08','鷹','徐夤','唐','唐诗','tang','','[]','害物傷生性豈馴，且宜籠罩待知人。',64,'全唐诗/poet.tang.39000.json','["害物傷生性豈馴，且宜籠罩待知人。", "惟擒燕雀啗腥血，却笑鸞皇啄翠筠。", "狡兔穴多非爾識，鳴鳩脰短罰君身。", "豪門不讀詩書者，走馬平原放翫頻。"]'),
('30a199ac-e508-46c2-b3ed-ecbcda4e4d81','晦日宴高氏林亭','陳嘉言','唐','唐诗','tang','','[]','公子申敬愛，攜朋翫物華。',48,'全唐诗/poet.tang.4000.json','["公子申敬愛，攜朋翫物華。", "人是平陽客，地即石崇家。", "水文生舊浦，風色滿新花。", "日暮連歸騎，長川照晚霞。"]'),
('d3098b52-2a7b-4e81-9afc-af4f6ed53817','晦日重宴','陳嘉言','唐','唐诗','tang','','[]','高門引冠蓋，下客抱支離。',48,'全唐诗/poet.tang.4000.json','["高門引冠蓋，下客抱支離。", "綺席珍羞滿，文場翰藻摛。", "蓂華彫上月，柳色藹春池。", "日斜歸戚里，連騎勒金羈。"]'),
('fb0abe69-b0e5-40d9-a852-5bddc6c38abf','上元夜效小庾體','陳嘉言','唐','唐诗','tang','','[]','今夜可憐春，河橋多麗人。',48,'全唐诗/poet.tang.4000.json','["今夜可憐春，河橋多麗人。", "寶馬金爲絡，香車玉作輪。", "連手窺潘掾，分頭看洛神。", "重城自不掩，出向小平津。"]'),
('d756f172-bcc6-4835-9efa-e3adc7c7d939','晦日宴高氏林亭','周彥暉','唐','唐诗','tang','','[]','砌蓂收晦魄，津柳競年華。',48,'全唐诗/poet.tang.4000.json','["砌蓂收晦魄，津柳競年華。", "既狎忘筌友，方淹投轄車。", "綺筵迴舞雪，瓊醑泛流霞。", "雲低上天晚，絲雨帶風斜。"]'),
('bcb57f9c-5b88-42f7-8316-af64a2c96c8f','晦日重宴','周彥暉','唐','唐诗','tang','','[]','春華歸柳樹，俯景落蓂枝。',48,'全唐诗/poet.tang.4000.json','["春華歸柳樹，俯景落蓂枝。", "置驛銅街右，開筵玉浦陲。", "林煙含障密，竹雨帶珠危。", "興闌巾倒戴，山公下習池。"]'),
('da41a40c-8b63-4731-b03c-558d7cd45a96','晦日宴高氏林亭','高嶠','唐','唐诗','tang','','[]','飛觀寫春望，開宴坐汀沙。',48,'全唐诗/poet.tang.4000.json','["飛觀寫春望，開宴坐汀沙。", "積溜含苔色，晴空蕩日華。", "歌入平陽第，舞對石崇家。", "莫慮能騎馬，投轄自停車。"]'),
('80b2953c-6047-49ee-88ee-d8d2b78aeb0c','晦日重宴','高嶠','唐','唐诗','tang','','[]','駕言尋鳳侶，乘歡俯雁池。',48,'全唐诗/poet.tang.4000.json','["駕言尋鳳侶，乘歡俯雁池。", "班荆逢舊識，斟桂喜深知。", "紫蘭方出徑，黃鶯未囀枝。", "別有陶春日，青天雲霧披。"]'),
('f468053a-b4d5-48a8-ac27-b55ae8b8aeed','晦日宴高氏林亭','劉友賢','唐','唐诗','tang','','[]','春來日漸賒，琴酒逐年華。',48,'全唐诗/poet.tang.4000.json','["春來日漸賒，琴酒逐年華。", "欲向文通逕，先遊武子家。", "池碧新流滿，巖紅落照斜。", "興闌情未盡，步步惜風花。"]'),
('058bf120-30d8-44e1-9524-b4a78b2355f4','晦日宴高氏林亭','周思鈞','唐','唐诗','tang','','[]','早春驚柳穟，初晦掩蓂華。',48,'全唐诗/poet.tang.4000.json','["早春驚柳穟，初晦掩蓂華。", "騎出平陽里，筵開衞尉家。", "竹影含雲密，池紋帶雨斜。", "重惜林亭晚，上路滿煙霞。"]'),
('2b0cf16d-fcb1-4492-bb0a-cc771db42415','晦日重宴','周思鈞','唐','唐诗','tang','','[]','綺筵乘晦景，高宴下陽池。',48,'全唐诗/poet.tang.4000.json','["綺筵乘晦景，高宴下陽池。", "濯雨梅香散，含風柳色移。", "輕塵依扇落，流水入弦危。", "勿顧林亭晚，方歡雲霧披。"]'),
('d0924990-7f5e-4384-ad61-acae007f72f3','祭汾陰樂章','蘇頲','唐','唐诗','tang','','[]','禮物斯具，樂章乃陳。',40,'全唐诗/poet.tang.4000.json','["禮物斯具，樂章乃陳。", "誰其作主，皇考聖真。", "對越在天，聖明佐神。", "窅然汾上，厚澤如春。"]'),
('90ab168e-cf2f-4972-a5c6-70c8d5bca0e0','奉和聖製行次成皐途經先聖擒建德之所感而成詩應制','蘇頲','唐','唐诗','tang','','[]','漢東不執象，河朔方鬬龍。',72,'全唐诗/poet.tang.4000.json','["漢東不執象，河朔方鬬龍。", "夏滅漸寧亂，唐興終奮庸。", "皇威正赫赫，兵氣何匈匈。", "用武三川震，歸淳六代醲。", "成臯覩王業，天下致人雍。", "即此巡於岱，曾孫受命封。"]'),
('5a63ad8c-148a-46c0-8e0d-b52c32ca5b0c','奉和聖製登蒲州逍遙樓應制','蘇頲','唐','唐诗','tang','','[]','在昔堯舜禹，遺塵成典謨。',72,'全唐诗/poet.tang.4000.json','["在昔堯舜禹，遺塵成典謨。", "聖皇東巡狩，況乃經此都。", "樓觀紛迤邐，河山幾縈紆。", "緬懷祖宗業，相繼文武圖。", "尚德既無險，觀風諒有孚。", "豈如汾水上，簫鼓事遊娛。"]'),
('3b0ef70c-ced6-49e9-a88e-4aef0f574f43','奉和聖製過晉陽宮應制','蘇頲','唐','唐诗','tang','','[]','隋運與天絕，生靈厭氛昏。',144,'全唐诗/poet.tang.4000.json','["隋運與天絕，生靈厭氛昏。", "聖期在寧亂，士馬興太原。", "立極萬邦推，登庸四海尊。", "慶膺神武帝，業付皇曾孫。", "緬慕封唐道，追惟歸沛魂。", "詔書感先義，典禮巡舊藩。", "高殿綵雲合，春旗祥風翻。", "率西見汾水，奔北空塞垣。", "款曲童兒佐，依遲故老言。", "里頒慈惠賞，家受復除恩。", "下輦崇三教，建碑當九門。", "孝思敦至美，億載奉開元。"]'),
('1f2ccf48-722e-4c48-8ac0-f3c9a4662f00','奉和姚令公溫湯舊館永懷故人盧公之作','蘇頲','唐','唐诗','tang','','[]','樹德豈孤邁，降神良竝出。',96,'全唐诗/poet.tang.4000.json','["樹德豈孤邁，降神良竝出。", "偉茲廊廟楨，調彼鹽梅實。", "正悅虞垂舉，翻悲鄭僑卒。", "同心不可忘，交臂何爲失。", "清路荷前幸，明時稱右弼。", "曾聯野外遊，尚記帷中密。", "新慟情莫遣，舊遊詞更述。", "空令還辱和，長歎知音日。"]'),
('a6cdc6ae-2328-4240-a0ea-4ea0812a7f2c','和杜主簿春日有所思','蘇頲','唐','唐诗','tang','','[]','朝上高樓上，俯見洛陽陌。',72,'全唐诗/poet.tang.4000.json','["朝上高樓上，俯見洛陽陌。", "搖蕩吹花風，落英紛已積。", "美人不共此，芳好空所惜。", "攬鏡塵網滋，當窗苔蘚碧。", "緬懷在雲漢，良願暌枕席。", "翻似無見時，如何久爲客。"]'),
('17c61854-cba7-4a56-969f-26c728cf5e60','餞郢州李使君','蘇頲','唐','唐诗','tang','','[]','楚有章華臺，遙遙雲夢澤。',72,'全唐诗/poet.tang.4000.json','["楚有章華臺，遙遙雲夢澤。", "復聞擁符傳，及是收圖籍。", "佳政在離人，能聲寄侯伯。", "離懷朔風起，試望秋陰積。", "中路悽以寒，羣山靄將夕。", "傷心聊把袂，怊悵麒麟客。"]'),
('ae2f1f6f-6683-4d66-832f-ce7ec626d142','餞唐州高使君赴任','蘇頲','唐','唐诗','tang','','[]','永日奏文時，東風搖蕩夕。',48,'全唐诗/poet.tang.4000.json','["永日奏文時，東風搖蕩夕。", "浩然思樂事，翻復餞征客。", "淮水春流清，楚山暮雲白。", "勿言行路遠，所貴專城伯。"]'),
('2ee39294-5e69-4fbd-a697-f9c046f35808','曉濟膠川南入密界','蘇頲','唐','唐诗','tang','','[]','飲馬膠川上，傍膠南趣密。',48,'全唐诗/poet.tang.4000.json','["飲馬膠川上，傍膠南趣密。", "林遙飛鳥遲，雲去晴山出。", "落暉隱桑柘，秋原被花實。", "慘然遊子寒，風露將蕭瑟。"]'),
('fe1eeb16-6997-4a02-a38f-afaa462312dd','夜發三泉即事','蘇頲','唐','唐诗','tang','','[]','暗發三泉山，窮秋聽騷屑。',182,'全唐诗/poet.tang.4000.json','["暗發三泉山，窮秋聽騷屑。", "北林夜鳴雨，南望曉成雪。", "祗詠北風涼，詎知南土熱。", "沙溪忽沸渭，石道乍明滅。", "宛若銀磧橫，復如瑤臺結。", "指程賦所戀，遇虞不遑歇。", "重纊濡莫解，懸旌凍猶揭。", "下奔泥棧榰，上覯雲梯設。", "[搏]頰羸馬頓，回眸惴人跌。", "憧憧往復還，心注思逾切。", "冉冉年將病，力困衰怠竭。", "天彭信方隅，地勢誠斗絕。", "忝曳尚書履，叨兼使臣節。", "京坻有歲饒，亭障無邊孽。", "歸奏丹墀左，騫能俟來哲。"]'),
('79262d57-0081-46bb-891c-dd702fe98ba8','小園納涼即事','蘇頲','唐','唐诗','tang','','[]','煩暑避蒸鬱，居閑習高明。',48,'全唐诗/poet.tang.4000.json','["煩暑避蒸鬱，居閑習高明。", "長風自遠來，層閣有餘清。", "散灑納涼氣，蕭條遺世情。", "奈何誇大隱，終日繫塵纓。"]'),
('8dc1017d-f8f9-43f8-b9a5-a5e3b52b0351','昆明池晏坐答王兵部珣三韻見示','蘇頲','唐','唐诗','tang','','[]','畫舸疾如飛，遙遙汎夕暉。',36,'全唐诗/poet.tang.4000.json','["畫舸疾如飛，遙遙汎夕暉。", "石黥吹浪隱，玉女步塵歸。", "獨有銜恩處，明珠在釣磯。"]'),
('9d609c55-0dae-4244-9c55-b52b32d3bd1a','奉和聖製春臺望應制','蘇頲','唐','唐诗','tang','','[]','壯麗天之府，神明王者宅。',204,'全唐诗/poet.tang.4000.json','["壯麗天之府，神明王者宅。", "大君乘飛龍，登彼復懷昔。", "圓闕朱光燄，橫山翠微積。", "河汧流作表，縣聚開成陌。", "即舊在皇家，維新具物華。", "雲連所上居恆屬，日更時中望不斜。", "三月滄池搖積水，萬年青樹綴新花。", "暴嬴國此嘗圖霸，霸業後仁先以詐。", "東破諸侯西入秦，咸陽北阪南渭津。", "詩書焚爇散學士，高閣奢踰嬌美人。", "事往覆輈經遠喻，春還按蹕憑高賦。", "戎觀愛力深惟省，越厭陳方何足務。", "清吹遙遙發帝臺，宸文耿耿照天迴。", "伯夷位事愚臣忝，喜奏聲成鳳鳥來。"]'),
('ba3fa087-f937-4e13-a715-e3fa86225bd5','長相思','蘇頲','唐','唐诗','tang','','[]','君不見天津橋下東流水，南望龍門北朝市。',51,'全唐诗/poet.tang.4000.json','["君不見天津橋下東流水，南望龍門北朝市。", "楊柳青青宛地垂，桃紅李白花參差。", "花參差，柳堪結，此時憶君心斷絕。"]'),
('519c3ae7-5ffa-41f9-b2a6-001e7d2b6dfb','蜀城哭台州樂安少府','蘇頲','唐','唐诗','tang','','[]','遠遊躋劒閣，長想屬天台。',276,'全唐诗/poet.tang.4000.json','["遠遊躋劒閣，長想屬天台。", "萬里隔三載，此邦余重來。", "音容曠不覩，夢寐殊悠哉。", "邊郡饒藉藉，晚庭正回回。", "喜傳上都封，因促傍吏開。", "向悟海鹽客，已而梁木摧。", "變衣寢門外，揮涕少城隈。", "却記分明得，猶持委曲猜。", "師儒昔訓獎，仲季時童孩。", "服義題書篋，邀歡汎酒杯。", "蹔令風雨散，仍迫歲時迴。", "其道惟正直，其人信美偲。", "白頭還作尉，黃綬固非才。", "可歎懸蛇疾，先貽問鵩災。", "故鄉閉窮壤，宿草生寒荄。", "零落九原去，蹉跎四序催。", "曩期冬贈橘，今哭夏成梅。", "執禮誰爲賵，居常不徇財。", "北登嵔𡻱坂，東望姑蘇臺。", "天路本懸絕，江波復泝洄。", "念孤心易斷，追往恨艱裁。", "不遂卿將伯，孰云陳與雷。", "吾衰亦如此，夫子復何哀。"]'),
('4fa0c22b-a7a2-4bed-aed2-b436bd5daf78','立春日侍宴內出剪綵花應制','蘇頲','唐','唐诗','tang','','[]','曉入宜春苑，穠芳吐禁中。',48,'全唐诗/poet.tang.4000.json','["曉入宜春苑，穠芳吐禁中。", "剪刀因裂素，妝粉爲開紅。", "彩異驚流雪，香饒點便風。", "裁成識天意，萬物與花同。"]'),
('61479e50-d043-4087-9210-ba372edd74e0','春日芙蓉園侍宴應制','蘇頲','唐','唐诗','tang','','[]','御道紅旗出，芳園翠輦遊。',48,'全唐诗/poet.tang.4000.json','["御道紅旗出，芳園翠輦遊。", "繞花開水殿，架竹起山樓。", "荷芰輕薰幄，魚龍出負舟。", "寧知穆天子，空賦白雲秋。"]'),
('9ad7ac00-3e4f-4c29-ace7-aff39377ea36','奉和聖製人日清暉閣宴羣臣遇雪應制','蘇頲','唐','唐诗','tang','','[]','樓觀空煙裏，初年瑞雪過。',48,'全唐诗/poet.tang.4000.json','["樓觀空煙裏，初年瑞雪過。", "苑花齊玉樹，池水作銀河。", "七日祥圖啓，千春御賞多。", "輕飛傳綵勝，天上奉薰歌。"]'),
('86d724ea-f6dc-4f4b-8343-39e155f5b21a','奉和七夕宴兩儀殿應制','蘇頲','唐','唐诗','tang','','[]','靈媛乘秋發，仙裝警夜催。',48,'全唐诗/poet.tang.4000.json','["靈媛乘秋發，仙裝警夜催。", "月光窺欲渡，河色辨應來。", "機石天文寫，針樓御賞開。", "竊觀棲鳥至，疑向鵲橋迴。"]'),
('f8827ebc-e47d-455a-8613-c3ea71f88fa7','奉和九日幸臨渭亭登高應制得時字','蘇頲','唐','唐诗','tang','','[]','嘉會宜長日，高筵順動時。',48,'全唐诗/poet.tang.4000.json','["嘉會宜長日，高筵順動時。", "曉光雲外洗，晴色雨餘滋。", "降鶴因韶德，吹花入御詞。", "願陪陽數節，億萬九秋期。"]'),
('65a277a9-3b82-4b7a-838a-c4aa26155c8f','游禁苑幸臨渭亭遇雪應制','蘇頲','唐','唐诗','tang','','[]','平明敞帝居，霰雪下凌虛。',48,'全唐诗/poet.tang.4000.json','["平明敞帝居，霰雪下凌虛。", "寫月含珠綴，從風薄綺疏。", "年驚花絮早，春夜管弦初。", "已屬雲天外，欣承霈澤餘。"]'),
('0915a3d1-5af4-403b-a2c1-1872e5e40edd','奉和送金城公主適西蕃應制','蘇頲','唐','唐诗','tang','','[]','帝女出天津，和戎轉罽輪。',48,'全唐诗/poet.tang.4000.json','["帝女出天津，和戎轉罽輪。", "川經斷腸望，地與析支鄰。", "奏曲風嘶馬，銜悲月伴人。", "旋知偃兵革，長是漢家親。"]'),
('28c8f4bd-ab2e-4eff-89a2-f576e3f07c21','奉和聖製登驪山高頂寓目應制','蘇頲','唐','唐诗','tang','','[]','仙蹕御層氛，高高積翠分。',48,'全唐诗/poet.tang.4000.json','["仙蹕御層氛，高高積翠分。", "巖聲中谷應，天語半空聞。", "豐樹連黃葉，函關入紫雲。", "聖圖恢宇縣，歌賦小橫汾。"]'),
('4e842aba-99c4-453a-9f01-57ebd48b37fe','幸白鹿觀應制','蘇頲','唐','唐诗','tang','','[]','碧虛清吹下，藹藹入仙宮。',48,'全唐诗/poet.tang.4000.json','["碧虛清吹下，藹藹入仙宮。", "松磴攀雲絕，花源接澗空。", "受符邀羽使，傳訣注香童。", "詎似閑居日，徒聞有順風。"]'),
('94da5d2e-2dfb-4c37-b301-6fd888c2b46a','題壽安王主簿池館','蘇頲','唐','唐诗','tang','','[]','洛邑通馳道，韓郊在屬城。',48,'全唐诗/poet.tang.4000.json','["洛邑通馳道，韓郊在屬城。", "館將花雨映，潭與竹聲清。", "賢俊鸞棲棘，賓遊馬佩衡。", "願言隨狎鳥，從此濯吾纓。"]'),
('807b1a6b-4135-4f2d-8ab8-dd59e4cd8a88','扈從溫泉奉和姚令公喜雪','蘇頲','唐','唐诗','tang','','[]','清道豐人望，乘時漢主遊。',48,'全唐诗/poet.tang.4000.json','["清道豐人望，乘時漢主遊。", "恩暉隨霰下，慶澤與雲浮。", "泉暖驚銀磧，花寒愛玉樓。", "鼎臣今有問，河伯且應留。"]'),
('d051f373-5d3a-4e30-8251-f2075e7be21f','秋社日崇讓園宴得新字','蘇頲','唐','唐诗','tang','','[]','鳴爵三農稔，勾龍百代神。',48,'全唐诗/poet.tang.4000.json','["鳴爵三農稔，勾龍百代神。", "運昌叨輔弼，時泰喜黎民。", "樹缺池光近，雲開日影新。", "生全應有地，長願樂交親。"]'),
('cb85f47a-eeb7-4050-86c2-406673a49f9d','奉和魏僕射秋日還鄉有懷之作','蘇頲','唐','唐诗','tang','','[]','南宮夙拜罷，東道晝遊初。',48,'全唐诗/poet.tang.4000.json','["南宮夙拜罷，東道晝遊初。", "飲餞傾冠蓋，傳呼問里閭。", "樹悲懸劒所，溪想釣璜餘。", "明發輝光至，增榮駟馬車。"]'),
('aab0986c-763c-491e-bea2-a886fd7734ce','武[擔]山寺','蘇頲','唐','唐诗','tang','','[]','武[擔]獨蒼然，墳山下玉泉。',50,'全唐诗/poet.tang.4000.json','["武[擔]獨蒼然，墳山下玉泉。", "鱉靈時共盡，龍女事同遷。", "松柏銜哀處，幡花種福田。", "詎知留鏡石，長與法輪圓。"]'),
('6b86918e-abf0-4054-8971-7f20c434843f','餞潞州陸長史再守汾州','蘇頲','唐','唐诗','tang','','[]','河尹政成期，爲汾昔所推。',48,'全唐诗/poet.tang.4000.json','["河尹政成期，爲汾昔所推。", "不榮三入地，還美再臨時。", "擁傳雲初合，聞鶯日正遲。", "道傍多出餞，別有吏民思。"]'),
('5bbdf15f-8b26-4b45-a853-1808fd830a70','餞荆州崔司馬','蘇頲','唐','唐诗','tang','','[]','茂禮雕龍昔，香名展驥初。',48,'全唐诗/poet.tang.4000.json','["茂禮雕龍昔，香名展驥初。", "水連南海漲，星拱北辰居。", "稍發仙人履，將題別駕輿。", "明年徵拜入，荆玉不藏諸。"]'),
('4f5a747e-f805-4a32-936f-f41b11e561b0','送吏部李侍郎東歸得歸字','蘇頲','唐','唐诗','tang','','[]','陌上有光輝，披雲向洛畿。',48,'全唐诗/poet.tang.4000.json','["陌上有光輝，披雲向洛畿。", "賞來榮扈從，別至惜分飛。", "泉溜含風急，山煙帶日微。", "茂曹今去矣，人物喜東歸。"]'),
('2b3dd1c8-9fe6-4f21-aeab-435e432ac5bd','送光祿姚卿還都','蘇頲','唐','唐诗','tang','','[]','漢室有英台，荀家寵俊才。',48,'全唐诗/poet.tang.4000.json','["漢室有英台，荀家寵俊才。", "九卿朝已入，三子暮同來。", "不授綸爲草，還司鼎用梅。", "兩京王者宅，駟馬日應迴。"]'),
('1e534536-557a-4e3d-a0b0-67b23141b312','春晚送瑕丘田少府還任因寄洛中鏡上人','蘇頲','唐','唐诗','tang','','[]','聞道還沂上，因聲寄洛濱。',48,'全唐诗/poet.tang.4000.json','["聞道還沂上，因聲寄洛濱。", "別時花欲盡，歸處酒應春。", "聚散同行客，悲歡屬故人。", "少年追樂地，遙贈一霑巾。"]'),
('a03f7eb5-f9e6-4298-8a54-f5cf9f65d477','送賈起居奉使入洛取圖書因便拜覲','蘇頲','唐','唐诗','tang','','[]','舊國才因地，當朝史命官。',48,'全唐诗/poet.tang.4000.json','["舊國才因地，當朝史命官。", "遺文徵闕簡，還思采芳蘭。", "傳發關門候，觴稱邑里歡。", "早持京副入，旋佇洛書刊。"]'),
('f0648fc4-6617-4e82-94d7-2390a914685a','送常侍舒公歸覲','蘇頲','唐','唐诗','tang','','[]','朝聞講藝餘，晨省拜恩初。',48,'全唐诗/poet.tang.4000.json','["朝聞講藝餘，晨省拜恩初。", "訓胄尊庠序，榮親耀里閭。", "朱丹華轂送，斑白綺筵舒。", "江上春流滿，還應薦躍魚。"]'),
('40f282ed-ccad-4b94-9c7a-f8e4045148b5','興州出行','蘇頲','唐','唐诗','tang','','[]','危途曉未分，驅馬傍江濆。',48,'全唐诗/poet.tang.4000.json','["危途曉未分，驅馬傍江濆。", "滴滴泣花露，微微出岫雲。", "松梢半吐月，蘿翳漸移曛。", "旅客腸應斷，吟猿更使聞。"]'),
('af75693d-cb7b-4e74-8e41-a66cb930fd94','邊秋薄暮','蘇頲','唐','唐诗','tang','','[]','海外秋鷹擊，霜前旅雁歸。',48,'全唐诗/poet.tang.4000.json','["海外秋鷹擊，霜前旅雁歸。", "邊風思鞞鼓，落日慘旌麾。", "浦暗漁舟入，川長獵騎稀。", "客悲逢薄暮，況乃事戎機。"]'),
('b419a2f7-bcdc-4387-8973-84546a1f62b0','曉發方騫驛','蘇頲','唐','唐诗','tang','','[]','傳置遠山蹊，龍鍾蹴澗泥。',48,'全唐诗/poet.tang.4000.json','["傳置遠山蹊，龍鍾蹴澗泥。", "片陰常作雨，微照已生霓。", "鬢髪愁氛換，心情險路迷。", "方知向蜀者，偏識子規啼。"]'),
('7f094723-d83a-4c36-a327-dcfd96594b9e','經三泉路作','蘇頲','唐','唐诗','tang','','[]','三月松作花，春行日漸賒。',48,'全唐诗/poet.tang.4000.json','["三月松作花，春行日漸賒。", "竹障山鳥路，藤蔓野人家。", "透石飛梁下，尋雲絕磴斜。", "此中誰與樂，揮涕語年華。"]'),
('d31bcf3f-9b75-4500-a914-bde28efb10b2','故高安大長公主挽詞','蘇頲','唐','唐诗','tang','','[]','彤管承師訓，青圭備禮容。',48,'全唐诗/poet.tang.4000.json','["彤管承師訓，青圭備禮容。", "孟孫家代寵，元女國朝封。", "柔軌題貞順，閑規賦肅雍。", "寧知落照盡，霜吹入悲松。"]'),
('a5e7d553-f748-43f2-9589-d01507371bb2','贈司徒豆盧府君挽詞','蘇頲','唐','唐诗','tang','','[]','寵贈追胡廣，親臨比賀循。',48,'全唐诗/poet.tang.4000.json','["寵贈追胡廣，親臨比賀循。", "幾聞投劒客，多會服緦人。", "草閉墳將古，松陰地不春。", "二陵猶可望，存歿有忠臣。"]'),
('12e0da1f-558e-4632-a50d-74c4cad68f4b','故右散騎常侍舒國公褚公挽詞','蘇頲','唐','唐诗','tang','','[]','陽翟疏豐構，臨平演慶源。',48,'全唐诗/poet.tang.4000.json','["陽翟疏豐構，臨平演慶源。", "學筵尊授几，儒服寵乘軒。", "審諭留中密，開陳與上言。", "徂暉一不借，空有賜東園。"]'),
('93baa0bf-4a69-4c0e-9431-c0b06e4d490c','奉和初春幸太平公主南莊應制','蘇頲','唐','唐诗','tang','','[]','主第山門起灞川，宸遊風景入初年。',64,'全唐诗/poet.tang.4000.json','["主第山門起灞川，宸遊風景入初年。", "鳳皇樓下交天仗，烏鵲橋頭敞御筵。", "往往花間逢綵石，時時竹裏見紅泉。", "今朝扈蹕平陽館，不羨乘槎雲漢邊。"]'),
('ba5e2fdc-3d12-4e3e-b73a-89b9c4393459','奉和春日幸望春宮應制','蘇頲','唐','唐诗','tang','','["\u6b4c\u9882", "\u6625\u5929", "\u5bb4\u4f1a", "\u8d5e\u7f8e"]','東望望春春可憐，更逢晴日柳含煙。',64,'全唐诗/poet.tang.4000.json','["東望望春春可憐，更逢晴日柳含煙。", "宮中下見南山盡，城上平臨北斗懸。", "細草徧承回輦處，輕花微落奉觴前。", "宸遊對此歡無極，鳥哢聲聲入管絃。"]'),
('08d15bf8-930d-4f71-93dc-dc0c4fd3febb','人日重宴大明宮恩賜綵縷人勝應制','蘇頲','唐','唐诗','tang','','[]','疏龍磴道切昭回，建鳳旗門繞帝臺。',64,'全唐诗/poet.tang.4000.json','["疏龍磴道切昭回，建鳳旗門繞帝臺。", "七葉仙蓂依月吐，千株御柳拂煙開。", "初年競貼宜春勝，長命先浮獻壽杯。", "是日皇靈知竊幸，羣心就捧大明來。"]'),
('9d6bbaa2-2896-4921-a8de-ba8a965682b4','侍宴安樂公主山莊應制','蘇頲','唐','唐诗','tang','','[]','駸駸羽騎歷城池，帝女樓臺向晚披。',64,'全唐诗/poet.tang.4000.json','["駸駸羽騎歷城池，帝女樓臺向晚披。", "霧灑旌旗雲外出，風回巖岫雨中移。", "當軒半落天河水，繞徑全低月樹枝。", "簫鼓宸遊陪宴日，和鳴雙鳳喜來儀。"]'),
('55580d53-8836-4f3c-bcfd-d8f96c576727','興慶池侍宴應制','蘇頲','唐','唐诗','tang','','[]','降鶴池前回步輦，棲鸞樹杪出行宮。',64,'全唐诗/poet.tang.4000.json','["降鶴池前回步輦，棲鸞樹杪出行宮。", "山光積翠遙疑逼，水態含青近若空。", "直視天河垂象外，俯窺京室畫圖中。", "皇歡未使恩波極，日暮樓船更起風。"]'),
('cb753059-30e7-4c32-8c89-88fe16a45eda','廣達樓下夜侍酺宴應制','蘇頲','唐','唐诗','tang','','["\u6cf0\u5c71"]','東嶽封廻宴洛京，西墉通晚會公卿。',64,'全唐诗/poet.tang.4000.json','["東嶽封廻宴洛京，西墉通晚會公卿。", "樓臺絕勝宜春苑，燈火還同不夜城。", "正覩人間朝市樂，忽聞天上管弦聲。", "酺來萬舞羣臣醉，喜戴千年聖主明。"]'),
('4313e81d-cd01-467a-a3ef-9fa52d77517c','龍池樂章','蘇頲','唐','唐诗','tang','','[]','西京鳳邸躍龍泉，佳氣休光鎮在天。',64,'全唐诗/poet.tang.4000.json','["西京鳳邸躍龍泉，佳氣休光鎮在天。", "軒后霧圖今已得，秦王水劒昔常傳。", "恩魚不入昆明釣，瑞鶴長如太液仙。", "願侍巡遊同舊里，更聞簫鼓濟樓船。"]'),
('365b7d0d-905e-4ea9-ac8e-2ed7f8fd8198','扈從鄠杜間奉呈刑部尚書舅崔黃門馬常侍','蘇頲','唐','唐诗','tang','','[]','翠輦紅旗出帝京，長楊鄠杜昔知名。',64,'全唐诗/poet.tang.4000.json','["翠輦紅旗出帝京，長楊鄠杜昔知名。", "雲山一一看皆美，竹樹蕭蕭畫不成。", "羽騎將過持袂拂，香車欲度捲簾行。", "漢家曾草巡遊賦，何似今來應聖明。"]'),
('54aa2552-b98a-4db2-81b0-108ae32fa263','景龍觀送裴士曹','蘇頲','唐','唐诗','tang','','[]','昔日嘗聞公主第，今時變作列仙家。',64,'全唐诗/poet.tang.4000.json','["昔日嘗聞公主第，今時變作列仙家。", "池傍坐客穿叢篠，樹下遊人掃落花。", "雨雪長疑向函谷，山泉直似到流沙。", "君還洛邑分明記，此處同來閱歲華。"]'),
('f11dba11-b96d-45d6-9b7f-b02014f9e204','春晚紫微省直寄內','蘇頲','唐','唐诗','tang','','[]','直省清華接建章，向來無事日猶長。',64,'全唐诗/poet.tang.4000.json','["直省清華接建章，向來無事日猶長。", "花間燕子棲鳷鵲，竹下鵷雛繞鳳皇。", "內史通宵承紫誥，中人落晚愛紅妝。", "別離不慣無窮憶，莫誤卿卿學太常。"]'),
('56711abb-01e3-4d70-9029-039eff2d7cf7','贈彭州權別駕','蘇頲','唐','唐诗','tang','','[]','雙流脈脈錦城開，追餞年年往復廻。',64,'全唐诗/poet.tang.4000.json','["雙流脈脈錦城開，追餞年年往復廻。", "秪道歌謠迎半刺，徒聞禮數揖中台。", "黃鶯急囀春風盡，斑馬長嘶落景催。", "莫愴分飛岐路別，還當奏最掖垣來。"]'),
('0b7ee52d-3960-438f-9bbd-256316f881ed','寒食宴于中舍別駕兄弟宅','蘇頲','唐','唐诗','tang','','[]','子推山上歌龍罷，定國門前結駟來。',64,'全唐诗/poet.tang.4000.json','["子推山上歌龍罷，定國門前結駟來。", "始覩元昆鏘玉至，旋聞季子佩刀廻。", "晴花處處因風起，御柳條條向日開。", "自有長筵歡不極，還將綵服詠南陔。"]'),
('c9fe5006-1e41-43ae-9e89-87af8b4a8e72','九月九日望蜀臺','蘇頲','唐','唐诗','tang','','[]','蜀王望蜀舊臺前，九日分明見一川。',64,'全唐诗/poet.tang.4000.json','["蜀王望蜀舊臺前，九日分明見一川。", "北料鄉關方自此，南辭城郭復依然。", "青松繫馬攢巖畔，黃菊留人籍道邊。", "自昔登臨湮滅盡，獨聞忠孝兩能傳。"]'),
('c59b1912-b88d-452b-8bf5-7b3a95b0acae','奉和晦日幸昆明池應制','蘇頲','唐','唐诗','tang','','[]','炎曆事邊陲，昆明始鑿池。',72,'全唐诗/poet.tang.4000.json','["炎曆事邊陲，昆明始鑿池。", "豫遊光後聖，征戰罷前規。", "霽色清珍宇，年芳入錦陂。", "御杯蘭薦葉，仙仗柳交枝。", "二石分河瀉，雙珠代月移。", "微臣比翔泳，恩廣自無涯。"]'),
('fb2b4199-42cb-4eee-b932-10415d968fc8','奉和聖製幸禮部尚書竇希玠宅應制','蘇頲','唐','唐诗','tang','','[]','尚書列侯第，外戚近臣家。',72,'全唐诗/poet.tang.4000.json','["尚書列侯第，外戚近臣家。", "飛棟臨青綺，迴輿轉翠華。", "日交當戶樹，泉漾滿池花。", "圓頂圖嵩石，方流擁魏沙。", "豫遊今聽履，侍從昔鳴笳。", "自有天文降，無勞訪海槎。"]'),
('3bd5d5a6-1ada-4373-ab13-591df02ce060','奉和幸韋嗣立山莊應制','蘇頲','唐','唐诗','tang','','[]','摐金寒野霽，步玉曉山幽。',96,'全唐诗/poet.tang.4000.json','["摐金寒野霽，步玉曉山幽。", "帝幄期松子，臣廬訪葛侯。", "百工徵往夢，七聖扈來遊。", "斗柄乘時轉，臺階捧日留。", "樹重巖籟合，泉迸水光浮。", "石徑喧朝履，璜溪擁釣舟。", "恩如犯星夜，歡擬濟河秋。", "不學堯年隱，空令傲許由。"]'),
('ad745180-13c0-4169-8cda-0ced3fbc997f','奉和聖製送張說上集賢學士賜宴得茲字','蘇頲','唐','唐诗','tang','','[]','肅肅金殿裏，招賢固在茲。',72,'全唐诗/poet.tang.4000.json','["肅肅金殿裏，招賢固在茲。", "鏘鏘石渠內，序拜亦同時。", "宴錫歡談道，文成貴說詩。", "用儒今作相，敦學舊爲師。", "下際天光近，中來帝渥滋。", "國朝良史載，能事日論思。"]'),
('e492e2c4-7708-4cef-bf2f-dfea76a4b675','奉和聖製途經華嶽應制','蘇頲','唐','唐诗','tang','','["\u534e\u5c71"]','朝望蓮華嶽，神心就日來。',72,'全唐诗/poet.tang.4000.json','["朝望蓮華嶽，神心就日來。", "晴觀五千仞，仙掌拓山開。", "受命金符叶，過祥玉瑞陪。", "霧披乘鹿見，雲起馭龍廻。", "偃樹枝封雪，殘碑石冐苔。", "聖皇惟道契，文字勒巖隈。"]'),
('de3bde44-ca15-4ad2-a27f-6b17e90a8503','奉和聖製經河上公廟應制','蘇頲','唐','唐诗','tang','','[]','河流無日夜，河上有神仙。',72,'全唐诗/poet.tang.4000.json','["河流無日夜，河上有神仙。", "輦路曾經此，壇場即宛然。", "下疑成洞穴，高若在空煙。", "善物遺方外，和光繞道邊。", "事因周史得，言與漢王傳。", "喜屬膺期聖，邦家業又玄。"]'),
('5200f73a-f7ce-46d6-a3ab-d0c8d4c3e27b','奉和聖製答張說出雀鼠谷','蘇頲','唐','唐诗','tang','','[]','雨施巡方罷，雲從訓俗廻。',72,'全唐诗/poet.tang.4000.json','["雨施巡方罷，雲從訓俗廻。", "密途汾水衞，清蹕晉郊陪。", "寒著山邊盡，春當日下來。", "御祠玄鳥應，仙仗綠楊開。", "作頌音傳雅，觀文色動台。", "更知西向樂，宸藻協鹽梅。"]'),
('af16bdfe-2ca4-411d-ad24-a7ac357266eb','奉和恩賜樂遊園宴應制','蘇頲','唐','唐诗','tang','','[]','樂遊光地選，酺飲慶天從。',72,'全唐诗/poet.tang.4000.json','["樂遊光地選，酺飲慶天從。", "座密千官盛，場開百戲容。", "綠塍際山盡，緹幕倚雲重。", "下上花齊發，周廻柳遍濃。", "奪晴紛劒履，喧聽雜歌鐘。", "日晚銜恩散，堯人倂可封。"]'),
('9c880c6d-5286-4bf3-a293-ed05633bbfde','恩制尚書省僚宴昆明池同用堯字','蘇頲','唐','唐诗','tang','','[]','露渥灑雲霄，天官次斗杓。',72,'全唐诗/poet.tang.4000.json','["露渥灑雲霄，天官次斗杓。", "昆明四十里，空水極晴朝。", "雁似銜紅葉，鯨疑噴海潮。", "翠山來徹底，白日去廻標。", "泳廣漁杈溢，浮深妓舫搖。", "飽恩皆醉止，合舞共歌堯。"]'),
('1e011e4f-6575-4716-8175-2ebf164df6c1','奉和聖製幸望春宮送[朔方]大總管張仁亶','蘇頲','唐','唐诗','tang','','[]','北風吹早雁，日夕渡河飛。',72,'全唐诗/poet.tang.4000.json','["北風吹早雁，日夕渡河飛。", "氣冷膠應折，霜明草正腓。", "老臣帷幄筭，元宰廟堂機。", "餞飲廻仙蹕，臨戎解御衣。", "軍裝乘曉發，師律候春歸。", "方佇勳庸盛，天詞降紫微。"]'),
('272d85a9-94b0-4804-9198-41d061854210','奉和聖製登太行山中言志應制','蘇頲','唐','唐诗','tang','','[]','北山東入海，馳道上連天。',96,'全唐诗/poet.tang.4000.json','["北山東入海，馳道上連天。", "順動三光柱，登臨萬象懸。", "俛觀河內邑，平指洛陽川。", "按蹕夷關險，張旗亙井泉。", "曉巖中警柝，春事下蒐田。", "德重周王問，歌輕漢后傳。", "宸遊鋪令典，睿思起芳年。", "願以封書奏，廻鑾禪肅然。"]'),
('ed6c933e-4db0-45b9-baba-6994d97cd657','奉和聖製漕橋東送新除岳牧','蘇頲','唐','唐诗','tang','','[]','寶賢不遺俊，臺閣盡鵷鸞。',120,'全唐诗/poet.tang.4000.json','["寶賢不遺俊，臺閣盡鵷鸞。", "未若調人切，其如簡帝難。", "上才膺出典，中旨念分官。", "特以專城貴，深惟列郡安。", "政行思務本，風靡屬勝殘。", "有令田知急，無分獄在寬。", "至言題睿札，殊渥灑仙翰。", "詔餞三台降，朝榮萬國歡。", "舉杯臨水發，張樂擁橋觀。", "式佇東封會，鏘鏘檢玉壇。"]'),
('93d311bc-2861-4a45-81ed-85d07b55236d','奉和聖製途次舊居應制','蘇頲','唐','唐诗','tang','','[]','潞國臨淄邸，天王別駕輿。',144,'全唐诗/poet.tang.4000.json','["潞國臨淄邸，天王別駕輿。", "出潛離隱際，小往大來初。", "東陸行春典，南陽即舊居。", "約川星罕駐，扶道日旂舒。", "雲覆連行在，風廻助掃除。", "木行城邑望，臯落土田疏。", "昔試邦興后，今過俗徯予。", "示威寧校獵，崇讓不陳魚。", "府吏趨宸扆，鄉耆捧帝車。", "帳傾三飲處，閑整六飛餘。", "盛業銘汾鼎，昌期應洛書。", "願陪歌賦末，留比蜀相如。"]'),
('26a4d85b-8ed4-4c17-b919-da5f41bbd8b5','奉和聖製至長春宮登樓望稼穡之作','蘇頲','唐','唐诗','tang','','[]','帝迹奚其遠，皇符之所崇。',144,'全唐诗/poet.tang.4000.json','["帝迹奚其遠，皇符之所崇。", "敬時堯務作，盡力禹稱功。", "赫赫惟元后，經營自左馮。", "變蕪秔稻實，流惡水泉通。", "國阜猶前豹，人疲詎昔熊。", "黃圖巡沃野，清吹入離宮。", "是閱京坻富，仍觀都邑雄。", "憑軒一何綺，積溜寫晴空。", "禮節家安外，和平俗在中。", "見龍垂渭北，辭雁指河東。", "睿思方居鎬，宸遊若飲豐。", "寧誇子雲從，秪爲獵扶風。"]'),
('724a9d0c-014d-4994-81df-aea98fa83af3','利州北佛龕前重于去歲題處作','蘇頲','唐','唐诗','tang','','[]','重巖載看美，分塔起層標。',60,'全唐诗/poet.tang.4000.json','["重巖載看美，分塔起層標。", "蜀守經塗處，巴人作禮朝。", "地疑三界出，空是六塵銷。", "臥石鋪蒼蘚，行塍覆綠條。", "歲年書有記，非爲學題橋。"]'),
('099ec5b8-1b41-4c45-81f1-c673e9ce9e22','閑園即事寄韋侍郎','蘇頲','唐','唐诗','tang','','[]','結廬東城下，直望江南山。',72,'全唐诗/poet.tang.4000.json','["結廬東城下，直望江南山。", "青靄遠相接，白雲來復還。", "拂筵紅蘚上，開幔綠條間。", "物應春偏好，情忘趣轉閑。", "憲臣饒美度，聯事惜徂顏。", "有酒空盈酌，高車不可攀。"]'),
('a75e85c5-a231-4575-a312-6b170f3fa3ad','扈從溫泉同紫微黃門羣公汎渭川得齊字','蘇頲','唐','唐诗','tang','','[]','虹旗映綠荑，春仗漢豐西。',72,'全唐诗/poet.tang.4000.json','["虹旗映綠荑，春仗漢豐西。", "侍蹕浮清渭，揚舲降紫泥。", "近臨鈞石地，遙指釣璜溪。", "岸轉帆飛疾，川平棹舉齊。", "傅舟來是用，軒馭往應迷。", "興闋菱歌動，沙洲亂夕鷖。"]'),
('3da2e839-9417-462d-9c76-41208552f0a3','餞趙尚書攝御史大夫赴朔方軍','蘇頲','唐','唐诗','tang','','[]','勁虜欲南窺，揚兵護朔陲。',72,'全唐诗/poet.tang.4000.json','["勁虜欲南窺，揚兵護朔陲。", "趙堯寧易印，鄧禹即分麾。", "野餞廻三傑，軍謀用六奇。", "雲邊愁出塞，日下愴臨岐。", "拔劒行人舞，揮戈戰馬馳。", "明年麟閣上，充國畫於斯。"]'),
('a91f7e21-a29e-4858-a43f-fe2b6599d29b','曉發興州入陳平路','蘇頲','唐','唐诗','tang','','[]','旌節指巴岷，年年行且巡。',72,'全唐诗/poet.tang.4000.json','["旌節指巴岷，年年行且巡。", "暮來青嶂宿，朝去綠江春。", "魚貫梁緣馬，猿奔樹息人。", "邑祠猶是漢，溪道即名陳。", "舊史饒遷謫，恆情厭苦辛。", "寧知報恩者，天子一忠臣。"]'),
('f178e58c-a5f5-4d73-bd2f-d98d41204804','同餞陽將軍兼源州都督御史中丞','蘇頲','唐','唐诗','tang','','[]','右地接龜沙，中朝任虎牙。',72,'全唐诗/poet.tang.4000.json','["右地接龜沙，中朝任虎牙。", "然明方改俗，去病不爲家。", "將禮登壇盛，軍容出塞華。", "朔風搖漢鼓，邊馬思胡笳。", "旗合無邀正，冠危有觸邪。", "當看勞還日，及此御溝花。"]'),
('53f759c4-6146-4875-b3c1-95d266ca4c0b','扈從鳳泉和崔黃門喜恩旨解嚴罷圍之作','蘇頲','唐','唐诗','tang','','[]','輦路岐山曲，儲胥渭水湄。',72,'全唐诗/poet.tang.4000.json','["輦路岐山曲，儲胥渭水湄。", "教成提將鼓，禮備植虞旗。", "不取從畋樂，先流去殺慈。", "舜韶同舞日，湯祝盡飛時。", "物應陽和施，人知雨露私。", "何如穆天子，七萃幾勞師。"]'),
('480b2056-f256-430e-abd4-80a36e93da35','秋夜寓直中書呈黃門舅','蘇頲','唐','唐诗','tang','','[]','簾櫳上夜鉤，清列聽更籌。',84,'全唐诗/poet.tang.4000.json','["簾櫳上夜鉤，清列聽更籌。", "忽共雞枝老，還如騎省秋。", "循庭喜三入，對渚憶雙遊。", "紫紱名初拜，黃縑迹尚留。", "月舒當北幌，雲賦直東樓。", "恩渥迷天施，童蒙慰我求。", "遲君台鼎節，聞義一承流。"]'),
('1487f6ef-f90d-400f-9ad0-8a9d88da3d64','先是新昌小園期京兆尹一訪兼郎官數子自頃沈痾年復一年茲願不果率然成章','蘇頲','唐','唐诗','tang','','[]','獨好中林隱，先期上月春。',96,'全唐诗/poet.tang.4000.json','["獨好中林隱，先期上月春。", "閑花傍戶落，喧鳥逼檐馴。", "寂寞東坡叟，傳呼北里人。", "在山琴易調，開甕酒歸醇。", "佇望應三接，彌留忽幾旬。", "不疑丹火變，空負綠條新。", "鬬蟻聞常日，歌龍值此辰。", "其如衆君子，嘉會阻清塵。"]'),
('a165caa5-f3fe-4b51-accf-1f7db97acaef','奉和馬常侍寺中之作','蘇頲','唐','唐诗','tang','','[]','怨暑時云謝，愆陽澤暫偏。',120,'全唐诗/poet.tang.4000.json','["怨暑時云謝，愆陽澤暫偏。", "鼎陳從祀日，鑰動問刑年。", "絳服龍雩寢，玄冠馬使旋。", "作霖期傅說，爲旱聽周宣。", "河嶽陰符啓，星辰暗檄傳。", "浮涼吹景氣，飛動灑空煙。", "颯颯將秋近，沈沈與暝連。", "分湍涇水石，合穎雍州田。", "德施超三五，文雄賦十千。", "及斯何以樂，明主敬人天。"]'),
('20c343cd-8de3-4ad3-af44-daf643332804','慈恩寺二月半寓言','蘇頲','唐','唐诗','tang','','[]','二月韶春半，三空霽景初。',120,'全唐诗/poet.tang.4000.json','["二月韶春半，三空霽景初。", "獻來應有受，滅盡竟無餘。", "化迹傳官寺，歸誠謁梵居。", "殿堂花覆席，觀閣柳垂疏。", "共命枝間鳥，長生水上魚。", "問津窺彼岸，迷路得真車。", "行密幽關靜，談精俗態祛。", "稻麻欣所遇，蓬籜愴焉如。", "不駐秦京陌，還題蜀郡輿。", "愛離方自此，廻望獨躊躇。"]'),
('a0433bf7-1dbe-4210-806a-756115c8d7b8','餞澤州盧使君赴任','蘇頲','唐','唐诗','tang','','[]','聞道降綸書，爲邦建綵旟。',120,'全唐诗/poet.tang.4000.json','["聞道降綸書，爲邦建綵旟。", "政憑循吏往，才以貴卿除。", "詞賦良無敵，聲華藹有餘。", "榮承四岳後，請絕五天初。", "關路通秦壁，城池接晉墟。", "撰期行子賦，分典列侯居。", "別望喧追餞，離言繫慘舒。", "平蕪寒蛬亂，喬木夜蟬疎。", "寥泬秋先起，推移月向諸。", "舊交何以贈，客至待烹魚。"]'),
('a47d71c5-8702-4005-89aa-c9d0d59d22a2','陳倉別隴州司戶李維深','蘇頲','唐','唐诗','tang','','[]','京國自攜手，同途欣解頤。',120,'全唐诗/poet.tang.4000.json','["京國自攜手，同途欣解頤。", "情言正的的，春物宛遲遲。", "忽背雕戎役，旋瞻獲寶祠。", "蜀城余出守，吳岳爾歸思。", "歡愜更傷此，眷殷殊念茲。", "揚麾北林徑，跂石南澗湄。", "中作壺觴餞，回添道路悲。", "數花臨磴日，百草覆田時。", "有美同人意，無爲行子辭。", "酣歌拔劒起，毋是答恩私。"]'),
('c4590f29-ee39-4a77-8a9a-ee7b2d5a93e4','奉和崔尚書贈大理陸卿鴻臚劉卿見示之作','蘇頲','唐','唐诗','tang','','[]','戲藻嘉魚樂，棲梧見鳳飛。',144,'全唐诗/poet.tang.4000.json','["戲藻嘉魚樂，棲梧見鳳飛。", "類從皆有召，聲應乃無違。", "美價逢時出，奇才選衆稀。", "避堂貽後政，掃第發前幾。", "出曳仙人履，還熏侍女衣。", "省中何赫奕，庭際滿芳菲。", "吏部端清鑒，丞郎肅紫機。", "會心歌詠是，廻迹宴言非。", "北寺鄰玄闕，南城寫翠微。", "參差交隱見，髣髴接光輝。", "賓序嘗柔德，刑孚已霽威。", "巨源林下契，不速自同歸。"]'),
('e2f7d463-77d1-4621-99de-0bb7d75c04ad','敬和崔尚書大明朝堂雨後望終南山見示之作','蘇頲','唐','唐诗','tang','','["\u7ec8\u5357\u5c71"]','奕奕輕車至，清晨朝未央。',168,'全唐诗/poet.tang.4000.json','["奕奕輕車至，清晨朝未央。", "未央在霄極，中路視咸陽。", "委曲漢京近，周廻秦塞長。", "日華動涇渭，天翠合岐梁。", "五丈旌旗色，百層枌橑光。", "東連歸馬地，南指鬬雞場。", "晴壑照金戺，秋雲含璧璫。", "由余窺霸國，蕭相奉興王。", "功役隱不見，頌聲存復揚。", "權宜珍構絕，聖作寶圖昌。", "在德期巢燧，居安法禹湯。", "冢卿才順美，多士賦成章。", "價重三臺俊，名超百郡良。", "焉知掖垣下，陳力自迷方。"]'),
('4e16cfd7-779f-499d-8981-4c18bcb2f103','夜聞故梓州韋使君明當引紼感而成章','蘇頲','唐','唐诗','tang','','[]','惻矣南鄰問，冥然東岱幽。',144,'全唐诗/poet.tang.4000.json','["惻矣南鄰問，冥然東岱幽。", "里閈寧相杵，朝歎忽遷舟。", "君心惟伯仲，吾人復款遊。", "對連時亦早，交喜歲纔周。", "序發扶陽贈，文因司寇酬。", "詎期危露盡，相續逝川流。", "臥疾無三弔，居閑有百憂。", "振風吟鼓夕，明月照帷秋。", "蘚駁題詩館，楊疎奏伎樓。", "共將歌笑歎，轉爲弟兄留。", "感物存如夢，觀生去若浮。", "余非忘情者，雪涕報林丘。"]'),
('cafb9d75-dac5-44e1-8cab-378fadc05fe0','御箭連中雙兔','蘇頲','唐','唐诗','tang','','[]','宸遊經上苑，羽獵向閑田。',72,'全唐诗/poet.tang.4000.json','["宸遊經上苑，羽獵向閑田。", "狡兔初迷窟，纖驪詎著鞭。", "三驅仍百步，一發遂雙連。", "影射含霜草，魂消向月弦。", "歡聲動寒木，喜氣滿晴天。", "那似陳王意，空隨樂府篇。"]'),
('e82534a1-6ce6-4bc3-95d0-1dae1fd46926','奉和聖製過潼津關','蘇頲','唐','唐诗','tang','','[]','在德何夷險，觀風復往還。',24,'全唐诗/poet.tang.4000.json','["在德何夷險，觀風復往還。", "自能同善閉，中路可無關。"]'),
('073133f4-f34c-44ec-acb2-660756d928a1','山鷓鴣詞二首 一','蘇頲','唐','唐诗','tang','','[]','玉關征戍久，空閨人獨愁。',24,'全唐诗/poet.tang.4000.json','["玉關征戍久，空閨人獨愁。", "寒露濕青苔，別來蓬鬢秋。"]'),
('06f70a3e-e6da-4a66-b6b9-bb42a35b51ed','山鷓鴣詞二首 二','蘇頲','唐','唐诗','tang','','[]','人坐青樓晚，鶯語百花時。',24,'全唐诗/poet.tang.4000.json','["人坐青樓晚，鶯語百花時。", "愁多人易老，斷腸君不知。"]'),
('e1ba6888-e597-44f5-bd3d-bff5269c01ef','汾上驚秋','蘇頲','唐','唐诗','tang','','["\u6292\u60c5", "\u79cb\u5929", "\u548f\u53f2"]','北風吹白雲，萬里渡河汾。',24,'全唐诗/poet.tang.4000.json','["北風吹白雲，萬里渡河汾。", "心緒逢搖落，秋聲不可聞。"]'),
('d64caa29-2d76-4651-a114-b97b4c9b4653','山驛閑臥即事','蘇頲','唐','唐诗','tang','','[]','息燕歸檐靜，飛花落院閑。',24,'全唐诗/poet.tang.4000.json','["息燕歸檐靜，飛花落院閑。", "不愁愁自著，誰道憶鄉關。"]'),
('af472b91-a1ce-4f19-8805-abb0874944b7','將赴益州題小園壁','蘇頲','唐','唐诗','tang','','[]','歲窮惟益老，春至却辭家。',24,'全唐诗/poet.tang.4000.json','["歲窮惟益老，春至却辭家。", "可惜東園樹，無人也作花。"]'),
('af3332e9-634d-45e6-a849-faf191b1b666','詠禮部尚書廳後鵲','蘇頲','唐','唐诗','tang','','[]','懷印喜將歸，窺巢戀且依。',24,'全唐诗/poet.tang.4000.json','["懷印喜將歸，窺巢戀且依。", "自知棲不定，還欲向南飛。"]'),
('3e4e4695-e506-4cda-8fbb-b9bdf36e37c4','詠死兔','蘇頲','唐','唐诗','tang','','[]','兔子死蘭彈，持來挂竹竿。',24,'全唐诗/poet.tang.4000.json','["兔子死蘭彈，持來挂竹竿。", "試將明鏡照，何異月中看。"]'),
('c189fa3a-1dba-46dc-a331-5b3858244833','夜宴安樂公主新宅','蘇頲','唐','唐诗','tang','','[]','車如流水馬如龍，仙使高臺十二重。',32,'全唐诗/poet.tang.4000.json','["車如流水馬如龍，仙使高臺十二重。", "天上初移衡漢匹，可憐歌舞夜相從。"]'),
('b08a0438-59c1-465f-8726-137def260b0a','侍宴桃花園詠桃花應制','蘇頲','唐','唐诗','tang','','[]','桃花灼灼有光輝，無數成蹊點更飛。',32,'全唐诗/poet.tang.4000.json','["桃花灼灼有光輝，無數成蹊點更飛。", "爲見芳林含笑待，遂同溫樹不言歸。"]'),
('02e90122-c223-4ddd-aeca-44a4738a23e7','奉和聖製幸韋嗣立莊應制','蘇頲','唐','唐诗','tang','','[]','樹色參差隱翠微，泉流百尺向空飛。',32,'全唐诗/poet.tang.4000.json','["樹色參差隱翠微，泉流百尺向空飛。", "傳聞此處投竿住，遂使茲辰扈蹕歸。"]'),
('4bcf6a35-c030-4300-8456-c73468bed27b','重送舒公','蘇頲','唐','唐诗','tang','','[]','散騎金貂服綵衣，松花水上逐春歸。',32,'全唐诗/poet.tang.4000.json','["散騎金貂服綵衣，松花水上逐春歸。", "懸知邑里遙相望，事主榮親代所稀。"]'),
('960b0f7c-d350-46a9-a562-6f9c11924001','句','蘇頲','唐','唐诗','tang','','[]','飛埃結紅霧，遊蓋飄青雲。',44,'全唐诗/poet.tang.4000.json','["飛埃結紅霧，遊蓋飄青雲。", "指如十挺墨，耳似兩張匙。", "丑雖有足，甲不全身。", "見君無口，知伊少人。"]'),
('1968045e-1a76-4187-b179-c5d9f91e862a','龍池篇','姜晞','唐','唐诗','tang','','[]','靈沼縈廻邸第前，浴日涵春寫曙天。',64,'全唐诗/poet.tang.4000.json','["靈沼縈廻邸第前，浴日涵春寫曙天。", "始見龍臺昇鳳闕，應如霄漢起神泉。", "石匱渚傍還啓聖，桃李初生更有仙。", "欲化帝圖從此受，正同河變一千年。"]'),
('fc0f58f9-78ac-4a46-960e-e062279aae09','龍池篇','姜皎','唐','唐诗','tang','','[]','龍池初出此龍山，常經此地謁龍顏。',64,'全唐诗/poet.tang.4000.json','["龍池初出此龍山，常經此地謁龍顏。", "日日芙蓉生夏水，年年楊柳變春灣。", "堯壇寶匣餘煙霧，舜海漁舟尚往還。", "願似飄颻五雲影，從來從去九天關。"]'),
('c07ae22d-3b74-4882-9ff9-2192cffa7cb8','奉和聖製龍池篇','蔡孚','唐','唐诗','tang','','[]','帝宅王家大道邊，神馬潛龍湧聖泉。',64,'全唐诗/poet.tang.4000.json','["帝宅王家大道邊，神馬潛龍湧聖泉。", "昔日昔時經此地，看來看去漸成川。", "歌臺舞榭宜正月，柳岸梅洲勝往年。", "莫疑波上春雲少，祗爲從龍直上天。"]'),
('d6e774be-f813-4612-a0b9-fe0f06ce52df','打毬篇','蔡孚','唐','唐诗','tang','','[]','德陽宮北苑東頭，雲作高臺月作樓。',144,'全唐诗/poet.tang.4000.json','["德陽宮北苑東頭，雲作高臺月作樓。", "金鎚玉鎣千金地，寶杖琱文七寶毬。", "竇融一家三尚主，梁翼頻封萬戶侯。", "容色由來荷恩顧，意氣平生事俠游。", "共道用兵如斷蔗，俱能走馬入長楸。", "紅鬣錦鬃風騄驥，黃絡青絲電紫騮。", "奔星亂下花場裏，初月飛來畫杖頭。", "自有長鳴須決勝，能馳迅走滿先籌。", "薄暮漢宮愉樂罷，還歸堯室曉垂旒。"]'),
('a4cbfbef-0ae9-4323-be18-1c0d2d6b1765','阮公體','徐晶','唐','唐诗','tang','','[]','秦王按劒怒，發卒戍龍沙。',48,'全唐诗/poet.tang.4000.json','["秦王按劒怒，發卒戍龍沙。", "雄圖尚未畢，海內已紛拏。", "黃塵暗天起，白日斂精華。", "唯見長城外，僵屍如亂麻。"]'),
('7ffe32aa-74ce-4b31-88c0-d968a9c25868','同蔡孚五亭詠','徐晶','唐','唐诗','tang','','[]','章奏中京罷，雲泉別業歸。',48,'全唐诗/poet.tang.4000.json','["章奏中京罷，雲泉別業歸。", "拂琴鋪野席，牽柳挂朝衣。", "翡翠巢書幌，鴛鴦立釣磯。", "幽栖可憐處，春事滿林扉。"]'),
('7bf5474c-9599-4d70-a33e-d6b3762a8a92','蔡起居山亭','徐晶','唐','唐诗','tang','','[]','文史歸休日，棲閑臥草亭。',48,'全唐诗/poet.tang.4000.json','["文史歸休日，棲閑臥草亭。", "薔薇一架紫，石竹數重青。", "垂露和仙藥，燒香誦道經。", "莫將山水弄，持與世人聽。"]'),
('4a786eb7-31b2-40aa-aa3f-e3b4f413d20d','送友人尉蜀中','徐晶','唐','唐诗','tang','','[]','故友漢中尉，請爲西蜀吟。',48,'全唐诗/poet.tang.4000.json','["故友漢中尉，請爲西蜀吟。", "人家多種橘，風土愛彈琴。", "水向昆明闊，山連大夏深。", "理閑無別事，時寄一登臨。"]'),
('f2af7241-0327-4b95-8a7d-8b8ff273c259','贈溫駙馬汝陽王','徐晶','唐','唐诗','tang','','[]','疇昔承餘論，文章幸濫推。',120,'全唐诗/poet.tang.4000.json','["疇昔承餘論，文章幸濫推。", "夜陪銀漢賞，朝奉桂山詞。", "梁邸調歌日，秦樓按舞時。", "登高頻作賦，體物屢爲詩。", "連騎長楸下，浮觴曲水湄。", "北堂留上客，南陌送佳期。", "憶昨陪臨泛，于今阻宴私。", "再看冬雪滿，三見夏花滋。", "都尉朝青閣，淮王侍紫墀。", "寧知倦遊者，華髪老京師。"]'),
('7019fd63-f6fd-4cd5-a2e5-671078b50111','邊詞','張敬忠','唐','唐诗','tang','','["\u6625\u5929", "\u8fb9\u585e"]','五原春色舊來遲，二月垂楊未挂絲。',32,'全唐诗/poet.tang.4000.json','["五原春色舊來遲，二月垂楊未挂絲。", "即今河畔冰開日，正是長安花落時。"]'),
('92b10870-5311-40de-9320-deff9ca2990e','戲詠','張敬忠','唐','唐诗','tang','','[]','有意嫌兵部，專心望考功。',24,'全唐诗/poet.tang.4000.json','["有意嫌兵部，專心望考功。", "誰知脚蹭蹬，幾落省牆東。"]'),
('21471a45-63f0-4f96-8ba7-3b9ac2a162a5','題巴州光福寺楠木','史俊','唐','唐诗','tang','','[]','近郭城南山寺深，亭亭奇樹出禪林。',112,'全唐诗/poet.tang.4000.json','["近郭城南山寺深，亭亭奇樹出禪林。", "結根幽壑不知歲，聳幹摩天凡幾尋。", "翠色晚將嵐氣合，月光時有夜猨吟。", "經行綠葉望成蓋，宴坐黃花長滿襟。", "此木嘗聞生豫章，今朝獨秀在巴鄉。", "凌霜不肯讓松柏，作宇由來稱棟梁。", "會待良工時一眄，應歸法水作慈航。"]'),
('74d13adc-024e-48c2-9a96-ebaf0bd5f1af','儀坤廟樂章 永和','徐彥伯','唐','唐诗','tang','','[]','猗若清廟，肅肅熒熒。',40,'全唐诗/poet.tang.4000.json','["猗若清廟，肅肅熒熒。", "國薦嚴祀，坤興淑靈。", "有几在室，有樂在庭。", "臨茲孝享，百祿惟寧。"]'),
('92f91dcc-2a26-4bc4-93ca-aa2d0811fe47','儀坤廟樂章 金奏','徐彥伯','唐','唐诗','tang','','[]','陰靈效祉，軒曜降精。',40,'全唐诗/poet.tang.4000.json','["陰靈效祉，軒曜降精。", "祥符淑氣，慶集柔明。", "瑤俎既列，雕桐發聲。", "徽猷永遠，比德皇英。"]'),
('07392d27-cd64-4ece-81c2-bff93cec802f','擬古三首 一','徐彥伯','唐','唐诗','tang','','[]','遙裔煙嶼鴻，雙影旦夕同。',84,'全唐诗/poet.tang.4000.json','["遙裔煙嶼鴻，雙影旦夕同。", "交翰倚沙月，和鳴弄江風。", "𦶜若茂芳序，君子從遠戎。", "雲生陰海沒，花落春潭空。", "紅淚掩促柱，錦衾羅薰籠。", "自傷瓊草綠，詎惜鉛粉紅。", "裂帛附雙燕，爲予向遼東。"]'),
('6f6cf477-56b1-4cae-98c1-6767f931f43c','擬古三首 二','徐彥伯','唐','唐诗','tang','','[]','讀書三十載，馳騖周六經。',132,'全唐诗/poet.tang.4000.json','["讀書三十載，馳騖周六經。", "儒衣干時主，忠策獻闕廷。", "一朝奉休盼，從容廁羣英。", "束身趨建禮，秉筆坐承明。", "廨署相填噎，僚吏紛縱橫。", "五日休澣時，屠蘇繞玉屏。", "橘花覆北沼，桂樹交西榮。", "樹棲兩鴛鴦，含春向我鳴。", "皎潔綺羅豔，便娟絲管清。", "擾擾天地間，出處各有情。", "何必巖石下，枯槁閑此生。"]'),
('dcb153ef-db2d-4222-b72e-f762b9f6ef6d','擬古三首 三','徐彥伯','唐','唐诗','tang','','[]','頽光無淹晷，逝水有迅流。',144,'全唐诗/poet.tang.4000.json','["頽光無淹晷，逝水有迅流。", "綠苔紛易歇，紅顏不再求。", "歌笑當及春，無令壯志秋。", "弱年仕關輔，簃門豁御溝。", "敷愉東城際，婉孌南陌頭。", "荷花嬌綠水，楊葉暖青樓。", "中有綺羅人，可憐名莫愁。", "畫屏繞金膝，珠簾懸玉鉤。", "纖指調寶琴，泠泠哀且柔。", "贈君鴛鴦帶，因以鷫鸘裘。", "窗曉吟日坐，閨夕秉燭遊。", "無作北門客，咄咄懷百憂。"]'),
('66bce47c-a620-4325-a2d2-15d8f9029a65','贈劉舍人古意','徐彥伯','唐','唐诗','tang','','[]','女牀閟靈鳥，文章世所希。',108,'全唐诗/poet.tang.4000.json','["女牀閟靈鳥，文章世所希。", "巢君碧梧樹，舞君青瑣闈。", "或言鳳池樂，撫翼更西飛。", "鳳池環禁林，仙閣靄沈沈。", "璇題激流日，珠綴緜清陰。", "郁穆絲言重，熒煌台座深。", "風張丹戺翮，月弄紫庭音。", "衆綵結不散，孤英跂莫尋。", "浩歌在西省，經傳恣潛心。"]'),
('23adc9b6-feae-46b8-bed7-dc3ff8cee505','和李適荅宋十一入崖口五渡見贈','徐彥伯','唐','唐诗','tang','','[]','聞有獨往客，拂衣捐世心。',120,'全唐诗/poet.tang.4000.json','["聞有獨往客，拂衣捐世心。", "結欣薄枉渚，撰念縈舊林。", "經亙去崖合，冥緜歸壑深。", "琪樹環碧彩，金潭生翠陰。", "沿洄弄沙榜，詭仄眺明岑。", "夕聞桂裏猿，曉玩松上禽。", "雜佩蘊孤袖，瓊敷綴雙襟。", "我懷滄州想，懿爾白雲吟。", "秉願理方協，存期跡易尋。", "茲言庶不負，爲報巖中琴。"]'),
('a522ec36-b5d3-451d-9915-aa2aa033611e','雪','徐彥伯','唐','唐诗','tang','','[]','雪暗窮海雲，灑空紛似露。',48,'全唐诗/poet.tang.4000.json','["雪暗窮海雲，灑空紛似露。", "朔風吹故里，宛轉玉階樹。", "孤妾調玉瑟，早寒生錦衿。", "況君張羅幕，愁坐北庭陰。"]'),
('03d35693-84ca-4c7c-bf03-14c690229114','比干墓','徐彥伯','唐','唐诗','tang','','[]','大位天下寶，維賢國之鎮。',264,'全唐诗/poet.tang.4000.json','["大位天下寶，維賢國之鎮。", "殷道微而在，受辛纂頹胤。", "山鳴鬼又哭，地裂川亦震。", "媟黷皆佞諛，虔劉盡英雋。", "孤卿帝叔父，特進貞而順。", "玉牀逾皜潔，銅柱方歊焮。", "奉國歷三朝，觀竅明一瞬。", "季代猖狂主，蓄怒提白刃。", "之子彌忠讜，憤然更勇進。", "撫膺誓隕越，知死故不恡。", "已矣竟剖心，哲婦亦同殉。", "驪龍暴雙骨，太嶽摧孤仞。", "周發次商郊，冤骸悲莫殣。", "鋒劒剿遺孽，報復一何迅。", "駐罕歌淑靈，命徒對旅櫬。", "自爾銜幽酷，于嗟流景駿。", "丘墳被宿莽，壇戺緣飛燐。", "貞觀戒北征，維皇念忠信。", "荒墳護草木，刻桷吹煨燼。", "代遠恩更崇，身頹名益振。", "帝詞書樂石，國饌羅芳衅。", "偉哉烈士圖，奇英千古徇。"]'),
('15a49db0-2593-4970-8c06-575793339ef5','題東山子李適碑陰二首 一','徐彥伯','唐','唐诗','tang','','[]','隴嶂縈紫氣，金光赫氛氳。',48,'全唐诗/poet.tang.4000.json','["隴嶂縈紫氣，金光赫氛氳。", "美人含遙靄，桃李芳自薰。", "圖高黃鶴羽，寶奪驪龍羣。", "忽驚薤露曲，掩噎東山雲。"]'),
('c506501a-0db9-4711-af71-ff9a4c843ab0','題東山子李適碑陰二首 二','徐彥伯','唐','唐诗','tang','','[]','回也寔夭折，賈生亦脆促。',48,'全唐诗/poet.tang.4000.json','["回也寔夭折，賈生亦脆促。", "今復哀若人，危光迅風燭。", "夜臺淪清鏡，窮塵埋結綠。", "何以贈下泉，生芻唯一束。"]'),
('5d3d7e2a-a3e2-49a1-8715-885be099d975','淮亭吟','徐彥伯','唐','唐诗','tang','','[]','貞寂慮兮淮山幽，憐芳若兮{臨/手}中洲。',147,'全唐诗/poet.tang.4000.json','["貞寂慮兮淮山幽，憐芳若兮{臨/手}中洲。", "崩湍委咽日夜流，孤客危坐心自愁。", "矧鶴唳兮風曉，復猿鳴兮霜秋。", "熠耀飛兮蟋蟀吟，倚清瑟兮橫涼琴。", "擷瑤芳兮弔楚水，弄琪樹兮歌越岑。", "山碕礒兮隈曲，水涓漣兮洞汩。", "金光延起兮驟興沒，青苔竟兮綠蘋歇。", "綠蘋歇兮凋朱顏，美人寂歷兮何時閑。", "君不見可憐桐柏上，丰茸桂樹花滿山。"]'),
('55378635-c0b2-4981-8ebd-984f701254f3','芳樹','徐彥伯','唐','唐诗','tang','','[]','玉花珍簟上，金縷畫屏開。',56,'全唐诗/poet.tang.4000.json','["玉花珍簟上，金縷畫屏開。", "曉月憐箏柱，春風憶鏡臺。", "箏柱春風吹曉月，芳樹落花朝暝歇。", "藁砧刀頭未有期，攀條拭淚坐相思。"]'),
('27d55004-2190-445a-ae0d-93019399814c','遊禁苑幸臨渭亭遇雪應制','徐彥伯','唐','唐诗','tang','','[]','玉律藏冰候，彤階飛雪時。',48,'全唐诗/poet.tang.4000.json','["玉律藏冰候，彤階飛雪時。", "日寒消不盡，風定舞還遲。", "瓊樹留宸矚，璇花入睿詞。", "懸知穆天子，黃竹謾言詩。"]'),
('639e344f-ab9d-4e52-9636-522c1a2ab6c7','奉和送金城公主適西蕃應制','徐彥伯','唐','唐诗','tang','','[]','鳳扆憐簫曲，鸞閨念掌珍。',48,'全唐诗/poet.tang.4000.json','["鳳扆憐簫曲，鸞閨念掌珍。", "羗庭遙築館，廟策重和親。", "星轉銀河夕，花移玉樹春。", "聖心悽送遠，留蹕望征塵。"]'),
('b75f8ca4-73ec-42d4-946c-70114adf3cec','幸白鹿觀應制','徐彥伯','唐','唐诗','tang','','[]','鳳輿乘八景，龜籙向三仙。',48,'全唐诗/poet.tang.4000.json','["鳳輿乘八景，龜籙向三仙。", "日月移平地，雲霞綴小天。", "金童擎紫藥，玉女獻青蓮。", "花洞留宸賞，還旗繞夕煙。"]'),
('82d12488-6e3c-448a-8265-405aad907a9e','胡無人行','徐彥伯','唐','唐诗','tang','','[]','十月繁霜下，征人遠鑿空。',48,'全唐诗/poet.tang.4000.json','["十月繁霜下，征人遠鑿空。", "雲搖錦車節，海照角端弓。", "暗磧埋沙樹，衝飆卷塞蓬。", "方隨膜拜入，歌舞玉門中。"]'),
('a49d9ba0-a3ca-44d1-84ae-0126e317b860','倢伃','徐彥伯','唐','唐诗','tang','','[]','君恩忽斷絕，妾思終未央。',48,'全唐诗/poet.tang.4000.json','["君恩忽斷絕，妾思終未央。", "巾櫛不可見，枕席空餘香。", "窗暗網羅白，階秋苔蘚黃。", "應門寂已閉，流涕向昭陽。"]'),
('a679494b-8d44-46b1-a877-343aeeee8690','採蓮曲','徐彥伯','唐','唐诗','tang','','[]','妾家越水邊，搖艇入江煙。',48,'全唐诗/poet.tang.4000.json','["妾家越水邊，搖艇入江煙。", "既覓同心侶，復采同心蓮。", "折藕絲能脆，開花葉正圓。", "春歌弄明月，歸櫂落花前。"]'),
('48449de7-a3f4-4bb8-8b50-3351b010728c','孤燭歎','徐彥伯','唐','唐诗','tang','','[]','切切夜閨冷，微微孤燭然。',48,'全唐诗/poet.tang.4000.json','["切切夜閨冷，微微孤燭然。", "玉盤紅淚滴，金燼彩光圓。", "煖手縫輕素，嚬蛾續斷弦。", "相思咽不語，回向錦屏眠。"]'),
('b17fa571-dc81-44c9-8dea-bf533a313f1f','閨怨','徐彥伯','唐','唐诗','tang','','[]','征客戍金微，愁閨獨掩扉。',48,'全唐诗/poet.tang.4000.json','["征客戍金微，愁閨獨掩扉。", "塵埃生半榻，花絮落殘機。", "褪暖蠶初臥，巢昏燕欲歸。", "春風日向盡，銜涕作征衣。"]'),
('e140b170-2321-45b7-bc93-32fc6940583f','餞唐州高使君赴任','徐彥伯','唐','唐诗','tang','','[]','香萼媚紅滋，垂條縈綠絲。',48,'全唐诗/poet.tang.4000.json','["香萼媚紅滋，垂條縈綠絲。", "情人拂瑤袂，共惜此芳時。", "驌驦已躑躅，鳥隼方葳蕤。", "跂予望太守，流潤及京師。"]'),
('c28b4557-dc2e-4479-b5f0-c1c5918ac1ab','奉和幸新豐溫泉宮應制','徐彥伯','唐','唐诗','tang','','[]','姬典歌時邁，虞篇記省方。',156,'全唐诗/poet.tang.4000.json','["姬典歌時邁，虞篇記省方。", "何如黑帝月，玄覽白雲鄉。", "翠仗縈船岸，明斾應萯陽。", "風搖花眊彩，雪豔寶戈芒。", "御陌開函次，離宮夾樹行。", "桂枝籠騕褭，松葉覆堂皇。", "仙石含珠液，溫池孕璧房。", "湧疑神瀵溢，澄若帝臺漿。", "獨沸流常熱，潛蒸氣轉香。", "青壇環玉甃，紅礎鑠金光。", "藻曜凝芳潔，葳蕤獻淑祥。", "五龍歸寶算，九鳸叶時康。", "同預華封老，中衢祝聖皇。"]'),
('7f6ae174-8f7a-46cc-acdf-b70ae2699fa9','同韋舍人元旦早朝','徐彥伯','唐','唐诗','tang','','[]','夕轉清壺漏，晨驚長樂鐘。',72,'全唐诗/poet.tang.4000.json','["夕轉清壺漏，晨驚長樂鐘。", "逶迤綸禁客，假寐守銅龍。", "予亦趨三殿，肩隨謁九重。", "繁珂接曙響，華劒比春容。", "相問韶光歇，彌憐芳意濃。", "願言乘日旰，攜手即雲峰。"]'),
('f9219812-4991-4b67-bf28-6c03c5bc994f','侍宴韋嗣立山莊應制','徐彥伯','唐','唐诗','tang','','[]','鼎臣休澣隙，方外結遙心。',96,'全唐诗/poet.tang.4000.json','["鼎臣休澣隙，方外結遙心。", "別業青霞境，孤潭碧樹林。", "每馳東墅策，遙弄北溪琴。", "帝眷紓時豫，台園賞歲陰。", "移鑾明月沼，張組白雲岑。", "御酒瑤觴落，仙壇竹徑深。", "三光懸聖藻，五等冠朝簪。", "自昔皇恩感，咸言獨自今。"]'),
('2db82ea8-264d-4ae4-b437-ae9e05f2a5d7','送特進李嶠入都祔廟','徐彥伯','唐','唐诗','tang','','[]','特進三公下，台臣百揆先。',96,'全唐诗/poet.tang.4000.json','["特進三公下，台臣百揆先。", "孝圖開寢石，祠主卜牲筵。", "恩級青綸賜，徂裝紫橐懸。", "綢繆金鼎席，宴餞玉潢川。", "北斗分征路，東山起贈篇。", "樂池歌綠藻，梁苑藉紅荃。", "騎轉商巖日，旌搖關塞煙。", "廟堂須鯁議，錦節佇來旋。"]'),
('f18a2a2d-2c0d-4a00-b5b8-4945581158d8','春閨','徐彥伯','唐','唐诗','tang','','[]','戍客戍清波，幽閨幽思多。',72,'全唐诗/poet.tang.4000.json','["戍客戍清波，幽閨幽思多。", "暗梁聞語燕，夜燭見飛蛾。", "寶鴨藏脂粉，金屏綴綺羅。", "裁衣卷紋素，織錦度鳴梭。", "有使通西極，緘書寄北河。", "年光只恐盡，征戰莫蹉跎。"]'),
('1dc42e3d-3286-4aec-b555-83ba0533e4f6','奉和興慶池戲競渡應制','徐彥伯','唐','唐诗','tang','','[]','夾道傳呼翊翠虬，天回日轉御芳洲。',64,'全唐诗/poet.tang.4000.json','["夾道傳呼翊翠虬，天回日轉御芳洲。", "青潭曉靄籠仙蹕，紅嶼晴花隔綵旒。", "香溢金杯環廣坐，聲傳妓舸匝中流。", "羣臣相慶嘉魚樂，共哂橫汾歌吹秋。"]'),
('ec16ab9a-b715-4c53-91c9-35ac727bc649','苑中遇雪應制','徐彥伯','唐','唐诗','tang','','[]','千鍾聖酒御筵披，六出祥英亂繞枝。',32,'全唐诗/poet.tang.4000.json','["千鍾聖酒御筵披，六出祥英亂繞枝。", "即此神仙對瓊圃，何煩轍迹向瑤池。"]'),
('abc7e5a6-52ee-4d5d-a195-9241bfdfd7ed','上巳日祓禊渭濱應制','徐彥伯','唐','唐诗','tang','','[]','晴風麗日滿芳洲，柳色春筵祓錦流。',32,'全唐诗/poet.tang.4000.json','["晴風麗日滿芳洲，柳色春筵祓錦流。", "皆言侍蹕橫汾宴，暫似乘槎天漢遊。"]'),
('d0d51239-1f23-455b-bdbc-93f2d6112f4f','夜宴安樂公主新宅應制','徐彥伯','唐','唐诗','tang','','[]','鳳樓開闔引明光，花酎連添醉益香。',32,'全唐诗/poet.tang.4000.json','["鳳樓開闔引明光，花酎連添醉益香。", "欲知帝女薰天貴，金柯玉柱夜成行。"]'),
('b8ed863d-583e-48d0-9b65-d8fc9c142109','餞唐永昌','徐彥伯','唐','唐诗','tang','','[]','金溪碧水玉潭沙，鳧舄翩翩弄日華。',32,'全唐诗/poet.tang.4000.json','["金溪碧水玉潭沙，鳧舄翩翩弄日華。", "鬬雞香陌行春倦，爲摘東園桃李花。"]'),
('1f7eeddb-acc8-4780-a3bb-384d09656150','侍宴桃花園','徐彥伯','唐','唐诗','tang','','[]','源水叢花無數開，丹跗紅萼間青梅。',32,'全唐诗/poet.tang.4000.json','["源水叢花無數開，丹跗紅萼間青梅。", "從今結子三千歲，預喜仙遊復摘來。"]'),
('c7c2a9eb-2e80-433b-8b23-60b6269dc0ee','石淙','徐彥伯','唐','唐诗','tang','','[]','碧淀紅涔崿嶂間，淙嵌洑岨洊成灣。',64,'全唐诗/poet.tang.4000.json','["碧淀紅涔崿嶂間，淙嵌洑岨洊成灣。", "琪樹琁娟花未落，銀芝窋䆛露初還。", "八風行殿開仙牓，七景飛輿下石關。", "張蔦席雲平圃讌，焜煌金記蘊名山。"]'),
('fcfb061b-4209-4925-9ef1-65722bb56781','夏日遊德州贈高四','駱賓王','唐','唐诗','tang','','[]','日觀鄰全趙，星臨俯舊吳。',288,'全唐诗/poet.tang.4000.json','["日觀鄰全趙，星臨俯舊吳。", "鬲津開巨浸，稽阜鎮名都。", "紫雲浮劍匣，青山孕寶符。", "封疆恢霸道，問鼎競雄圖。", "神光包四大，皇威震八區。", "風煙通地軸，星象正天樞。", "天樞限南北，地軸殊鄉國。", "闢門通舜賓，比屋封堯德。", "言謝垂鉤隱，來參負鼎職。", "天子不見知，羣公詎相識。", "未展從東駿，空戢圖南翼。", "時命欲何言，撫膺長嘆息。", "嘆息將如何，遊人意氣多。", "白雪梁山曲，寒風易水歌。", "泣魏傷吳起，思趙切廉頗。", "淒斷韓王劍，生死翟公羅。", "羅悲翟公意，劍負韓王氣。", "驕餌去易論，忌途良可畏。", "夙昔懷江海，平生混涇渭。", "千載契風雲，一言忘賤貴。", "去去訪林泉，空谷有遺賢。", "言投爵里刺，來泛野人船。", "締交君贈縞，投分我忘筌。", "成風郢匠斲，流水伯牙弦。"]'),
('a55784a0-189c-4dc1-b2b2-a38c7dfa3368','在江南贈宋五之問','駱賓王','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','井絡雙源濬，潯陽九派長。',288,'全唐诗/poet.tang.4000.json','["井絡雙源濬，潯陽九派長。", "淪波通地穴，輸委下歸塘。", "別島籠朝蜃，連洲擁夕漲。", "韞珠澄積潤，讓璧動浮光。", "浮光凝折水，積潤疎圓沚。", "玉輪涵地開，劍閣連星起。", "風煙標迥秀，英靈信多美。", "懷德踐遺芳，端操慙謀己。", "謀己謬觀光，牽迹強悽惶。", "揆拙迷三省，勞生昧兩忘。", "彈隨空被笑，獻楚自多傷。", "一朝殊默語，千里易炎涼。", "炎涼幾遷貿，川陸疲臻湊。", "積水架吳濤，連山橫楚岫。", "風月雖殊昔，星河猶是舊。", "姑蘇望南浦，邯鄲通北走。", "北走平生親，南浦別離津。", "瀟湘一超忽，洞庭多苦辛。", "秋江無綠芷，寒汀有白蘋。", "采之將何遺，故人漳水濱。", "漳濱已遼遠，江潭未旋返。", "爲聽短歌行，當想長洲苑。", "露金熏菊岸，風佩搖蘭坂。", "蟬鳴稻葉秋，雁起蘆花晚。"]'),
('62834bab-7430-41b0-a6b9-1070182b62d6','晚憩田家','駱賓王','唐','唐诗','tang','','[]','轉蓬勞遠役，披薜下田家。',96,'全唐诗/poet.tang.4000.json','["轉蓬勞遠役，披薜下田家。", "山形類九折，水勢急三巴。", "懸梁接斷岸，澀路擁崩查。", "霧巖淪曉魄，風漵漲寒沙。", "心迹一朝舛，關山萬里賒。", "龍章徒表越，閩俗本殊華。", "旅行悲泛梗，離贈折疎麻。", "唯有寒潭菊，獨似故園花。"]'),
('ff47213a-4434-48cf-bce5-69b4fd8bd179','出石門','駱賓王','唐','唐诗','tang','','[]','層巖遠接天，絕嶺上棲烟。',36,'全唐诗/poet.tang.4000.json','["層巖遠接天，絕嶺上棲烟。", "松低輕蓋偃，藤細弱絲懸。", "石明如挂鏡，苔分似列錢。"]'),
('841d4cbd-d032-459e-b133-0c86e92682e1','至分陝','駱賓王','唐','唐诗','tang','','[]','陝西開勝壤，召南分沃疇。',48,'全唐诗/poet.tang.4000.json','["陝西開勝壤，召南分沃疇。", "列樹巢維鵲，平渚下雎鳩。", "憩棠疑勿剪，曳葛似攀樛。", "至今王化美，非獨在隆周。"]'),
('cd6611b2-fd72-4f3f-bc20-48f71b7995e5','寓居洛濱對雪憶謝二','駱賓王','唐','唐诗','tang','','[]','旅思眇難裁，衝飆恨易哀。',72,'全唐诗/poet.tang.4000.json','["旅思眇難裁，衝飆恨易哀。", "曠望洛川晚，飄颻瑞雪來。", "積彩明書幌，流韻繞琴臺。", "色奪迎仙羽，花避犯霜梅。", "謝庭賞方逸，袁扉掩未開。", "高人儻有訪，興盡詎須回。"]'),
('8a3e827d-061c-425a-8f3f-dba2fbb7af96','北眺舂陵','駱賓王','唐','唐诗','tang','','[]','攬轡疲宵邁，驅馬倦晨興。',48,'全唐诗/poet.tang.4000.json','["攬轡疲宵邁，驅馬倦晨興。", "既出封泥谷，還過避雨陵。", "山行明照上，谿宿密雲蒸。", "登高徒欲賦，詞殫獨撫膺。"]'),
('9b627e8f-713c-479e-83ad-06dab7c3b064','夏日遊目聊作','駱賓王','唐','唐诗','tang','','[]','暫屏囂塵累，言尋物外情。',48,'全唐诗/poet.tang.4000.json','["暫屏囂塵累，言尋物外情。", "致逸心逾默，神幽體自輕。", "浦夏荷香滿，田秋麥氣清。", "詎假滄浪上，將濯楚臣纓。"]'),
('15a0622c-0b94-4a23-9b6b-6ebe9e1bb573','同崔駙馬曉初登樓思京','駱賓王','唐','唐诗','tang','','[]','麗譙通四望，繁憂起萬端。',48,'全唐诗/poet.tang.4000.json','["麗譙通四望，繁憂起萬端。", "綺疏低晚魄，鏤檻肅初寒。", "白雲鄉思遠，黃圖歸路難。", "唯餘西向笑，暫似當長安。"]'),
('81b62a42-8c52-4769-938d-158861184f1f','月夜有懷簡諸同病','駱賓王','唐','唐诗','tang','','[]','閑庭落景盡，疎簾夜月通。',48,'全唐诗/poet.tang.4000.json','["閑庭落景盡，疎簾夜月通。", "山靈響似應，水淨望如空。", "棲枝猶繞鵲，遵渚未來鴻。", "可歎高樓婦，悲思杳難終。"]'),
('e4ab4c8c-c363-4e55-9ab5-9d1dcdde1789','敘寄員半千','駱賓王','唐','唐诗','tang','','[]','薄宦三河道，自負十餘年。',144,'全唐诗/poet.tang.4000.json','["薄宦三河道，自負十餘年。", "不應驚若厲，秪爲直如弦。", "坐歷山川險，吁嗟陵谷遷。", "長吟空抱膝，短翮詎沖天。", "魂歸滄海上，望斷白雲前。", "釣名勞拾紫，隱迹自談玄。", "不學多能聖，徒思鴻寶仙。", "斯志良難已，此道豈徒然。", "嗟爲刀筆吏，恥從繩墨牽。", "岐路情雖狎，人倫地本偏。", "長揖謝時事，獨往訪林泉。", "寄言二三子，生死不來旋。"]'),
('2517adb9-f684-4ffb-a2f4-5fc261f7fe4c','詠懷古意上裴侍郎','駱賓王','唐','唐诗','tang','','[]','三十二餘罷，鬢是潘安仁。',168,'全唐诗/poet.tang.4000.json','["三十二餘罷，鬢是潘安仁。", "四十九仍入，年非朱買臣。", "縱橫愁繫越，坎壈倦遊秦。", "出籠窮短翮，委轍涸枯鱗。", "窮經不霑用，彈鋏欲誰申。", "天子未驅策，歲月幾沈淪。", "輕生長慷慨，效死獨殷勤。", "徒歌易水客，空老渭川人。", "一得視邊塞，萬里何苦辛。", "劍匣胡霜影，弓開漢月輪。", "金刀動秋色，鐵騎想風塵。", "爲國堅誠款，捐軀忘賤貧。", "勒功思比憲，決略暗欺陳。", "若不犯霜雪，虛擲玉京春。"]'),
('99c03343-3f55-457d-9f4d-d554f9c689b6','春夜韋明府宅宴得春字','駱賓王','唐','唐诗','tang','','[]','酌桂陶芳夜，披薜嘯幽人。',48,'全唐诗/poet.tang.4000.json','["酌桂陶芳夜，披薜嘯幽人。", "雅琴馴魯雉，清歌落范塵。", "宿雲低迥蓋，殘月上虛輪。", "幸此承恩洽，聊當故鄉春。"]'),
('476087fe-881e-47af-a337-e324da7f2e4c','過張平子墓','駱賓王','唐','唐诗','tang','','[]','西鄂該通理，南陽擅德音。',60,'全唐诗/poet.tang.4000.json','["西鄂該通理，南陽擅德音。", "玉巵浮藻麗，銅渾積思深。", "忽懷今日昔，非復昔時今。", "日落豐碑暗，風來古木吟。", "惟歎窮泉下，終鬱羨魚心。"]'),
('f6537b9c-e947-4b5b-b906-372aa3e8b973','從軍中行路難二首 一','駱賓王','唐','唐诗','tang','','[]','君不見封狐雄虺自成羣，馮深負固結妖氛。',343,'全唐诗/poet.tang.4000.json','["君不見封狐雄虺自成羣，馮深負固結妖氛。", "玉璽分兵徵惡少，金壇受律動將軍。", "將軍擁旄宣廟略，戰士橫行靜夷落。", "長驅一息背銅梁，直指三巴登劍閣。", "閣道岧嶤起戍樓，劍門遙裔俯靈丘。", "邛關九折無平路，江水雙源有急流。", "征役無期返，他鄉歲華晚。", "杳杳丘陵出，蒼蒼林薄遠。", "途危紫蓋峰，路澀青泥坂。", "去去指哀牢，行行入不毛。", "絕壁千里險，連山四望高。", "中外分區宇，夷夏殊風土。", "交趾枕南荒，昆彌臨北戶。", "川原繞毒霧，溪谷多淫雨。", "行潦四時流，崩查千歲古。", "漂梗飛蓬不自安，捫藤引葛度危巒。", "昔時聞道從軍樂，今日方知行路難。", "滄江綠水東流駛，炎洲丹徼南中地。", "南中南斗映星河，秦川秦塞阻煙波。", "三春邊地風光少，五月瀘中瘴癘多。", "朝驅疲斥候，夕息倦樵歌。", "向月彎繁弱，連星轉太阿。", "重義輕生懷一顧，東伐西征凡幾度。", "夜夜朝朝斑鬢新，年年歲歲戎衣故。"]'),
('a1a4dc5e-9d1c-4ed8-8357-605d76f92f34','從軍中行路難二首 二','駱賓王','唐','唐诗','tang','','[]','君不見玉關塵色暗邊庭，銅鞮雜虜寇長城。',211,'全唐诗/poet.tang.4000.json','["君不見玉關塵色暗邊庭，銅鞮雜虜寇長城。", "天子按劍徵餘勇，將軍受脤事橫行。", "七德龍韜開玉帳，千里鼉鼓壘金鉦。", "陰山苦霧埋高壘，交河孤月照連營。", "連營去去無窮極，擁斾遙遙過絕國。", "陣雲朝結晦天山，寒沙夕漲迷疎勒。", "龍鱗水上開魚貫，馬首山前振雕翼。", "長驅萬里讋祈連，分麾三命武功宣。", "百發烏號遙碎柳，七尺龍文迥照蓮。", "春來秋去移灰琯，蘭閨柳市芳塵斷。", "雁門迢遞尺書稀，鴛被相思雙帶緩。", "行路難，行路難，誓令氛祲靜臯蘭。", "但使封侯龍頟貴，詎隨中婦鳳樓寒。"]'),
('1073d277-650a-4736-a248-952252e4e342','帝京篇','駱賓王','唐','唐诗','tang','','[]','山河千里國，城闕九重門。',348,'全唐诗/poet.tang.4000.json','["山河千里國，城闕九重門。", "不覩皇居壯，安知天子尊。", "皇居帝里崤函谷，鶉野龍山侯甸服。", "五緯連影集星躔，八水分流橫地軸。", "秦塞重關一百二，漢家離宮三十六。", "桂殿嶔岑對玉樓，椒房窈窕連金屋。", "三條九陌麗城隈，萬戶千門平旦開。", "複道斜通鳷鵲觀，交衢直指鳳皇臺。", "劍履南宮入，簪纓北闕來。", "聲名冠寰宇，文物象昭回。", "鉤陳肅蘭戺，璧沼浮槐市。", "銅羽應風回，金莖承露起。", "校文天祿閣，習戰昆明水。", "朱邸抗平臺，黃扉通戚里。", "平臺戚里帶崇墉，炊金饌玉待鳴鐘。", "小堂綺帳三千戶，大道青樓十二重。", "寶蓋雕鞍金絡馬，蘭窗繡柱玉盤龍。", "繡柱璇題粉壁映，鏘金鳴玉王侯盛。", "王侯貴人多近臣，朝遊北里暮南鄰。", "陸賈分金將讌喜，陳遵投轄正留賓。", "趙李經過密，蕭朱交結親。", "丹鳳朱城白日暮，青牛紺幰紅塵度。", "俠客珠彈垂楊道，倡婦銀鉤采桑路。", "倡家桃李自芳菲，京華遊俠盛輕肥。"]'),
('3f7a1d13-870a-40bf-8315-9ee29123659d','疇昔篇','駱賓王','唐','唐诗','tang','','[]','少年重英俠，弱歲賤衣冠。',340,'全唐诗/poet.tang.4000.json','["少年重英俠，弱歲賤衣冠。", "既託寰中賞，方承膝下歡。", "遨遊灞水曲，風月洛城端。", "且知無玉饌，誰肯逐金丸。", "金丸玉饌盛繁華，自言輕侮季倫家。", "五霸爭馳千里馬，三條競騖七香車。", "掩映飛軒乘落照，參差步障引朝霞。", "池中舊水如懸鏡，屋裏新妝不讓花。", "意氣風雲倏如昨，歲月春秋屢回薄。", "上苑頻經柳絮飛，中園幾見梅花落。", "當時門客今何在？疇昔交朋已疎索。", "莫教憔悴損容儀，會得高秋雲霧廓。", "淹留坐帝鄉，無事積炎涼。", "一朝披短褐，六載奉長廊。", "賦文慙昔馬，執戟歎前揚。", "揮戈出武帳，荷筆入文昌。", "文昌隱隱皇城裏，由來奕奕多才子。", "潘陸詞鋒駱驛飛，張曹翰苑縱橫起。", "卿相未曾識，王侯寧見擬。", "垂釣甘成白首翁，負薪何處逢知己？", "判將運命賦窮通，從來奇舛任西東。", "不應永棄同芻狗，且復飄颻類轉蓬。", "容鬢年年異，春華歲歲同。", "榮觀未盡禮，徇主欲申功。"]'),
('37dcb266-35d0-4cb3-9b17-89e33e8b78e7','豔情代郭氏荅盧照鄰','駱賓王','唐','唐诗','tang','','[]','迢迢芊路望芝田，眇眇函關恨蜀川。',380,'全唐诗/poet.tang.4000.json','["迢迢芊路望芝田，眇眇函關恨蜀川。", "歸雲已落涪江外，還雁應過洛水瀍。", "洛水傍連帝城側，帝宅層甍垂鳳翼。", "銅駝路上柳千條，金谷園中花幾色。", "柳葉園花處處新，洛陽桃李應芳春。", "妾向雙流窺石鏡，君住三川守玉人。", "此時離別那堪道，此日空牀對芳沼。", "芳沼徒遊比目魚，幽徑還生拔心艸。", "流風回雪儻便娟，驥子魚文實可憐。", "擲果河陽君有分，貨酒成都妾亦然。", "莫言貧賤無人重，莫言富貴應須種。", "綠珠猶得石崇憐，飛燕曾經漢皇寵。", "良人何處醉縱橫？直如循默守空名。", "倒提新縑成慊慊，翻將故劍作平平。", "離前吉夢成蘭兆，別後啼痕上竹生。", "別日分明相約束，已取宜家成誡勖。", "當時擬弄掌中珠，豈謂先摧庭際玉。", "悲鳴五里無人問，腸斷三聲誰爲續。", "思君欲上望夫臺，端居懶聽將雛曲。", "沈沈落日向山低，檐前歸燕竝頭栖。", "抱膝當窗看夕兔，側耳空房聽曉雞。", "舞蝶臨階秪自舞，啼鳥逢人亦助啼。", "獨坐傷孤枕，春來悲更甚。", "峨眉山上月如眉，濯錦江中霞似錦。"]'),
('f2aedb6a-3ea2-455f-94b5-0347dd126a21','代女道士王靈妃贈道士李榮','駱賓王','唐','唐诗','tang','','[]','玄都五府風塵絕，碧海三山波浪深。',384,'全唐诗/poet.tang.4000.json','["玄都五府風塵絕，碧海三山波浪深。", "桃實千年非易待，桑田一變已難尋。", "別有仙居對三市，金闕銀宮相向起。", "臺前鏡影伴仙娥，樓上簫聲隨鳳史。", "鳳樓迢遞絕塵埃，鶯時物色正裴回。", "靈芝紫檢參差長，仙桂丹花重疊開。", "雙童綽約時遊陟，三鳥聯翩報消息。", "盡言真侶出遨遊，傳道風光無限極。", "輕花委砌惹裾香，殘月窺窗覘幌色。", "箇時無數倂妖妍，箇裏無窮總可憐。", "別有衆中稱黜帝，天上人間少流例。", "洛濱仙駕啓遙源，淮浦靈津符遠筮。", "自言少小慕幽玄，只言容易得神仙。", "珮中邀勒經時序，簫裏尋思復幾年。", "尋思許事真情變，二人容華識少選。", "漫道燒丹止七飛，空傳化石曾三轉。", "寄語天上弄機人，寄語河邊值查客。", "乍可悤悤共百年，誰使遙遙期七夕。", "想知人意自相尋，果得深心共一心。", "一心一意無窮已，投漆投膠非足擬。", "只將羞澀當風流，持此相憐保終始。", "相憐相念倍相親，一生一代一雙人。", "不把丹心比玄石，惟將濁水況清塵。", "只言柱下留期信，好欲將心學松蕣。"]'),
('8469e6ef-1e50-41c1-869c-be8ca42efc7e','從軍行','駱賓王','唐','唐诗','tang','','[]','平生一顧重，意氣溢三軍。',48,'全唐诗/poet.tang.4000.json','["平生一顧重，意氣溢三軍。", "埜日分戈影，天星合劍文。", "弓弦抱漢月，馬足踐胡塵。", "不求生入塞，唯當死報君。"]'),
('24d8a8be-11d7-4b13-8e09-6e923f6486e1','王昭君','駱賓王','唐','唐诗','tang','','[]','歛容辭豹尾，緘恨度龍鱗。',48,'全唐诗/poet.tang.4000.json','["歛容辭豹尾，緘恨度龍鱗。", "金鈿明漢月，玉筯染胡塵。", "古鏡菱花暗，愁眉柳葉顰。", "唯有清笳曲，時聞芳樹春。"]'),
('227f5573-870b-4e59-88c5-3ee310ba87f6','於紫雲觀贈道士','駱賓王','唐','唐诗','tang','','[]','碧落澄秋景，玄門啓曙關。',48,'全唐诗/poet.tang.4000.json','["碧落澄秋景，玄門啓曙關。", "人疑列禦至，客似令威還。", "羽蓋徒欣仰，雲車未可攀。", "衹應傾玉醴，時許寄頹顏。"]'),
('48804762-1db7-43cb-b548-7fd9eb410d83','渡瓜步江','駱賓王','唐','唐诗','tang','','[]','捧檄辭幽徑，鳴榔下貴洲。',48,'全唐诗/poet.tang.4000.json','["捧檄辭幽徑，鳴榔下貴洲。", "驚濤疑躍馬，積氣似連牛。", "月迥寒沙淨，風急夜江秋。", "不學浮雲影，他鄉空滯留。"]'),
('5996e4b6-e6be-400a-bff8-46efce32bac2','途中有懷','駱賓王','唐','唐诗','tang','','[]','睠然懷楚奏，悵矣背秦關。',48,'全唐诗/poet.tang.4000.json','["睠然懷楚奏，悵矣背秦關。", "涸鱗驚照轍，墜羽怯虛彎。", "素服三川化，烏裘十上還。", "莫言無皓齒，時俗薄朱顏。"]'),
('2fd24380-2a77-4f91-8821-a66aaa76655a','至分水戍','駱賓王','唐','唐诗','tang','','[]','行役忽離憂，復此愴分流。',48,'全唐诗/poet.tang.4000.json','["行役忽離憂，復此愴分流。", "濺石回湍咽，縈叢曲澗幽。", "陰巖常結晦，宿莽競含秋。", "況乃霜晨早，寒風入戍樓。"]'),
('b1e35830-cf22-47cf-b558-966d41ac08b2','望鄉夕泛','駱賓王','唐','唐诗','tang','','[]','歸懷剩不安，促榜犯風瀾。',48,'全唐诗/poet.tang.4000.json','["歸懷剩不安，促榜犯風瀾。", "落宿含樓近，浮月帶江寒。", "喜逐行前至，憂從望裏寬。", "今夜南枝鵲，應無繞樹難。"]'),
('72f740d8-ad52-4299-83a2-5a13f315a7f9','久客臨海有懷','駱賓王','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','天涯非日觀，地屺望星樓。',48,'全唐诗/poet.tang.4000.json','["天涯非日觀，地屺望星樓。", "練光搖亂馬，劍氣上連牛。", "草濕姑蘇夕，葉下洞庭秋。", "欲知悽斷意，江上涉安流。"]'),
('67da108e-ffff-42a1-bfef-b8e1e6ee831e','遊兗部逢孔君自衞來欣然相遇若舊','駱賓王','唐','唐诗','tang','','[]','遊人自衞返，背客隔淮來。',48,'全唐诗/poet.tang.4000.json','["遊人自衞返，背客隔淮來。", "傾蓋金蘭合，忘筌玉葉開。", "繁花明日柳，疎蕊落風梅。", "將期重交態，時慰不然灰。"]'),
('ff5c4d33-2b95-4ada-9b69-b04cc22a2835','西京守歲','駱賓王','唐','唐诗','tang','','[]','閑居寡言宴，獨坐慘風塵。',48,'全唐诗/poet.tang.4000.json','["閑居寡言宴，獨坐慘風塵。", "忽見嚴冬盡，方知列宿春。", "夜將寒色去，年共曉光新。", "耿耿他鄉夕，無由展舊親。"]'),
('aee1d767-5c3a-4de7-b9c4-1b9c2958f1df','同辛簿簡仰酬思玄上人林泉四首 一','駱賓王','唐','唐诗','tang','','[]','聞君招隱地，髣髴武陵春。',48,'全唐诗/poet.tang.4000.json','["聞君招隱地，髣髴武陵春。", "緝芰知還楚，披榛似避秦。", "崩查年祀積，幽草歲時新。", "一謝滄浪水，安知有逸人。"]'),
('7afdc3f0-ecdd-45fa-8f19-a9a918688460','同辛簿簡仰酬思玄上人林泉四首 二','駱賓王','唐','唐诗','tang','','[]','芳晨臨上月，幽賞狎中園。',48,'全唐诗/poet.tang.4000.json','["芳晨臨上月，幽賞狎中園。", "有蝶堪成夢，無羊可觸藩。", "忘懷南澗藻，蠲思北堂萱。", "坐歎華滋歇，思君誰爲言。"]'),
('8ff002aa-1c25-4b7c-a2fa-909f2ef83bfd','同辛簿簡仰酬思玄上人林泉四首 三','駱賓王','唐','唐诗','tang','','[]','林泉恣探歷，風景暫裴徊。',48,'全唐诗/poet.tang.4000.json','["林泉恣探歷，風景暫裴徊。", "客有遷鶯處，人無結駟來。", "聚花如薄雪，沸水若輕雷。", "今日徒招隱，終知異鑿坏。"]'),
('fd3d7d7d-478c-47bc-bf7f-8c9a4f5539c0','同辛簿簡仰酬思玄上人林泉四首 四','駱賓王','唐','唐诗','tang','','[]','俗遠風塵隔，春還初服遲。',48,'全唐诗/poet.tang.4000.json','["俗遠風塵隔，春還初服遲。", "林疑中散地，人似上皇時。", "芳杜湘君曲，幽蘭楚客詞。", "山中有春草，長似寄相思。"]'),
('64957b56-388c-4e61-8cf3-b5f557b6b1bc','秋日餞陸道士陳文林','駱賓王','唐','唐诗','tang','','["\u534e\u5c71"]','青牛遊華嶽，赤馬走吳宮。',48,'全唐诗/poet.tang.4000.json','["青牛遊華嶽，赤馬走吳宮。", "玉柱離鴻怨，金罍浮蟻空。", "日霽崤陵雨，塵起洛陽風。", "唯當玄度月，千里與君同。"]'),
('227828e3-4cf2-4248-b96e-1343c0136578','送鄭少府入遼共賦俠客遠從戎','駱賓王','唐','唐诗','tang','','["\u4fa0\u5ba2", "\u9001\u522b"]','邊烽警榆塞，俠客度桑乾。',48,'全唐诗/poet.tang.4000.json','["邊烽警榆塞，俠客度桑乾。", "柳葉開銀鏑，桃花照玉鞍。", "滿月臨弓影，連星入劍端。", "不學燕丹客，空歌易水寒。"]'),
('c0983351-34e7-4c47-a3a2-162d47616a54','送費六還蜀','駱賓王','唐','唐诗','tang','','[]','星樓望蜀道，月峽指吳門。',48,'全唐诗/poet.tang.4000.json','["星樓望蜀道，月峽指吳門。", "萬行流別淚，九折切驚魂。", "雪影含花落，雲陰帶葉昏。", "還愁三徑晚，獨對一清尊。"]'),
('195b1741-f2ae-4a66-8eb2-6c9b38412364','秋日送侯四得彈字','駱賓王','唐','唐诗','tang','','[]','我留安豹隱，君去學鵬摶。',48,'全唐诗/poet.tang.4000.json','["我留安豹隱，君去學鵬摶。", "岐路分襟易，風雲促膝難。", "夕漲流波急，秋山落日寒。", "惟有思歸引，悽斷爲君彈。"]'),
('e727d037-44cc-44bf-9909-732df0162e7a','秋日送尹大赴京','駱賓王','唐','唐诗','tang','','[]','挂瓢余隱舜，負鼎爾干湯。',48,'全唐诗/poet.tang.4000.json','["挂瓢余隱舜，負鼎爾干湯。", "竹葉離罇滿，桃花別路長。", "低河耿秋色，落月抱寒光。", "素書如可嗣，幽谷竚賓行。"]'),
('e305ee57-72fc-42f3-9421-bd88d33157d0','秋夜送閰五還潤州','駱賓王','唐','唐诗','tang','','[]','通莊抵舊里，溝水泣新知。',48,'全唐诗/poet.tang.4000.json','["通莊抵舊里，溝水泣新知。", "斷雲飄易滯，連露積難披。", "素風啼迥堞，驚月繞疎枝。", "無力勵短翰，輕舉送長離。"]'),
('4a4c207d-d884-4123-b01c-90dd5f012dc9','送王明府參選賦得鶴','駱賓王','唐','唐诗','tang','','[]','振衣遊紫府，飛蓋背青田。',48,'全唐诗/poet.tang.4000.json','["振衣遊紫府，飛蓋背青田。", "虛心恆警露，孤影尚凌煙。", "離歌悽妙曲，別操繞繁弦。", "在陰如可和，輕響會聞天。"]'),
('b9f4bd5f-2ecb-4a79-85b7-eaea498e7b86','秋日送別','駱賓王','唐','唐诗','tang','','[]','寂寥心事晚，搖落歲時秋。',48,'全唐诗/poet.tang.4000.json','["寂寥心事晚，搖落歲時秋。", "共此傷年髪，相看惜去留。", "當歌應破涕，哀命返窮愁。", "別後能相憶，東陵有故侯。"]'),
('a907cd8f-d460-4840-8d8f-4efe8868d1c2','別李嶠得勝字','駱賓王','唐','唐诗','tang','','[]','芳尊徒自滿，別恨轉難勝。',48,'全唐诗/poet.tang.4000.json','["芳尊徒自滿，別恨轉難勝。", "客似遊江岸，人疑上灞陵。", "寒更承夜永，涼景向秋澄。", "離心何以贈，自有玉壺冰。"]'),
('d152da55-3805-4d82-99b6-62c80cfd3ff0','在衮州餞宋五之問','駱賓王','唐','唐诗','tang','','[]','淮沂泗水地，梁甫汶陽東。',48,'全唐诗/poet.tang.4000.json','["淮沂泗水地，梁甫汶陽東。", "別路青驪遠，離尊綠蟻空。", "柳寒凋密翠，棠晚落疎紅。", "別後相思曲，悽斷入琴風。"]'),
('ee99fe2b-4060-4f60-bfec-7bc5e400ef74','遊靈公觀','駱賓王','唐','唐诗','tang','','[]','靈峰標勝境，神府枕通川。',48,'全唐诗/poet.tang.4000.json','["靈峰標勝境，神府枕通川。", "玉殿斜連漢，金堂迥架煙。", "斷風疎晚竹，流水切危弦。", "別有青門外，空懷玄圃仙。"]'),
('1e9a9657-fdec-466f-874b-e784efdfbde0','夏日遊山家同夏少府','駱賓王','唐','唐诗','tang','','[]','返照下層岑，物外狎招尋。',48,'全唐诗/poet.tang.4000.json','["返照下層岑，物外狎招尋。", "蘭徑薰幽珮，槐庭落暗金。", "谷靜風聲徹，山空月色深。", "一遣樊籠累，唯餘松桂心。"]'),
('0cf317aa-b2c8-46c8-b445-2595beecbcc4','初秋登王司馬樓宴得同字','駱賓王','唐','唐诗','tang','','[]','展驥端居暇，登龍喜宴同。',48,'全唐诗/poet.tang.4000.json','["展驥端居暇，登龍喜宴同。", "締賞三清滿，承歡六義通。", "野晦寒陰積，潭虛夕照空。", "顧慙非夢鳥，濫此廁雕蟲。"]'),
('8a31f906-c8f6-43f0-919e-6f2c866ee2a1','初秋於竇六郎宅宴','駱賓王','唐','唐诗','tang','','[]','千里風雲契，一朝心賞同。',48,'全唐诗/poet.tang.4000.json','["千里風雲契，一朝心賞同。", "意盡深交合，神靈俗累空。", "草帶銷寒翠，花枝發夜紅。", "唯將澹若水，長揖古人風。"]'),
('c38bac7c-df0a-4b01-bed7-e3988182cc51','冬日宴','駱賓王','唐','唐诗','tang','','[]','二三物外友，一百杖頭錢。',48,'全唐诗/poet.tang.4000.json','["二三物外友，一百杖頭錢。", "賞洽袁公地，情披樂令天。", "促席鸞觴滿，當爐獸炭然。", "何須攀桂樹，逢此自留連。"]'),
('748e5fe1-9d6d-4f60-ae55-9b43beff357d','鏤雞子','駱賓王','唐','唐诗','tang','','[]','幸遇清明節，欣逢舊練人。',48,'全唐诗/poet.tang.4000.json','["幸遇清明節，欣逢舊練人。", "刻花爭臉態，寫月競眉新。", "暈罷空餘月，詩成倂道春。", "誰知懷玉者，含響未吟晨。"]'),
('3f8e4588-5318-4bbd-822e-366d6d2ae56a','詠美人在天津橋','駱賓王','唐','唐诗','tang','','[]','美女出東鄰，容與上天津。',48,'全唐诗/poet.tang.4000.json','["美女出東鄰，容與上天津。", "整衣香滿路，移步襪生塵。", "水下看妝影，眉頭畫月新。", "寄言曹子建，箇是洛川神。"]'),
('d9a103f7-5097-442e-8f0c-ae0f6264197e','送宋五之問得涼字','駱賓王','唐','唐诗','tang','','[]','願言遊泗水，支離去二漳。',48,'全唐诗/poet.tang.4000.json','["願言遊泗水，支離去二漳。", "道術君所篤，筌蹄余自忘。", "雪威侵竹冷，秋爽帶池涼。", "欲騐離襟切，岐路在他鄉。"]'),
('4a83b3d1-fa75-4824-a38c-52c44c167dba','憲臺出縶寒夜有懷','駱賓王','唐','唐诗','tang','','[]','獨坐懷明發，長謠苦未安。',48,'全唐诗/poet.tang.4000.json','["獨坐懷明發，長謠苦未安。", "自應迷北叟，誰肯問南冠。", "生死交情異，殷憂歲序闌。", "空餘朝夕鳥，相伴夜啼寒。"]'),
('6b0a2038-5d84-46d5-aa5c-149260def8f5','送郭少府探得憂字','駱賓王','唐','唐诗','tang','','[]','開筵枕德水，輟棹艤仙舟。',48,'全唐诗/poet.tang.4000.json','["開筵枕德水，輟棹艤仙舟。", "貝闕桃花浪，龍門竹箭流。", "當歌悽別曲，對酒泣離憂。", "還望青門外，空見白雲浮。"]'),
('1fd56ed7-68df-4c22-8272-1c74fc0d83eb','冬日過故人任處士書齋','駱賓王','唐','唐诗','tang','','[]','神交尚投漆，虛室罷遊蘭。',48,'全唐诗/poet.tang.4000.json','["神交尚投漆，虛室罷遊蘭。", "網積窗文亂，苔深履跡殘。", "雪明書帳冷，水靜墨池寒。", "獨此琴臺夜，流水爲誰彈。"]'),
('0abe4244-72e1-44ed-9b5b-538eaff9f813','送劉少府遊越州','駱賓王','唐','唐诗','tang','','[]','一丘余枕石，三越爾懷鉛。',48,'全唐诗/poet.tang.4000.json','["一丘余枕石，三越爾懷鉛。", "離亭分鶴蓋，別岸指龍川。", "露下蟬聲斷，寒來雁影連。", "如何溝水上，悽斷聽離弦。"]'),
('7f480e7c-023b-4235-adce-365445c69b13','賦得白雲抱幽石','駱賓王','唐','唐诗','tang','','[]','重巖抱危石，幽澗曳輕雲。',48,'全唐诗/poet.tang.4000.json','["重巖抱危石，幽澗曳輕雲。", "繞鎮仙衣動，飄蓬羽蓋分。", "錦色連花靜，苔光帶葉熏。", "詎知吳會影，長抱穀城文。"]'),
('e824450a-bcf5-46eb-b6d8-138bc17cf8a6','賦得春雲處處生','駱賓王','唐','唐诗','tang','','[]','千里年光靜，四望春雲生。',48,'全唐诗/poet.tang.4000.json','["千里年光靜，四望春雲生。", "槧日祥光舉，疎雲瑞葉輕。", "蓋陰籠迥樹，陣影抱危城。", "非將吳會遠，飄蕩帝鄉情。"]'),
('c65539db-4e2b-4ce4-a22b-563b6ef3f4f1','在嶽詠蟬','駱賓王','唐','唐诗','tang','','["\u5510\u8bd7\u4e09\u767e\u9996", "\u548f\u7269", "\u548f\u7269\u8bd7", "\u4e94\u8a00\u5f8b\u8bd7"]','西陸蟬聲唱，南冠客思侵。',48,'全唐诗/poet.tang.4000.json','["西陸蟬聲唱，南冠客思侵。", "那堪玄鬢影，來對白頭吟。", "露重飛難進，風多響易沈。", "無人信高潔，誰爲表予心。"]'),
('944a609b-e752-4265-af6f-816adb90ffd1','詠水','駱賓王','唐','唐诗','tang','','[]','列名通地紀，疎派合天津。',48,'全唐诗/poet.tang.4000.json','["列名通地紀，疎派合天津。", "波隨月色淨，態逐桃花春。", "照霞如隱石，映柳似沈鱗。", "終當挹上善，屬意澹交人。"]'),
('73fe26a8-8070-4284-96c7-3ff1548c62dd','同張二詠雁','駱賓王','唐','唐诗','tang','','[]','唼藻滄江遠，銜盧紫塞長。',48,'全唐诗/poet.tang.4000.json','["唼藻滄江遠，銜盧紫塞長。", "霧深迷曉景，風急斷秋行。", "陣照通宵月，書封幾夜霜。", "無復能鳴分，空知愧稻粱。"]'),
('be8e645a-f12f-46fc-8cc9-b98104bc61be','詠雪','駱賓王','唐','唐诗','tang','','[]','龍雲玉葉上，鶴雪瑞花新。',48,'全唐诗/poet.tang.4000.json','["龍雲玉葉上，鶴雪瑞花新。", "影亂銅烏吹，光銷玉馬津。", "含輝明素篆，隱迹表祥輪。", "幽蘭不可儷，徒自繞陽春。"]'),
('e43c06f3-eab6-4d4b-af6f-77e66e3c24a9','詠雲酒','駱賓王','唐','唐诗','tang','','[]','朔空曾紀曆，帶地舊疏泉。',48,'全唐诗/poet.tang.4000.json','["朔空曾紀曆，帶地舊疏泉。", "色泛臨碭瑞，香流赴蜀仙。", "款交欣散玉，洽友悅沈錢。", "無復中山賞，空吟吳會篇。"]'),
('155a4eeb-0d10-431f-8d1f-b4eaac313f61','塵灰','駱賓王','唐','唐诗','tang','','[]','洛川流雅韻，秦道擅苛威。',48,'全唐诗/poet.tang.4000.json','["洛川流雅韻，秦道擅苛威。", "聽歌梁上動，應律管中飛。", "光飄神女襪，影落羽人衣。", "願言心未翳，終冀效輕微。"]'),
('59fcea3f-abe8-4110-afe5-fd776a6a5e15','秋晨同淄川毛司馬秋九詠 秋風','駱賓王','唐','唐诗','tang','','[]','紫陌炎氛歇，青蘋晚吹浮。',48,'全唐诗/poet.tang.4000.json','["紫陌炎氛歇，青蘋晚吹浮。", "亂竹搖疎影，縈池織細流。", "飄香曳舞袖，帶粉泛妝樓。", "不分君恩絕，紈扇曲中秋。"]'),
('a33b29f9-73ac-4ad1-9977-45e876d86d67','秋晨同淄川毛司馬秋九詠 秋雲','駱賓王','唐','唐诗','tang','','[]','南陸銅渾改，西郊玉葉輕。',48,'全唐诗/poet.tang.4000.json','["南陸銅渾改，西郊玉葉輕。", "泛斗瑤光動，臨陽瑞色明。", "蓋陰連鳳闕，陣影翼龍城。", "詎知時不遇，空傷流滯情。"]'),
('568f6142-ff89-49f7-bfb8-91d32a1fa7f5','秋晨同淄川毛司馬秋九詠 秋蟬','駱賓王','唐','唐诗','tang','','[]','九秋行已暮，一枝聊暫安。',48,'全唐诗/poet.tang.4000.json','["九秋行已暮，一枝聊暫安。", "隱榆非諫楚，噪柳異悲潘。", "分形妝薄鬢，鏤影飾危冠。", "自憐疎影斷，寒林夕吹寒。"]'),
('9ff128ba-2da9-4a60-8406-5845618b3b51','秋晨同淄川毛司馬秋九詠 秋露','駱賓王','唐','唐诗','tang','','[]','玉關寒氣早，金塘秋色歸。',48,'全唐诗/poet.tang.4000.json','["玉關寒氣早，金塘秋色歸。", "泛掌光逾淨，添荷滴尚微。", "變霜凝曉液，承月委圓輝。", "別有吳臺上，應濕楚臣衣。"]'),
('ca0b81b7-cf97-49be-a00a-67a7759e9ad3','秋晨同淄川毛司馬秋九詠 秋月','駱賓王','唐','唐诗','tang','','[]','雲披玉繩淨，月滿鏡輪圓。',48,'全唐诗/poet.tang.4000.json','["雲披玉繩淨，月滿鏡輪圓。", "裛露珠暉冷，凌霜桂影寒。", "漏彩含疎薄，浮光漾急瀾。", "西園徒自賞，南飛終未安。"]'),
('fb82f7c9-4664-497a-8d25-242a0554db45','秋晨同淄川毛司馬秋九詠 秋水','駱賓王','唐','唐诗','tang','','[]','貝闕寒流徹，玉輪秋浪清。',48,'全唐诗/poet.tang.4000.json','["貝闕寒流徹，玉輪秋浪清。", "圖雲錦色淨，寫月練花明。", "泛曲鵾弦動，隨軒鳳轄驚。", "唯當御溝上，悽斷送歸情。"]'),
('aa3beea8-4ccb-4c00-95df-9f91dc2bf6d4','秋晨同淄川毛司馬秋九詠 秋螢','駱賓王','唐','唐诗','tang','','[]','玉虬分靜夜，金螢照晚涼。',48,'全唐诗/poet.tang.4000.json','["玉虬分靜夜，金螢照晚涼。", "含輝疑泛月，帶火怯凌霜。", "散彩縈虛牖，飄花繞洞房。", "下帷如不倦，當解惜餘光。"]'),
('06e80340-ed49-4ef7-aca0-1ad1a5e3ea09','秋晨同淄川毛司馬秋九詠 秋菊','駱賓王','唐','唐诗','tang','','[]','擢秀三秋晚，開芳十步中。',48,'全唐诗/poet.tang.4000.json','["擢秀三秋晚，開芳十步中。", "分黃俱笑日，含翠共搖風。", "碎影涵流動，浮香隔岸通。", "金翹徒可泛，玉斝竟誰同。"]'),
('bd4de1aa-8aa1-4b0a-89e7-26ec3439ba57','秋晨同淄川毛司馬秋九詠 秋雁','駱賓王','唐','唐诗','tang','','[]','聯翩辭海曲，遙曳指江干。',48,'全唐诗/poet.tang.4000.json','["聯翩辭海曲，遙曳指江干。", "陣去金河冷，書歸玉塞寒。", "帶月凌空易，迷煙逗浦難。", "何當同顧影，刷羽泛清瀾。"]'),
('0c0987c9-5e9a-4795-8b0d-c82c278d366e','樂大夫挽詞五首 一','駱賓王','唐','唐诗','tang','','[]','可歎浮生促，吁嗟此路難。',48,'全唐诗/poet.tang.4000.json','["可歎浮生促，吁嗟此路難。", "丘陵一起恨，言笑幾時懽。", "蕭索郊埏晚，荒涼井徑寒。", "誰當門下客，獨見有任安。"]'),
('ffb568f8-71d7-4845-bc74-25802517f199','樂大夫挽詞五首 二','駱賓王','唐','唐诗','tang','','[]','蒿里誰家地，松門何代丘。',36,'全唐诗/poet.tang.4000.json','["蒿里誰家地，松門何代丘。", "百年三萬日，一別幾千秋。", "返照寒無影，窮泉凍不流。"]'),
('cd5ffcfb-f1dc-499d-be47-a6fbf9a4eb70','樂大夫挽詞五首 三','駱賓王','唐','唐诗','tang','','[]','昔去梅笳發，今來薤露晞。',48,'全唐诗/poet.tang.4000.json','["昔去梅笳發，今來薤露晞。", "彤騶朝帝闕，丹旐背王畿。", "城郭猶疑是，原陵稍覺非。", "九原如可作，千載與誰歸。"]'),
('487c871a-a858-4d49-9916-6685d9750cb3','樂大夫挽詞五首 四','駱賓王','唐','唐诗','tang','','[]','一旦先朝菌，千秋掩夜臺。',48,'全唐诗/poet.tang.4000.json','["一旦先朝菌，千秋掩夜臺。", "青烏新兆去，白馬故人來。", "草露當春泣，松風向暮哀。", "寧知荒壠外，弔鶴自裴徊。"]'),
('836bfbf4-f0e3-4675-a896-5c597a37a54a','樂大夫挽詞五首 五','駱賓王','唐','唐诗','tang','','[]','忽見泉臺路，猶疑水鏡懸。',48,'全唐诗/poet.tang.4000.json','["忽見泉臺路，猶疑水鏡懸。", "何如開白日，非復覩青天。", "華表迎千歲，幽扃送百年。", "獨嗟流水引，長掩伯牙弦。"]'),
('ebf7ec3e-66a1-4f31-99a2-0419c946872f','丹陽刺史挽詞三首 一','駱賓王','唐','唐诗','tang','','[]','百齡嗟倏忽，一旦向山阿。',48,'全唐诗/poet.tang.4000.json','["百齡嗟倏忽，一旦向山阿。", "丹桂銷已盡，青松哀更多。", "薰風虛聽曲，薤露反成歌。", "自有藏舟處，誰憐隙駟過。"]'),
('04c9c9c6-f4f1-4aef-bf58-9ae7d10a0a8d','丹陽刺史挽詞三首 二','駱賓王','唐','唐诗','tang','','[]','惻愴恆山羽，留連棣萼篇。',48,'全唐诗/poet.tang.4000.json','["惻愴恆山羽，留連棣萼篇。", "佳城非舊日，京兆即新阡。", "城郭三千歲，丘陵幾萬年。", "唯餘松柏壠，朝夕起寒煙。"]'),
('28635bb6-7a75-4bb2-96f3-ea3b97a43b22','丹陽刺史挽詞三首 三','駱賓王','唐','唐诗','tang','','[]','短歌三獻曲，長夜九泉臺。',48,'全唐诗/poet.tang.4000.json','["短歌三獻曲，長夜九泉臺。", "此室玄扃掩，何年白日開。", "荒郊疎古木，寒隧積陳荄。", "獨此傷心地，松聲薄暮來。"]'),
('d7283c0f-95fa-4c73-95ff-9be77f0b20c6','稱心寺','駱賓王','唐','唐诗','tang','','[]','征帆恣遠尋，逶迤過稱心。',48,'全唐诗/poet.tang.4000.json','["征帆恣遠尋，逶迤過稱心。", "凝滯蘅𦶜岸，沿洄樝柚林。", "穿漵不厭曲，艤潭惟愛深。", "爲樂凡幾許，聽取舟中琴。"]'),
('8938d82b-fdf4-46f4-8545-b3c58d4adce1','陪潤州薛司空丹徒桂明府遊招隱寺','駱賓王','唐','唐诗','tang','','[]','共尋招隱寺，初識戴顒家。',48,'全唐诗/poet.tang.4000.json','["共尋招隱寺，初識戴顒家。", "還依舊泉壑，應改昔雲霞。", "綠竹寒天笋，紅蕉臘月花。", "金繩倘留客，爲繫日光斜。"]'),
('8833fcd8-564e-4ee8-bcf5-c2fb4ab94718','棹歌行','駱賓王','唐','唐诗','tang','','[]','寫月塗黃罷，凌波拾翠通。',72,'全唐诗/poet.tang.4000.json','["寫月塗黃罷，凌波拾翠通。", "鏡花搖芰日，衣麝入荷風。", "葉密舟難蕩，蓮疎浦易空。", "鳳媒羞自托，鴛翼恨難窮。", "秋帳燈華翠，倡樓粉色紅。", "相思無別曲，倂在棹歌中。"]'),
('a9846044-c569-4ce0-b97c-6834d55d860c','海曲書情','駱賓王','唐','唐诗','tang','','[]','薄遊倦千里，勞生負百年。',60,'全唐诗/poet.tang.4000.json','["薄遊倦千里，勞生負百年。", "未能槎上漢，詎肯劍遊燕。", "白雲照春海，青山橫曙天。", "江濤讓雙璧，渭水擲三錢。", "坐惜風光晚，長歌獨塊然。"]'),
('b069ca02-e0bb-477b-aeef-5e6797c14d6e','蓬萊鎮','駱賓王','唐','唐诗','tang','','[]','旅客春心斷，邊城夜望高。',60,'全唐诗/poet.tang.4000.json','["旅客春心斷，邊城夜望高。", "野樓疑海氣，白鷺似江濤。", "結綬疲三入，承冠泣二毛。", "將飛憐弱羽，欲濟乏輕舠。", "賴有陽春曲，窮愁且代勞。"]'),
('d0843e83-f257-47ba-9a06-bc667c4be00d','和李明府','駱賓王','唐','唐诗','tang','','[]','傳聞葉縣履，飛向洛陽城。',60,'全唐诗/poet.tang.4000.json','["傳聞葉縣履，飛向洛陽城。", "馳道臨層掖，津門對小平。", "霞殘疑製錦，雲度似飄纓。", "藻掞潘江澈，塵虛范甑清。", "詎憐衝斗氣，猶向匣中鳴。"]'),
('17216691-40ea-465c-827a-d9170135fb87','春晚從李長史遊開道林故山','駱賓王','唐','唐诗','tang','','[]','幽尋極幽壑，春望陟春臺。',60,'全唐诗/poet.tang.4000.json','["幽尋極幽壑，春望陟春臺。", "雲光棲斷樹，靈影入仙杯。", "古藤依格上，野徑約山隈。", "落蘂飜風去，流鶯滿樹來。", "興闌荀御動，歸路起浮埃。"]'),
('67810e04-93aa-4299-a636-8d2cb6041478','冬日野望','駱賓王','唐','唐诗','tang','','[]','故人無與晤，安步陟山椒。',60,'全唐诗/poet.tang.4000.json','["故人無與晤，安步陟山椒。", "野靜連雲卷，川明斷霧銷。", "靈巖聞曉籟，洞浦漲秋潮。", "三江歸望斷，千里故鄉遙。", "勞歌徒自奏，客魂誰爲招。"]'),
('6e63dcbb-c6ad-4301-bc74-6a8fef7caa13','晚渡黃河','駱賓王','唐','唐诗','tang','','["\u9ec4\u6cb3"]','千里尋歸路，一葦亂平源。',72,'全唐诗/poet.tang.4000.json','["千里尋歸路，一葦亂平源。", "通波連馬頰，迸水急龍門。", "照日榮光淨，驚風瑞浪翻。", "棹唱臨風斷，樵謳入聽喧。", "岸迥秋霞落，潭深夕霧繁。", "誰堪逝川上，日暮不歸魂。"]'),
('3f4eae61-e877-4895-bb79-47537683f391','宿山莊','駱賓王','唐','唐诗','tang','','[]','金陵一超忽，玉燭幾還周。',72,'全唐诗/poet.tang.4000.json','["金陵一超忽，玉燭幾還周。", "露積吳臺草，風入郢門楸。", "林虛宿斷霧，磴險挂懸流。", "拾青非漢策，化緇類秦裘。", "牽迹猶多蹇，勞生未寡尤。", "獨此他鄉夢，空山明月秋。"]'),
('bb23bc9b-af6c-4c70-a761-aa336ec1b5b4','晚度天山有懷京邑','駱賓王','唐','唐诗','tang','','["\u601d\u4e61", "\u60c6\u6005", "\u8fb9\u585e"]','忽上天山路，依然想物華。',72,'全唐诗/poet.tang.4000.json','["忽上天山路，依然想物華。", "雲疑上苑葉，雪似御溝花。", "行歎戎麾遠，坐憐衣帶賒。", "交河浮絕塞，弱水浸流沙。", "旅思徒漂梗，歸期未及瓜。", "寧知心斷絕，夜夜泣胡笳。"]'),
('f254b2bd-8fd1-4e45-9107-321a7decdbaa','夕次蒲類津','駱賓王','唐','唐诗','tang','','["\u6218\u4e89", "\u7231\u56fd", "\u8fb9\u585e", "\u601d\u4e61"]','二庭歸望斷，萬里客心愁。',72,'全唐诗/poet.tang.4000.json','["二庭歸望斷，萬里客心愁。", "山路猶南屬，河源自北流。", "晚風連朔氣，新月照邊秋。", "竈火通軍壁，烽煙上戍樓。", "龍庭但苦戰，燕頷會封侯。", "莫作蘭山下，空令漢國羞。"]'),
('598f031a-bae2-46be-af96-21159764821b','遠使海曲春夜多懷','駱賓王','唐','唐诗','tang','','[]','長嘯三春晚，端居百慮盈。',72,'全唐诗/poet.tang.4000.json','["長嘯三春晚，端居百慮盈。", "未安胡蝶夢，遽切魯禽情。", "別島連寰海，離魂斷戍城。", "流星疑伴使，低月似依營。", "懷祿寧期達，牽時匪狥名。", "艱虞行已遠，時迹自相驚。"]'),
('c70bd580-e561-4407-8aa9-368b8771aeaf','早發諸暨','駱賓王','唐','唐诗','tang','','[]','征夫懷遠路，夙駕上危巒。',72,'全唐诗/poet.tang.4000.json','["征夫懷遠路，夙駕上危巒。", "薄煙橫絕巘，輕凍澁回湍。", "野霧連空暗，山風入曙寒。", "帝城臨灞涘，禹穴枕江干。", "橘性行應化，蓬心去不安。", "獨掩窮途淚，長歌行路難。"]'),
('81202d59-dad1-4a4c-917e-a9ee07931976','望月有所思','駱賓王','唐','唐诗','tang','','[]','九秋涼風肅，千里月華開。',72,'全唐诗/poet.tang.4000.json','["九秋涼風肅，千里月華開。", "圓光隨露湛，碎影逐波來。", "似霜明玉砌，如鏡寫珠胎。", "晚色依關近，邊聲雜吹哀。", "離居分照耀，怨緒共裴徊。", "自繞南飛羽，空忝北堂才。"]'),
('4cf4b908-12be-4530-bee1-eab41765043e','送吳七遊蜀','駱賓王','唐','唐诗','tang','','[]','日觀分齊壤，星橋接蜀門。',72,'全唐诗/poet.tang.4000.json','["日觀分齊壤，星橋接蜀門。", "桃花嘶別路，竹葉瀉離樽。", "夏老蘭猶茂，秋深柳尚繁。", "霧銷山望迥，風高野聽喧。", "勞歌徒欲奏，贈別竟無言。", "唯有當秋月，空照野人園。"]'),
('62a62768-402c-411a-a769-43e24dfcb171','西行別東臺詳正學士','駱賓王','唐','唐诗','tang','','[]','意氣坐相親，關河別故人。',72,'全唐诗/poet.tang.4000.json','["意氣坐相親，關河別故人。", "客似秦川上，歌疑易水濱。", "塞荒行辨玉，臺遠尚名輪。", "洩井懷邊將，尋源重漢臣。", "上苑梅花早，御溝楊柳新。", "只應持此曲，別作邊城春。"]'),
('f3be7897-9013-4ae9-98d7-e966a95177a7','和王記室從趙王春日遊陀山寺','駱賓王','唐','唐诗','tang','','[]','鳥旟陪訪道，鷲嶺狎棲真。',72,'全唐诗/poet.tang.4000.json','["鳥旟陪訪道，鷲嶺狎棲真。", "四禪明靜業，三空廣勝因。", "祥河疎疊澗，慧日皎重輪。", "葉暗龍宮密，花明鹿苑春。", "彫談筌奧旨，妙辯漱玄津。", "雅曲終難和，徒自奏巴人。"]'),
('3579f6bd-6a8a-45f4-b50e-250f3a516e72','夏日夜憶張二','駱賓王','唐','唐诗','tang','','[]','伏枕憂思深，擁膝獨長吟。',84,'全唐诗/poet.tang.4000.json','["伏枕憂思深，擁膝獨長吟。", "烹鯉無尺素，筌魚勞寸心。", "疎麻空有折，芳桂湛無斟。", "廣庭含夕氣，閑宇澹虛陰。", "織蟲垂夜砌，驚鳥棲暝林。", "驩娛百年促，羈病一生侵。", "詎堪孤月夜，流水入鳴琴。"]'),
('fd39503a-7504-4ba4-98a8-ec70d3d37bfe','寒夜獨坐遊子多懷簡知己','駱賓王','唐','唐诗','tang','','[]','故鄉眇千里，離憂積萬端。',84,'全唐诗/poet.tang.4000.json','["故鄉眇千里，離憂積萬端。", "鶉服長悲碎，蝸廬未卜安。", "富鉤徒有想，貧鋏爲誰彈。", "柳秋風葉脆，荷曉露文團。", "晚金叢岸菊，餘佩下幽蘭。", "伐木傷心易，維桑歸去難。", "獨有孤明月，時照客庭寒。"]'),
('4f1a311f-0c46-4957-ab49-5fa5f954205b','在軍中贈先還知己','駱賓王','唐','唐诗','tang','','[]','蓬轉俱行役，瓜時獨未還。',84,'全唐诗/poet.tang.4000.json','["蓬轉俱行役，瓜時獨未還。", "魂迷金闕路，望斷玉門關。", "獻凱多慙霍，論封幾謝班。", "風塵催白首，歲月損紅顏。", "落雁低秋塞，驚鳧起暝灣。", "胡霜如劍鍔，漢月似刀環。", "別後邊庭樹，相思幾度攀。"]'),
('60e26fb8-c279-478d-8eab-35c8227ed575','秋日山行簡梁大官','駱賓王','唐','唐诗','tang','','[]','乘馬陟層阜，回首睇山川。',96,'全唐诗/poet.tang.4000.json','["乘馬陟層阜，回首睇山川。", "攢峰銜宿霧，疊巘架寒煙。", "百重含翠色，一道落飛泉。", "香吹分巖桂，鮮雲抱石蓮。", "地偏心易遠，致默體逾玄。", "得性虛遊刃，忘言已棄筌。", "彈冠勞巧拙，結綬倦牽纏。", "不如從四皓，丘中鳴一弦。"]'),
('57072cd6-42bf-457e-a71a-a298d2ac2ed9','晚泊江鎮','駱賓王','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','四運移陰律，三翼泛陽侯。',96,'全唐诗/poet.tang.4000.json','["四運移陰律，三翼泛陽侯。", "荷香銷晚夏，菊氣入新秋。", "夜烏喧粉堞，宿雁下蘆洲。", "海霧籠邊徼，江風繞戍樓。", "轉蓬驚別渚，徙橘愴離憂。", "魂飛灞陵岸，淚盡洞庭流。", "振影希鴻陸，逃名謝蟻丘。", "還嗟帝鄉遠，空望白雲浮。"]'),
('09ec75e0-b22c-4272-b810-8c9aa455086c','浮槎','駱賓王','唐','唐诗','tang','','[]','昔負千尋質，高臨九仞峰。',96,'全唐诗/poet.tang.4000.json','["昔負千尋質，高臨九仞峰。", "真心凌晚桂，勁節掩寒松。", "忽值風飆折，坐爲波浪衝。", "摧殘空有恨，擁腫遂無庸。", "渤海三千里，泥沙幾萬重。", "似舟飄不定，如梗泛何從。", "仙客終難托，良工豈易逢。", "徒懷萬乘器，誰爲一先容。"]'),
('5d88b013-98f5-4fad-809f-efbd3c464b5b','晚泊河曲','駱賓王','唐','唐诗','tang','','[]','三秋倦行役，千里泛歸潮。',96,'全唐诗/poet.tang.4000.json','["三秋倦行役，千里泛歸潮。", "通波竹箭水，輕舸木蘭橈。", "金隄連曲岸，貝闕影浮橋。", "水淨千年近，星飛五老遙。", "疊花開宿浪，浮葉下涼飆。", "浦荷疎晚菂，津柳漬寒條。", "恓惶勞梗泛，悽斷倦蓬飄。", "仙槎不可託，河上獨長謠。"]'),
('7953f497-5684-4902-b730-6d7f312bef64','早發淮口望盱眙','駱賓王','唐','唐诗','tang','','[]','養蒙分四瀆，習坎奠三荆。',96,'全唐诗/poet.tang.4000.json','["養蒙分四瀆，習坎奠三荆。", "徙帝留餘地，封王表舊城。", "岸昏涵蜃氣，潮滿應雞聲。", "洲迥連沙靜，川虛積溜明。", "一朝從捧檄，千里倦懸旌。", "背流桐柏遠，逗浦木蘭輕。", "小山迷隱路，大塊切勞生。", "唯有貞心在，獨映寒潭清。"]'),
('874a0ca3-62ca-4c9f-976b-895b035ac3d6','邊城落日','駱賓王','唐','唐诗','tang','','[]','紫塞流沙北，黃圖灞水東。',96,'全唐诗/poet.tang.4000.json','["紫塞流沙北，黃圖灞水東。", "一朝辭俎豆，萬里逐沙蓬。", "候月恆持滿，尋源屢鑿空。", "野昏邊氣合，烽迥戍煙通。", "膂力風塵倦，疆場歲月窮。", "河流控積石，山路遠崆峒。", "壯志凌蒼兕，精誠貫白虹。", "君恩如可報，龍劍有雌雄。"]'),
('b60d6783-9c7a-4308-949d-8169ca25898c','宿溫城望軍營','駱賓王','唐','唐诗','tang','','[]','虜地寒膠折，邊城夜柝聞。',96,'全唐诗/poet.tang.4000.json','["虜地寒膠折，邊城夜柝聞。", "兵符關帝闕，天策動將軍。", "塞靜胡笳徹，沙明楚練分。", "風旗翻翼影，霜劍轉龍文。", "白羽搖如月，青山斷若雲。", "煙疎疑卷幔，塵滅似銷氛。", "投筆懷班業，臨戎想顧勳。", "還應雪漢恥，持此報明君。"]'),
('cc08140a-3b05-47e4-9e8f-1dd7184b1516','過故宋','駱賓王','唐','唐诗','tang','','[]','舊國千年盡，荒城四望通。',96,'全唐诗/poet.tang.4000.json','["舊國千年盡，荒城四望通。", "雲浮非隱帝，日舉類遊童。", "綺琴朝化洽，祥石夜論空。", "馬去遙奔鄭，蛇分近帶豐。", "池文斂束水，竹影漏寒叢。", "園兔承行月，川禽避斷風。", "故宋誠難定，從梁事未工。", "唯當過周客，獨愧吳臺空。"]'),
('c1e0678f-343a-4b68-9904-bff58a5ca0b4','邊夜有懷','駱賓王','唐','唐诗','tang','','[]','漢地行逾遠，燕山去不窮。',96,'全唐诗/poet.tang.4000.json','["漢地行逾遠，燕山去不窮。", "城荒猶築怨，碣毀尚銘功。", "古戍煙塵滿，邊庭人事空。", "夜關明隴月，秋塞急胡風。", "倚伏良難定，榮枯豈易通。", "旅魂勞泛梗，離恨斷征蓬。", "蘇武封猶薄，崔駰宦不工。", "惟餘北叟意，欲寄南飛鴻。"]'),
('7b856ebd-84aa-46c8-9ad9-049b81cbe86b','傷祝阿王明府','駱賓王','唐','唐诗','tang','','[]','洛川真氣上，重泉惠政融。',96,'全唐诗/poet.tang.4000.json','["洛川真氣上，重泉惠政融。", "含章光後烈，繼武嗣前雄。", "與善良難驗，生涯忽易窮。", "翔鳧猶化履，狎雉尚馴童。", "錢滿荒階綠，塵浮虛帳紅。", "夏餘將宿草，秋近未驚蓬。", "煙晦泉門閉，日盡夜臺空。", "誰堪孤隴外，獨聽白楊風。"]'),
('2e2acb69-3721-407d-a65e-63418e4008d4','四月八日題七級','駱賓王','唐','唐诗','tang','','[]','化城分鳥堞，香閣俯龍川。',108,'全唐诗/poet.tang.4000.json','["化城分鳥堞，香閣俯龍川。", "複棟侵黃道，重檐架紫煙。", "銘書非晉代，壁畫是梁年。", "霸略今何在，王宮尚巋然。", "二帝曾遊聖，三卿是偶賢。", "因茲遊勝侶，超彼託良緣。", "我出有爲界，君登非想天。", "悠悠青曠裏，蕩蕩白雲前。", "今日經行處，曲音號蓋煙。"]'),
('194b29bc-7915-4130-bcbe-c034996b93ae','和孫長史秋日臥病','駱賓王','唐','唐诗','tang','','[]','霍第疏天府，潘園近帝臺。',120,'全唐诗/poet.tang.4000.json','["霍第疏天府，潘園近帝臺。", "調弦三婦至，置驛五侯來。", "尚想歡娛洽，吁嗟歲月催。", "金壇分上將，玉帳引瓌材。", "決勝鯨波靜，騰謀鳥谷開。", "白雲淮水外，紫陌灞陵隈。", "節變驚衰柳，笳繁思落梅。", "調神和玉燭，掞藻握珠胎。", "悵矣欣懷土，居然欲死灰。", "還因承雅曲，暫喜躍沈鰓。"]'),
('cf31adb3-7462-432c-a5c4-0478388ee49c','餞鄭安陽入蜀','駱賓王','唐','唐诗','tang','','[]','彭山折坂外，井絡少城隈。',120,'全唐诗/poet.tang.4000.json','["彭山折坂外，井絡少城隈。", "地是三巴俗，人非百里材。", "畏途君悵望，岐路我裴徊。", "心賞風煙隔，容華歲月催。", "遙遙分鳳野，去去轉龍媒。", "遺錦非前邑，鳴琴即舊臺。", "劍門千仞起，石路五丁開。", "海客乘槎渡，仙童馭竹回。", "魂將離鶴遠，思逐斷猿哀。", "唯有雙鳧舄，飛去復飛來。"]'),
('18f09ced-8f0d-433f-9c5b-8c6ab2031ad1','詠懷','駱賓王','唐','唐诗','tang','','[]','少年識事淺，不知交道難。',132,'全唐诗/poet.tang.4000.json','["少年識事淺，不知交道難。", "一言芬若桂，四海臭如蘭。", "寶劍思存楚，金鎚許報韓。", "虛心徒有託，循迹諒無端。", "太息關山險，吁嗟歲月闌。", "忘機殊會俗，守拙異懷安。", "阮籍空長嘯，劉琨獨未懽。", "十步庭芳斂，三秋隴月團。", "槐疎非盡意，松晚夜凌寒。", "悲調弦中急，窮愁醉裏寬。", "莫將流水引，空向俗人彈。"]'),
('b480e85b-070f-477e-a2e0-072e207722f0','春日離長安客中言懷','駱賓王','唐','唐诗','tang','','[]','年華開早律，霽色蕩芳晨。',144,'全唐诗/poet.tang.4000.json','["年華開早律，霽色蕩芳晨。", "城闕千門曉，山河四望春。", "御溝通太液，戚里對平津。", "寶瑟調中婦，金罍引上賓。", "劇談推曼倩，驚坐揖陳遵。", "意氣一言合，風期萬里親。", "自惟安直道，守拙忌因人。", "談器非先木，圖榮異後薪。", "揶揄慙路鬼，憔悴切波臣。", "玄草終疲漢，烏裘幾滯秦。", "生涯無歲月，岐路有風塵。", "還嗟太行道，處處白頭新。"]'),
('69c96b89-d73a-4e21-ba84-ddd2c8e17f92','夕次舊吳','駱賓王','唐','唐诗','tang','','[]','維舟背楚服，振策下吳畿。',144,'全唐诗/poet.tang.4000.json','["維舟背楚服，振策下吳畿。", "盛德弘三讓，雄圖枕九圍。", "黃池通霸跡，赤壁暢戎威。", "文物俄遷謝，英靈有盛衰。", "行歎鴟夷沒，遽惜湛盧飛。", "地古煙塵暗，年深館宇稀。", "山川四望是，人事一朝非。", "懸劍空留信，亡珠尚識機。", "鄭風遙可託，關月眇難依。", "西北雲逾滯，東南氣轉微。", "徒懷伯通隱，多謝買臣歸。", "唯有荒臺露，薄暮濕征衣。"]'),
('d5934743-bc79-4911-9fdb-e6625d9aba1b','早秋出塞寄東臺詳正學士','駱賓王','唐','唐诗','tang','','[]','促駕踰三水，長驅望五原。',168,'全唐诗/poet.tang.4000.json','["促駕踰三水，長驅望五原。", "天階分斗極，地理接樓煩。", "溪月明關隴，戎雲聚塞垣。", "山川殊物候，風壤異涼喧。", "戍古秋塵合，沙寒宿霧繁。", "昔余迷學步，投迹忝詞源。", "蘭渚浮延閣，蓬山款禁園。", "彯纓陪紱冕，載筆偶璵璠。", "汲冢寧詳蠹，秦牢詎辨冤。", "一朝從篚服，千里騖輕軒。", "鄉夢隨魂斷，邊聲入聽喧。", "南圖終鎩翮，北上遽催轅。", "弔影慙連茹，浮生倦觸藩。", "數奇何以託，桃李自無言。"]'),
('36dd309e-3630-4f6d-9bfe-1c0b5e534d61','幽縶書情通簡知己','駱賓王','唐','唐诗','tang','','[]','昔歲逢楊意，觀光貴楚材。',216,'全唐诗/poet.tang.4000.json','["昔歲逢楊意，觀光貴楚材。", "穴疑丹鳳起，場似白駒來。", "一命淪驕餌，三緘慎禍胎。", "不言勞倚伏，忽此遘邅迴。", "驄馬刑章峻，蒼鷹獄吏猜。", "絕縑非易辨，疑璧果難裁。", "揆畫慙周道，端憂滯夏臺。", "生涯一滅裂，岐路幾裴徊。", "青陸春芳動，黃沙旅思催。", "圓扉長寂寂，疎網尚恢恢。", "入穽先搖尾，迷津正曝腮。", "覆盆徒望日，蟄戶未經雷。", "霜歇蘭猶敗，風多木屢摧。", "地幽蠶室閉，門靜雀羅開。", "自憫秦冤痛，誰憐楚奏哀。", "漢陽窮鳥客，梁甫臥龍才。", "有氣還衝斗，無時會鑿坏。", "莫言韓長孺，長作不然灰。"]'),
('dabe664b-6a0c-428d-8823-ca5471fc8ef2','久戍邊城有懷京邑','駱賓王','唐','唐诗','tang','','[]','擾擾風塵地，遑遑名利途。',288,'全唐诗/poet.tang.4000.json','["擾擾風塵地，遑遑名利途。", "盈虛一易舛，心迹兩難俱。", "弱齡小山志，寧期大丈夫。", "九微光賁玉，千仞忽彈珠。", "棘寺游三禮，蓬山簉八儒。", "懷鉛慙後進，投筆願前驅。", "北走非通趙，西之似化胡。", "錦車朝促候，刁斗夜傳呼。", "戰士青絲絡，將軍黃石符。", "連星入寶劍，半月上彫弧。", "拜井開疎勒，鳴桴動密須。", "戎機習短蔗，祆祲靜長榆。", "季月炎初盡，邊亭草早枯。", "層陰籠古木，窮色變寒蕪。", "海鶴聲嘹唳，城烏尾畢逋。", "葭繁秋色引，桂滿夕輪虛。", "行役風霜久，鄉園夢想孤。", "灞池遙夏國，秦海望陽紆。", "沙塞三千里，京城十二衢。", "楊溝連鳳闕，槐路擬鴻都。", "璧殿規宸象，金堤法斗樞。", "雲浮西北蓋，月照東南隅。", "寶帳垂連理，銀牀轉轆轤。", "廣筵留上客，豐饌引中廚。"]'),
('4aad284b-d25d-4776-bfe1-5bebc6ebe062','在軍登城樓','駱賓王','唐','唐诗','tang','','["\u6124\u6168", "\u5199\u666f", "\u6292\u60c5", "\u79cb\u5929"]','城上風威冷，江中水氣寒。',24,'全唐诗/poet.tang.4000.json','["城上風威冷，江中水氣寒。", "戎衣何日定，歌舞入長安。"]'),
('cc9a6bbc-8a05-4c89-a41c-74c271b6065b','於易水送人','駱賓王','唐','唐诗','tang','','["\u968b\u30fb\u5510\u30fb\u4e94\u4ee3", "\u9001\u522b", "\u5730\u70b9", "\u548f\u53f2\u6000\u53e4"]','此地別燕丹，壯士髪衝冠。',24,'全唐诗/poet.tang.4000.json','["此地別燕丹，壯士髪衝冠。", "昔時人已沒，今日水猶寒。"]'),
('ccef7202-1a53-43fa-907c-462aa0e07525','詠鏡','駱賓王','唐','唐诗','tang','','[]','寫月無芳桂，照日有花菱。',24,'全唐诗/poet.tang.4000.json','["寫月無芳桂，照日有花菱。", "不持光謝水，翻將影學冰。"]'),
('6fd37f32-04db-41de-895b-45202c59f88c','挑燈杖','駱賓王','唐','唐诗','tang','','[]','稟質非貪熱，焦心豈憚熬。',24,'全唐诗/poet.tang.4000.json','["稟質非貪熱，焦心豈憚熬。", "終知不自潤，何處用脂膏。"]'),
('93fbc3f7-f7be-4276-bf47-08dd2dd2cc2b','詠塵','駱賓王','唐','唐诗','tang','','[]','凌波起羅襪，含風染素衣。',24,'全唐诗/poet.tang.4000.json','["凌波起羅襪，含風染素衣。", "別有知音調，聞歌應自飛。"]'),
('e3384767-fea6-41d4-9d35-11c4eb73f95f','翫初月','駱賓王','唐','唐诗','tang','','[]','忌滿光先缺，乘昏影暫流。',24,'全唐诗/poet.tang.4000.json','["忌滿光先缺，乘昏影暫流。", "既能明似鏡，何用曲如鉤。"]'),
('6131d6e0-1ee4-42b8-848c-eb4744bbe385','送別','駱賓王','唐','唐诗','tang','','["\u79bb\u522b"]','寒更承夜永，涼夕向秋澄。',24,'全唐诗/poet.tang.4000.json','["寒更承夜永，涼夕向秋澄。", "離心何以贈，自有玉壺冰。"]'),
('b19be5ca-d1d4-4844-8397-89b4df030477','憶蜀地佳人','駱賓王','唐','唐诗','tang','','[]','東西吳蜀關山遠，魚來雁去兩難聞。',32,'全唐诗/poet.tang.4000.json','["東西吳蜀關山遠，魚來雁去兩難聞。", "莫怪常有千行淚，只爲陽臺一片雲。"]'),
('b038a31d-5b14-42bc-bc8e-ce616ebb390d','詠鵝','駱賓王','唐','唐诗','tang','','["\u4e00\u5e74\u7ea7\u4e0a\u518c", "\u548f\u7269\u8bd7", "\u6c34", "\u548f\u7269"]','鵝，鵝，鵝，曲項向天歌。',24,'全唐诗/poet.tang.4000.json','["鵝，鵝，鵝，曲項向天歌。", "白毛浮綠水，紅掌撥清波。"]'),
('22de88cd-87c4-4892-bf6c-8f2b3cfecdee','奉和聖製夏日遊石淙山','武三思','唐','唐诗','tang','','[]','此地巖壑數千重，吾君駕鶴□乘龍。',64,'全唐诗/poet.tang.4000.json','["此地巖壑數千重，吾君駕鶴□乘龍。", "掩暎葉光含翡翠，參差石影帶芙蓉。", "白日將移衝疊巘，玄雲欲度礙高峰。", "對酒鳴琴追野趣，時聞清吹入長松。"]'),
('03baef25-f668-4ca3-85b9-da900235eb6f','仙鶴篇','武三思','唐','唐诗','tang','','[]','白鶴乘空何處來？青田紫蓋本相依。',256,'全唐诗/poet.tang.4000.json','["白鶴乘空何處來？青田紫蓋本相依。", "緱山七月雖長去，遼水千年會憶歸。", "緱山杳杳翔寥廓，遼水纍纍歎城郭。", "經隨羽客步丹丘，曾逐仙人遊碧落。", "迢迢碧落斷氛埃，霞堂雲閣幾重開。", "欲尋東海黃金竈，仍向西山白玉臺。", "九臯獨唳方清切，五里驚羣俄斷絕。", "月下分行似度雲，風前颺影疑迴雪。", "風前月下路漫漫，水宿雲翔去幾般。", "宛轉能傾吳國市，裴回巧拂漢皇壇。", "琴中作曲從來易，鼓裏傳聲有甚難。", "夜夜恆飛銀漢曲，朝朝常飲玉池瀾。", "別有聞簫出紫煙，還如化履上青天。", "霜毛忽控三神下，玉羽俄看二客旋。", "燕雀終迷橫海志，蜉蝣豈識在陰年。", "莫言一舉輕千里，爲與三山送九仙。"]'),
('1ab1bdbd-2f09-4776-b270-27340a1780b4','宴龍泓','武三思','唐','唐诗','tang','','[]','登臨開勝託，眺矚盡良遊。',48,'全唐诗/poet.tang.4000.json','["登臨開勝託，眺矚盡良遊。", "巖崿縈紆上，澄潭屈曲流。", "泛蘭清興洽，折桂野文遒。", "別後相思處，崎嶇碧澗幽。"]'),
('84e17f8c-056d-4f4a-945f-3cf140f88c4b','凝碧池侍宴應制得出水槎','武三思','唐','唐诗','tang','','[]','彼木生何代，爲槎復幾年。',48,'全唐诗/poet.tang.4000.json','["彼木生何代，爲槎復幾年。", "欲乘銀漢曲，先泛玉池邊。", "擁溜根橫岸，沈波影倒懸。", "無勞問蜀客，此處即高天。"]'),
('72b2a93e-276f-49a2-89b6-6d39744ebdad','奉和宴小山池賦得谿字應制','武三思','唐','唐诗','tang','','[]','年光開碧沼，雲色歛青谿。',60,'全唐诗/poet.tang.4000.json','["年光開碧沼，雲色歛青谿。", "凍解魚方戲，風暄鳥欲啼。", "巖泉飛野鶴，石鏡舞山雞。", "柳發龍鱗出，松新麈尾齊。", "九韶從此驗，三月定應迷。"]'),
('ca4c0cfa-7fcb-4be5-b4c4-d77c7dfb3f65','奉和過梁王宅即目應制','武三思','唐','唐诗','tang','','[]','巖居多水石，野宅滿風煙。',60,'全唐诗/poet.tang.4000.json','["巖居多水石，野宅滿風煙。", "本謂開三徑，俄欣降九天。", "穿林移步輦，拂岸轉行旃。", "鳳竹初垂籜，龜河未吐蓮。", "願持山作壽，恆用劫爲年。"]'),
('d441a467-c7a4-4a9b-8f4a-bcba626c16d8','奉和春日游龍門應制','武三思','唐','唐诗','tang','','[]','鳳架臨香地，龍輿上翠微。',72,'全唐诗/poet.tang.4000.json','["鳳架臨香地，龍輿上翠微。", "星宮含雨氣，月殿抱春輝。", "碧澗長虹下，雕梁早燕歸。", "雲疑浮寶蓋，石似拂天衣。", "露草侵階長，風花遶席飛。", "日斜宸賞洽，清吹入重闈。"]'),
('d547f652-9a67-484b-8dba-375f39461e1e','秋日于天中寺尋復禮上人','武三思','唐','唐诗','tang','','[]','妙域三時殿，香巖七寶宮。',120,'全唐诗/poet.tang.4000.json','["妙域三時殿，香巖七寶宮。", "金繩先界道，玉柄即談空。", "喻筏知何極，傳燈竟不窮。", "彌天高義遠，初地勝因通。", "理詣歸一處，心行不二中。", "有無雙惑遣，真俗兩緣同。", "摘葉疑焚翠，投花若散紅。", "網珠遙映日，檐鐸近吟風。", "定沼寒光素，禪枝暝色葱。", "願隨方便力，長冀釋塵籠。"]'),
('459d5ac2-2367-4ab4-817c-d6e9b21867e4','句','武三思','唐','唐诗','tang','','[]','雲螭非易匹，月駟本難儔。',12,'全唐诗/poet.tang.4000.json','["雲螭非易匹，月駟本難儔。"]'),
('36164dcf-cc54-4fbe-8a1c-010f4076b182','奉和聖製夏日遊石淙山','張易之','唐','唐诗','tang','','[]','六龍驤首曉駸駸，七聖陪軒集潁陰。',64,'全唐诗/poet.tang.4000.json','["六龍驤首曉駸駸，七聖陪軒集潁陰。", "千丈松蘿交翠幕，一丘山水當鳴琴。", "青鳥白雲王母使，垂藤斷葛野人心。", "山中日暮幽巖下，泠然香吹落花深。"]'),
('942dd601-a3d6-47a6-b960-1efd6eddb24d','侍從過公主南宅侍宴探得風字應制','張易之','唐','唐诗','tang','','[]','逐賞平陽第，鳴笳上苑東。',48,'全唐诗/poet.tang.4000.json','["逐賞平陽第，鳴笳上苑東。", "鳥吟千戶竹，蝶舞百花叢。", "時攀小山桂，共挹大王風。", "坐客無勞起，秦簫曲未終。"]'),
('5091b00a-4a76-456b-9623-f5b50eb1252e','出塞','張易之','唐','唐诗','tang','','[]','俠客重恩光，駿馬飾金裝。',84,'全唐诗/poet.tang.4000.json','["俠客重恩光，駿馬飾金裝。", "瞥聞傳羽檄，馳突救邊荒。", "轉戰磨笄地，橫行戴斗鄉。", "將軍占太白，小婦怨流黃。", "騕褭青絲騎，娉婷紅粉妝。", "一春鶯度曲，八月雁成行。", "誰堪坐秋思，羅袖拂空牀。"]'),
('b2864c4b-9c98-44f0-802a-490a8478304b','泛舟侍宴應制','張易之','唐','唐诗','tang','','[]','平明出御溝，解纜坐迴舟。',48,'全唐诗/poet.tang.4000.json','["平明出御溝，解纜坐迴舟。", "綠水澄明月，紅羅結綺樓。", "弦歌爭浦入，冠蓋逐川流。", "白魚臣作伴，相對舞王舟。"]'),
('a44c9bf8-b76d-400b-8455-2d17c3af2d4a','奉和聖製夏日遊石淙山','張昌宗','唐','唐诗','tang','','[]','雲車遙裔三珠樹，帳殿交陰八桂叢。',64,'全唐诗/poet.tang.4000.json','["雲車遙裔三珠樹，帳殿交陰八桂叢。", "磵險泉聲疑度雨，川平橋勢若晴虹。", "叔夜彈琴歌白雪，孫登長嘯韻清風。", "即此陪歡遊閬苑，無勞辛苦向崆峒。"]'),
('86629c14-0fcf-4095-9206-7243637e8a31','少年行','張昌宗','唐','唐诗','tang','','[]','少年不識事，落魄遊韓魏。',96,'全唐诗/poet.tang.4000.json','["少年不識事，落魄遊韓魏。", "珠軒流水車，玉勒浮雲騎。", "縱橫意不一，然諾心無二。", "白璧贈穰苴，黃金奉毛遂。", "妙舞飄龍管，清歌吟鳳吹。", "三春小苑遊，千日中山醉。", "直言身可沈，誰論名與利。", "依倚孟嘗君，自知能市義。"]'),
('56b786ad-a9ee-4453-991e-5f366bff798a','太平公主山亭侍宴','張昌宗','唐','唐诗','tang','','[]','淮南有小山，嬴女隱其間。',48,'全唐诗/poet.tang.4000.json','["淮南有小山，嬴女隱其間。", "折桂芙蓉浦，吹簫明月灣。", "扇掩將雛曲，釵承墮馬鬟。", "歡情本無限，莫掩洛城關。"]'),
('e4b0e58c-a5c6-4211-b86e-9e779ba63437','奉和聖製夏日遊石淙山','薛曜','唐','唐诗','tang','','[]','玉洞幽尋更是天，朱霞綠景鎮韶年。',64,'全唐诗/poet.tang.4000.json','["玉洞幽尋更是天，朱霞綠景鎮韶年。", "飛花藉藉迷行路，囀鳥遙遙作管弦。", "霧隱長林成翠幄，風吹細雨即虹泉。", "此中碧酒恆參聖，浪道崑山別有仙。"]'),
('68f499d7-37a4-4d0f-9cec-7976c13e53e8','子夜冬歌','薛曜','唐','唐诗','tang','','[]','朔風扣羣木，嚴霜凋百草。',24,'全唐诗/poet.tang.4000.json','["朔風扣羣木，嚴霜凋百草。", "借問月中人，安得長不老。"]'),
('f903c883-52c3-4871-b133-abdbccff5360','舞馬篇','薛曜','唐','唐诗','tang','','[]','星精龍種競騰驤，雙眼黃金紫豔光。',326,'全唐诗/poet.tang.4000.json','["星精龍種競騰驤，雙眼黃金紫豔光。", "一朝逢遇昇平代，伏皂銜圖事帝王。", "我皇盛德苞六宇，俗泰時和虞石拊。", "昔聞九代有餘名，今日百獸先來舞。", "鉤陳周衞儼旌旄，鐘鎛陶匏聲殷地。", "承雲嘈囋駭日靈，調露鏗鈜動天駟。", "奔塵飛箭若麟螭，躡景追風忽見知。", "咀銜拉鐵並權奇，被服雕章何陸離。", "紫玉鳴珂臨寶鐙，青絲綵絡帶金羈。", "隨歌鼓而電驚，逐丸劒而飆馳。", "態聚𨄳還急，驕凝驟不移。", "光敵白日下，氣擁綠煙垂。", "婉轉盤跚殊未已，懸空步驟紅塵起。", "驚鳧翔鷺不堪儔，矯鳳迴鸞那足擬。", "蘅垂桂褭香氛氳，長鳴汗血盡浮雲。", "不辭辛苦來東道，祗爲簫韶朝夕聞。", "閶闔間，玉臺側，承恩煦兮生光色。", "鸞鏘鏘，車翼翼，備國容兮爲戎飾。", "充雲翹兮天子庭，荷日用兮情無極。", "吉良乘兮一千歲，神是得兮天地期。", "大易占云南山壽，䟃𧽼共樂聖明時。"]'),
('e9f22d13-9972-49eb-9895-f5282431c96c','正夜侍宴應詔','薛曜','唐','唐诗','tang','','[]','重關鐘漏通，夕敞鳳皇宮。',48,'全唐诗/poet.tang.4000.json','["重關鐘漏通，夕敞鳳皇宮。", "雙闕祥煙裏，千門明月中。", "酒杯浮湛露，歌曲唱風流。", "侍臣咸醉止，恆慙恩遇崇。"]'),
('699f7536-1aab-43d2-bdef-4dc1658197be','送道士入天台','薛曜','唐','唐诗','tang','','[]','洛陽陌上多離別，蓬萊山下足波潮。',32,'全唐诗/poet.tang.4000.json','["洛陽陌上多離別，蓬萊山下足波潮。", "碧海桑田何處在？笙歌一聽一遙遙。"]'),
('b1565b0d-731a-459c-ad6e-b88afffb7832','奉和聖製夏日遊石淙山','楊敬述','唐','唐诗','tang','','[]','山中別有神仙地，屈曲幽深碧澗垂。',64,'全唐诗/poet.tang.4000.json','["山中別有神仙地，屈曲幽深碧澗垂。", "巖前暫駐黃金輦，席上還飛白玉巵。", "遠近風泉俱合雜，高低雲石共參差。", "林壑偏能留睿賞，長天莫遽下丹曦。"]'),
('51a98c2e-ca0d-4d77-82f6-2c10adc4aeae','奉和聖製夏日遊石淙山','于季子','唐','唐诗','tang','','[]','九旗雲布臨嵩室，萬騎星陳集潁川。',64,'全唐诗/poet.tang.4000.json','["九旗雲布臨嵩室，萬騎星陳集潁川。", "瑞液含滋登禹膳，飛流薦響入虞弦。", "山扉野徑朝花積，帳殿帷宮夏葉連。", "微臣獻壽迎千壽，願奉堯年倚萬年。"]'),
('0d795435-6662-4bc1-ad09-a94080bfe33a','詠雲','于季子','唐','唐诗','tang','','[]','瑞雲千里映，祥輝四望新。',48,'全唐诗/poet.tang.4000.json','["瑞雲千里映，祥輝四望新。", "隨風亂鳥翅，汎水結魚鱗。", "布葉疑臨夏，開花詎待春。", "願得承嘉景，無令掩桂輪。"]'),
('6c3b82b5-0a24-441f-8add-e5c75179794d','詠螢','于季子','唐','唐诗','tang','','[]','卉草誠幽賤，枯朽絕因依。',48,'全唐诗/poet.tang.4000.json','["卉草誠幽賤，枯朽絕因依。", "忽逢借羽翼，不覺生光輝。", "直念恩華重，長嗟報効微。", "方思助日月，爲許願曾飛。"]'),
('3d4703aa-4250-441a-9ee5-2cc12fb24172','早春洛陽荅杜審言','于季子','唐','唐诗','tang','','[]','梓澤年光往復來，杜霸遊人去不迴。',64,'全唐诗/poet.tang.4000.json','["梓澤年光往復來，杜霸遊人去不迴。", "若非載筆登麟閣，定是吹簫伴鳳臺。", "路傍桃李花猶嫩，波上芙蕖葉未開。", "分明寄語長安道，莫教留滯洛陽才。"]'),
('d8abe5f3-34ae-4547-a239-bb4702616074','詠項羽','于季子','唐','唐诗','tang','','[]','北伐雖全趙，東歸不王秦。',24,'全唐诗/poet.tang.4000.json','["北伐雖全趙，東歸不王秦。", "空歌拔山力，羞作渡江人。"]'),
('3cac9992-e0ef-4f2b-80c5-f0324df74d74','詠漢高祖','于季子','唐','唐诗','tang','','[]','百戰方夷項，三章且代秦。',24,'全唐诗/poet.tang.4000.json','["百戰方夷項，三章且代秦。", "功歸蕭相國，氣盡戚夫人。"]'),
('6cab8d79-a3be-4aed-bb77-f95c280982fc','南行別弟','于季子','唐','唐诗','tang','','["\u548f\u7269\u8bd7", "\u601d\u4e61", "\u548f\u7269"]','萬里人南去，三春雁北飛。',24,'全唐诗/poet.tang.4000.json','["萬里人南去，三春雁北飛。", "不知何歲月？得與爾同歸。"]'),
('8c6cccf1-5d2e-451f-830f-33327a652461','長信宮中樹','喬知之','唐','唐诗','tang','','[]','婀娜當軒樹，䒠茸倚蘭殿。',48,'全唐诗/poet.tang.4000.json','["婀娜當軒樹，䒠茸倚蘭殿。", "葉豔九春華，香搖五明扇。", "餘花鳥弄盡，新葉蟲書徧。", "零落心自知，芳菲君不見。"]'),
('2e93af1d-9385-458d-809d-8589ac15ae3e','下山逢故夫','喬知之','唐','唐诗','tang','','[]','妾身本薄命，輕棄城南隅。',48,'全唐诗/poet.tang.4000.json','["妾身本薄命，輕棄城南隅。", "庭前厭芍藥，山上采蘼蕪。", "春風罥紈袖，零露濕羅襦。", "羞將憔悴日，提籠逢故夫。"]'),
('be65f9a4-d8ad-4161-ae02-fb8d6eeaea69','巫山高','喬知之','唐','唐诗','tang','','[]','巫山十二峰，參差互隱見。',72,'全唐诗/poet.tang.4000.json','["巫山十二峰，參差互隱見。", "潯陽幾千里，周覽忽已徧。", "想像神女姿，摘芳共珍薦。", "楚雲何逶迤，紅樹日葱蒨。", "楚雲沒湘源，紅樹斷荆門。", "郢路不可見，況復夜聞猨。"]'),
('21e40b25-da95-4352-84a4-142e54f65062','棄妾篇','喬知之','唐','唐诗','tang','','[]','妾本叢臺右，君在鴈門陲。',72,'全唐诗/poet.tang.4000.json','["妾本叢臺右，君在鴈門陲。", "悠悠淇水曲，綵燕入桑枝。", "不因媒結好，本以容相知。", "容謝君應去，情移會有離。", "還君結縷帶，歸妾識成詩。", "此物雖輕賤，不用使人嗤。"]'),
('625e49c0-43ec-4636-91f1-03eb749ad9d6','苦寒行','喬知之','唐','唐诗','tang','','[]','胡天夜清迥，孤雲獨飄颺。',108,'全唐诗/poet.tang.4000.json','["胡天夜清迥，孤雲獨飄颺。", "遙裔出鴈關，逶迤含晶光。", "陰陵久裴回，幽都無多陽。", "初寒凍巨海，殺氣流大荒。", "朔馬飲寒冰，行子履胡霜。", "路有從役倦，臥死黃沙場。", "羈旅因相依，慟之淚霑裳。", "由來從軍行，賞存不賞亡。", "亡者誠已矣，徒令存者傷。"]'),
('87c9d22c-64a8-4cc6-a4a2-e89a2cad02cf','從軍行','喬知之','唐','唐诗','tang','','[]','南庭結白露，北風掃黃葉。',144,'全唐诗/poet.tang.4000.json','["南庭結白露，北風掃黃葉。", "此時鴻鴈來，驚鳴催思妾。", "曲房理針線，平砧擣文練。", "鴛綺裁易成，龍鄉信難見。", "窈窕九重閨，寂寞十年啼。", "紗窗白雲宿，羅幌月光棲。", "雲月隱微微，夜上流黃機。", "玉霜凍珠履，金吹薄羅衣。", "漢家已得地，君去將何事。", "宛轉結蠶書，寂寥無鴈使。", "生平荷恩信，本爲榮華進。", "況復落紅顏，蟬聲催綠鬢。"]'),
('340d98e9-d8ec-4e7d-9a23-cce3bc41ee92','擬古贈陳子昂','喬知之','唐','唐诗','tang','','[]','惸惸孤形影，悄悄獨遊心。',144,'全唐诗/poet.tang.4000.json','["惸惸孤形影，悄悄獨遊心。", "以此從王事，常與子同衾。", "別離三河間，征戰二庭深。", "胡天夜雨霜，胡鴈晨南翔。", "節物感離居，同衾違故鄉。", "南歸日將遠，北方尚蓬飄。", "孟秋七月時，相送出外郊。", "海風吹涼木，邊聲響梢梢。", "勤役千萬里，將臨五十年。", "心事爲誰道，抽琴歌坐筵。", "一彈再三歎，賓御淚潺湲。", "送君竟此曲，從茲長絕弦。"]'),
('ec4bfedf-b0a4-4958-9ba9-6c5dc25a3add','定情篇','喬知之','唐','唐诗','tang','','[]','共君結新婚，歲寒心未卜。',288,'全唐诗/poet.tang.4000.json','["共君結新婚，歲寒心未卜。", "相與遊春園，各隨情所逐。", "君愛菖蒲花，妾感苦寒竹。", "菖花多豔姿，寒竹有貞葉。", "此時妾比君，君心不如妾。", "簪玉步河堤，妖韶援綠荑。", "鳧鴈將子遊，鶯燕從雙栖。", "君念春光好，妾向春光啼。", "君時不得意，棄妾還金閨。", "結言本同心，悲歡何未齊。", "怨咽前致辭，願得申所悲。", "人間丈夫易，世路婦難爲。", "始如經天月，終若流星馳。", "天月相終始，流星無定期。", "長信佳麗人，失意非蛾眉。", "廬江小吏婦，非關織作遲。", "本願長相對，今已長相思。", "復有遊宦子，結援從梁陳。", "燕居崇三朝，去來歷九春。", "誓心妾終始，蠶桑奉所親。", "歸願未克從，黃金贈路人。", "潔婦懷明義，從泛河之津。", "于今千萬年，誰當問水濱。", "更憶娼家樓，夫婿事封侯。"]'),
('f2005e3a-aac5-4459-8045-8b7e770f34f1','綠珠篇','喬知之','唐','唐诗','tang','','[]','石家金谷重新聲，明珠十斛買娉婷。',96,'全唐诗/poet.tang.4000.json','["石家金谷重新聲，明珠十斛買娉婷。", "此日可憐君自許，此時可喜得人情。", "君家閨閣不曾難，常將歌舞借人看。", "意氣雄豪非分理，驕矜勢力橫相干。", "辭君去君終不忍，徒勞掩袂傷鉛粉。", "百年離別在高樓，一旦紅顏爲君盡。"]'),
('5b622f0d-7563-4e59-9b01-cc69147ac4e2','和李侍郎古意','喬知之','唐','唐诗','tang','','[]','妾家巫山隔漢川，君度南庭向胡苑。',192,'全唐诗/poet.tang.4000.json','["妾家巫山隔漢川，君度南庭向胡苑。", "高樓迢遰想金天，河漢昭回更愴然。", "夜如何其夜未央，閑花照月愁洞房。", "自矜夫婿勝王昌，三十曾作侍中郎。", "一從流落戍漁陽，懷哉萬恨結中腸。", "南山冪冪兔絲花，北陵青青女蘿樹。", "由來花葉同一根，今日枝條分兩處。", "三星差池光照灼，北斗西指秋雲薄。", "莖枯花謝枝憔悴，香銷色盡花零落。", "美人長歎豔容萎，含情收取摧折枝。", "調絲獨彈聲未移，感君行坐星歲遲。", "閨中宛轉今若斯，誰能爲報征人知。"]'),
('b8c5c4ae-6682-48d7-8a67-bf15e0181c90','倡女行','喬知之','唐','唐诗','tang','','[]','石榴酒，葡萄漿，蘭桂芳，茱萸香。',108,'全唐诗/poet.tang.4000.json','["石榴酒，葡萄漿，蘭桂芳，茱萸香。", "願君駐金鞍，暫此共年芳。", "願君解羅襦，一醉同匡牀。", "文君正新寡，結念在歌倡。", "昨宵綺帳迎韓壽，今朝羅袖引潘郎。", "莫吹羌笛驚鄰里，不用琵琶喧洞房。", "且歌新夜曲，莫弄楚明光。", "此曲怨且豔，哀音斷人腸。"]'),
('dd5ac002-dc5f-491d-b8b1-c4e6fd09d31a','羸駿篇','喬知之','唐','唐诗','tang','','["\u9ec4\u6cb3"]','噴玉長鳴西北來，自言當代是龍媒。',336,'全唐诗/poet.tang.4000.json','["噴玉長鳴西北來，自言當代是龍媒。", "萬里鐵關行入貢，九重金闕爲君開。", "蹀躞朝馳過上苑，䟃𧽼暝走發章臺。", "玉勒金鞍荷裝飾，路傍觀者無窮極。", "小山桂樹比權奇，上林桃花況顏色。", "忽聞天將出龍沙，漢主持將駕鼓車。", "去去山川勞日夜，遙遙關塞斷煙霞。", "山川關塞十年征，汗血流離赴月營。", "肌膚銷遠道，膂力盡長城。", "長城日夕苦風霜，中有連年百戰場。", "搖珂嚙勒金羈盡，爭鋒足頓鐵菱傷。", "垂耳罷輕齎，棄置在寒谿。", "大宛蒲海北，滇壑雋崖西。", "沙平留緩步，路遠闇頻嘶。", "從來力盡君須棄，何必尋途我已迷。", "歲歲年年奔遠道，朝朝暮暮催疲老。", "扣冰晨飲黃河源，拂雪夜食天山草。", "楚水澶谿征戰事，吳塞烏江辛苦地。", "持來報主不辭勞，宿昔立功非重利。", "丹心素節本無求，長鳴向君君不留。", "祗應澶漫歸田里，萬里低昂任生死。", "君王倘若不見遺，白骨黃金猶可市。"]'),
('dbf9c280-2c3d-458f-b189-8019915f597f','銅雀妓','喬知之','唐','唐诗','tang','','[]','金閣惜分香，鉛華不重妝。',48,'全唐诗/poet.tang.4000.json','["金閣惜分香，鉛華不重妝。", "空餘歌舞地，猶是爲君王。", "哀弦調已絕，豔曲不須長。", "共看西陵暮，秋煙起白楊。"]'),
('6aa46acf-2a22-4559-868f-9f31d7259563','侍宴應制得分字','喬知之','唐','唐诗','tang','','[]','紫禁肅晴氛，朱樓落曉雲。',48,'全唐诗/poet.tang.4000.json','["紫禁肅晴氛，朱樓落曉雲。", "豫遊龍駕轉，天樂鳳簫聞。", "竹外仙亭出，花間輦路分。", "微臣一何幸，詞賦奉明君。"]'),
('2f6e99ce-4cfd-4740-a2cf-de2717d46c6a','梨園亭子侍宴','喬知之','唐','唐诗','tang','','[]','年光陌上發，香輦禁中遊。',48,'全唐诗/poet.tang.4000.json','["年光陌上發，香輦禁中遊。", "草綠鴛鴦殿，花紅翡翠樓。", "天杯承露酌，仙管雜風流。", "今日陪歡豫，皇恩不可酬。"]'),
('77828789-8bb8-4b4c-b6b0-4bc3db6e4bc6','和蘇員外寓直','喬知之','唐','唐诗','tang','','[]','自昔重爲郎，伊人練國章。',72,'全唐诗/poet.tang.4000.json','["自昔重爲郎，伊人練國章。", "三旬登建禮，五夜直明光。", "墨草尚書奏，衣飄侍御香。", "開軒竹氣靜，拂簟蕙風涼。", "曉漏離閶闔，鳴鐘出未央。", "從來宿臺上，天子貴文強。"]'),
('8b740c39-e58f-4831-b5da-29be6fb4d1ab','哭故人','喬知之','唐','唐诗','tang','','[]','生死久離居，悽涼歷舊廬。',72,'全唐诗/poet.tang.4000.json','["生死久離居，悽涼歷舊廬。", "歎茲三徑斷，不踐十年餘。", "古木巢禽合，荒庭愛客疎。", "匣留彈罷劒，牀積讀殘書。", "玉沒終無像，蘭言強問虛。", "平生不得意，泉路復何如。"]'),
('192b781a-ddfa-42f7-bda0-de181dc59d39','折楊柳','喬知之','唐','唐诗','tang','','[]','可憐濯濯春楊柳，攀折將來就纖手。',32,'全唐诗/poet.tang.4000.json','["可憐濯濯春楊柳，攀折將來就纖手。", "妾容與此同盛衰，何必君恩能獨久。"]'),
('40574096-1599-41ea-8388-00ffbd043b00','人日登高','喬侃','唐','唐诗','tang','','[]','僕本多悲者，年來不悟春。',60,'全唐诗/poet.tang.4000.json','["僕本多悲者，年來不悟春。", "登高一遊目，始覺柳條新。", "杜陵猶識漢，桃源不辨秦。", "蹔若升雲霧，還似出囂塵。", "賴得煙霞氣，淹留攀桂人。"]'),
('fe00ac4c-7b96-4129-800a-28952ad69f65','出塞','喬備','唐','唐诗','tang','','[]','沙場三萬里，猛將五千兵。',48,'全唐诗/poet.tang.4000.json','["沙場三萬里，猛將五千兵。", "旌斷冰谿戍，笳吹鐵關城。", "陰雲暮下雪，寒日晝無晶。", "直爲懷恩苦，誰知邊塞情。"]'),
('6403a5d8-e1fd-48e8-9ee7-375b162dc62c','長門怨','喬備','唐','唐诗','tang','','[]','秋入長門殿，木落洞房虛。',48,'全唐诗/poet.tang.4000.json','["秋入長門殿，木落洞房虛。", "妾思宵徒靜，君恩日更疎。", "墜露清金閣，流螢點玉除。", "還將閨裏恨，遙問馬相如。"]'),
('c7a99df2-5e23-45d7-a9c6-283277760654','將軍行','劉希夷','唐','唐诗','tang','','[]','將軍闢轅門，耿介當風立。',120,'全唐诗/poet.tang.4000.json','["將軍闢轅門，耿介當風立。", "諸將欲言事，逡巡不敢入。", "劒氣射雲天，鼓聲振原隰。", "黃塵塞路起，走馬追兵急。", "彎弓從此去，飛箭如雨集。", "截圍一百里，斬首五千級。", "代馬流血死，胡人抱鞍泣。", "古來養甲兵，有事常討襲。", "乘我廟堂運，坐使干戈戢。", "獻凱歸京師，軍容何翕習。"]'),
('f72f7516-3859-484d-9984-bab0438b736e','從軍行','劉希夷','唐','唐诗','tang','','["\u9ec4\u6cb3"]','秋天風颯颯，羣胡馬行疾。',108,'全唐诗/poet.tang.4000.json','["秋天風颯颯，羣胡馬行疾。", "嚴城晝不開，伏兵暗相失。", "天子廟堂拜，將軍凶門出。", "紛紛伊洛道，戎馬幾萬匹。", "軍門壓黃河，兵氣衝白日。", "平生懷仗劒，慷慨即投筆。", "南登漢月孤，北走代雲密。", "近取韓彭計，早知孫吳術。", "丈夫清萬里，誰能掃一室。"]'),
('ba5d84f0-cb26-4687-b1c9-c708e7dae9d8','春女行','劉希夷','唐','唐诗','tang','','[]','春女顏如玉，怨歌陽春曲。',168,'全唐诗/poet.tang.4000.json','["春女顏如玉，怨歌陽春曲。", "巫山春樹紅，沅湘春草綠。", "自憐妖豔姿，妝成獨見時。", "愁心伴楊柳，春盡亂如絲。", "目極千餘里，悠悠春江水。", "頻想玉關人，愁臥金閨裏。", "尚言春花落，不知秋風起。", "嬌愛猶未終，悲涼從此始。", "憶昔楚王宮，玉樓粧粉紅。", "纖腰弄明月，長袖舞春風。", "容華委西山，光陰不可還。", "桑林變東海，富貴今何在？", "寄言桃李容，胡爲閨閤重。", "但看楚王墓，唯有數株松。"]'),
('e2adcb31-928f-4481-8207-fada8940a00f','孤松篇','劉希夷','唐','唐诗','tang','','[]','蠶月桑葉青，鸎時柳花白。',192,'全唐诗/poet.tang.4000.json','["蠶月桑葉青，鸎時柳花白。", "澹豔煙雨姿，敷芬陽春陌。", "如何秋風起，零落從此始。", "獨有南澗松，不歎東流水。", "玄陰天地冥，皓雪朝夜零。", "豈不罹寒暑，爲君留青青。", "青青好顏色，落落任孤直。", "羣樹遙相望，衆草不敢逼。", "靈龜卜真隱，仙鳥宜棲息。", "恥受秦帝封，願言唐侯食。", "寒山夜月明，山冷氣清清。", "淒兮歸鳳集，吹之作琴聲。", "松子臥仙岑，寂聽疑野心。", "清泠有真曲，樵採無知音。", "美人何時來？幽徑委綠苔。", "吁嗟深澗底，棄捐廣廈材。"]'),
('bd58a01b-8e6f-435a-a7a8-3843c83e0ece','嵩嶽聞笙','劉希夷','唐','唐诗','tang','','[]','月出嵩山東，月明山益空。',108,'全唐诗/poet.tang.4000.json','["月出嵩山東，月明山益空。", "山人愛清景，散髪臥秋風。", "風止夜何清，獨夜草蟲鳴。", "仙人不可見，乘月近吹笙。", "絳脣吸靈氣，玉指調真聲。", "真聲是何曲，三山鸞鶴情。", "昔去落塵俗，願言聞此曲。", "今來臥嵩岑，何幸承幽音。", "神仙樂吾事，笙歌銘夙心。"]'),
('128b7cf2-1333-4e85-bd06-cd9b2f472aab','秋日題汝陽潭壁','劉希夷','唐','唐诗','tang','','[]','獨坐秋陰生，悲來從所適。',120,'全唐诗/poet.tang.4000.json','["獨坐秋陰生，悲來從所適。", "行見汝陽潭，飛蘿蒙水石。", "懸瓢木葉上，風吹何歷歷。", "幽人不耐煩，振衣步閑寂。", "迴流清見底，金沙覆銀礫。", "錯落非一文，空朧幾千尺。", "魚鱗可憐紫，鴨毛自然碧。", "吟詠秋水篇，渺然忘損益。", "秋水隨形影，清濁混心迹。", "歲暮歸去來，東山余宿昔。"]'),
('e61f13a4-8f37-4c7d-b4d6-693001f9925b','采桑','劉希夷','唐','唐诗','tang','','[]','楊柳送行人，青青西入秦。',120,'全唐诗/poet.tang.4000.json','["楊柳送行人，青青西入秦。", "誰家采桑女，樓上不勝春。", "盈盈灞水曲，步步春芳綠。", "紅臉耀明珠，絳脣含白玉。", "回首渭橋東，遙憐春色同。", "青絲嬌落日，緗綺弄春風。", "攜籠長歎息，逶遲戀春色。", "看花若有情，倚樹疑無力。", "薄暮思悠悠，使君南陌頭。", "相逢不相識，歸去夢青樓。"]'),
('973f20b5-ae5e-406a-b4e8-2c3ba92ed895','謁漢世祖廟','劉希夷','唐','唐诗','tang','','[]','舂陵氣初發，漸臺首未傳。',192,'全唐诗/poet.tang.4000.json','["舂陵氣初發，漸臺首未傳。", "列營百萬衆，持國十八年。", "運開朱旗後，道合赤符先。", "宛城劒鳴匣，昆陽鏑應弦。", "獷獸血塗地，巨人聲沸天。", "長驅過北趙，短兵出南燕。", "太守迎門外，王郎死道邊。", "昇壇九城陌，端拱千秋年。", "朝廷方雀躍，劒珮幾聯翩。", "至德刑四海，神儀翳九泉。", "宗子行舊邑，恭聞清廟篇。", "君容穆而聖，臣像儼猶賢。", "攢木承危柱，疎蘿挂朽椽。", "祠庭巢鳥啄，祭器網蟲緣。", "懷古江山在，惟新曆數遷。", "空餘今夜月，長似舊時懸。"]'),
('16d007eb-e119-499d-aa10-77c6524727ec','巫山懷古','劉希夷','唐','唐诗','tang','','[]','巫山幽陰地，神女豔陽年。',96,'全唐诗/poet.tang.4000.json','["巫山幽陰地，神女豔陽年。", "襄王伺容色，落日望悠然。", "歸來高唐夜，金釭燄青煙。", "頹想臥瑤席，夢魂何翩翩。", "搖落殊未已，榮華倏徂遷。", "愁思瀟湘浦，悲涼雲夢田。", "猿啼秋風夜，鴈飛明月天。", "巴歌不可聽，聽此益潺湲。"]'),
('d9ed2a27-6c6b-46d7-b41c-1df254a6e6f2','歸山','劉希夷','唐','唐诗','tang','','[]','歸去嵩山道，煙花覆青草。',36,'全唐诗/poet.tang.4000.json','["歸去嵩山道，煙花覆青草。", "草綠山無塵，山青楊柳春。", "日暮松聲合，空歌思殺人。"]'),
('865f621d-c2f6-48f3-a8ca-5a6dbb46c507','代閨人春日','劉希夷','唐','唐诗','tang','','[]','珠簾的曉光，玉顏豔春彩。',72,'全唐诗/poet.tang.4000.json','["珠簾的曉光，玉顏豔春彩。", "林間鳥鳴喚，戶外花相待。", "花鳥惜芳菲，鳥鳴花亂飛。", "人今伴花鳥，日暮不能歸。", "池月憐歌扇，山雲愛舞衣。", "佳期楊柳陌，攜手莫相違。"]'),
('8b5d15f2-8429-49ca-9708-e1b20ece4504','蜀城懷古','劉希夷','唐','唐诗','tang','','[]','蜀土遶水竹，吳天積風霜。',120,'全唐诗/poet.tang.4000.json','["蜀土遶水竹，吳天積風霜。", "窮覽通表裏，氣色何蒼蒼。", "舊國有年代，青樓思豔妝。", "古人無歲月，白骨冥丘荒。", "寂歷彈琴地，幽流讀書堂。", "玄龜埋卜室，彩鳳滅詞場。", "陣圖一一在，栢樹雙雙行。", "鬼神清漢廟，鳥雀參秦倉。", "歎世已多感，懷心益自傷。", "賴蒙靈丘境，時當明月光。"]'),
('232f945b-61d2-4c44-a382-efa15de48831','洛川懷古','劉希夷','唐','唐诗','tang','','["\u6cf0\u5c71"]','萋萋春草綠，悲歌牧征馬。',192,'全唐诗/poet.tang.4000.json','["萋萋春草綠，悲歌牧征馬。", "行見白頭翁，坐泣青竹下。", "感歎前問之，贈予辛苦詞。", "歲月移今古，山河更盛衰。", "晉家都洛濱，朝廷多近臣。", "詞賦歸潘岳，繁華稱季倫。", "梓澤春草菲，河陽亂華飛。", "綠珠不可奪，白首同所歸。", "高樓倏冥滅，茂林久摧折。", "昔時歌舞臺，今成狐兔穴。", "人事互消亡，世路多悲傷。", "北邙是吾宅，東嶽爲吾鄉。", "君看北邙道，髑髏縈蔓草。", "芳□□□□，□□□□□。", "碑塋或半存，荆棘斂幽魂。", "揮涕棄之去，不忍聞此言。"]'),
('26340e1c-ac83-497e-910e-281647d85a2d','春日行歌','劉希夷','唐','唐诗','tang','','[]','山樹落梅花，飛落野人家。',48,'全唐诗/poet.tang.4000.json','["山樹落梅花，飛落野人家。", "野人何所有，滿甕陽春酒。", "攜酒上春臺，行歌伴落梅。", "醉罷臥明月，乘夢遊天台。"]'),
('48809356-a51f-40dd-bb2d-ce803947f2dc','江南曲八首 一','劉希夷','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','暮宿南洲草，晨行北岸林。',60,'全唐诗/poet.tang.4000.json','["暮宿南洲草，晨行北岸林。", "日懸滄海闊，水隔洞庭深。", "煙景無留意，風波有異潯。", "歲遊難極目，春戲易爲心。", "朝夕無榮遇，芳菲已滿襟。"]'),
('fb70e8de-52d5-4728-a097-63c50fbee3b8','江南曲八首 二','劉希夷','唐','唐诗','tang','','[]','豔唱潮初落，江花露未晞。',60,'全唐诗/poet.tang.4000.json','["豔唱潮初落，江花露未晞。", "春洲驚翡翠，朱服弄芳菲。", "畫舫煙中淺，青陽日際微。", "錦帆衝浪濕，羅袖拂行衣。", "含情罷所採，相歎惜流暉。"]'),
('39e859bf-e12e-485d-a4e8-d0d560c5ec21','江南曲八首 三','劉希夷','唐','唐诗','tang','','[]','君爲隴西客，妾遇江南春。',60,'全唐诗/poet.tang.4000.json','["君爲隴西客，妾遇江南春。", "朝遊含靈果，夕採弄風蘋。", "果氣時不歇，蘋花日自新。", "以此江南物，持贈隴西人。", "空盈萬里懷，欲贈竟無因。"]'),
('3be9142f-2262-4efa-be9a-91d29ca77981','江南曲八首 四','劉希夷','唐','唐诗','tang','','[]','皓如楚江月，靄若吳岫雲。',60,'全唐诗/poet.tang.4000.json','["皓如楚江月，靄若吳岫雲。", "波中自皎鏡，山上亦氤氳。", "明月留照妾，輕雲持贈君。", "山川各離散，光氣乃殊分。", "天涯一爲別，江北不相聞。"]'),
('5bde1ef7-e93d-4dd5-bfbd-dc16c137b440','江南曲八首 五','劉希夷','唐','唐诗','tang','','[]','艤舟乘潮去，風帆振早涼。',62,'全唐诗/poet.tang.4000.json','["艤舟乘潮去，風帆振早涼。", "潮平見楚甸，天際望維揚。", "洄泝經千里，煙波接兩鄉。", "雲明江嶼出，日照海流長。", "此中逢歲[晏]，浦樹落花芳。"]'),
('77e1c53d-c15a-4a29-9a22-4a2e2859855d','江南曲八首 六','劉希夷','唐','唐诗','tang','','[]','暮春三月晴，維揚吳楚城。',68,'全唐诗/poet.tang.4000.json','["暮春三月晴，維揚吳楚城。", "城臨大江汜，回映洞浦清。", "晴雲曲金閣，珠樓碧煙裏。", "月明芳樹羣鳥飛，風過長林雜花起。", "可憐離別誰家子，於此一至情何已。"]'),
('906bf983-de04-4551-b6dd-5d090a524a8c','江南曲八首 七','劉希夷','唐','唐诗','tang','','[]','北堂紅草盛䒠茸，南湖碧水照芙蓉。',64,'全唐诗/poet.tang.4000.json','["北堂紅草盛䒠茸，南湖碧水照芙蓉。", "朝遊暮起金花盡，漸覺羅裳珠露濃。", "自惜妍華三五歲，已歎關山千萬重。", "人情一去無還日，欲贈懷芳怨不逢。"]'),
('70a2b682-8acd-4362-97e9-7bf9b4e0f834','江南曲八首 八','劉希夷','唐','唐诗','tang','','["\u6d1e\u5ead\u6e56"]','憶昔江南年盛時，平生怨在長洲曲。',64,'全唐诗/poet.tang.4000.json','["憶昔江南年盛時，平生怨在長洲曲。", "冠蓋星繁江水上，衝風摽落洞庭淥。", "落花兩袖紅紛紛，朝霞高閣洗晴雲。", "誰言此處嬋娟子，珠玉爲心以奉君。"]'),
('6c0c6f83-70ad-415d-8afd-61ee109a9a93','擣衣篇','劉希夷','唐','唐诗','tang','','[]','秋天瑟瑟夜漫漫，夜白風清玉露漙。',224,'全唐诗/poet.tang.4000.json','["秋天瑟瑟夜漫漫，夜白風清玉露漙。", "燕山遊子衣裳薄，秦地佳人閨閣寒。", "欲向樓中縈楚練，還來機上裂齊紈。", "攬紅袖兮愁徙倚，盼青砧兮悵盤桓。", "盤桓徙倚夜已久，螢火雙飛入簾牖。", "西北風來吹細腰，東南月上浮纖手。", "此時秋月可憐明，此時秋風別有情。", "君看月下參差影，爲聽莎間斷續聲。", "絳河轉兮青雲曉，飛鳥鳴兮行人少。", "攢眉緝縷思紛紛，對影穿鍼魂悄悄。", "聞道還家未有期，誰憐登隴不勝悲。", "夢見形容亦舊日，爲許裁縫改昔時。", "緘書遠寄交河曲，須及明年春草綠。", "莫言衣上有斑斑，只爲思君淚相續。"]'),
('63d7cd25-b545-481e-8495-8332854f47e7','公子行','劉希夷','唐','唐诗','tang','','[]','天津橋下陽春水，天津橋上繁華子。',224,'全唐诗/poet.tang.4000.json','["天津橋下陽春水，天津橋上繁華子。", "馬聲迴合青雲外，人影動搖綠波裏。", "綠波蕩漾玉爲砂，青雲離披錦作霞。", "可憐楊柳傷心樹，可憐桃李斷腸花。", "此日遨遊邀美女，此時歌舞入娼家。", "娼家美女鬱金香，飛來飛去公子傍。", "的的珠簾白日映，娥娥玉顏紅粉妝。", "花際裴回雙蛺蝶，池邊顧步兩鴛鴦。", "傾國傾城漢武帝，爲雲爲雨楚襄王。", "古來容光人所羨，況復今日遙相見。", "願作輕羅著細腰，願爲明鏡分嬌面。", "與君相向轉相親，與君雙棲共一身。", "願作貞松千歲古，誰論芳槿一朝新。", "百年同謝西山日，千秋萬古北邙塵。"]'),
('18a05868-c889-4fc4-b835-b97f83e18ec6','代悲白頭吟','劉希夷','唐','唐诗','tang','','["\u9752\u6625", "\u82b1", "\u5199\u82b1", "\u76f8\u548c\u6b4c\u8f9e", "\u611f\u4f24"]','洛陽城東桃李花，飛來飛去落誰家。',208,'全唐诗/poet.tang.4000.json','["洛陽城東桃李花，飛來飛去落誰家。", "洛陽女兒好顏色，坐見落花長歎息。", "今年花落顏色改，明年花開復誰在。", "已見松柏摧爲薪，更闻桑田變成海。", "古人無復洛城東，今人還對落花風。", "年年歲歲花相似，歲歲年年人不同。", "寄言全盛紅顏子，應憐半死白頭翁。", "此翁白頭真可憐，伊昔紅顏美少年。", "公子王孫芳樹下，清歌妙舞落花前。", "光祿池臺開錦繡，將軍樓閣畫神仙。", "一朝臥病無相識，三春行樂在誰邊。", "宛轉蛾眉能幾時，須臾鶴髪亂如絲。", "但看古來歌舞地，惟有黃昏鳥雀悲。"]'),
('fd02e272-f109-4e8d-ad3d-266581d3b286','代秦女赠行人','劉希夷','唐','唐诗','tang','','[]','鸞鏡曉含春，蛾眉向影嚬。',80,'全唐诗/poet.tang.4000.json','["鸞鏡曉含春，蛾眉向影嚬。", "開□衣裳破，那堪粉黛新。", "春還洛陽道，爲憶春階草。", "楊葉未能攀，梅花待君掃。", "今朝喜鵲傍人飛，應是狂夫走馬歸。", "遙想行歌共遊樂，迎前含笑著春衣。"]'),
('530ee513-c67b-4265-9416-bdd137545c4f','洛中晴月送殷四入關','劉希夷','唐','唐诗','tang','','[]','清洛浮橋南渡頭，天晶萬里散華洲。',64,'全唐诗/poet.tang.4000.json','["清洛浮橋南渡頭，天晶萬里散華洲。", "晴看石瀨光無數，曉入寒潭浸不流。", "微雲一點曙煙起，南陌憧憧遍行子。", "欲將此意與君論，復道秦關尚千里。"]'),
('baff64d7-4897-4299-b03c-700f301bd255','入塞','劉希夷','唐','唐诗','tang','','[]','將軍陷虜圍，邊務息戎機。',48,'全唐诗/poet.tang.4000.json','["將軍陷虜圍，邊務息戎機。", "霜雪交河盡，旌旗入塞飛。", "曉光隨馬度，春色伴人歸。", "課績朝明主，臨軒拜武威。"]'),
('c7e3d1ad-b195-4540-90e6-37795c589e9e','覽鏡','劉希夷','唐','唐诗','tang','','[]','青樓挂明鏡，臨照不勝悲。',48,'全唐诗/poet.tang.4000.json','["青樓挂明鏡，臨照不勝悲。", "白髮今如此，人生能幾時。", "秋風下山路，明月上春期。", "歎息君恩盡，容顏不可思。"]'),
('65ff0552-4213-4edd-bc94-b7e70888f5ce','晚春','劉希夷','唐','唐诗','tang','','[]','佳人眠洞房，回首見垂楊。',48,'全唐诗/poet.tang.4000.json','["佳人眠洞房，回首見垂楊。", "寒盡鴛鴦被，春生玳瑁牀。", "庭陰幕青靄，簾影散紅芳。", "寄語同心伴，迎春且薄妝。"]'),
('78b77857-c252-4c50-92bd-f57b928279fe','送友人之新豐','劉希夷','唐','唐诗','tang','','[]','日暮秋風起，關山斷別情。',48,'全唐诗/poet.tang.4000.json','["日暮秋風起，關山斷別情。", "淚隨黃葉下，愁向綠樽生。", "野路歸驂轉，河洲宿鳥驚。", "賓遊寬旅宴，王事促嚴程。"]'),
('6f9d2877-a8da-4d84-a00c-a39925f523ba','餞李秀才赴舉','劉希夷','唐','唐诗','tang','','[]','鴻鵠振羽翮，翻飛入帝鄉。',48,'全唐诗/poet.tang.4000.json','["鴻鵠振羽翮，翻飛入帝鄉。", "朝鳴集銀樹，暝宿下金塘。", "日月天門近，風煙夜路長。", "自憐窮浦鴈，歲歲不隨陽。"]'),
('8770df95-5fd5-4c31-bbed-84673c44bf0d','夜集張諲所居','劉希夷','唐','唐诗','tang','','[]','江南成久客，門館日蕭條。',60,'全唐诗/poet.tang.4000.json','["江南成久客，門館日蕭條。", "惟有圖書在，多傷鬢髪凋。", "諸生陪講誦，稚子給漁樵。", "隱室寒燈淨，空階落葉飄。", "滄洲自有趣，誰道隱須招。"]'),
('04b25c1a-99ee-47af-9293-8c97360fd8a7','故園置酒','劉希夷','唐','唐诗','tang','','[]','酒熟人須飲，春還鬢已秋。',72,'全唐诗/poet.tang.4000.json','["酒熟人須飲，春還鬢已秋。", "願逢千日醉，得緩百年憂。", "舊里多青草，新知盡白頭。", "風前燈易滅，川上月難留。", "卒卒周姬旦，栖栖魯孔丘。", "平生能幾日，不及且遨遊。"]'),
('91716c18-5b2d-48a2-a931-a2235491a32d','晚憩南陽旅館','劉希夷','唐','唐诗','tang','','[]','旅館何年廢，征夫此日過。',72,'全唐诗/poet.tang.4000.json','["旅館何年廢，征夫此日過。", "途窮人自哭，春至鳥還歌。", "行路新知少，荒田古徑多。", "池篁覆丹谷，墳樹遶清波。", "日照蓬陰轉，風微野氣和。", "傷心不可去，回首怨如何。"]'),
('adb7b5ad-2563-408b-ba48-dc181ce10a8b','慶雲章','陳子昂','唐','唐诗','tang','','[]','崑崙元氣，實生慶雲。',100,'全唐诗/poet.tang.4000.json','["崑崙元氣，實生慶雲。", "大人作矣，五色氤氳。", "昔在帝嬀，南風既薰。", "叢芳爛熳，郁郁纷纷。", "曠矣千祀，慶雲來止。", "玉葉金柯，祚我天子。", "非我天子，慶雲誰昌。", "非我聖母，慶雲誰光。", "慶雲光矣，周道昌矣。", "九萬八千，天授皇年。"]'),
('bb031d03-9ba9-46fb-917c-a031de89c0e0','感遇詩三十八首 一','陳子昂','唐','唐诗','tang','','[]','微月生西海，幽陽始代昇。',48,'全唐诗/poet.tang.4000.json','["微月生西海，幽陽始代昇。", "圓光正東滿，陰魂已朝凝。", "太極生天地，三元更廢興。", "至精諒斯在，三五誰能徵。"]'),
('813e4c17-280a-4b7f-929e-ade3aea6615f','感遇詩三十八首 二','陳子昂','唐','唐诗','tang','','[]','蘭若生春夏，芊蔚何青青。',48,'全唐诗/poet.tang.4000.json','["蘭若生春夏，芊蔚何青青。", "幽獨空林色，朱蕤冒紫莖。", "遲遲白日晚，嫋嫋秋風生。", "歲華盡搖落，芳意竟何成。"]'),
('ccdfb12e-2b17-46dd-b76b-fcb3fd9c1df8','感遇詩三十八首 三','陳子昂','唐','唐诗','tang','','[]','蒼蒼丁零塞，今古緬荒途。',60,'全唐诗/poet.tang.4000.json','["蒼蒼丁零塞，今古緬荒途。", "亭堠何摧兀，暴骨無全軀。", "黃沙幕南起，白日隱西隅。", "漢甲三十萬，曾以事匈奴。", "但見沙場死，誰憐塞上孤。"]'),
('b5018154-99a3-4b60-a73f-6f2c020d3026','感遇詩三十八首 四','陳子昂','唐','唐诗','tang','','[]','樂羊爲魏將，食子殉軍功。',48,'全唐诗/poet.tang.4000.json','["樂羊爲魏將，食子殉軍功。", "骨肉且相薄，他人安得忠。", "吾聞中山相，乃屬放麑翁。", "孤獸猶不忍，況以奉君終。"]'),
('96def3fd-c079-48be-a7b0-61c98b158751','感遇詩三十八首 五','陳子昂','唐','唐诗','tang','','[]','市人矜巧智，於道若童蒙。',48,'全唐诗/poet.tang.4000.json','["市人矜巧智，於道若童蒙。", "傾奪相夸侈，不知身所終。", "曷見玄真子，觀世玉壺中。", "窅然遺天地，乘化入無窮。"]'),
('35a0467d-7ae0-4322-8f0b-4933fa5a358c','感遇詩三十八首 六','陳子昂','唐','唐诗','tang','','[]','吾觀龍變化，乃知至陽精。',72,'全唐诗/poet.tang.4000.json','["吾觀龍變化，乃知至陽精。", "石林何冥密，幽洞無留行。", "古之得仙道，信與元化幷。", "玄感非象識，誰能測沈冥。", "世人拘目見，酣酒笑丹經。", "崑崙有瑤樹，安得采其英。"]'),
('a5e07e0f-d8b4-41ce-8fc6-40dbff5ff6f9','感遇詩三十八首 七','陳子昂','唐','唐诗','tang','','[]','白日每不歸，青陽時暮矣。',48,'全唐诗/poet.tang.4000.json','["白日每不歸，青陽時暮矣。", "茫茫吾何思，林臥觀無始。", "衆芳委時晦，鶗鴂鳴悲耳。", "鴻荒古已頹，誰識巢居子。"]'),
('993937e9-e699-4105-b851-30f0c081a142','感遇詩三十八首 八','陳子昂','唐','唐诗','tang','','[]','吾觀崑崙化，日月淪洞冥。',72,'全唐诗/poet.tang.4000.json','["吾觀崑崙化，日月淪洞冥。", "精魄相交會，天壤以羅生。", "仲尼推太極，老聃貴窈冥。", "西方金仙子，崇義乃無明。", "空色皆寂滅，緣業定何成。", "名教信紛藉，死生俱未停。"]'),
('9791cbe9-4036-4c6b-95ed-656f2afc2e1b','感遇詩三十八首 九','陳子昂','唐','唐诗','tang','','[]','聖人秘元命，懼世亂其真。',72,'全唐诗/poet.tang.4000.json','["聖人秘元命，懼世亂其真。", "如何嵩公輩，詼譎誤時人。", "先天誠爲美，階亂禍誰因。", "長城備胡寇，嬴禍發其親。", "赤精既迷漢，子年何救秦。", "去去桃李花，多言死如麻。"]'),
('4bb8a1b3-116e-4376-ad2c-2e2851ef7b9a','感遇詩三十八首 十','陳子昂','唐','唐诗','tang','','[]','深居觀元化，悱然爭朵頤。',60,'全唐诗/poet.tang.4000.json','["深居觀元化，悱然爭朵頤。", "讒說相啖食，利害紛㘈㘈。", "便便夸毘子，榮耀更相持。", "務光讓天下，商賈競刀錐。", "已矣行采芝，萬世同一時。"]'),
('b6f95606-1644-4604-aa41-9236c8aff802','感遇詩三十八首 十一','陳子昂','唐','唐诗','tang','','[]','吾愛鬼谷子，青谿無垢氛。',72,'全唐诗/poet.tang.4000.json','["吾愛鬼谷子，青谿無垢氛。", "囊括經世道，遺身在白雲。", "七雄方龍鬬，天下久無君。", "浮榮不足貴，遵養晦時文。", "舒可彌宇宙，卷之不盈分。", "豈徒山木壽，空與麋鹿羣。"]'),
('46c4857c-2d99-433f-9814-4958dee37b34','感遇詩三十八首 十二','陳子昂','唐','唐诗','tang','','[]','呦呦南山鹿，罹罟以媒和。',72,'全唐诗/poet.tang.4000.json','["呦呦南山鹿，罹罟以媒和。", "招搖青桂樹，幽蠹亦成科。", "世情甘近習，榮耀紛如何。", "怨憎未相復，親愛生禍羅。", "瑤臺傾巧笑，玉杯殞雙蛾。", "誰見枯城蘖，青青成斧柯。"]');
